// ════════════════════════════════════════════════════════════════════════
// Environment variable bindings (Phase 3p.36)
//
// These were missing from the monolith and surfaced by `tsc --noEmit`
// with checkJs: true. Despite being referenced 49 times (MASSIVE_API_KEY)
// + 8 more across the other keys, the monolith never declared them. The
// build succeeded because Vite doesn't fail on undeclared globals at
// build time — but at runtime any code path that touched any of these
// would have ReferenceError'd as the closure scope evaluated.
//
// Confirmed missing (from sweep): MASSIVE_API_KEY (49 use sites), 
// EXA_API_KEY (2), OPENAI_API_KEY (1), CURRENTS_KEY (1), MEDIASTACK_KEY
// (1), NEWSDATA_KEY (2), NYT_KEY (1).
// ════════════════════════════════════════════════════════════════════════
const MASSIVE_API_KEY  = (() => { try { return import.meta.env?.VITE_MASSIVE_API_KEY  ?? ''; } catch { return ''; } })();
const EXA_API_KEY      = (() => { try { return import.meta.env?.VITE_EXA_API_KEY      ?? ''; } catch { return ''; } })();
const OPENAI_API_KEY   = (() => { try { return import.meta.env?.VITE_OPENAI_API_KEY   ?? ''; } catch { return ''; } })();
const CURRENTS_KEY     = (() => { try { return import.meta.env?.VITE_CURRENTS_KEY     ?? ''; } catch { return ''; } })();
const MEDIASTACK_KEY   = (() => { try { return import.meta.env?.VITE_MEDIASTACK_KEY   ?? ''; } catch { return ''; } })();
const NEWSDATA_KEY     = (() => { try { return import.meta.env?.VITE_NEWSDATA_KEY     ?? ''; } catch { return ''; } })();
const NYT_KEY          = (() => { try { return import.meta.env?.VITE_NYT_KEY          ?? ''; } catch { return ''; } })();

