// MicButton — small voice-input button using the Web Speech API. Tap
// to start listening; tap again or auto-stop on silence to commit the
// transcript to the parent input. Used by AI Edit and the ticker
// search box. Browser support: Chrome, Edge, Safari; Firefox has no
// built-in support so the button gracefully hides itself.
//
// Props:
//   onTranscript(text)  — called when speech is recognized (final or
//                         interim if `interim` is true)
//   size                — 'sm' (default) or 'xs' for inline variants
//   title               — tooltip override
// useVoiceWakeWord — always-listening Web Speech recognizer that
// watches for the wake phrase "Hey IMO" (and a handful of close
// homophones the engine often hears instead — "hey emo", "hi imo",
// "a-imo", etc.). On wake detection, it stops the wake-listener,
// fires onWake() so the surrounding UI can switch to "capturing"
// mode, and captures the user's next utterance to deliver as a
// command. After the command (or timeout) it re-arms the wake
// listener.
//
// Architecture rationale: a single recognizer instance can either
// listen for short utterances (commands) or run continuously (wake
// word). We can't run BOTH at once because the browser only
// permits one active recognizer per tab. So we run the same
// instance in two modes: continuous-with-wake-grep, then
// continuous-capture-until-pause.
//
// Browser support: Chromium-based (Chrome, Edge, Brave, Arc,
// Opera) — full support. Safari macOS — partial. Firefox — none.
// The hook exposes `supported` so the UI can hide gracefully.
//
// Privacy: nothing leaves the browser. The Web Speech API uses
// the browser's own speech recognition (Chromium ships Google's
// engine, which DOES send audio to Google's servers). We do not
// proxy or store anything ourselves. Users who care about that
// can disable the feature in Settings.
const WAKE_PATTERNS = [
  // Loose normalized matches — the engine often substitutes nearby
  // sounds, so we accept a handful of variants that all mean "hey imo".
  /\bhe?y +(imo|emo|imho|amo|ammo|info)\b/i,
  /\bhi +(imo|emo|imho|amo)\b/i,
  /\b(imo|emo) +(here|there|are you|listen)\b/i,
];
const matchesWakeWord = (transcript) => {
  if (!transcript) return false;
  const norm = transcript.trim().toLowerCase();
  return WAKE_PATTERNS.some(rx => rx.test(norm));
};
const useVoiceWakeWord = ({ enabled, onCommand }) => {
  // 'unsupported' | 'idle' | 'listening' | 'wake-detected' | 'capturing' | 'error'
  const [status, setStatus] = useState('idle');
  const [supported, setSupported] = useState(false);
  const [lastError, setLastError] = useState(null);
  const recRef = useRef(null);
  const modeRef = useRef('wake'); // 'wake' | 'capture'
  // Track whether the user enabled the feature. We re-read enabled
  // via a ref so the recognizer's onend handler (which may fire
  // long after the effect ran) sees the current value.
  const enabledRef = useRef(enabled);
  useEffect(() => { enabledRef.current = enabled; }, [enabled]);
  const onCommandRef = useRef(onCommand);
  useEffect(() => { onCommandRef.current = onCommand; }, [onCommand]);

  useEffect(() => {
    if (typeof window === 'undefined') return;
    const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SR) {
      setSupported(false);
      setStatus('unsupported');
      return;
    }
    setSupported(true);
  }, []);

  useEffect(() => {
    if (!supported) return;
    if (!enabled) {
      // Tear down any running recognizer when the feature is disabled.
      try { recRef.current?.stop(); } catch {}
      recRef.current = null;
      setStatus('idle');
      return;
    }
    // Spin up the recognizer and start in wake mode.
    const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
    let restartTimer = null;
    let captureTimer = null;
    const startWakeMode = () => {
      modeRef.current = 'wake';
      try {
        const rec = new SR();
        rec.lang = 'en-US';
        rec.continuous = true;       // keep listening across silences
        rec.interimResults = true;   // we want partial results to wake fast
        rec.maxAlternatives = 1;
        rec.onresult = (e) => {
          if (modeRef.current !== 'wake') return;
          // Scan all results — interim or final — for the wake word.
          // If the engine is still settling on what it heard, partial
          // matches are fine; we just want to react fast.
          for (let i = e.resultIndex; i < e.results.length; i++) {
            const text = e.results[i][0]?.transcript ?? '';
            if (matchesWakeWord(text)) {
              setStatus('wake-detected');
              // Stop the wake recognizer; capture mode starts on its
              // onend handler so we don't try to start a new
              // recognizer while the old one is still tearing down
              // (browsers throw "InvalidStateError" otherwise).
              modeRef.current = 'capture-pending';
              try { rec.stop(); } catch {}
              return;
            }
          }
        };
        rec.onerror = (ev) => {
          // 'no-speech' is normal when the room is quiet. 'aborted'
          // happens during stop(). 'not-allowed' is denied permission.
          if (ev.error === 'not-allowed' || ev.error === 'service-not-allowed') {
            setLastError('Microphone permission was denied. Re-enable in your browser site settings.');
            setStatus('error');
            modeRef.current = 'wake';
            return;
          }
          // Anything else: keep going. The onend handler will restart.
          if (ev.error && ev.error !== 'no-speech' && ev.error !== 'aborted') {
            console.warn('[wakeword]', ev.error);
          }
        };
        rec.onend = () => {
          if (!enabledRef.current) {
            // User disabled — don't restart.
            setStatus('idle');
            return;
          }
          if (modeRef.current === 'capture-pending') {
            // Wake fired; flip to capture mode.
            startCaptureMode();
          } else {
            // Wake recognizer ended for some other reason (silence
            // timeout, network blip, browser idle policy). Restart
            // after a short backoff so we don't tight-loop.
            if (restartTimer) clearTimeout(restartTimer);
            restartTimer = setTimeout(() => startWakeMode(), 500);
          }
        };
        rec.start();
        recRef.current = rec;
        setStatus('listening');
      } catch (err) {
        console.warn('[wakeword] failed to start:', err.message);
        setStatus('error');
        setLastError(err.message);
      }
    };
    const startCaptureMode = () => {
      modeRef.current = 'capture';
      setStatus('capturing');
      try {
        const rec = new SR();
        rec.lang = 'en-US';
        rec.continuous = false;      // stop on first natural pause
        rec.interimResults = false;
        rec.maxAlternatives = 1;
        let captured = '';
        rec.onresult = (e) => {
          for (let i = e.resultIndex; i < e.results.length; i++) {
            if (e.results[i].isFinal) {
              captured = (e.results[i][0]?.transcript ?? '').trim();
            }
          }
        };
        rec.onerror = (ev) => {
          if (ev.error === 'not-allowed') {
            setStatus('error');
            setLastError('Microphone permission was denied.');
          }
        };
        rec.onend = () => {
          // Deliver the captured command (if any) and re-arm the
          // wake listener after a small delay so we don't hear our
          // own TTS response (if the AI agent speaks back).
          if (captured && captured.length >= 2 && !matchesWakeWord(captured)) {
            try { onCommandRef.current?.(captured); } catch {}
          }
          if (captureTimer) clearTimeout(captureTimer);
          captureTimer = setTimeout(() => {
            if (enabledRef.current) startWakeMode();
            else setStatus('idle');
          }, 600);
        };
        rec.start();
        recRef.current = rec;
        // Hard ceiling: if the user starts but doesn't say anything
        // for 8s, abort the capture and re-arm wake mode.
        captureTimer = setTimeout(() => {
          try { rec.stop(); } catch {}
        }, 8000);
      } catch (err) {
        console.warn('[wakeword] capture failed:', err.message);
        setStatus('listening');
        modeRef.current = 'wake';
      }
    };
    startWakeMode();
    return () => {
      if (restartTimer) clearTimeout(restartTimer);
      if (captureTimer) clearTimeout(captureTimer);
      try { recRef.current?.stop(); } catch {}
      recRef.current = null;
    };
  }, [enabled, supported]);
  return { status, supported, lastError };
};

// VoiceTriggerOverlay — tiny floating pill in the bottom-right of
// the viewport showing the wake-word listener's current state.
// Hidden when the feature is disabled or unsupported. Pulses softly
// while listening; flashes mint when the wake word fires; turns
// red on permission errors.
const VoiceTriggerOverlay = ({ status, lastError }) => {
  if (status === 'idle' || status === 'unsupported') return null;
  const palette = {
    'listening':      { bg: 'rgba(0,0,0,0.55)',           border: COLORS.border,  fg: COLORS.textDim, label: 'Listening', dot: COLORS.textDim },
    'wake-detected':  { bg: `${COLORS.mint}26`,           border: COLORS.mint,    fg: COLORS.mint,    label: 'Wake — say your command', dot: COLORS.mint },
    'capturing':      { bg: `${COLORS.mint}26`,           border: COLORS.mint,    fg: COLORS.mint,    label: 'Listening for command', dot: COLORS.mint },
    'error':          { bg: 'rgba(237,112,136,0.10)',     border: COLORS.red,     fg: COLORS.red,     label: lastError || 'Voice error', dot: COLORS.red },
  }[status] ?? { bg: 'transparent', border: COLORS.border, fg: COLORS.textDim, label: '', dot: COLORS.textDim };
  return (
    <div className="fixed z-40 flex items-center gap-1.5 px-2.5 py-1.5 rounded-full text-[10.5px]"
         style={{
           bottom: 16,
           right: 16,
           background: palette.bg,
           border: `1px solid ${palette.border}`,
           color: palette.fg,
           backdropFilter: 'blur(8px) saturate(160%)',
           WebkitBackdropFilter: 'blur(8px) saturate(160%)',
           pointerEvents: 'none',
         }}
         title={status === 'listening'
           ? 'Wake-word listener active. Say "Hey IMO" to send a command.'
           : status === 'capturing' || status === 'wake-detected'
             ? 'Speak your command — pause when you\'re done and it will fire.'
             : (lastError ?? 'Voice trigger error')}>
      <span className="rounded-full"
            style={{
              width: 6, height: 6,
              background: palette.dot,
              animation: (status === 'listening' || status === 'capturing') ? 'pulse 1.4s ease-in-out infinite' : 'none',
            }} />
      <span style={{ fontWeight: 500 }}>{palette.label}</span>
    </div>
  );
};

// Phase 3p.02 (file split, batch 14): workspace lock storage extracted
// to src/lib/lock-storage.js — LOCK_KEY, loadLockState, saveLockState,
// hashPin (21 usage sites in monolith).

// useIdleLock — fires onLock() after `idleMins` of mouse/keyboard
// inactivity. The timer resets on any pointer / key / touch event.
// Disabled if `enabled` is false. Listens for 'imo:lock-now' so
// keyboard shortcuts and Settings buttons can lock manually.
const useIdleLock = ({ enabled, idleMins, onLock, isLocked }) => {
  useEffect(() => {
    if (typeof window === 'undefined') return;
    if (!enabled) return;
    if (isLocked) return; // don't run idle timer while already locked
    let timer = null;
    const ms = Math.max(1, idleMins ?? 5) * 60 * 1000;
    const reset = () => {
      if (timer) clearTimeout(timer);
      timer = setTimeout(() => { try { onLock(); } catch {} }, ms);
    };
    const events = ['mousemove', 'mousedown', 'keydown', 'touchstart', 'wheel', 'scroll'];
    events.forEach(ev => window.addEventListener(ev, reset, { passive: true }));
    const onManualLock = () => { try { onLock(); } catch {} };
    window.addEventListener('imo:lock-now', onManualLock);
    reset();
    return () => {
      if (timer) clearTimeout(timer);
      events.forEach(ev => window.removeEventListener(ev, reset));
      window.removeEventListener('imo:lock-now', onManualLock);
    };
  }, [enabled, idleMins, onLock, isLocked]);
};

// LockScreen — fullscreen overlay shown when the workspace is
// locked. Two states:
//   - No PIN set yet → "set PIN" view (4-6 digit numeric)
//   - PIN set → unlock view with PIN dots + numeric keypad
//
// On successful unlock: clears `locked` in localStorage and calls
// onUnlock(). On wrong PIN: shake animation + small attempt counter.
// After 5 wrong attempts the screen offers a "sign out" escape so
// the user isn't permanently locked out (sign-out clears the user
// and routes back to the login flow, which is the intended escape
// hatch for a forgotten PIN — there's no PIN reset email since
// this is a local-only feature).

