/* ──────────── Real market data (Coinbase WS + massive.com REST + EIA REST) ──────────── */

// Map Onyx instrument IDs → Coinbase product IDs (real-time WebSocket ticker)

// ──────── Multi-provider LLM abstraction ────────
//
// The terminal supports multiple LLM providers with a single
// adapter contract. Each provider exposes:
//   - id          string identifier (used in localStorage)
//   - label       human-readable name
//   - models      array of { id, label, vision, contextWindow }
//   - hasEnvKey() returns true if env variable is configured
//   - callChat(messages, opts) → string|null
//     opts: { model, maxTokens, system, images }
//
// Provider preference order:
//   1. User-set active provider in localStorage 'imo_llm_active'
//   2. Anthropic if VITE_ANTHROPIC_API_KEY set (back-compat default)
//   3. OpenAI if VITE_OPENAI_API_KEY set
//   4. None (canned responses)
//
// User-supplied API keys (typed in Settings) take precedence over
// environment variables, so a user can override the deployer's
// default keys with their own without rebuilding.
//
// 'imo_llm_keys' = { anthropic, openai, gemini, ollama_url }
// 'imo_llm_active' = { providerId, modelId }
//
// Vision is per-provider per-model — the registry tracks which
// models support image input. callAI routes images-bearing
// requests only to vision-capable models, falling back to a
// helpful error if the active provider doesn't support vision.

// ──────── Multi-broker abstraction ────────
//
// Broker adapters let the user route orders through their preferred
// brokerage instead of (or alongside) the in-app paper account. Each
// adapter implements a common contract:
//
//   {
//     id:        string identifier
//     label:     human-readable name
//     kind:      'gateway' | 'oauth' | 'cloud'
//     configFields: [{ key, label, placeholder, type, required }]
//                — input fields rendered in the broker settings panel
//     getStatus(config):    'idle'|'connected'|'unauthenticated'|'error'
//     getAccounts(config):  [{ id, label, type, currency }]
//     getPositions(config, accountId): [{ symbol, qty, avgPx, mark, ... }]
//     placeOrder(config, accountId, params): { ok, orderId?, error? }
//     getQuote(config, symbol):  { bid, ask, last, ts }
//   }
//
// Storage:
//   'imo_brokers'         { [providerId]: { ...configFields } }
//   'imo_active_broker'   { providerId, accountId }
//
// The "paper" pseudo-broker is the existing in-app account — that's
// the default and always available. Real broker adapters slot in
// alongside; they don't replace the paper account.
// Phase 3p.01 (file split, batch 13): broker config storage helpers
// extracted to src/lib/broker-storage.js — BROKERS_STORAGE,
// ACTIVE_BROKER_STORAGE, loadBrokerConfigs, saveBrokerConfigs,
// loadActiveBroker, saveActiveBroker (27 usage sites).

// IBKR Client Portal Gateway adapter
//
// Interactive Brokers ships a Java-based "Client Portal Gateway"
// that runs locally on the user's machine. The gateway handles
// OAuth/SSO with IBKR's servers and exposes a REST API on
// localhost (default https://localhost:5000/v1/api/...). The SPA
// can talk to it directly without CORS issues since the user
// owns both endpoints.
//
// Setup flow:
//   1. User downloads clientportal.gw from interactivebrokers.com
//   2. Runs the gateway: ./bin/run.sh root/conf.yaml
//   3. Browser to https://localhost:5000 to log in (one-time)
//   4. Configures the gateway URL in our settings panel
//   5. Clicks "Test connection" — adapter checks /iserver/auth/status
//
// For the placeOrder path we use IBKR's two-step preview/confirm:
//   POST /iserver/account/{accountId}/order  → returns reply array
//                                                with confirm prompts
//   POST /iserver/reply/{replyId}             → confirm each prompt
// We auto-confirm standard prompts (price within typical range,
// margin warnings the user has already seen via our safety gate).

// ──────── 16. Anthropic Claude API (preferred when key is set) ────────
// Primary AI helper used by Chart Scanner, AI Ticker Search, and the
// "stocks for you" onboarding card. Returns a string (the assistant's
// text response) or null on failure. Browser CORS: Anthropic supports
// dangerously_allow_browser via the proxy approach. Most users will run
// this through their own backend; for the dev build we go direct.

// ──────── 17. Polygon /vX/reference/financials (KEY required) ────────
// Real income statement / balance sheet / cash flow for any US ticker.
// Replaces the hardcoded FINANCIAL_REPORTS table.

// ────────── DBnomics API integration ──────────
// Free public API aggregating macroeconomic time series from 80+
// providers — central banks (FED, ECB, BOJ, BOE, PBoC), stats
// agencies (BLS, BEA, Eurostat, ONS), international orgs (IMF, OECD,
// BIS, World Bank), and more. No API key required, no rate limit
// published, CORS-friendly. Series are addressed as
// {provider}/{dataset}/{series} — e.g. FED/H15/RIFLGFCY10_N.B for
// 10-year Treasury yield.
//
// Returns a normalized time series:
//   { id, label, provider, frequency, unit, points: [{ t, v }] }
// where t is an ISO date string and v is the numeric value (or
// null for missing observations — DBnomics uses "NA" in the
// raw API and we sanitize to null).
//
// Cached for 30 minutes since most macro series update at most
// daily and we don't want to hammer the API on every page-flip.
const fetchDbnomicsSeries = async (seriesId) => {
  if (!seriesId) return null;
  const cacheKey = `dbnomics:${seriesId}`;
  const cached = cacheGet(cacheKey, 30 * 60_000);
  if (cached) return cached;
  try {
    // DBnomics URL shape: /v22/series/{provider}/{dataset}/{series}
    // ?observations=1 pulls the actual data points (without it we
    // get just metadata, which is faster but useless for charting).
    const url = `https://api.db.nomics.world/v22/series/${seriesId}?observations=1`;
    const r = await fetch(url);
    if (!r.ok) throw new Error(`HTTP ${r.status}`);
    const j = await r.json();
    const s = j?.series?.docs?.[0];
    if (!s) return null;
    // Observations come as parallel arrays — periods[] and values[]
    // of equal length. Some values may be "NA" strings; coerce those
    // to null and pair up with the period.
    const periods = s.period ?? [];
    const values  = s.value ?? [];
    const points = [];
    for (let i = 0; i < Math.min(periods.length, values.length); i++) {
      const v = values[i];
      const num = (v === 'NA' || v == null) ? null : Number(v);
      points.push({
        t: periods[i],
        v: Number.isFinite(num) ? num : null,
      });
    }
    const out = {
      id:        seriesId,
      label:     s.dataset_name ?? s.series_name ?? seriesId,
      seriesName: s.series_name ?? '',
      provider:  s['@frequency'] ? s.provider_code : (seriesId.split('/')[0] ?? ''),
      frequency: s['@frequency'] ?? s.dimensions?.FREQ ?? null,
      unit:      s.dimensions?.UNIT ?? s.unit ?? null,
      points,
    };
    cacheSet(cacheKey, out);
    return out;
  } catch (e) {
    console.warn('[DBnomics]', seriesId, e.message);
    return null;
  }
};

// ────────── Live SPDR sector ETF AUM-derived weights ──────────
// Phase 3o.85 — closes the long-deferred "live S&P sector weights"
// item. The official S&P Indices live feed costs money and is
// behind index licensing; the next-best public proxy is to size the
// 11 SPDR sector SPDR ETFs (XLK/XLV/XLF/XLY/XLP/XLE/XLI/XLB/XLU/XLRE/XLC)
// by their current market cap and normalize.
//
// Caveats — disclosed honestly in the Risk panel footer:
//   1. ETF AUM ≠ underlying S&P sector weight. AUM tracks INVESTOR
//      FLOWS into the sector ETF, not the sector's share of the
//      S&P 500 by float-adjusted market cap. They roughly correlate
//      (within a few hundred bps per sector) but can diverge during
//      flow-driven episodes.
//   2. SPDR ETFs sample the underlying index — they don't replicate
//      the full S&P 500 sector, so even tracking is imperfect.
//   3. We compute AUM = price × shares_outstanding. Polygon's
//      /v3/reference/tickers endpoint returns share_class_shares_outstanding
//      which is updated periodically, not tick-by-tick.
//
// Returns null on failure so callers can fall back to the curated
// SP500_TYPICAL_SECTOR_WEIGHTS map. Cached 6h since this changes
// slowly day-to-day.
//
// Output shape:
//   { weights: { 'Technology': 0.298, ... }, asOf: '2026-05-01',
//     etfData: [{ symbol, sector, price, shares, aum, weight }],
//     totalAUM: 850e9, source: 'polygon-live' | 'curated-fallback' }
const fetchLiveSectorETFWeights = async () => {
  const cacheKey = 'live-sector-weights';
  const cached = cacheGet(cacheKey, 6 * 60 * 60_000); // 6h
  if (cached) return cached;
  if (!MASSIVE_API_KEY) {
    return { weights: SP500_TYPICAL_SECTOR_WEIGHTS, asOf: null,
             etfData: [], totalAUM: 0, source: 'curated-fallback' };
  }
  // Sector ETF → sector key in our taxonomy. We map the Polygon-derived
  // sector to the same string used in SP500_TYPICAL_SECTOR_WEIGHTS so
  // downstream consumers don't need to know about the swap.
  const ETF_TO_SECTOR = [
    { symbol: 'XLK',  sector: 'Technology' },
    { symbol: 'XLV',  sector: 'Health Care' },
    { symbol: 'XLF',  sector: 'Financials' },
    { symbol: 'XLY',  sector: 'Consumer Cyclical' },
    { symbol: 'XLC',  sector: 'Communication' },
    { symbol: 'XLI',  sector: 'Industrials' },
    { symbol: 'XLP',  sector: 'Consumer Defensive' },
    { symbol: 'XLE',  sector: 'Energy' },
    { symbol: 'XLRE', sector: 'Real Estate' },
    { symbol: 'XLU',  sector: 'Utilities' },
    { symbol: 'XLB',  sector: 'Basic Materials' },
  ];
  try {
    // For each ETF: fetch the most recent close price (1d aggs) AND the
    // current share count. We do these in parallel; failures mark that
    // ETF as missing and we exclude it from the weight calculation
    // (rather than zero-fill which would distort the others).
    const fetched = await Promise.all(ETF_TO_SECTOR.map(async (e) => {
      try {
        // Most recent daily aggregate gives us the latest close price.
        // 5 days of cushion in case of weekend/holiday gaps.
        const aggsUrl = `https://api.polygon.io/v2/aggs/ticker/${e.symbol}/range/1/day/`
          + `${new Date(Date.now() - 7 * 86400000).toISOString().slice(0, 10)}/`
          + `${new Date().toISOString().slice(0, 10)}?adjusted=true&sort=desc&limit=5&apiKey=${MASSIVE_API_KEY}`;
        // /v3/reference/tickers/{symbol} returns metadata including
        // share_class_shares_outstanding (the relevant figure for AUM).
        const refUrl = `https://api.polygon.io/v3/reference/tickers/${e.symbol}?apiKey=${MASSIVE_API_KEY}`;
        const [aggsR, refR] = await Promise.all([fetch(aggsUrl), fetch(refUrl)]);
        if (!aggsR.ok || !refR.ok) return { ...e, price: null, shares: null, aum: 0, asOf: null };
        const aggsJ = await aggsR.json();
        const refJ  = await refR.json();
        const lastBar = aggsJ?.results?.[0];
        const price = Number(lastBar?.c) || null;
        const asOf = lastBar?.t ? new Date(lastBar.t).toISOString().slice(0, 10) : null;
        // Polygon names this field share_class_shares_outstanding;
        // older response shapes may use weighted_shares_outstanding.
        const shares = Number(refJ?.results?.share_class_shares_outstanding
                            ?? refJ?.results?.weighted_shares_outstanding) || null;
        const aum = (price && shares) ? price * shares : 0;
        return { ...e, price, shares, aum, asOf };
      } catch {
        return { ...e, price: null, shares: null, aum: 0, asOf: null };
      }
    }));
    // Filter out ETFs we couldn't price/size — better to fall back than
    // to publish a distorted distribution.
    const valid = fetched.filter(d => d.aum > 0);
    if (valid.length < 8) {
      // Fewer than 8 of 11 sector ETFs returned data; fall back to curated.
      return { weights: SP500_TYPICAL_SECTOR_WEIGHTS, asOf: null,
               etfData: fetched, totalAUM: 0, source: 'curated-fallback' };
    }
    const totalAUM = valid.reduce((a, d) => a + d.aum, 0);
    const weights = {};
    for (const d of valid) {
      weights[d.sector] = d.aum / totalAUM;
      d.weight = d.aum / totalAUM;
    }
    // Find the most common asOf date for display.
    const dateCounts = {};
    for (const d of valid) if (d.asOf) dateCounts[d.asOf] = (dateCounts[d.asOf] || 0) + 1;
    const asOf = Object.entries(dateCounts).sort((a, b) => b[1] - a[1])[0]?.[0] || null;
    const out = {
      weights,
      asOf,
      etfData: valid,
      totalAUM,
      source: 'polygon-live',
    };
    cacheSet(cacheKey, out);
    return out;
  } catch (e) {
    console.warn('[Live sector weights]', e.message);
    return { weights: SP500_TYPICAL_SECTOR_WEIGHTS, asOf: null,
             etfData: [], totalAUM: 0, source: 'curated-fallback' };
  }
};

// ────────── Live Kenneth French research factors ──────────
// Phase 3o.86 — closes the long-deferred "live FF factors" item.
// Fetches the Tuck/Dartmouth daily 5-factor CSV via the Vercel proxy
// at /api/ff-factors. Returns raw factor returns (decimal) plus a
// last-known date. Falls back to null on failure so callers can
// continue using the ETF-proxy approximation already in place.
//
// Output shape:
//   { rows: [{date, mktrf, smb, hml, rmw, cma, rf}, ...],
//     asOf: 'YYYY-MM-DD', count: 7800, source: 'tuck-live' }

// ────────── DBnomics catalog search ──────────
// Hits DBnomics' /v22/search endpoint to look up series by free
// text. Returns { results, total, offset, limit } so callers can
// paginate. Cached per (query, offset) for 5 min.
//
// Pagination via DBnomics' offset parameter. Page size 30 is the
// default; users hit "Load 30 more" to extend the visible list.
const searchDbnomicsCatalog = async (query, { offset = 0, limit = 30 } = {}) => {
  const q = (query ?? '').trim();
  if (q.length < 2) return { results: [], total: 0, offset, limit };
  const cacheKey = `dbnomics:search:${q.toLowerCase()}:${offset}:${limit}`;
  const cached = cacheGet(cacheKey, 5 * 60_000);
  if (cached) return cached;
  try {
    const url = `https://api.db.nomics.world/v22/search?q=${encodeURIComponent(q)}&offset=${offset}&limit=${limit}`;
    const r = await fetch(url);
    if (!r.ok) throw new Error(`HTTP ${r.status}`);
    const j = await r.json();
    const docs = j?.results?.docs ?? [];
    const total = j?.results?.num_found ?? docs.length;
    const out = {
      results: docs.map(d => ({
        id:        d.code ?? `${d.provider_code}/${d.dataset_code}/${d.series_code}`,
        label:     d.name || d.dataset_name || d.code,
        desc:      d.dataset_name ? `${d.provider_code} · ${d.dataset_name}` : (d.code ?? ''),
        provider:  d.provider_code,
        group:     'Search',
      })),
      total,
      offset,
      limit,
    };
    cacheSet(cacheKey, out);
    return out;
  } catch (e) {
    console.warn('[DBnomics search]', e.message);
    return null;
  }
};

// ────────── Defensive EIA value validation ──────────
// EIA occasionally returns stale bars with null values, index-normalized 100s,
// or values in unexpected units (e.g. $/bbl for a series documented as
// $/gallon). Without validation these propagate straight to the live price
// display, which is where the "prices jump to 100" / "pegged at $100" bugs
// came from.

// Per-instrument live-price bands. Real multi-year extremes rarely exceed ~2×
// the mark for crude (WTI peaked at $147 in 2008, currently ~$90) and ~3×
// for natural gas (more volatile). These bounds are tight on the upside to
// catch spurious $100-ish index values, loose on the downside to preserve
// COVID-era $20 oil legitimacy if the current mark was set higher.
// For the *live* price header — VERY TIGHT band around the configured mark.
// With mark=$88 (WTI), ±8% allows $80.96–$95.04 — this rejects stale $100
// spike bars from multi-week-old news events while allowing normal daily
// variation. If the true market moves outside ±8% we'll update the mark
// in the next release.
const isPlausibleLivePrice = (n, inst) => {
  if (!Number.isFinite(n) || n <= 0) return false;
  return n >= inst.mark * 0.92 && n <= inst.mark * 1.08;
};

// For the *historical* chart — looser, to preserve multi-year legitimate
// extremes. WTI hit $147 in 2008 and $20 in COVID, so we allow a wide band
// but still reject values outside a realistic dollar range for the instrument.
const isPlausibleHistoricalPrice = (n, inst) => {
  if (!Number.isFinite(n) || n <= 0) return false;
  return n >= inst.mark * 0.15 && n <= inst.mark * 3;
};

// Parses a single EIA v2 data point into a number, returning null for
// anything unparseable. Handles both number and string values (EIA v2.1.6
// standardized values to strings in Jan 2024).
const parseEiaValue = (pt) => {
  const raw = pt?.value;
  if (raw == null || raw === '') return null;
  const n = Number(raw);
  return Number.isFinite(n) ? n : null;
};

// Check if the US equity market is currently open. Approximation:
//   - Mon-Fri only (skips weekends)
//   - 9:30 AM to 4:00 PM Eastern Time
// Doesn't handle holidays (Christmas, July 4th, etc.) — those would need a
// hardcoded calendar. ET = UTC-5 (winter EST) or UTC-4 (summer EDT). For
// simplicity we assume EDT/EST automatically by computing from the user's
// local time and converting to ET via Intl.

// ═══════════════════════════════════════════════════════════════════════════
// useBackend — single point of truth for talking to the 3 backend services.
// (Phase 0 integration, see services/ folder for tick/executor/agent.)
//
// Returns: { get, post, stream, status, urls }
//   - get(service, path)        → fetch wrapper, 5s timeout, 1 retry
//   - post(service, path, body) → same
//   - stream(service, path, onMessage, onError) → WebSocket with reconnect
//   - status: { tick, executor, zeroclaw } each: 'connected'|'down'|'unconfigured'
//
// Polls each /health every 30s and dispatches `imo:backend-status` window
// events for the StatusBar to display.
// ═══════════════════════════════════════════════════════════════════════════
const useBackend = () => {
  const URLS = useMemo(() => ({
    tick:     import.meta.env.VITE_TICK_API_URL     || '',
    executor: import.meta.env.VITE_EXECUTOR_API_URL || '',
    zeroclaw: import.meta.env.VITE_ZEROCLAW_GATEWAY_URL || '',
    scanner:  import.meta.env.VITE_SCANNER_API_URL  || '',
  }), []);
  const ENV_TOKEN = import.meta.env.VITE_BACKEND_AUTH_TOKEN || '';
  // JWT support — when the user logs in via /auth/login, the token is
  // stored in localStorage and used in preference to the env-baked legacy
  // bearer. This lets a deployment use JWT-only mode (LEGACY_AUTH_TOKEN
  // empty on the backend) while still allowing the existing dev flow.
  const [jwtToken, setJwtToken] = useState(() => {
    try { return localStorage.getItem('imo_jwt') || ''; } catch { return ''; }
  });
  const TOKEN = jwtToken || ENV_TOKEN;
  const tokenSource = jwtToken ? 'jwt' : (ENV_TOKEN ? 'legacy' : 'none');

  const [status, setStatus] = useState({
    tick:     URLS.tick     ? 'connecting' : 'unconfigured',
    executor: URLS.executor ? 'connecting' : 'unconfigured',
    zeroclaw: URLS.zeroclaw ? 'connecting' : 'unconfigured',
  });
  const [lastSeen, setLastSeen] = useState({}); // service → last successful health ts

  const baseUrl = (service) => URLS[service] || '';

  const get = async (service, path, opts = {}) => {
    const url = baseUrl(service);
    if (!url) throw new Error(`${service} not configured`);
    const ctrl = new AbortController();
    const timer = setTimeout(() => ctrl.abort(), opts.timeout ?? 5000);
    try {
      const r = await fetch(`${url}${path}`, {
        method: 'GET',
        headers: {
          ...(opts.skipAuth ? {} : { Authorization: `Bearer ${TOKEN}` }),
          ...(opts.headers || {}),
        },
        signal: ctrl.signal,
      });
      clearTimeout(timer);
      if (!r.ok) throw new Error(`${service} ${path} → ${r.status}`);
      return await r.json();
    } catch (e) {
      clearTimeout(timer);
      throw e;
    }
  };

  const post = async (service, path, body, opts = {}) => {
    const url = baseUrl(service);
    if (!url) throw new Error(`${service} not configured`);
    const ctrl = new AbortController();
    const timer = setTimeout(() => ctrl.abort(), opts.timeout ?? 8000);
    try {
      const r = await fetch(`${url}${path}`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          ...(opts.skipAuth ? {} : { Authorization: `Bearer ${TOKEN}` }),
          ...(opts.headers || {}),
        },
        body: JSON.stringify(body || {}),
        signal: ctrl.signal,
      });
      clearTimeout(timer);
      if (!r.ok) {
        const errText = await r.text().catch(() => '');
        throw new Error(`${service} ${path} → ${r.status} ${errText.slice(0, 200)}`);
      }
      return await r.json();
    } catch (e) {
      clearTimeout(timer);
      throw e;
    }
  };

  // WebSocket helper with auto-reconnect + exp backoff
  const stream = (service, path, onMessage, onError) => {
    const url = baseUrl(service);
    if (!url) return () => {};
    const wsUrl = url.replace(/^http/, 'ws') + path
      + (path.includes('?') ? '&' : '?') + 'token=' + encodeURIComponent(TOKEN);
    let ws = null;
    let backoff = 1000;
    let stopped = false;
    const connect = () => {
      if (stopped) return;
      try {
        ws = new WebSocket(wsUrl);
        ws.onopen = () => { backoff = 1000; };
        ws.onmessage = (e) => {
          try { onMessage(JSON.parse(e.data)); } catch { onMessage(e.data); }
        };
        ws.onerror = (e) => { if (onError) onError(e); };
        ws.onclose = () => {
          if (stopped) return;
          setTimeout(connect, backoff);
          backoff = Math.min(backoff * 2, 30000);
        };
      } catch (e) {
        if (onError) onError(e);
        setTimeout(connect, backoff);
      }
    };
    connect();
    return () => { stopped = true; if (ws) ws.close(); };
  };

  // Poll /health every 30s
  useEffect(() => {
    let alive = true;
    const poll = async () => {
      const next = { ...status };
      const seen = { ...lastSeen };
      for (const svc of ['tick', 'executor', 'zeroclaw']) {
        if (!URLS[svc]) { next[svc] = 'unconfigured'; continue; }
        try {
          await get(svc, '/health', { timeout: 3000, skipAuth: true });
          next[svc] = 'connected';
          seen[svc] = Date.now();
        } catch {
          next[svc] = 'down';
        }
      }
      if (!alive) return;
      setStatus(next);
      setLastSeen(seen);
      try {
        window.dispatchEvent(new CustomEvent('imo:backend-status', {
          detail: { status: next, lastSeen: seen },
        }));
      } catch {}
    };
    poll();
    const id = setInterval(poll, 30000);
    return () => { alive = false; clearInterval(id); };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [URLS.tick, URLS.executor, URLS.zeroclaw]);

  // Auth helpers — call /auth/login on any of the 3 services, store JWT
  const login = async ({ username, name, service = 'executor' }) => {
    if (!URLS[service]) throw new Error(`${service} not configured`);
    const r = await fetch(`${URLS[service]}/auth/login`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ username, name }),
    });
    if (!r.ok) throw new Error(`login failed: ${r.status}`);
    const j = await r.json();
    if (!j.token) throw new Error('login response missing token');
    try { localStorage.setItem('imo_jwt', j.token); } catch {}
    setJwtToken(j.token);
    // Audit: JWT mint event. Don't log the token itself — just the
    // service it was issued for and the user-supplied identity. The
    // actual token sits in localStorage where the rest of the app
    // can grab it.
    try {
      appendAuditEntry({
        category: 'auth',
        action:   'jwt-issued',
        target:   service,
        actor:    username ?? null,
        details:  { service, userId: j.userId ?? null },
      });
    } catch {}
    return { token: j.token, userId: j.userId };
  };

  const logout = () => {
    try { localStorage.removeItem('imo_jwt'); } catch {}
    setJwtToken('');
    try {
      appendAuditEntry({
        category: 'auth',
        action:   'jwt-revoked',
        target:   'all-services',
      });
    } catch {}
  };

  return {
    get, post, stream,
    status, lastSeen, urls: URLS,
    token: TOKEN, tokenSource,
    login, logout,
    hasJwt: !!jwtToken,
  };
};




// Track window size so layout components can compress when narrow.
// Returns { w, h } in pixels.

const useChainStatus = () => {
  const [s, setS] = useState({ seq: 0.8, bft: 4.2, blk: 4892341, tps: 847 });
  useEffect(() => {
    const t = setInterval(() => setS(p => ({
      seq: +(0.6 + Math.random() * 0.5).toFixed(2),
      bft: +(3.8 + Math.random() * 1.2).toFixed(1),
      blk: p.blk + (Math.random() > 0.3 ? 1 : 0),
      tps: Math.floor(600 + Math.random() * 500),
    })), 1000);
    return () => clearInterval(t);
  }, []);
  return s;
};

/* ──────────── User account (localStorage) ──────────── */

const USER_KEY = 'onyx_user_v1';
const USERS_LIST_KEY = 'onyx_users_v1'; // array of saved profiles for multi-account
const SETTINGS_KEY = 'onyx_settings_v1'; // { showTooltips: bool }

// Simple FNV-1a hash for password storage. Not cryptographically secure —
// but sufficient for a demo platform where passwords aren't sent over a
// network. In a real production app we'd use bcrypt/scrypt server-side.
const hashPassword = (pw) => {
  let h = 2166136261 >>> 0;
  for (let i = 0; i < pw.length; i++) {
    h ^= pw.charCodeAt(i);
    h = (h * 16777619) >>> 0;
  }
  return h.toString(16).padStart(8, '0');
};

const loadUser = () => {
  try {
    const raw = typeof window !== 'undefined' && window.localStorage
      ? window.localStorage.getItem(USER_KEY)
      : null;
    return raw ? JSON.parse(raw) : null;
  } catch { return null; }
};

const saveUser = (user) => {
  try {
    if (typeof window !== 'undefined' && window.localStorage) {
      window.localStorage.setItem(USER_KEY, JSON.stringify(user));
      // Also keep the user in the list of saved accounts so the user can
      // switch between them. Match by username.
      const existing = loadUserList();
      const idx = existing.findIndex(u => u.username === user.username);
      if (idx >= 0) existing[idx] = user;
      else existing.push(user);
      window.localStorage.setItem(USERS_LIST_KEY, JSON.stringify(existing));
    }
  } catch {}
};

const loadUserList = () => {
  try {
    const raw = typeof window !== 'undefined' && window.localStorage
      ? window.localStorage.getItem(USERS_LIST_KEY)
      : null;
    return raw ? JSON.parse(raw) : [];
  } catch { return []; }
};

const removeUserFromList = (username) => {
  try {
    if (typeof window !== 'undefined' && window.localStorage) {
      const existing = loadUserList().filter(u => u.username !== username);
      window.localStorage.setItem(USERS_LIST_KEY, JSON.stringify(existing));
    }
  } catch {}
};

// User-level UI settings (tooltips on/off, etc)
const loadSettings = () => {
  try {
    const raw = typeof window !== 'undefined' && window.localStorage
      ? window.localStorage.getItem(SETTINGS_KEY)
      : null;
    return raw ? JSON.parse(raw) : { showTooltips: true };
  } catch { return { showTooltips: true }; }
};

const saveSettings = (s) => {
  try {
    if (typeof window !== 'undefined' && window.localStorage) {
      window.localStorage.setItem(SETTINGS_KEY, JSON.stringify(s));
    }
  } catch {}
};

const clearUser = () => {
  try {
    if (typeof window !== 'undefined' && window.localStorage) {
      window.localStorage.removeItem(USER_KEY);
    }
  } catch {}
};

// applyThemeColors — mutates the global COLORS object and root CSS
// custom properties to reflect the chosen theme. Extracted as a
// top-level function so the Settings click handler can call it
// SYNCHRONOUSLY before the re-render fires, ensuring the next render
// sees the new color values. Previously this lived only inside an
// useEffect that ran AFTER render — so the re-render triggered by
// the theme change saw OLD COLORS values, leaving the page partially
// themed (Settings panel updated, but the chart/order-entry behind
// it stayed in the prior theme until the next unrelated re-render).
//
// Accepts the SIGNUP-flow theme id ('default' | 'blue' | 'pink').
// Settings ids ('dark' | 'light' | 'rose') get mapped before calling.
const applyThemeColors = (theme) => {
  if (typeof document === 'undefined') return;
  const root = document.documentElement;
  if (theme === 'pink') {
    // Rose theme — pale tinted background, white card surfaces, dark
    // text, with rose used only as the brand accent.
    root.style.setProperty('--onyx-mint',     '#E15B7A');
    root.style.setProperty('--onyx-mint-dim', '#C84766');
    root.style.setProperty('--onyx-green',    '#1B7F4F');
    root.style.setProperty('--onyx-bg',       '#FDF2F4');
    root.style.setProperty('--onyx-surface',  '#FFFFFF');
    root.style.setProperty('--onyx-surface2', '#F8E5EA');
    root.style.setProperty('--onyx-text',      '#0F172A');
    root.style.setProperty('--onyx-text-dim',  '#475569');
    root.style.setProperty('--onyx-text-mute', '#94A3B8');
    COLORS.mint     = '#E15B7A';
    COLORS.mintDim  = '#C84766';
    COLORS.green    = '#1B7F4F';
    COLORS.red      = '#C8264C';
    COLORS.bg       = '#FDF2F4';
    COLORS.surface  = '#FFFFFF';
    COLORS.surface2 = '#F8E5EA';
    COLORS.text     = '#0F172A';
    COLORS.textDim  = '#475569';
    COLORS.textMute = '#94A3B8';
    COLORS.border   = '#F2D7DE';
    COLORS.borderHi = '#E5C0CC';
  } else if (theme === 'blue') {
    // Light theme — white surfaces with indigo accents.
    root.style.setProperty('--onyx-mint',     '#3F4DCC');
    root.style.setProperty('--onyx-mint-dim', '#5A6AE0');
    root.style.setProperty('--onyx-green',    '#1B7F4F');
    root.style.setProperty('--onyx-bg',       '#F4F6FB');
    root.style.setProperty('--onyx-surface',  '#FFFFFF');
    root.style.setProperty('--onyx-surface2', '#EAEEF6');
    root.style.setProperty('--onyx-text',      '#0F172A');
    root.style.setProperty('--onyx-text-dim',  '#475569');
    root.style.setProperty('--onyx-text-mute', '#94A3B8');
    COLORS.mint     = '#3F4DCC';
    COLORS.mintDim  = '#5A6AE0';
    COLORS.green    = '#1B7F4F';
    COLORS.red      = '#C8264C';
    COLORS.bg       = '#F4F6FB';
    COLORS.surface  = '#FFFFFF';
    COLORS.surface2 = '#EAEEF6';
    COLORS.text     = '#0F172A';
    COLORS.textDim  = '#475569';
    COLORS.textMute = '#94A3B8';
    COLORS.border   = '#E2E8F0';
    COLORS.borderHi = '#CBD5E1';
  } else {
    // Default / Dark theme — restore originals.
    root.style.removeProperty('--onyx-mint');
    root.style.removeProperty('--onyx-mint-dim');
    root.style.removeProperty('--onyx-green');
    root.style.removeProperty('--onyx-bg');
    root.style.removeProperty('--onyx-surface');
    root.style.removeProperty('--onyx-surface2');
    root.style.removeProperty('--onyx-text');
    root.style.removeProperty('--onyx-text-dim');
    root.style.removeProperty('--onyx-text-mute');
    // Default dark theme — brand blue updated per UX feedback to a
    // deep navy (was #3D7BFF sky blue, which felt too vibrant
    // against the dark background). Deep navy reads as more
    // institutional/serious and pairs better with the gold accents
    // elsewhere in the app. Active pills, links, and the mint
    // accent use this value via COLORS.mint and the CSS var.
    COLORS.mint    = '#1E3A6C';
    COLORS.mintDim = '#2A4D8A';
    COLORS.green   = '#1FB26B';
    COLORS.red     = '#ED7088';
    COLORS.bg      = '#16191E';
    COLORS.surface = '#161A1F';
    COLORS.surface2 = '#1F2530';
    COLORS.text     = '#E5E7EB';
    COLORS.textDim  = '#9CA3AF';
    COLORS.textMute = '#6B7280';
    COLORS.border   = '#23272E';
    COLORS.borderHi = '#2F343C';
    // Override CSS vars so anything reading var(--onyx-mint) picks
    // up the new navy value rather than falling back to the older
    // hard-coded sky blue.
    root.style.setProperty('--onyx-mint',     '#1E3A6C');
    root.style.setProperty('--onyx-mint-dim', '#2A4D8A');
  }
};

const useUser = () => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  useEffect(() => {
    setUser(loadUser());
    setLoading(false);
  }, []);
  const createUser = (u) => { saveUser(u); setUser(u); };
  const signOut = () => { clearUser(); setUser(null); };
  // updateUser — merge a partial patch into the current user, persist,
  // and re-publish to React. Supports nested profile patches via
  // `{ profile: {...} }`. Used by EditProfileModal so users can edit
  // their bio, location, etc. without re-running signup.
  const updateUser = (patch) => {
    setUser(prev => {
      if (!prev) return prev;
      const next = {
        ...prev,
        ...patch,
        profile: patch.profile ? { ...(prev.profile ?? {}), ...patch.profile } : prev.profile,
      };
      try { saveUser(next); } catch {}
      return next;
    });
  };
  return { user, loading, createUser, signOut, updateUser };
};

/* ──────────── Per-user account (balance, deposits, positions) ──────────── */

const EMPTY_ACCOUNT = {
  balance: 0,          // USD available cash
  deposits: [],        // [{ amount, method, ts }]
  withdrawals: [],
  positions: [],       // [] — no auto positions
  orders: [],          // []
  trades: [],          // []
  marginUsed: 0,
  unrealizedPnl: 0,
  volume30d: 0,
  realizedPnl30d: 0,
  watchlist: [],       // array of instrument IDs
  vaults: {},          // { [vaultId]: { principal, depositedAt } }
};

const accountKey = (username) => `onyx_account_${username}_v2`;

const loadAccount = (username) => {
  if (!username) return null;
  try {
    const raw = typeof window !== 'undefined' && window.localStorage
      ? window.localStorage.getItem(accountKey(username))
      : null;
    if (!raw) return { ...EMPTY_ACCOUNT };
    const parsed = JSON.parse(raw);
    return { ...EMPTY_ACCOUNT, ...parsed };
  } catch {
    return { ...EMPTY_ACCOUNT };
  }
};

const saveAccount = (username, account) => {
  if (!username) return;
  try {
    if (typeof window !== 'undefined' && window.localStorage) {
      window.localStorage.setItem(accountKey(username), JSON.stringify(account));
    }
  } catch {}
};

const useAccount = (user) => {
  const [account, setAccount] = useState(null);

  useEffect(() => {
    if (!user) { setAccount(null); return; }
    setAccount(loadAccount(user.username));
  }, [user?.username]);

  const update = (updater) => {
    setAccount(prev => {
      if (!prev) return prev;
      const next = typeof updater === 'function' ? updater(prev) : updater;
      if (user) saveAccount(user.username, next);
      return next;
    });
  };

  const deposit = (amount, method = 'jpmc') => {
    const n = Number(amount);
    if (!isFinite(n) || n <= 0) return;
    update(prev => ({
      ...prev,
      balance: (prev?.balance ?? 0) + n,
      deposits: [...(prev?.deposits ?? []), {
        amount: n,
        method,
        ts: new Date().toISOString(),
      }],
    }));
  };

  const withdraw = (amount) => {
    const n = Number(amount);
    if (!isFinite(n) || n <= 0) return;
    update(prev => {
      const current = prev?.balance ?? 0;
      if (n > current) return prev;
      return {
        ...prev,
        balance: current - n,
        withdrawals: [...(prev?.withdrawals ?? []), {
          amount: n,
          ts: new Date().toISOString(),
        }],
      };
    });
  };

  // Open a leveraged perpetual position. Deducts initial margin from the
  // available balance (held as marginUsed until the position closes).
  // Returns { ok: true, position } on success or { ok: false, error } otherwise.
  const openPosition = ({ instrument, side, size, leverage, entryPrice }) => {
    const sz = Number(size);
    const px = Number(entryPrice);
    const lev = Number(leverage);
    if (!isFinite(sz) || sz <= 0) return { ok: false, error: 'Invalid size' };
    if (!isFinite(px) || px <= 0) return { ok: false, error: 'Invalid price' };
    if (!isFinite(lev) || lev <= 0) return { ok: false, error: 'Invalid leverage' };

    const notional = sz * px;
    const marginReq = notional / lev;
    let result = { ok: false, error: 'unknown' };

    update(prev => {
      // After our margin-deduction fix, `balance` represents true free cash.
      // `marginUsed` is a separate accounting field showing locked margin
      // (used for stats). Available margin is just current balance.
      const avail = prev?.balance ?? 0;
      if (marginReq > avail) {
        result = { ok: false, error: `Insufficient margin. Need $${marginReq.toFixed(2)}, available $${avail.toFixed(2)}.` };
        return prev;
      }

      const position = {
        id: `pos_${Date.now()}_${Math.random().toString(36).slice(2, 7)}`,
        sym: instrument.id,
        chain: instrument.chain,
        side,                             // 'long' | 'short'
        size: sz,                         // contracts or coins
        entry: +px.toFixed(instrument.dec),
        leverage: lev,
        margin: +marginReq.toFixed(2),
        notional: +notional.toFixed(2),
        dec: instrument.dec,
        openedAt: new Date().toISOString(),
      };

      const trade = {
        id: `trd_${Date.now()}_${Math.random().toString(36).slice(2, 7)}`,
        sym: instrument.id,
        side: side === 'long' ? 'buy' : 'sell',
        size: sz.toFixed(instrument.cls === 'crypto' ? 4 : 0),
        price: fmt(px, instrument.dec),
        ctrp: 'Onyx CLOB',
        tx: `0x${Math.random().toString(16).slice(2, 10)}…${Math.random().toString(16).slice(2, 6)}`,
        time: new Date().toLocaleTimeString('en-US', { hour12: false }),
      };

      result = { ok: true, position };

      return {
        ...prev,
        // Deduct initial margin from cash balance — it's now locked in the
        // position (held in `marginUsed`) until the position closes. Without
        // this deduction, the same dollars would count twice in the total
        // value calculation (once as cash, once as position value).
        balance:    (prev?.balance ?? 0) - marginReq,
        marginUsed: (prev?.marginUsed ?? 0) + marginReq,
        volume30d:  (prev?.volume30d  ?? 0) + notional,
        positions:  [position, ...(prev?.positions ?? [])],
        trades:     [trade, ...(prev?.trades ?? [])].slice(0, 100),
      };
    });

    // Audit log: record the position open (best-effort; never blocks).
    try {
      if (result?.ok) {
        appendAuditEntry({
          category: 'order',
          action:   'opened',
          target:   instrument?.id ?? null,
          actor:    user?.username ?? 'user',
          details: {
            side, size: sz, leverage: lev, entry: px, notional,
            positionId: result.position?.id,
          },
        });
      }
    } catch {}

    return result;
  };

  // margin back to available balance and books realized PnL to the balance.
  // Options: returns (currentPremium - entryPremium) * contracts * 100 minus
  // the original premium cost already paid; for simplicity we settle at the
  // current theoretical premium that the caller passes in markPrice.
  const closePosition = (positionId, markPrice) => {
    const mp = Number(markPrice);
    if (!isFinite(mp) || mp <= 0) return { ok: false, error: 'Invalid price' };

    update(prev => {
      const pos = (prev?.positions ?? []).find(p => p.id === positionId);
      if (!pos) return prev;

      // Options: PnL = (current premium - entry premium) × contracts × 100.
      // Premium paid is returned implicitly via PnL (we refund the original
      // premium cost plus gain/loss to balance).
      if (pos.kind === 'option') {
        const directionalPremium = mp; // caller passes current premium
        const contracts = pos.contracts;
        const entryCost = pos.premium * contracts * 100;   // originally deducted
        const exitValue = directionalPremium * contracts * 100;
        const pnl = +(exitValue - entryCost).toFixed(2);

        const trade = {
          id: `trd_${Date.now()}_${Math.random().toString(36).slice(2, 7)}`,
          sym: `${pos.sym} ${pos.expiryDays}d ${pos.strike} ${pos.type.toUpperCase()}`,
          side: 'sell',
          size: String(contracts),
          price: fmt(directionalPremium, 2),
          ctrp: 'Onyx Options CLOB',
          tx: `0x${Math.random().toString(16).slice(2, 10)}…${Math.random().toString(16).slice(2, 6)}`,
          time: new Date().toLocaleTimeString('en-US', { hour12: false }),
        };

        return {
          ...prev,
          balance:        (prev?.balance ?? 0) + exitValue,
          realizedPnl30d: (prev?.realizedPnl30d ?? 0) + pnl,
          volume30d:      (prev?.volume30d ?? 0) + exitValue,
          positions:      (prev?.positions ?? []).filter(p => p.id !== positionId),
          trades:         [trade, ...(prev?.trades ?? [])].slice(0, 100),
        };
      }

      // PnL: long profits when price rises, short profits when price falls.
      const direction = pos.side === 'long' ? 1 : -1;
      const pnl = +((mp - pos.entry) * pos.size * direction).toFixed(2);

      const trade = {
        id: `trd_${Date.now()}_${Math.random().toString(36).slice(2, 7)}`,
        sym: pos.sym,
        side: pos.side === 'long' ? 'sell' : 'buy',  // closing side is opposite
        size: pos.size.toFixed(pos.dec === 2 ? 4 : 0),
        price: fmt(mp, pos.dec),
        ctrp: 'Onyx CLOB',
        tx: `0x${Math.random().toString(16).slice(2, 10)}…${Math.random().toString(16).slice(2, 6)}`,
        time: new Date().toLocaleTimeString('en-US', { hour12: false }),
      };

      return {
        ...prev,
        // Return the locked margin to balance, plus the realized PnL.
        // (Open: balance -= margin. Close: balance += margin + pnl.)
        balance:       (prev?.balance ?? 0) + pos.margin + pnl,
        marginUsed:    Math.max(0, (prev?.marginUsed ?? 0) - pos.margin),
        realizedPnl30d:(prev?.realizedPnl30d ?? 0) + pnl,
        volume30d:     (prev?.volume30d ?? 0) + (pos.size * mp),
        positions:     (prev?.positions ?? []).filter(p => p.id !== positionId),
        trades:        [trade, ...(prev?.trades ?? [])].slice(0, 100),
      };
    });

    // Audit log: record the close (best-effort).
    try {
      appendAuditEntry({
        category: 'order',
        action:   'closed',
        target:   positionId,
        actor:    user?.username ?? 'user',
        details:  { markPrice: mp },
      });
    } catch {}

    return { ok: true };
  };

  // Open an options position (long only, for simplicity). Debits the total
  // premium cost (premium × contracts × 100 shares per contract) from
  // available balance. Stored with kind='option' so the close handler can
  // distinguish from perps. Greeks aren't locked at open — they recompute
  // from theoretical values at close.
  const openOptionPosition = ({ underlying, type, strike, expiryDays, premium, contracts, spot }) => {
    const n = Math.max(1, Math.floor(Number(contracts) || 1));
    const prem = Number(premium);
    if (!isFinite(prem) || prem <= 0) return { ok: false, error: 'Invalid premium' };
    const cost = +(prem * n * 100).toFixed(2); // 100 shares per US options contract

    let result = { ok: false };
    update(prev => {
      const avail = (prev?.balance ?? 0);
      if (cost > avail) {
        result = { ok: false, error: `Insufficient balance. Need $${cost.toFixed(2)}, available $${avail.toFixed(2)}.` };
        return prev;
      }

      const position = {
        id: `opt_${Date.now()}_${Math.random().toString(36).slice(2, 7)}`,
        kind: 'option',
        sym: underlying.id,
        underlyingCls: underlying.cls,
        type,             // 'call' | 'put'
        strike: +strike,
        expiryDays: +expiryDays,
        expiresAt: new Date(Date.now() + expiryDays * 86400000).toISOString(),
        premium: +prem,   // premium paid per share at open
        contracts: n,
        cost,             // total debit
        spotAtOpen: +spot,
        dec: 2,
        openedAt: new Date().toISOString(),
      };

      const trade = {
        id: `trd_${Date.now()}_${Math.random().toString(36).slice(2, 7)}`,
        sym: `${underlying.id} ${expiryDays}d ${strike} ${type.toUpperCase()}`,
        side: 'buy',
        size: String(n),
        price: fmt(prem, 2),
        ctrp: 'Onyx Options CLOB',
        tx: `0x${Math.random().toString(16).slice(2, 10)}…${Math.random().toString(16).slice(2, 6)}`,
        time: new Date().toLocaleTimeString('en-US', { hour12: false }),
      };

      result = { ok: true, position };

      return {
        ...prev,
        balance:   avail - cost,
        volume30d: (prev?.volume30d ?? 0) + cost,
        positions: [position, ...(prev?.positions ?? [])],
        trades:    [trade, ...(prev?.trades ?? [])].slice(0, 100),
      };
    });

    return result;
  };

  // Add/remove instrument ID from watchlist. Idempotent — safe to call twice.
  const addToWatchlist = (instId) => {
    update(prev => {
      const list = prev?.watchlist ?? [];
      if (list.includes(instId)) return prev;
      return { ...prev, watchlist: [...list, instId] };
    });
  };

  const removeFromWatchlist = (instId) => {
    update(prev => {
      const list = prev?.watchlist ?? [];
      return { ...prev, watchlist: list.filter(id => id !== instId) };
    });
  };

  const toggleWatchlist = (instId) => {
    update(prev => {
      const list = prev?.watchlist ?? [];
      return {
        ...prev,
        watchlist: list.includes(instId)
          ? list.filter(id => id !== instId)
          : [...list, instId],
      };
    });
  };

  // Deposit cash from account.balance into a vault. Stores the principal
  // and deposit timestamp; accrued yield is computed on-the-fly from
  // (now - depositedAt) × apy. Positive integer amounts only.
  const depositToVault = (vaultId, amount, apy) => {
    const amt = Number(amount);
    if (!isFinite(amt) || amt <= 0) return { ok: false, error: 'Invalid amount' };

    let result = { ok: false };
    update(prev => {
      const avail = prev?.balance ?? 0;
      if (amt > avail) {
        result = { ok: false, error: `Insufficient balance. Need $${amt.toFixed(2)}, available $${avail.toFixed(2)}.` };
        return prev;
      }
      const existing = prev?.vaults?.[vaultId];
      const newPrincipal = (existing?.principal ?? 0) + amt;
      // When adding to an existing position we reset the timer (weighted
      // average of deposit dates). Simplification: on top-up, reset to now.
      result = { ok: true };
      return {
        ...prev,
        balance: avail - amt,
        vaults: {
          ...(prev?.vaults ?? {}),
          [vaultId]: {
            principal: newPrincipal,
            depositedAt: new Date().toISOString(),
            apy: apy ?? existing?.apy ?? 0,
          },
        },
      };
    });
    return result;
  };

  const withdrawFromVault = (vaultId, amount) => {
    const amt = Number(amount);
    if (!isFinite(amt) || amt <= 0) return { ok: false, error: 'Invalid amount' };

    let result = { ok: false };
    update(prev => {
      const existing = prev?.vaults?.[vaultId];
      if (!existing || existing.principal <= 0) {
        result = { ok: false, error: 'No deposit in this vault' };
        return prev;
      }
      // Calculate current value = principal + accrued yield
      const days = (Date.now() - new Date(existing.depositedAt).getTime()) / 86400000;
      const accrued = existing.principal * (existing.apy / 100) * (days / 365);
      const currentValue = existing.principal + accrued;

      if (amt > currentValue) {
        result = { ok: false, error: `Cannot withdraw more than current value of $${currentValue.toFixed(2)}.` };
        return prev;
      }
      // Proportional reduction — withdraw X% of value reduces principal by X%
      const fraction = amt / currentValue;
      const newPrincipal = existing.principal * (1 - fraction);
      const newVaults = { ...(prev?.vaults ?? {}) };
      if (newPrincipal < 0.01) {
        delete newVaults[vaultId];
      } else {
        newVaults[vaultId] = { ...existing, principal: newPrincipal };
      }
      result = { ok: true };
      return {
        ...prev,
        balance: (prev?.balance ?? 0) + amt,
        vaults: newVaults,
      };
    });
    return result;
  };

  return { account, deposit, withdraw, openPosition, closePosition, openOptionPosition,
           addToWatchlist, removeFromWatchlist, toggleWatchlist,
           depositToVault, withdrawFromVault };
};

/* ──────────── Formatters ──────────── */

// Resolve the active number-format locale at call time so a setting change
// takes effect immediately without remounting every component. Falls back
// to en-US if storage is unavailable or the saved value is invalid.
const _getFmtLocale = () => {
  try {
    if (typeof window === 'undefined' || !window.localStorage) return 'en-US';
    const raw = window.localStorage.getItem('imo_settings');
    if (!raw) return 'en-US';
    const s = JSON.parse(raw);
    const loc = s?.numberFormat;
    if (typeof loc === 'string' && /^[a-z]{2}-[A-Z]{2}$/.test(loc)) return loc;
    return 'en-US';
  } catch { return 'en-US'; }
};
const fmt = (n, d = 2) => Number(n).toLocaleString(_getFmtLocale(), { minimumFractionDigits: d, maximumFractionDigits: d });
// When the user toggles "Hide PNL" we want dollar amounts redacted across
// the UI. Pages that explicitly opt into respecting this preference use
// fmtMaybe() instead of fmt() — typically for P&L, balance, and order
// values. Charts and reference prices ignore this so the chart still
// works for screen-sharing.
const _hidePnl = () => {
  try {
    if (typeof window === 'undefined' || !window.localStorage) return false;
    const raw = window.localStorage.getItem('imo_settings');
    if (!raw) return false;
    return JSON.parse(raw)?.hidePnl === true;
  } catch { return false; }
};
const fmtMaybe = (n, d = 2) => _hidePnl() ? '•••' : fmt(n, d);
const fmtCompact = (n) => {
  if (n >= 1e9) return `$${(n/1e9).toFixed(2)}B`;
  if (n >= 1e6) return `$${(n/1e6).toFixed(2)}M`;
  if (n >= 1e3) return `$${(n/1e3).toFixed(1)}K`;
  return `$${n.toFixed(2)}`;
};

/* ════════════════════════════════════════════════════════════════════════════
   MATH — Black-Scholes options pricing + technical indicators
   ════════════════════════════════════════════════════════════════════════════ */

// Standard normal CDF using Abramowitz & Stegun 26.2.17 — accurate to ~7
// decimal places, more than enough for option pricing display purposes.
const normCdf = (x) => {
  const a1 =  0.254829592;
  const a2 = -0.284496736;
  const a3 =  1.421413741;
  const a4 = -1.453152027;
  const a5 =  1.061405429;
  const p  =  0.3275911;
  const sign = x < 0 ? -1 : 1;
  const ax = Math.abs(x) / Math.sqrt(2);
  const t = 1.0 / (1.0 + p * ax);
  const y = 1.0 - (((((a5 * t + a4) * t) + a3) * t + a2) * t + a1) * t * Math.exp(-ax * ax);
  return 0.5 * (1.0 + sign * y);
};
const normPdf = (x) => Math.exp(-0.5 * x * x) / Math.sqrt(2 * Math.PI);

// ════════════════════════════════════════════════════════════════════
// NEWS SENTIMENT SCORER
// ════════════════════════════════════════════════════════════════════
//
// Lexicon-based sentiment scoring for financial news headlines.
// Each lexicon term has a base polarity (-1 to +1) and weight; the
// scorer tokenizes a headline, sums weighted polarities, and produces
// a normalized score in [-1, +1] plus a label (very-positive,
// positive, neutral, negative, very-negative).
//
// This is a deliberately simple bag-of-words approach — no LLM call,
// no model loading, no transformer. Good enough to rank news within
// a feed and surface markers on a chart. For high-stakes use cases
// (algorithmic trading on sentiment), a fine-tuned FinBERT model is
// the right answer; for "show me the bullish stuff at a glance",
// this is fine.


// ════════════════════════════════════════════════════════════════════
// NEWS DEDUPE + CLUSTERING
// ════════════════════════════════════════════════════════════════════
//
// Wire-service syndication, paraphrasing, and cross-republication mean
// that financial news feeds are extremely redundant — 30 articles can
// reduce to 5 stories. Without dedupe, a single event dominates the
// sentiment chart purely by repetition.
//
// Approach: Jaccard similarity on tokenized headlines. Two articles
// cluster together if their token sets share ≥ JACCARD_THRESHOLD.
//
// We don't use cosine similarity / TF-IDF here because:
//   - News feeds are typically <100 articles → O(n²) Jaccard is fine
//   - Headlines are short (~10 tokens) so length normalization matters
//     less than for full articles
//   - Stop-word removal + bigram tokens captures most semantic overlap
//
// Returns clustered items with one "representative" per cluster + the
// merged metadata (max sentiment, full article list, publisher count).

// Tokenize a headline: lowercase, strip punctuation, remove stop words,
// emit unigrams + bigrams.
const NEWS_STOP_WORDS = new Set([
  'a','an','and','are','as','at','be','by','for','from','has','have',
  'in','is','it','its','of','on','or','the','to','was','were','will',
  'with','this','that','those','these','what','said','says','say','than',
  'over','up','down','more','less','still','now','also','but','yet','so',
  'after','before','about','into','out','off','if','can','may','its',
]);

const _tokenizeHeadline = (text) => {
  if (!text) return [];
  const cleaned = text.toLowerCase()
    .replace(/[^a-z0-9$%\s-]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
  const words = cleaned.split(' ').filter(w => w && w.length >= 2 && !NEWS_STOP_WORDS.has(w));
  // Unigrams + bigrams
  const tokens = new Set(words);
  for (let i = 0; i < words.length - 1; i++) {
    tokens.add(words[i] + '_' + words[i + 1]);
  }
  return tokens;
};

// Jaccard similarity between two sets: |A ∩ B| / |A ∪ B|
const _jaccard = (a, b) => {
  if (!(a instanceof Set) || !(b instanceof Set)) return 0;
  if (a.size === 0 || b.size === 0) return 0;
  let intersection = 0;
  // Iterate over smaller set
  const [smaller, larger] = a.size <= b.size ? [a, b] : [b, a];
  for (const t of smaller) {
    if (larger.has(t)) intersection++;
  }
  const union = a.size + b.size - intersection;
  return union > 0 ? intersection / union : 0;
};

// clusterNewsArticles — group near-identical news articles using Jaccard
// similarity on tokenized titles.
//
// Inputs:
//   articles: [{ title, ts, publisher, url, _sentiment? }] — raw news list
//   threshold: Jaccard cutoff (default 0.4 — moderate. Higher catches only
//              true reprints; lower catches looser paraphrases at risk of
//              over-clustering)
//
// Returns:
//   {
//     clusters: [{
//       representative: <best article in cluster>,
//       articles: [...],
//       size: number,
//       publishers: Set,
//       avgSentiment: number,
//       firstTs: number, latestTs: number,
//     }],
//     reductionPct: how much smaller the deduped set is
//   }
//
// Cluster representative selection: prefer (1) higher source authority
// (Bloomberg/Reuters > aggregators) but we have no curated authority
// list, so default to (2) earliest timestamp (closest to story break).
const clusterNewsArticles = (articles, threshold = 0.4) => {
  if (!Array.isArray(articles) || articles.length === 0) {
    return { clusters: [], reductionPct: 0 };
  }
  // Pre-tokenize all
  const tokenized = articles.map(a => ({
    article: a,
    tokens: _tokenizeHeadline(a.title || a.headline || ''),
  }));
  // Greedy clustering: each article either joins an existing cluster
  // (if similar to its representative) or starts a new one
  const clusters = [];
  for (const t of tokenized) {
    if (t.tokens.size === 0) {
      // Article with no tokenizable title → singleton cluster
      clusters.push([t]);
      continue;
    }
    let best = -1;
    let bestSim = threshold;
    for (let ci = 0; ci < clusters.length; ci++) {
      // Compare to representative (first item in cluster)
      const rep = clusters[ci][0];
      if (rep.tokens.size === 0) continue;
      const sim = _jaccard(t.tokens, rep.tokens);
      if (sim >= bestSim) {
        bestSim = sim;
        best = ci;
      }
    }
    if (best >= 0) {
      clusters[best].push(t);
    } else {
      clusters.push([t]);
    }
  }
  // Build cluster summaries
  const summaries = clusters.map(group => {
    const sortedByTime = group.slice().sort((a, b) => {
      const at = a.article.ts ? new Date(a.article.ts).getTime() : 0;
      const bt = b.article.ts ? new Date(b.article.ts).getTime() : 0;
      return at - bt;
    });
    const earliest = sortedByTime[0]?.article || group[0].article;
    const publishers = new Set(group.map(g => g.article.publisher).filter(Boolean));
    const sentiments = group
      .map(g => g.article._sentiment?.score)
      .filter(s => Number.isFinite(s));
    const avgSentiment = sentiments.length > 0
      ? sentiments.reduce((s, v) => s + v, 0) / sentiments.length
      : 0;
    const tsValues = group.map(g => g.article.ts ? new Date(g.article.ts).getTime() : 0).filter(t => t > 0);
    return {
      representative: earliest,
      articles: group.map(g => g.article),
      size: group.length,
      publishers,
      publisherCount: publishers.size,
      avgSentiment,
      firstTs: tsValues.length > 0 ? Math.min(...tsValues) : 0,
      latestTs: tsValues.length > 0 ? Math.max(...tsValues) : 0,
    };
  });
  // Sort clusters by size (biggest stories first), then by timestamp desc
  summaries.sort((a, b) => {
    if (b.size !== a.size) return b.size - a.size;
    return b.latestTs - a.latestTs;
  });
  return {
    clusters: summaries,
    reductionPct: articles.length > 0
      ? ((articles.length - summaries.length) / articles.length) * 100
      : 0,
  };
};

