// Annualized implied vol assumption per asset class. Real markets quote per
// strike/expiry; this is a flat surface for display purposes only.




// Ticker tile style — first letter of the ticker in a colored tile, which
// avoids any third-party dependency. Clearbit's logo API was retired in
// late 2024 and many corporate networks block direct hotlinks to company
// domains (apple.com, vanguard.com, etc.) via DNS filtering or CSP rules.
// This tile renders reliably everywhere with no network request.

// Boxed sector/asset-class letter — placed next to ticker text everywhere
// the user might want to disambiguate at a glance: E=equity, C=crypto,
// O=oil/energy, M=metal, F=fx, R=rates, I=index, B=bond, A=ag.

/* ════════════════════════════════════════════════════════════════════════════
   TOAST NOTIFICATION SYSTEM
   ────────────────────────────────────────────────────────────────────────────
   Lightweight in-app toast that replaces window.alert() for non-blocking
   confirmations like "Metric added to fundamentals chart" or
   "Indicator activated". Toasts stack in the top-right and auto-dismiss
   after 3.5s. Call window.imoToast(message, kind?) from anywhere.
   ════════════════════════════════════════════════════════════════════════════ */

const ToastHost = () => {
  const [toasts, setToasts] = useState([]);
  useEffect(() => {
    // Expose a global so any function can fire a toast without prop drilling
    window.imoToast = (message, kind = 'info') => {
      const id = Date.now() + Math.random();
      setToasts(prev => [...prev, { id, message, kind }]);
      setTimeout(() => {
        setToasts(prev => prev.filter(t => t.id !== id));
      }, 3500);
    };
    return () => { try { delete window.imoToast; } catch {} };
  }, []);
  if (toasts.length === 0) return null;
  return (
    <div className="fixed top-4 right-4 z-[9999] flex flex-col gap-2 pointer-events-none"
         style={{ maxWidth: 360 }}>
      {toasts.map(t => {
        const tone = t.kind === 'success' ? COLORS.green :
                     t.kind === 'error'   ? COLORS.red :
                     t.kind === 'warn'    ? '#FFB84D' :
                                             COLORS.mint;
        return (
          <div key={t.id}
               className="rounded-md shadow-2xl pointer-events-auto px-4 py-3 flex items-start gap-2.5 animate-in"
               style={{
                 background: COLORS.surface,
                 border: `1px solid ${tone}55`,
                 borderLeft: `3px solid ${tone}`,
                 boxShadow: '0 12px 36px rgba(0,0,0,0.35), 0 1px 0 rgba(255,255,255,0.06) inset',
                 color: COLORS.text,
                 fontSize: 12.5,
                 lineHeight: 1.4,
               }}>
            <span className="shrink-0 mt-0.5" style={{ color: tone, fontWeight: 700 }}>
              {t.kind === 'success' ? '✓' : t.kind === 'error' ? '!' : t.kind === 'warn' ? '⚠' : 'ℹ'}
            </span>
            <span className="flex-1">{t.message}</span>
          </div>
        );
      })}
    </div>
  );
};

// Convenience wrapper — works even before React mount (queues silently if so).
const notify = (msg, kind = 'info') => {
  try { window.imoToast?.(msg, kind); } catch {}
};

