// Messages page — chat thread view with mock contacts.
// Stores messages per-user in localStorage so threads persist across sessions.
const MOCK_CONTACTS = [
  { id: 'sarah-li',     name: 'Sarah Li',        handle: '@sarahli',     desk: 'Equity Derivatives', avatarColor: '#FF7AB6', avatar: 'SL', online: true },
  { id: 'mike-chen',    name: 'Mike Chen',       handle: '@mchen',       desk: 'FX Macro',           avatarColor: '#7AC8FF', avatar: 'MC', online: true },
  { id: 'priya-patel',  name: 'Priya Patel',     handle: '@ppatel',      desk: 'Rates Trading',      avatarColor: '#A0C476', avatar: 'PP', online: false },
  { id: 'jordan-king',  name: 'Jordan King',     handle: '@jking',       desk: 'Crypto Desk',        avatarColor: '#F7931A', avatar: 'JK', online: true },
  { id: 'desk-lead',    name: 'Desk Lead Alex',  handle: '@desklead',    desk: 'Manager',            avatarColor: '#0066B2', avatar: 'AX', online: false },
  { id: 'onyx-bot',     name: 'Onyx Bot',        handle: '@onyx_bot',    desk: 'Automated alerts',   avatarColor: COLORS.mint, avatar: 'O',  online: true },
];

