// ─── BackendAuthRow ───────────────────────────────────────────────────────
// Phase 3p.04 (file split, batch 16): BackendAuthRow extracted to
// src/components/settings-panels.jsx (internal helper of BackendServicesPanel).

// ─── NotificationPrefsPanel ───────────────────────────────────────────────
