function makeVaultHistory(base, apy, volatile) {
  const out = [];
  let v = base;
  const dailyDrift = apy / 365;
  for (let i = 0; i < 90; i++) {
    const vol = volatile ? 0.008 : 0.002;
    v = v * (1 + dailyDrift/100 + (Math.random() - 0.5) * vol);
    out.push({ d: i, nav: +v.toFixed(4) });
  }
  return out;
}

