const LearnPage = ({ user, setPage, setActive }) => {
  const STORAGE_KEY = `imo_learn_${user?.username ?? 'guest'}`;
  const [progress, setProgress] = useState(() => {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (raw) return JSON.parse(raw);
    } catch {}
    return { completed: {}, current: 1 };
  });
  const [openLesson, setOpenLesson] = useState(null);

  const persist = (next) => {
    setProgress(next);
    try { localStorage.setItem(STORAGE_KEY, JSON.stringify(next)); } catch {}
  };

  const markComplete = (id) => {
    const next = {
      ...progress,
      completed: { ...progress.completed, [id]: true },
      current: Math.min(28, Math.max(progress.current, id + 1)),
    };
    persist(next);
  };

  const completedCount = Object.values(progress.completed ?? {}).filter(Boolean).length;
  const completionPct = Math.round((completedCount / 28) * 100);

  // Group lessons by week
  const byWeek = useMemo(() => {
    const w = { 1: [], 2: [], 3: [], 4: [] };
    LEARN_LESSONS.forEach(l => w[l.week].push(l));
    return w;
  }, []);

  const WEEK_THEMES = {
    1: { name: 'Foundations',          color: '#7AC8FF' },
    2: { name: 'Orders & Risk',        color: '#FFB84D' },
    3: { name: 'Charts & Indicators',  color: '#E07AFC' },
    4: { name: 'Portfolio & Strategy', color: COLORS.mint },
  };

  return (
    <div className="flex-1 min-h-0 overflow-y-auto" style={{ background: COLORS.bg }}>
      <div className="max-w-[1100px] mx-auto px-8 py-8">
        {/* Hero */}
        <div className="mb-8">
          <div className="flex items-baseline justify-between gap-4 flex-wrap mb-3">
            <div>
              <h1 className="text-[28px] font-medium" style={{ color: COLORS.text }}>Learn to invest</h1>
              <p className="text-[13px] mt-1" style={{ color: COLORS.textMute }}>
                A 28-lesson, 4-week course covering everything from chart-reading to portfolio construction.
              </p>
            </div>
            <div className="flex items-center gap-2">
              <span className="text-[10px] px-2 py-0.5 rounded-full"
                    style={{ background: 'rgba(61,123,255,0.08)', color: COLORS.mint }}>
                Built for novices
              </span>
            </div>
          </div>
          {/* Progress bar */}
          <div className="rounded-md border p-4" style={{ background: COLORS.surface, borderColor: COLORS.border }}>
            <div className="flex items-baseline justify-between mb-2">
              <div className="text-[13px]" style={{ color: COLORS.text }}>
                <strong className="tabular-nums">{completedCount}</strong> of 28 lessons complete
              </div>
              <div className="text-[12px] tabular-nums" style={{ color: COLORS.mint }}>{completionPct}%</div>
            </div>
            <div className="h-2 rounded-full overflow-hidden" style={{ background: COLORS.bg }}>
              <div className="h-full transition-all"
                   style={{ width: `${completionPct}%`, background: COLORS.mint }} />
            </div>
            <div className="flex items-center justify-between mt-3 text-[11px]">
              <span style={{ color: COLORS.textMute }}>
                {completionPct === 100
                  ? '🎓 Course complete — congrats!'
                  : `Next up: Lesson ${progress.current}`}
              </span>
              <button onClick={() => {
                const next = LEARN_LESSONS.find(l => !progress.completed[l.id]);
                if (next) setOpenLesson(next);
              }}
                      className="px-2.5 py-1 rounded text-[11px] font-medium"
                      style={{ background: COLORS.mint, color: COLORS.bg }}>
                {completionPct > 0 ? 'Continue' : 'Start lesson 1'} →
              </button>
            </div>
          </div>
        </div>

        {/* Week-by-week timeline */}
        {[1, 2, 3, 4].map(week => {
          const theme = WEEK_THEMES[week];
          const lessons = byWeek[week];
          const weekDone = lessons.every(l => progress.completed[l.id]);
          return (
            <div key={week} className="mb-7">
              <div className="flex items-baseline gap-3 mb-3">
                <div className="w-8 h-8 rounded-full flex items-center justify-center text-[12px] font-medium"
                     style={{ background: weekDone ? theme.color : COLORS.surface,
                              color: weekDone ? COLORS.bg : theme.color,
                              border: `1.5px solid ${theme.color}` }}>
                  {weekDone ? '✓' : week}
                </div>
                <div>
                  <h2 className="text-[16px] font-medium" style={{ color: COLORS.text }}>Week {week} · {theme.name}</h2>
                  <p className="text-[11px]" style={{ color: COLORS.textMute }}>
                    {lessons.length} lessons · {lessons.reduce((s, l) => s + parseInt(l.duration), 0)} minutes total
                  </p>
                </div>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-2 ml-11">
                {lessons.map(l => {
                  const done = progress.completed[l.id];
                  const isLocked = l.id > 1 && !progress.completed[l.id - 1];
                  return (
                    <button key={l.id}
                            disabled={isLocked}
                            onClick={() => !isLocked && setOpenLesson(l)}
                            className="text-left rounded-md border p-3 transition-colors disabled:opacity-40 disabled:cursor-not-allowed hover:bg-white/[0.03]"
                            style={{
                              background: done ? 'rgba(61,123,255,0.04)' : COLORS.surface,
                              borderColor: done ? `${theme.color}40` : COLORS.border,
                            }}>
                      <div className="flex items-start gap-2.5">
                        <div className="w-9 h-9 rounded flex items-center justify-center text-[16px] shrink-0"
                             style={{ background: COLORS.bg }}>
                          {done ? '✓' : isLocked ? '🔒' : l.icon}
                        </div>
                        <div className="flex-1 min-w-0">
                          <div className="flex items-baseline justify-between gap-2 mb-0.5">
                            <span className="text-[12.5px] font-medium" style={{ color: COLORS.text }}>
                              Lesson {l.id}
                            </span>
                            <span className="text-[10px] shrink-0" style={{ color: COLORS.textMute }}>{l.duration}</span>
                          </div>
                          <div className="text-[12px] truncate" style={{ color: done ? theme.color : COLORS.textDim }}>
                            {l.title}
                          </div>
                          <div className="text-[10px] mt-0.5" style={{ color: COLORS.textMute }}>{l.category}</div>
                        </div>
                      </div>
                    </button>
                  );
                })}
              </div>
            </div>
          );
        })}

        {/* Footer CTA */}
        <div className="rounded-md border p-5 text-center mt-8"
             style={{ background: COLORS.surface, borderColor: COLORS.border }}>
          <div className="text-[13px] mb-2" style={{ color: COLORS.text }}>Ready to apply what you've learned?</div>
          <div className="flex items-center justify-center gap-2">
            <button onClick={() => setPage('trade')}
                    className="px-4 py-1.5 rounded text-[12px]"
                    style={{ background: COLORS.surface2, color: COLORS.text }}>
              Try a chart →
            </button>
            <button onClick={() => setPage('portfolio')}
                    className="px-4 py-1.5 rounded text-[12px] font-medium"
                    style={{ background: COLORS.mint, color: COLORS.bg }}>
              Build a portfolio →
            </button>
          </div>
        </div>
      </div>

      {/* Lesson modal */}
      {openLesson && (
        <LessonModal lesson={openLesson}
                     onClose={() => setOpenLesson(null)}
                     onComplete={() => { markComplete(openLesson.id); setOpenLesson(null); }}
                     completed={!!progress.completed[openLesson.id]} />
      )}
    </div>
  );
};

