// Interactive quiz component — used inside LessonModal when lesson is a Quiz.
// Shows one question at a time with multiple choices. Tracks score, lets the
// user retry. When they pass (>= 60%), `onPass` fires so the lesson completes.
const InteractiveQuiz = ({ week, onPass, onClose }) => {
  const questions = QUIZ_BANK[week] ?? [];
  const [idx, setIdx] = useState(0);
  const [picked, setPicked] = useState(null); // selected choice index for current
  const [answers, setAnswers] = useState([]); // history: [{correct: bool}]
  const [done, setDone] = useState(false);

  if (questions.length === 0) {
    return (
      <div className="rounded-md p-4 text-[12px] text-center"
           style={{ background: COLORS.bg, color: COLORS.textMute, border: `1px solid ${COLORS.border}` }}>
        No quiz questions available for this week yet.
      </div>
    );
  }

  if (done) {
    const correct = answers.filter(a => a.correct).length;
    const total = answers.length;
    const pct = Math.round((correct / total) * 100);
    const passed = correct / total >= 0.6;
    return (
      <div className="rounded-md p-5 text-center"
           style={{ background: passed ? 'rgba(31,178,107,0.08)' : 'rgba(237,112,136,0.08)',
                    border: `1px solid ${passed ? COLORS.green : COLORS.red}55` }}>
        <div className="text-[28px] mb-1" style={{ color: passed ? COLORS.green : COLORS.red }}>
          {passed ? '✓' : '×'}
        </div>
        <div className="text-[16px] font-medium mb-1" style={{ color: COLORS.text }}>
          {correct} / {total} correct ({pct}%)
        </div>
        <div className="text-[12px] mb-4" style={{ color: COLORS.textDim }}>
          {passed
            ? 'Nice work — you passed the checkpoint.'
            : 'You need 60% to pass. Review the lessons and try again.'}
        </div>
        <div className="flex items-center justify-center gap-2">
          <button onClick={() => { setIdx(0); setPicked(null); setAnswers([]); setDone(false); }}
                  className="px-3 py-1.5 rounded text-[11.5px]"
                  style={{ background: COLORS.surface2, color: COLORS.text, border: `1px solid ${COLORS.border}` }}>
            Try again
          </button>
          {passed && (
            <button onClick={onPass}
                    className="px-3 py-1.5 rounded text-[11.5px] font-medium"
                    style={{ background: COLORS.green, color: '#FFF' }}>
              Mark complete
            </button>
          )}
        </div>
      </div>
    );
  }

  const cur = questions[idx];
  const isCorrect = picked === cur.a;
  const submit = () => {
    if (picked === null) return;
    const next = [...answers, { correct: picked === cur.a }];
    setAnswers(next);
    if (idx + 1 >= questions.length) {
      setDone(true);
    } else {
      setIdx(idx + 1);
      setPicked(null);
    }
  };

  return (
    <div className="rounded-md p-4" style={{ background: COLORS.bg, border: `1px solid ${COLORS.border}` }}>
      <div className="flex items-center justify-between mb-3">
        <div className="text-[10px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>
          Question {idx + 1} of {questions.length}
        </div>
        <div className="text-[10px] tabular-nums" style={{ color: COLORS.textMute }}>
          Score: {answers.filter(a => a.correct).length} / {answers.length}
        </div>
      </div>
      <div className="text-[13.5px] mb-3 font-medium" style={{ color: COLORS.text }}>
        {cur.q}
      </div>
      <div className="space-y-1.5 mb-4">
        {cur.choices.map((c, i) => (
          <button key={i} onClick={() => setPicked(i)}
                  className="w-full text-left px-3 py-2 rounded text-[12px] transition-colors"
                  style={{
                    background: picked === i ? `${COLORS.mint}1A` : COLORS.surface2,
                    border: `1px solid ${picked === i ? COLORS.mint : COLORS.border}`,
                    color: COLORS.text,
                  }}>
            <span style={{ color: COLORS.textMute, marginRight: 8, fontFamily: 'JetBrains Mono, monospace' }}>
              {String.fromCharCode(65 + i)}
            </span>
            {c}
          </button>
        ))}
      </div>
      <div className="flex justify-end">
        <button onClick={submit} disabled={picked === null}
                className="px-4 py-1.5 rounded text-[12px] font-medium transition-opacity"
                style={{ background: COLORS.mint, color: '#FFF', opacity: picked === null ? 0.4 : 1 }}>
          {idx + 1 >= questions.length ? 'Finish' : 'Next →'}
        </button>
      </div>
    </div>
  );
};

// Web-sourced supplementary reading. Exa fetches 3-4 articles related to the
// lesson's topic; user can click through to read on the source site. Cached
// per-title to avoid refetching every time the lesson is re-opened.
const _lessonReadingCache = {};
const LessonExternalReading = ({ lessonTitle, category }) => {
  const [items, setItems] = useState(() => _lessonReadingCache[lessonTitle] ?? null);
  const [loading, setLoading] = useState(false);
  useEffect(() => {
    if (!EXA_API_KEY || items) return;
    let cancelled = false;
    setLoading(true);
    (async () => {
      const r = await exaSearch(`${lessonTitle} ${category} explained for beginners`, {
        numResults: 3,
        type: 'fast',
        maxAgeHours: 24 * 30, // up to 30 days old
        highlights: true,
        excludeDomains: ['reddit.com', 'pinterest.com', 'youtube.com'],
      });
      if (cancelled) return;
      const out = r?.results ?? [];
      _lessonReadingCache[lessonTitle] = out;
      setItems(out);
      setLoading(false);
    })();
    return () => { cancelled = true; };
  }, [lessonTitle, items]);

  if (!EXA_API_KEY) return null; // hide entirely without key — no value to show

  return (
    <div className="mt-4">
      <div className="text-[10px] uppercase tracking-wider mb-2 flex items-center gap-1.5" style={{ color: COLORS.mint }}>
        <Sparkles size={10} />
        Further reading
      </div>
      {loading && (
        <div className="text-[11px]" style={{ color: COLORS.textMute }}>
          Finding related articles…
        </div>
      )}
      {items && items.length === 0 && (
        <div className="text-[11px]" style={{ color: COLORS.textMute }}>
          No related articles found.
        </div>
      )}
      {items && items.length > 0 && (
        <div className="space-y-2">
          {items.map((it, i) => (
            <a key={i} href={it.url} target="_blank" rel="noopener noreferrer"
               className="block p-2.5 rounded-md text-[11.5px] hover:bg-white/[0.04] transition-colors"
               style={{ background: COLORS.bg, border: `1px solid ${COLORS.border}` }}>
              <div className="font-medium mb-0.5" style={{ color: COLORS.text }}>{it.title}</div>
              <div className="flex items-center gap-1.5 text-[9.5px]" style={{ color: COLORS.textMute }}>
                <span>{(() => { try { return new URL(it.url).hostname.replace('www.', ''); } catch { return ''; } })()}</span>
                {it.publishedDate && <span>· {new Date(it.publishedDate).toLocaleDateString()}</span>}
              </div>
              {it.text && (
                <div className="text-[10.5px] mt-1" style={{ color: COLORS.textDim }}>
                  {it.text.slice(0, 150)}{it.text.length > 150 ? '…' : ''}
                </div>
              )}
            </a>
          ))}
        </div>
      )}
    </div>
  );
};

const LessonModal = ({ lesson, onClose, onComplete, completed }) => {
  return (
    <>
      <div className="fixed inset-0 z-40" style={{ background: 'rgba(0,0,0,0.7)' }} onClick={onClose} />
      <div className="fixed left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 z-50 rounded-md border overflow-hidden flex flex-col"
           style={{ background: COLORS.surface, borderColor: COLORS.borderHi, width: 640, maxWidth: '95vw', maxHeight: '90vh' }}>
        {/* Header */}
        <div className="px-5 py-4 border-b flex items-center gap-3 shrink-0"
             style={{ borderColor: COLORS.border, background: COLORS.bg }}>
          <div className="w-12 h-12 rounded flex items-center justify-center text-[24px]"
               style={{ background: COLORS.surface2 }}>
            {lesson.icon}
          </div>
          <div className="flex-1 min-w-0">
            <div className="text-[10px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>
              Lesson {lesson.id} · {lesson.category} · {lesson.duration}
            </div>
            <h2 className="text-[18px] font-medium" style={{ color: COLORS.text }}>{lesson.title}</h2>
          </div>
          <button onClick={onClose} className="p-1.5 rounded hover:bg-white/[0.06]"
                  style={{ color: COLORS.textMute }}>×</button>
        </div>
        {/* Body */}
        <div className="flex-1 overflow-y-auto p-6">
          {/* Lesson illustration — title-aware SVG hero image. We inspect
              the lesson title for keywords (compounding, candlesticks,
              bid/ask, market hours, RSI, MACD, etc.) and pick a graphic
              that actually matches that lesson's topic. Falls back to
              category-themed illustration when no keyword match. */}
          <div className="mb-5 rounded-md overflow-hidden border"
               style={{ borderColor: COLORS.border, background: COLORS.bg, height: 140 }}>
            <svg viewBox="0 0 640 140" preserveAspectRatio="none" width="100%" height="140"
                 style={{ background: `linear-gradient(135deg, ${COLORS.surface2} 0%, ${COLORS.bg} 100%)` }}>
              {(() => {
                const title = (lesson.title ?? '').toLowerCase();
                const cat = lesson.category;

                // ─── Title keyword → specific graphic ───
                // Compounding / time-in-market — exponential curve
                if (title.includes('compound') || title.includes('time in') || title.includes('long-term')) {
                  const pts = Array.from({ length: 60 }, (_, i) => {
                    const x = 20 + i * 10;
                    const y = 130 - Math.pow(i / 60, 2.2) * 110;
                    return `${x},${y}`;
                  });
                  return (
                    <>
                      <polyline points={pts.join(' ')} stroke={COLORS.mint} strokeWidth={2.5} fill="none" />
                      <polyline points={pts.join(' ') + ' 620,140 20,140'} fill={COLORS.mint} opacity={0.18} />
                      <text x="540" y="40" fill={COLORS.mint} fontSize="10" fontWeight="600">📈 EXPONENTIAL</text>
                      <text x="40" y="125" fill={COLORS.textMute} fontSize="9">Year 1</text>
                      <text x="560" y="125" fill={COLORS.textMute} fontSize="9">Year 30</text>
                    </>
                  );
                }
                // Candlesticks / chart reading
                if (title.includes('candle') || title.includes('reading') && title.includes('chart')) {
                  const bars = Array.from({ length: 18 }, (_, i) => {
                    const seed = (lesson.id + i) * 13;
                    const open = 70 + (seed % 30);
                    const close = open + ((seed * 7) % 25) - 12;
                    const hi = Math.max(open, close) + (seed % 8);
                    const lo = Math.min(open, close) - ((seed * 3) % 8);
                    return { x: 35 + i * 32, open, close, hi, lo };
                  });
                  return (
                    <>
                      {bars.map((b, i) => (
                        <g key={i}>
                          <line x1={b.x} y1={b.hi} x2={b.x} y2={b.lo} stroke={b.close >= b.open ? '#7BFFB5' : '#FF8855'} strokeWidth={1.2} />
                          <rect x={b.x - 5} y={Math.min(b.open, b.close)} width={10} height={Math.abs(b.close - b.open) || 2}
                                fill={b.close >= b.open ? '#7BFFB5' : '#FF8855'} opacity={0.9} />
                        </g>
                      ))}
                      <text x="530" y="22" fill="#7BFFB5" fontSize="9">▲ BULLISH</text>
                      <text x="530" y="36" fill="#FF8855" fontSize="9">▼ BEARISH</text>
                    </>
                  );
                }
                // Stocks / bonds / ETFs
                if (title.includes('stock') && title.includes('bond')) {
                  return (
                    <>
                      {/* 3 columns: stocks, bonds, ETFs */}
                      <g>
                        <rect x="80" y="35" width="120" height="80" rx="6" fill="#7BFFB5" opacity={0.2} stroke="#7BFFB5" strokeWidth={1.5} />
                        <text x="140" y="68" textAnchor="middle" fill="#7BFFB5" fontSize="22" fontWeight="700">S</text>
                        <text x="140" y="100" textAnchor="middle" fill={COLORS.text} fontSize="11">Stocks</text>
                      </g>
                      <g>
                        <rect x="260" y="35" width="120" height="80" rx="6" fill={COLORS.chartCyan} opacity={0.2} stroke={COLORS.chartCyan} strokeWidth={1.5} />
                        <text x="320" y="68" textAnchor="middle" fill={COLORS.chartCyan} fontSize="22" fontWeight="700">B</text>
                        <text x="320" y="100" textAnchor="middle" fill={COLORS.text} fontSize="11">Bonds</text>
                      </g>
                      <g>
                        <rect x="440" y="35" width="120" height="80" rx="6" fill="#FFD050" opacity={0.2} stroke="#FFD050" strokeWidth={1.5} />
                        <text x="500" y="68" textAnchor="middle" fill="#FFD050" fontSize="20" fontWeight="700">ETF</text>
                        <text x="500" y="100" textAnchor="middle" fill={COLORS.text} fontSize="11">Baskets</text>
                      </g>
                    </>
                  );
                }
                // Exchanges
                if (title.includes('exchange')) {
                  return (
                    <>
                      <rect x="80" y="40" width="200" height="70" rx="6" fill="none" stroke={COLORS.mint} strokeWidth={1.5} />
                      <text x="180" y="80" textAnchor="middle" fill={COLORS.mint} fontSize="20" fontWeight="700">NYSE</text>
                      <rect x="360" y="40" width="200" height="70" rx="6" fill="none" stroke={COLORS.chartCyan} strokeWidth={1.5} />
                      <text x="460" y="80" textAnchor="middle" fill={COLORS.chartCyan} fontSize="20" fontWeight="700">NASDAQ</text>
                      <line x1="280" y1="75" x2="360" y2="75" stroke={COLORS.textMute} strokeWidth={1} strokeDasharray="3 3" />
                    </>
                  );
                }
                // Bid / ask / volume
                if (title.includes('bid') || title.includes('ask') || title.includes('volume')) {
                  return (
                    <>
                      {/* Order book mini */}
                      {Array.from({ length: 4 }).map((_, i) => (
                        <g key={`bid-${i}`}>
                          <rect x="80" y={30 + i * 18} width={120 - i * 15} height={14} fill="#7BFFB5" opacity={0.25} />
                          <text x="86" y={42 + i * 18} fill="#7BFFB5" fontSize="10" fontFamily="ui-monospace,monospace">{(228.5 - i * 0.05).toFixed(2)}</text>
                        </g>
                      ))}
                      <line x1="80" y1="106" x2="320" y2="106" stroke={COLORS.textMute} strokeDasharray="2 2" />
                      <text x="200" y="118" textAnchor="middle" fill={COLORS.textMute} fontSize="9">SPREAD</text>
                      {Array.from({ length: 4 }).map((_, i) => (
                        <g key={`ask-${i}`}>
                          <rect x="200" y={30 + i * 18} width={(120 - i * 15)} height={14} fill="#FF8855" opacity={0.25} />
                          <text x="206" y={42 + i * 18} fill="#FF8855" fontSize="10" fontFamily="ui-monospace,monospace">{(229.5 + i * 0.05).toFixed(2)}</text>
                        </g>
                      ))}
                      <text x="380" y="40" fill="#7BFFB5" fontSize="11" fontWeight="600">BIDS</text>
                      <text x="380" y="58" fill={COLORS.text} fontSize="9">Highest buyer</text>
                      <text x="380" y="80" fill="#FF8855" fontSize="11" fontWeight="600">ASKS</text>
                      <text x="380" y="98" fill={COLORS.text} fontSize="9">Lowest seller</text>
                    </>
                  );
                }
                // Market hours
                if (title.includes('hour') || title.includes('pre-market') || title.includes('after-hours')) {
                  return (
                    <>
                      <line x1="40" y1="80" x2="600" y2="80" stroke={COLORS.border} strokeWidth={2} />
                      {[
                        { x: 80,  l: '4 AM', sub: 'Pre-market', c: COLORS.textMute },
                        { x: 200, l: '9:30', sub: 'Open',       c: '#7BFFB5' },
                        { x: 380, l: '4 PM', sub: 'Close',      c: '#FF8855' },
                        { x: 540, l: '8 PM', sub: 'After-hrs',  c: COLORS.textMute },
                      ].map((p, i) => (
                        <g key={i}>
                          <circle cx={p.x} cy={80} r={6} fill={p.c} />
                          <text x={p.x} y={66} textAnchor="middle" fill={p.c} fontSize="10" fontWeight="600">{p.l}</text>
                          <text x={p.x} y={104} textAnchor="middle" fill={COLORS.textMute} fontSize="9">{p.sub}</text>
                        </g>
                      ))}
                      <rect x={200} y={75} width={180} height={10} fill={COLORS.mint} opacity={0.2} />
                    </>
                  );
                }
                // RSI / oscillators
                if (title.includes('rsi') || title.includes('oscillator')) {
                  const pts = Array.from({ length: 50 }, (_, i) => {
                    const seed = (lesson.id + i) * 11;
                    return `${20 + i * 12.5},${70 + Math.sin((i + seed) * 0.3) * 28}`;
                  });
                  return (
                    <>
                      <rect x={20} y={42} width={580} height={12} fill="#FF5577" opacity={0.15} />
                      <text x={30} y={52} fill="#FF5577" fontSize="9" fontWeight="600">OVERBOUGHT (70+)</text>
                      <rect x={20} y={82} width={580} height={12} fill="#7BFFB5" opacity={0.15} />
                      <text x={30} y={92} fill="#7BFFB5" fontSize="9" fontWeight="600">OVERSOLD (30−)</text>
                      <polyline points={pts.join(' ')} stroke={COLORS.mint} strokeWidth={2} fill="none" />
                    </>
                  );
                }
                // MACD
                if (title.includes('macd')) {
                  const bars = Array.from({ length: 30 }, (_, i) => ({
                    x: 30 + i * 19,
                    h: Math.sin((i + lesson.id) * 0.4) * 25,
                  }));
                  return (
                    <>
                      <line x1="20" y1="70" x2="620" y2="70" stroke={COLORS.border} />
                      {bars.map((b, i) => (
                        <rect key={i} x={b.x - 6} y={b.h >= 0 ? 70 - b.h : 70} width={12} height={Math.abs(b.h)}
                              fill={b.h >= 0 ? '#7BFFB5' : '#FF8855'} opacity={0.7} />
                      ))}
                      <polyline points={bars.map((b, i) => `${b.x},${70 - b.h * 0.8}`).join(' ')} stroke={COLORS.mint} strokeWidth={1.5} fill="none" />
                    </>
                  );
                }
                // Moving average
                if (title.includes('moving average') || title.includes('sma') || title.includes('ema')) {
                  const price = Array.from({ length: 60 }, (_, i) => 70 + Math.sin(i * 0.4) * 20 + (i - 30) * 0.4);
                  const ma    = price.map((_, i) => {
                    const slice = price.slice(Math.max(0, i - 10), i + 1);
                    return slice.reduce((s, v) => s + v, 0) / slice.length;
                  });
                  return (
                    <>
                      <polyline points={price.map((y, i) => `${20 + i * 10},${y}`).join(' ')} stroke={COLORS.textDim} strokeWidth={1} fill="none" />
                      <polyline points={ma.map((y, i) => `${20 + i * 10},${y}`).join(' ')} stroke={COLORS.mint} strokeWidth={2.5} fill="none" />
                      <text x="540" y="40" fill={COLORS.mint} fontSize="10" fontWeight="600">SMA</text>
                      <text x="540" y="55" fill={COLORS.textDim} fontSize="9">price</text>
                    </>
                  );
                }
                // Diversification
                if (title.includes('diversif') || title.includes('allocation') || title.includes('portfolio')) {
                  const slices = [
                    { pct: 0.40, color: '#7BFFB5', label: 'Stocks' },
                    { pct: 0.30, color: '#7AC8FF', label: 'Bonds' },
                    { pct: 0.15, color: '#FFD050', label: 'Real Est.' },
                    { pct: 0.10, color: '#FF9CDB', label: 'Crypto' },
                    { pct: 0.05, color: '#FFC7A2', label: 'Cash' },
                  ];
                  let acc = 0;
                  const cx = 90, cy = 70, r = 50;
                  return (
                    <>
                      {slices.map((s, i) => {
                        const start = acc * 2 * Math.PI - Math.PI / 2;
                        acc += s.pct;
                        const end = acc * 2 * Math.PI - Math.PI / 2;
                        const large = s.pct > 0.5 ? 1 : 0;
                        const x1 = cx + r * Math.cos(start), y1 = cy + r * Math.sin(start);
                        const x2 = cx + r * Math.cos(end),   y2 = cy + r * Math.sin(end);
                        return (
                          <path key={i}
                                d={`M ${cx} ${cy} L ${x1} ${y1} A ${r} ${r} 0 ${large} 1 ${x2} ${y2} Z`}
                                fill={s.color} opacity={0.85} />
                        );
                      })}
                      {slices.map((s, i) => (
                        <g key={`l${i}`}>
                          <rect x={200} y={20 + i * 20} width={10} height={10} fill={s.color} />
                          <text x={218} y={30 + i * 20} fill={COLORS.text} fontSize="11">{s.label} · {Math.round(s.pct * 100)}%</text>
                        </g>
                      ))}
                    </>
                  );
                }
                // Risk / volatility
                if (title.includes('risk') || title.includes('volatil') || title.includes('drawdown')) {
                  return (
                    <>
                      <path d="M 120 110 A 80 80 0 0 1 280 110" stroke="#FF8855" strokeWidth={4} fill="none" opacity={0.5} />
                      <path d="M 280 110 A 80 80 0 0 1 440 110" stroke={COLORS.chartAmber} strokeWidth={4} fill="none" opacity={0.5} />
                      <path d="M 440 110 A 80 80 0 0 1 520 110" stroke="#7BFFB5" strokeWidth={4} fill="none" opacity={0.5} />
                      <line x1="320" y1="110" x2="280" y2="50" stroke={COLORS.mint} strokeWidth={2.5} />
                      <circle cx="320" cy="110" r="6" fill={COLORS.mint} />
                      <text x="120" y="130" fill="#FF8855" fontSize="9" fontWeight="600">CONSERVATIVE</text>
                      <text x="500" y="130" fill="#7BFFB5" fontSize="9" fontWeight="600">AGGRESSIVE</text>
                    </>
                  );
                }
                // Stop-loss / position sizing
                if (title.includes('stop') || title.includes('position siz') || title.includes('r-multiple')) {
                  const pts = Array.from({ length: 30 }, (_, i) => `${30 + i * 20},${50 + Math.sin(i * 0.3) * 12 - i * 0.5}`);
                  return (
                    <>
                      <line x1="20" y1="60" x2="620" y2="60" stroke="#7BFFB5" strokeWidth={1.5} strokeDasharray="4 3" />
                      <text x="30" y="55" fill="#7BFFB5" fontSize="10" fontWeight="600">ENTRY</text>
                      <line x1="20" y1="100" x2="620" y2="100" stroke="#FF5577" strokeWidth={1.5} strokeDasharray="4 3" />
                      <text x="30" y="115" fill="#FF5577" fontSize="10" fontWeight="600">STOP</text>
                      <rect x="20" y="60" width="600" height="40" fill="#FF5577" opacity={0.08} />
                      <polyline points={pts.join(' ')} stroke={COLORS.mint} strokeWidth={2} fill="none" />
                    </>
                  );
                }
                // Quiz / checkpoint
                if (cat === 'Quiz') {
                  return (
                    <>
                      <rect x="240" y="15" width="160" height="110" rx="6" fill={COLORS.surface} stroke={COLORS.mint} strokeWidth={1.5} />
                      <rect x="290" y="5" width="60" height="18" rx="3" fill={COLORS.mint} opacity={0.3} stroke={COLORS.mint} />
                      {[40, 60, 80, 100].map((y, i) => (
                        <g key={i}>
                          <circle cx="260" cy={y} r="5" fill={i < 3 ? COLORS.mint : 'transparent'} stroke={COLORS.mint} strokeWidth={1} />
                          <line x1="280" y1={y} x2={350 + i * 8} y2={y} stroke={COLORS.textDim} strokeWidth={1} opacity={0.4} />
                        </g>
                      ))}
                      <text x="320" y="14" fill={COLORS.bg} fontSize="11" fontWeight="600" textAnchor="middle">QUIZ</text>
                    </>
                  );
                }
                // Default — line chart with grid
                const pts = Array.from({ length: 50 }, (_, i) => {
                  const seed = (lesson.id + i) * 11;
                  return `${20 + i * 12.5},${110 - 35 - Math.sin(i * 0.4 + seed * 0.01) * 22 - i * 0.5}`;
                });
                return (
                  <>
                    {[20, 50, 80, 110].map(y => (
                      <line key={y} x1="0" y1={y} x2="640" y2={y} stroke={COLORS.border} strokeWidth={0.5} opacity={0.5} />
                    ))}
                    <polyline points={pts.join(' ')} stroke={COLORS.mint} strokeWidth={2} fill="none" />
                    <polyline points={pts.join(' ') + ' 640,140 0,140'} fill={COLORS.mint} opacity={0.1} />
                  </>
                );
              })()}
              {/* Big icon overlay top-left for visual identity */}
              <text x="20" y="48" fontSize="36" opacity={0.6}>{lesson.icon}</text>
            </svg>
          </div>
          <p className="text-[13.5px] mb-5 leading-relaxed" style={{ color: COLORS.textDim }}>
            {lesson.summary}
          </p>
          <div className="text-[11px] uppercase tracking-wider mb-2" style={{ color: COLORS.textMute }}>
            Key takeaways
          </div>
          <ul className="space-y-2.5 mb-6">
            {lesson.keyPoints.map((p, i) => (
              <li key={i} className="flex items-start gap-2.5 text-[13px]" style={{ color: COLORS.text }}>
                <span className="mt-0.5 text-[11px] w-5 h-5 rounded-full flex items-center justify-center shrink-0"
                      style={{ background: 'rgba(61,123,255,0.1)', color: COLORS.mint }}>
                  {i + 1}
                </span>
                <span>{p}</span>
              </li>
            ))}
          </ul>
          {lesson.category === 'Quiz' ? (
            <InteractiveQuiz week={lesson.week}
                             onPass={onComplete}
                             onClose={onClose} />
          ) : (
            <>
              <div className="rounded p-4 text-[12px]" style={{ background: COLORS.bg, color: COLORS.textDim, border: `1px solid ${COLORS.border}` }}>
                💡 <strong>Practice:</strong> Open the trade page and look for an example of what you just learned. Reading the markets in real-time is the fastest way to internalize these concepts.
              </div>
              {/* Web-sourced supplementary reading via Exa */}
              <LessonExternalReading lessonTitle={lesson.title} category={lesson.category} />
            </>
          )}
        </div>
        {/* Footer */}
        <div className="px-5 py-4 border-t flex items-center justify-between shrink-0"
             style={{ borderColor: COLORS.border }}>
          <span className="text-[11px]" style={{ color: COLORS.textMute }}>
            {completed ? '✓ Already completed' : 'Mark as complete to unlock the next lesson'}
          </span>
          <div className="flex items-center gap-2">
            <button onClick={onClose}
                    className="px-3 py-1.5 rounded text-[12px]"
                    style={{ color: COLORS.textDim, background: 'transparent', border: `1px solid ${COLORS.border}` }}>
              Later
            </button>
            <button onClick={onComplete}
                    className="px-4 py-1.5 rounded text-[12px] font-medium"
                    style={{ background: COLORS.mint, color: COLORS.bg }}>
              {completed ? '✓ Mark again' : '✓ Mark complete'}
            </button>
          </div>
        </div>
      </div>
    </>
  );
};

const BuildPage = ({ user }) => {
  const STORAGE_KEY = `imo_roadmaps_${user?.username ?? 'guest'}`;
  // Two modes: Roadmap (existing AI roadmap builder) or Health Check
  // (Business Manager — input metrics, get a health report)
  const [mode, setMode] = useState('roadmap'); // 'roadmap' | 'health'
  const [companyName, setCompanyName] = useState('');
  const [industry, setIndustry] = useState('');
  const [stage, setStage] = useState('idea');
  const [funding, setFunding] = useState('bootstrap');
  const [vision, setVision] = useState('');
  const [generating, setGenerating] = useState(false);
  const [roadmap, setRoadmap] = useState(null);
  const [error, setError] = useState(null);
  const [saved, setSaved] = useState(() => {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      return raw ? JSON.parse(raw) : [];
    } catch { return []; }
  });

  const persistSaved = (next) => {
    setSaved(next);
    try { localStorage.setItem(STORAGE_KEY, JSON.stringify(next)); } catch {}
  };

  const handleGenerate = async () => {
    if (!companyName.trim() || !industry.trim()) {
      setError('Company name and industry are required');
      return;
    }
    setError(null);
    setGenerating(true);
    setRoadmap(null);

    const apiKey = import.meta.env?.VITE_ANTHROPIC_API_KEY;
    if (!apiKey) {
      // Fall back to a synthetic roadmap if no API key is configured
      const fallback = synthesizeRoadmap(companyName, industry, stage, funding, vision);
      setRoadmap(fallback);
      setGenerating(false);
      return;
    }

    try {
      const prompt = `You are a startup advisor. Generate a 5-stage roadmap for the following company. Return ONLY a JSON object — no markdown, no code fences, no commentary.

Company: ${companyName}
Industry: ${industry}
Current stage: ${stage}
Funding plan: ${funding}
Vision: ${vision || '(not provided)'}

Format:
{
  "summary": "1-sentence elevator pitch",
  "stages": [
    {
      "title": "Stage 1 title",
      "duration": "0-3 months",
      "goal": "primary objective",
      "actions": ["specific action 1", "specific action 2", "specific action 3"],
      "metrics": ["measurable success criterion 1", "criterion 2"],
      "risks": ["main risk to watch"]
    }
  ]
}

Generate exactly 5 stages covering: 1) Validation/MVP, 2) Initial customers, 3) Product-market fit, 4) Scaling, 5) Growth/exit. Be specific to ${industry}, not generic.`;

      const res = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'x-api-key': apiKey,
          'anthropic-version': '2023-06-01',
          'anthropic-dangerous-direct-browser-access': 'true',
        },
        body: JSON.stringify({
          model: 'claude-haiku-4-5-20251001',
          max_tokens: 2500,
          messages: [{ role: 'user', content: prompt }],
        }),
      });
      if (!res.ok) throw new Error(`API error: ${res.status}`);
      const data = await res.json();
      const textBlock = (data.content ?? []).find(b => b.type === 'text');
      if (!textBlock) throw new Error('No text in response');
      // Strip any markdown fences and parse
      const cleaned = textBlock.text.replace(/```json|```/g, '').trim();
      const parsed = JSON.parse(cleaned);
      setRoadmap({ ...parsed, company: companyName, industry, generatedAt: Date.now() });
    } catch (e) {
      console.warn('Roadmap generation failed, using synthetic fallback:', e);
      const fallback = synthesizeRoadmap(companyName, industry, stage, funding, vision);
      setRoadmap(fallback);
    } finally {
      setGenerating(false);
    }
  };

  const handleSave = () => {
    if (!roadmap) return;
    const entry = {
      id: `rm_${Date.now()}`,
      company: companyName,
      industry,
      data: roadmap,
      savedAt: Date.now(),
    };
    persistSaved([entry, ...saved].slice(0, 12));
  };

  const handleLoad = (entry) => {
    setCompanyName(entry.company);
    setIndustry(entry.industry);
    setRoadmap(entry.data);
  };

  const handleDelete = (id) => {
    persistSaved(saved.filter(s => s.id !== id));
  };

  return (
    <div className="flex-1 min-h-0 overflow-y-auto" style={{ background: COLORS.bg }}>
      <div className="max-w-[1200px] mx-auto px-8 py-8">
        <div className="flex items-baseline justify-between mb-2 flex-wrap gap-3">
          <h1 className="text-[24px] font-medium" style={{ color: COLORS.text }}>Business</h1>
          <div className="flex items-center gap-2">
            <div className="flex items-center gap-0.5 p-0.5 rounded" style={{ background: COLORS.surface }}>
              {[
                { id: 'roadmap', label: 'Roadmap Builder' },
                { id: 'health',  label: 'Health Check' },
              ].map(m => (
                <button key={m.id} onClick={() => setMode(m.id)}
                        className="px-2.5 py-1 text-[11px] rounded transition-colors"
                        style={{
                          background: mode === m.id ? COLORS.mint : 'transparent',
                          color: mode === m.id ? COLORS.bg : COLORS.textDim,
                        }}>{m.label}</button>
              ))}
            </div>
          </div>
        </div>
        <p className="text-[13px] mb-6" style={{ color: COLORS.textMute }}>
          {mode === 'roadmap'
            ? 'Describe a company you want to build. AI generates a 5-stage roadmap with goals, actions, and success metrics for each stage.'
            : 'Input your business metrics across 6 dimensions. Get a health score and identify the weakest links holding you back from scaling.'}
        </p>

        {mode === 'health' ? (
          <BusinessHealthCheck user={user} />
        ) : (
        <>
        {/* Input form */}
        <div className="grid grid-cols-1 lg:grid-cols-[1fr_320px] gap-5">
          <div className="rounded-md border p-5" style={{ background: COLORS.surface, borderColor: COLORS.border }}>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-3 mb-3">
              <div>
                <label className="text-[10px] uppercase tracking-wider mb-1.5 block" style={{ color: COLORS.textMute }}>
                  Company name
                </label>
                <input value={companyName}
                       onChange={e => setCompanyName(e.target.value)}
                       placeholder="e.g. Stellar Robotics"
                       className="w-full px-3 py-2 rounded text-[13px] outline-none"
                       style={{ background: COLORS.bg, color: COLORS.text, border: `1px solid ${COLORS.border}` }} />
              </div>
              <div>
                <label className="text-[10px] uppercase tracking-wider mb-1.5 block" style={{ color: COLORS.textMute }}>
                  Industry / market
                </label>
                <input value={industry}
                       onChange={e => setIndustry(e.target.value)}
                       placeholder="e.g. warehouse automation"
                       className="w-full px-3 py-2 rounded text-[13px] outline-none"
                       style={{ background: COLORS.bg, color: COLORS.text, border: `1px solid ${COLORS.border}` }} />
              </div>
              <div>
                <label className="text-[10px] uppercase tracking-wider mb-1.5 block" style={{ color: COLORS.textMute }}>
                  Current stage
                </label>
                <select value={stage} onChange={e => setStage(e.target.value)}
                        className="w-full px-3 py-2 rounded text-[13px] outline-none"
                        style={{ background: COLORS.bg, color: COLORS.text, border: `1px solid ${COLORS.border}`, colorScheme: 'dark' }}>
                  <option value="idea">Idea / pre-MVP</option>
                  <option value="mvp">Building MVP</option>
                  <option value="early">Early customers</option>
                  <option value="growth">Growing revenue</option>
                  <option value="scale">Scaling</option>
                </select>
              </div>
              <div>
                <label className="text-[10px] uppercase tracking-wider mb-1.5 block" style={{ color: COLORS.textMute }}>
                  Funding plan
                </label>
                <select value={funding} onChange={e => setFunding(e.target.value)}
                        className="w-full px-3 py-2 rounded text-[13px] outline-none"
                        style={{ background: COLORS.bg, color: COLORS.text, border: `1px solid ${COLORS.border}`, colorScheme: 'dark' }}>
                  <option value="bootstrap">Bootstrap (self-fund)</option>
                  <option value="angel">Angel / friends-and-family</option>
                  <option value="seed">Seed VC</option>
                  <option value="series-a">Series A+</option>
                  <option value="grants">Grants / accelerator</option>
                </select>
              </div>
            </div>
            <div>
              <label className="text-[10px] uppercase tracking-wider mb-1.5 block" style={{ color: COLORS.textMute }}>
                Vision (optional)
              </label>
              <textarea value={vision}
                        onChange={e => setVision(e.target.value.slice(0, 400))}
                        placeholder="What problem does this solve? Who is the customer?"
                        rows={3}
                        className="w-full px-3 py-2 rounded text-[12.5px] outline-none resize-none"
                        style={{ background: COLORS.bg, color: COLORS.text, border: `1px solid ${COLORS.border}` }} />
              <div className="text-[9px] mt-1 text-right" style={{ color: COLORS.textMute }}>{vision.length}/400</div>
            </div>
            {error && (
              <div className="mt-3 px-3 py-2 rounded text-[11px]"
                   style={{ background: 'rgba(237,112,136,0.08)', color: COLORS.red, border: `1px solid rgba(237,112,136,0.2)` }}>
                {error}
              </div>
            )}
            <button onClick={handleGenerate}
                    disabled={generating || !companyName.trim() || !industry.trim()}
                    className="w-full mt-4 py-2.5 rounded-md text-[13px] font-medium transition-opacity disabled:opacity-40"
                    style={{ background: COLORS.mint, color: COLORS.bg }}>
              {generating ? 'Generating roadmap…' : 'Generate roadmap'}
            </button>
          </div>

          {/* Saved roadmaps sidebar */}
          <div className="rounded-md border p-4" style={{ background: COLORS.surface, borderColor: COLORS.border }}>
            <div className="text-[11px] uppercase tracking-wider mb-3" style={{ color: COLORS.textMute }}>
              Saved roadmaps
            </div>
            {saved.length === 0 ? (
              <div className="text-[11px] py-4 text-center" style={{ color: COLORS.textMute }}>
                No saved roadmaps yet. Generate one and hit Save.
              </div>
            ) : (
              <div className="space-y-2">
                {saved.map(s => (
                  <div key={s.id} className="rounded border p-2 hover:bg-white/[0.02] transition-colors group"
                       style={{ borderColor: COLORS.border }}>
                    <button onClick={() => handleLoad(s)} className="w-full text-left">
                      <div className="text-[12px] font-medium truncate" style={{ color: COLORS.text }}>
                        {s.company}
                      </div>
                      <div className="text-[10px] truncate" style={{ color: COLORS.textMute }}>
                        {s.industry} · {new Date(s.savedAt).toLocaleDateString()}
                      </div>
                    </button>
                    <button onClick={() => handleDelete(s.id)}
                            className="text-[9px] mt-1 opacity-0 group-hover:opacity-100 transition-opacity"
                            style={{ color: COLORS.red }}>
                      Delete
                    </button>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>

        {/* Roadmap output */}
        {generating && (
          <div className="mt-6 rounded-md border p-12 text-center"
               style={{ background: COLORS.surface, borderColor: COLORS.border }}>
            <div className="inline-block w-8 h-8 border-2 rounded-full animate-spin mb-3"
                 style={{ borderColor: COLORS.border, borderTopColor: COLORS.mint }} />
            <div className="text-[12.5px]" style={{ color: COLORS.text }}>
              Generating your roadmap…
            </div>
            <div className="text-[10.5px] mt-1" style={{ color: COLORS.textMute }}>
              Claude is mapping out 5 stages for {companyName}
            </div>
          </div>
        )}

        {roadmap && !generating && (
          <div className="mt-6">
            <div className="flex items-center justify-between mb-4">
              <div>
                <h2 className="text-[18px] font-medium" style={{ color: COLORS.text }}>{roadmap.company ?? companyName}</h2>
                <p className="text-[11.5px] mt-0.5" style={{ color: COLORS.textDim }}>{roadmap.summary}</p>
              </div>
              <button onClick={handleSave}
                      className="px-3 py-1.5 rounded-md text-[12px] font-medium transition-colors"
                      style={{ background: 'transparent', color: COLORS.mint, border: `1px solid ${COLORS.mint}` }}>
                Save roadmap
              </button>
            </div>

            {/* Vertical timeline of stages */}
            <div className="relative">
              {(roadmap.stages ?? []).map((s, i) => (
                <div key={i} className="flex gap-4 mb-5 last:mb-0">
                  {/* Stage number + connector line */}
                  <div className="flex flex-col items-center shrink-0">
                    <div className="w-9 h-9 rounded-full flex items-center justify-center text-[14px] font-semibold"
                         style={{
                           background: COLORS.mint,
                           color: COLORS.bg,
                         }}>
                      {i + 1}
                    </div>
                    {i < (roadmap.stages.length - 1) && (
                      <div className="flex-1 w-0.5 mt-1" style={{ background: COLORS.border, minHeight: 20 }} />
                    )}
                  </div>
                  {/* Stage card */}
                  <div className="flex-1 rounded-md border p-4"
                       style={{ background: COLORS.surface, borderColor: COLORS.border }}>
                    <div className="flex items-baseline justify-between mb-2 gap-2">
                      <h3 className="text-[14px] font-medium" style={{ color: COLORS.text }}>{s.title}</h3>
                      <span className="text-[10px] px-2 py-0.5 rounded-full shrink-0"
                            style={{ background: COLORS.surface2, color: COLORS.textDim }}>
                        {s.duration}
                      </span>
                    </div>
                    {s.goal && (
                      <div className="mb-3 text-[12px]" style={{ color: COLORS.textDim }}>
                        <span className="text-[10px] uppercase tracking-wider mr-1.5" style={{ color: COLORS.textMute }}>Goal:</span>
                        {s.goal}
                      </div>
                    )}
                    {s.actions && s.actions.length > 0 && (
                      <div className="mb-3">
                        <div className="text-[10px] uppercase tracking-wider mb-1.5" style={{ color: COLORS.textMute }}>Actions</div>
                        <ul className="space-y-1">
                          {s.actions.map((a, j) => (
                            <li key={j} className="flex items-start gap-2 text-[11.5px]" style={{ color: COLORS.textDim }}>
                              <span className="mt-0.5" style={{ color: COLORS.mint }}>→</span>
                              <span>{a}</span>
                            </li>
                          ))}
                        </ul>
                      </div>
                    )}
                    {s.metrics && s.metrics.length > 0 && (
                      <div className="mb-3">
                        <div className="text-[10px] uppercase tracking-wider mb-1.5" style={{ color: COLORS.textMute }}>Success metrics</div>
                        <div className="flex flex-wrap gap-1.5">
                          {s.metrics.map((m, j) => (
                            <span key={j} className="text-[10.5px] px-2 py-0.5 rounded"
                                  style={{ background: 'rgba(31,178,107,0.08)', color: COLORS.green, border: `1px solid rgba(31,178,107,0.2)` }}>
                              {m}
                            </span>
                          ))}
                        </div>
                      </div>
                    )}
                    {s.risks && s.risks.length > 0 && (
                      <div>
                        <div className="text-[10px] uppercase tracking-wider mb-1.5" style={{ color: COLORS.textMute }}>Watch out for</div>
                        <ul className="space-y-1">
                          {s.risks.map((r, j) => (
                            <li key={j} className="flex items-start gap-2 text-[11px]" style={{ color: COLORS.textDim }}>
                              <span className="mt-0.5" style={{ color: COLORS.red }}>⚠</span>
                              <span>{r}</span>
                            </li>
                          ))}
                        </ul>
                      </div>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
        </>
        )}
      </div>
    </div>
  );
};

// ──────────── Business Health Check ────────────
// Lets users self-score their business across 6 dimensions: revenue,
// retention, margin, growth, runway, team health. Shows composite health
// score + per-dimension breakdown + tactical recommendations for each.
const BusinessHealthCheck = ({ user }) => {
  const STORAGE_KEY = `imo_health_${user?.username ?? 'guest'}`;
  const [metrics, setMetrics] = useState(() => {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (raw) return JSON.parse(raw);
    } catch {}
    return {
      mrr: 50000,                    // monthly recurring revenue
      mrrGrowthPct: 8,               // MoM growth %
      grossMargin: 60,               // %
      churnRate: 4,                  // % monthly
      netRetention: 105,             // %
      cac: 800,                      // $
      ltv: 2400,                     // $
      runwayMonths: 12,
      headcount: 8,
      eNPS: 30,                      // employee NPS
    };
  });
  const persist = (next) => {
    setMetrics(next);
    try { localStorage.setItem(STORAGE_KEY, JSON.stringify(next)); } catch {}
  };

  // Score each dimension 0-100
  const scores = useMemo(() => {
    const ltvCac = metrics.cac > 0 ? metrics.ltv / metrics.cac : 0;
    return {
      revenue:    Math.min(100, Math.round((metrics.mrr / 100000) * 100)),
      growth:     Math.min(100, Math.round(metrics.mrrGrowthPct * 10)),
      profitability: Math.min(100, Math.round(metrics.grossMargin * 1.4)),
      retention:  Math.max(0, Math.min(100, Math.round(metrics.netRetention - 50))),
      churn:      Math.max(0, Math.min(100, 100 - metrics.churnRate * 12)),
      ltvCac:     Math.min(100, Math.round(ltvCac * 25)),
      runway:     Math.min(100, Math.round(metrics.runwayMonths * 5.5)),
      team:       Math.max(0, Math.min(100, Math.round((metrics.eNPS + 50) * 1.0))),
    };
  }, [metrics]);

  const composite = Math.round(
    (scores.revenue + scores.growth + scores.profitability + scores.retention +
     scores.runway + scores.team) / 6
  );
  const tier = composite >= 80 ? { label: 'Excellent', color: COLORS.green }
             : composite >= 65 ? { label: 'Healthy', color: COLORS.mint }
             : composite >= 45 ? { label: 'Concerning', color: '#FFB84D' }
             : { label: 'Critical', color: COLORS.red };

  // Identify weakest dimension for recommendation
  const weakest = useMemo(() => {
    const entries = Object.entries(scores).sort((a, b) => a[1] - b[1]);
    return entries[0];
  }, [scores]);

  const RECOMMENDATIONS = {
    revenue:       'Focus on adding net-new logos. Hire 2 SDRs, refine ICP, and double outbound activity.',
    growth:        'Test pricing increases. Improve conversion funnel — A/B test landing pages and onboarding.',
    profitability: 'Audit COGS line items. Negotiate vendor contracts. Consider self-serve to reduce cost-to-serve.',
    retention:     'Build a CSM playbook. Identify at-risk accounts proactively. Add stickier features (integrations, automations).',
    churn:         'Investigate top 5 churn reasons. Add check-in calls in first 30 days. Improve onboarding completion.',
    ltvCac:        'CAC is too high relative to LTV. Improve activation, run referral program, double down on cheapest channels.',
    runway:        'Less than 18 months runway is risky. Cut burn 15-25% or start fundraising 6+ months ahead.',
    team:          'Low team morale predicts attrition. Invest in 1:1s, transparency, comp benchmarking, and growth paths.',
  };

  const Slider = ({ label, value, onChange, min, max, step, suffix }) => (
    <div>
      <div className="flex items-center justify-between mb-1.5 gap-2">
        <span className="text-[11px]" style={{ color: COLORS.text }}>{label}</span>
        {/* Text input mirrors the slider — typing a value moves the slider,
            and dragging the slider updates the text. Allows precise entry
            without scrubbing the slider for exact figures. */}
        <input
          type="number"
          min={min}
          max={max}
          step={step ?? 1}
          value={value}
          onChange={e => {
            const v = e.target.value === '' ? min : Number(e.target.value);
            if (Number.isFinite(v)) onChange(Math.max(min, Math.min(max, v)));
          }}
          className="text-[12px] tabular-nums font-medium px-2 py-0.5 rounded outline-none w-24 text-right"
          style={{
            background: COLORS.surface2,
            color: COLORS.text,
            border: `1px solid ${COLORS.border}`,
          }}
        />
        {suffix && (
          <span className="text-[11px]" style={{ color: COLORS.textMute }}>{suffix}</span>
        )}
      </div>
      <input type="range" min={min} max={max} step={step ?? 1} value={value}
             onChange={e => onChange(+e.target.value)}
             className="w-full" style={{ accentColor: COLORS.mint }} />
    </div>
  );

  const ScoreBar = ({ label, value, hint }) => (
    <div>
      <div className="flex items-center justify-between mb-1">
        <span className="text-[11px]" style={{ color: COLORS.text }}>{label}</span>
        <span className="text-[11px] tabular-nums" style={{ color: COLORS.textDim }}>{value}/100</span>
      </div>
      <div className="h-1.5 rounded-full overflow-hidden" style={{ background: COLORS.bg }}>
        <div className="h-full"
             style={{ width: `${value}%`,
                      background: value >= 70 ? COLORS.green : value >= 50 ? COLORS.mint : value >= 30 ? '#FFB84D' : COLORS.red }} />
      </div>
      {hint && <div className="text-[10px] mt-1" style={{ color: COLORS.textMute }}>{hint}</div>}
    </div>
  );

  return (
    <div className="grid grid-cols-1 lg:grid-cols-[1fr_360px] gap-5">
      {/* Inputs */}
      <div className="rounded-md border p-5"
           style={{ background: COLORS.surface, borderColor: COLORS.border }}>
        <h2 className="text-[14px] font-medium mb-4" style={{ color: COLORS.text }}>Your business metrics</h2>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          <Slider label="Monthly Recurring Revenue" value={metrics.mrr} min={0} max={5000000} step={5000}
                  suffix=" / mo" onChange={(v) => persist({ ...metrics, mrr: v })} />
          <Slider label="MRR Growth (MoM %)" value={metrics.mrrGrowthPct} min={-20} max={50} suffix="%"
                  onChange={(v) => persist({ ...metrics, mrrGrowthPct: v })} />
          <Slider label="Gross Margin" value={metrics.grossMargin} min={0} max={95} suffix="%"
                  onChange={(v) => persist({ ...metrics, grossMargin: v })} />
          <Slider label="Monthly Churn" value={metrics.churnRate} min={0} max={20} step={0.5} suffix="%"
                  onChange={(v) => persist({ ...metrics, churnRate: v })} />
          <Slider label="Net Revenue Retention" value={metrics.netRetention} min={70} max={150} suffix="%"
                  onChange={(v) => persist({ ...metrics, netRetention: v })} />
          <Slider label="CAC" value={metrics.cac} min={0} max={5000} step={50} suffix=""
                  onChange={(v) => persist({ ...metrics, cac: v })} />
          <Slider label="LTV" value={metrics.ltv} min={0} max={20000} step={100}
                  onChange={(v) => persist({ ...metrics, ltv: v })} />
          <Slider label="Runway (months)" value={metrics.runwayMonths} min={0} max={36}
                  onChange={(v) => persist({ ...metrics, runwayMonths: v })} />
          <Slider label="Headcount" value={metrics.headcount} min={1} max={500}
                  onChange={(v) => persist({ ...metrics, headcount: v })} />
          <Slider label="Employee NPS" value={metrics.eNPS} min={-50} max={70}
                  onChange={(v) => persist({ ...metrics, eNPS: v })} />
        </div>
      </div>

      {/* Health report */}
      <div className="space-y-4">
        {/* Composite score */}
        <div className="rounded-md border p-4"
             style={{ background: COLORS.surface, borderColor: COLORS.border }}>
          <div className="text-[10px] uppercase tracking-wider mb-1" style={{ color: COLORS.textMute }}>
            Composite health
          </div>
          <div className="flex items-baseline gap-3">
            <span className="text-[32px] font-medium tabular-nums" style={{ color: tier.color }}>{composite}</span>
            <span className="text-[14px] font-medium" style={{ color: tier.color }}>{tier.label}</span>
          </div>
          <div className="text-[10.5px] mt-1" style={{ color: COLORS.textMute }}>
            Average of 6 weighted dimensions
          </div>
        </div>
        {/* Dimension scores */}
        <div className="rounded-md border p-4 space-y-3"
             style={{ background: COLORS.surface, borderColor: COLORS.border }}>
          <h3 className="text-[12px] font-medium" style={{ color: COLORS.text }}>Score by dimension</h3>
          <ScoreBar label="Revenue scale" value={scores.revenue} hint={`MRR: $${(metrics.mrr / 1000).toFixed(0)}K`} />
          <ScoreBar label="Growth velocity" value={scores.growth} hint={`${metrics.mrrGrowthPct > 0 ? '+' : ''}${metrics.mrrGrowthPct}% MoM`} />
          <ScoreBar label="Unit profitability" value={scores.profitability} hint={`${metrics.grossMargin}% gross margin`} />
          <ScoreBar label="Retention" value={scores.retention} hint={`${metrics.netRetention}% NRR`} />
          <ScoreBar label="LTV/CAC" value={scores.ltvCac} hint={`${(metrics.ltv / Math.max(1, metrics.cac)).toFixed(1)}× ratio · target 3×+`} />
          <ScoreBar label="Runway" value={scores.runway} hint={`${metrics.runwayMonths} months`} />
          <ScoreBar label="Team health" value={scores.team} hint={`eNPS ${metrics.eNPS}`} />
        </div>
        {/* Recommendation */}
        <div className="rounded-md border p-4"
             style={{ background: 'rgba(255,184,77,0.05)', borderColor: '#FFB84D40' }}>
          <div className="flex items-center gap-1.5 mb-2">
            <span className="text-[12px] font-bold" style={{ color: '#FFB84D' }}>›</span>
            <h3 className="text-[12px] font-medium" style={{ color: '#FFB84D' }}>Top recommendation</h3>
          </div>
          <div className="text-[10.5px] mb-1" style={{ color: COLORS.textMute }}>
            Weakest dimension: <strong style={{ color: COLORS.text }}>{weakest[0]}</strong> ({weakest[1]}/100)
          </div>
          <p className="text-[11.5px]" style={{ color: COLORS.textDim }}>
            {RECOMMENDATIONS[weakest[0]] ?? 'Address the lowest-scoring dimension first — it\'s the bottleneck.'}
          </p>
        </div>
      </div>
    </div>
  );
};

