const VaultsPage = ({ account, onDepositToVault, onWithdrawFromVault }) => {
  const [selected, setSelected] = useState(VAULTS[0]);

  // Compute each vault's current value from real account state
  const getVaultValue = (vaultId, apy) => {
    const userVault = account?.vaults?.[vaultId];
    if (!userVault || userVault.principal <= 0) return 0;
    const days = (Date.now() - new Date(userVault.depositedAt).getTime()) / 86400000;
    const accrued = userVault.principal * (apy / 100) * (days / 365);
    return userVault.principal + accrued;
  };

  const totalAllocation = VAULTS.reduce((sum, v) => sum + getVaultValue(v.id, v.apy), 0);
  const vaultCount = VAULTS.filter(v => (account?.vaults?.[v.id]?.principal ?? 0) > 0).length;

  return (
    <div className="flex-1 min-h-0 overflow-auto">
      <div className="max-w-[1400px] mx-auto px-8 py-8">
        <div className="flex items-baseline justify-between mb-8">
          <div>
            <h1 className="text-[22px] font-medium" style={{ color: COLORS.text }}>Liquidity Funds</h1>
            <p className="text-[12px] mt-1" style={{ color: COLORS.textMute }}>JPM-managed strategies · whitelisted LEIs only</p>
          </div>
          <div className="text-[11px] px-2.5 py-1 rounded-md"
               style={{ background: 'rgba(61,123,255,0.08)', color: COLORS.mint }}>
            {totalAllocation > 0
              ? `Your total allocation: ${fmtCompact(totalAllocation)} across ${vaultCount} vault${vaultCount === 1 ? '' : 's'}`
              : 'No vault deposits yet'}
          </div>
        </div>

        <div className="grid grid-cols-4 gap-4 mb-8">
          {VAULTS.map(v => {
            const userValue = getVaultValue(v.id, v.apy);
            return (
              <button key={v.id} onClick={() => setSelected(v)}
                      className="text-left px-5 py-4 rounded-md border transition-all hover:border-white/20"
                      style={{
                        borderColor: selected.id === v.id ? COLORS.mint : COLORS.border,
                        background: COLORS.surface,
                      }}>
                <div className="flex items-center justify-between mb-3">
                  <div>
                    <div className="text-[13px] font-medium" style={{ color: COLORS.text }}>{v.name}</div>
                    <div className="text-[10px] mt-0.5" style={{ color: COLORS.textMute }}>Vault {v.id}</div>
                  </div>
                  <Vault size={16} style={{ color: COLORS.mintDim }} />
                </div>

                <div className="grid grid-cols-2 gap-3 mb-3">
                  <div>
                    <div className="text-[9px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>APY</div>
                    <div className="text-[18px] tabular-nums" style={{ color: COLORS.mint }}>{v.apy.toFixed(1)}%</div>
                  </div>
                  <div>
                    <div className="text-[9px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>TVL</div>
                    <div className="text-[14px] tabular-nums mt-0.5" style={{ color: COLORS.text }}>{fmtCompact(v.tvl)}</div>
                  </div>
                </div>

                <div style={{ height: 40 }}>
                  <ResponsiveContainer width="100%" height="100%">
                    <AreaChart data={v.hist} margin={{ top: 2, right: 0, left: 0, bottom: 0 }}>
                      <defs>
                        <linearGradient id={`vg${v.id}`} x1="0" y1="0" x2="0" y2="1">
                          <stop offset="0%" stopColor={COLORS.mint} stopOpacity={0.3} />
                          <stop offset="100%" stopColor={COLORS.mint} stopOpacity={0} />
                        </linearGradient>
                      </defs>
                      <Area type="monotone" dataKey="nav" stroke={COLORS.mint} strokeWidth={1}
                            fill={`url(#vg${v.id})`} isAnimationActive={false} dot={false} />
                    </AreaChart>
                  </ResponsiveContainer>
                </div>

                <div className="flex items-center justify-between mt-3 text-[10px]">
                  <span style={{ color: COLORS.textMute }}>Your deposit</span>
                  <span className="tabular-nums" style={{ color: userValue > 0 ? COLORS.text : COLORS.textMute }}>
                    {userValue > 0 ? `$${fmt(userValue, 2)}` : '—'}
                  </span>
                </div>
              </button>
            );
          })}
        </div>

        <VaultDetail
          vault={selected}
          account={account}
          userValue={getVaultValue(selected.id, selected.apy)}
          onDeposit={(amt) => onDepositToVault(selected.id, amt, selected.apy)}
          onWithdraw={(amt) => onWithdrawFromVault(selected.id, amt)}
        />
      </div>
    </div>
  );
};

const VaultDetail = ({ vault, account, userValue, onDeposit, onWithdraw }) => {
  const [amount, setAmount] = useState('');
  const [tab, setTab] = useState('deposit');
  const [feedback, setFeedback] = useState(null); // { ok, msg }
  const riskColor = vault.risk === 'Low' ? COLORS.green : vault.risk === 'Medium' ? '#F5B041' : COLORS.red;
  const balance = account?.balance ?? 0;

  const userVault = account?.vaults?.[vault.id];
  const principal = userVault?.principal ?? 0;
  const accruedYield = userValue - principal;
  const depositedAt = userVault?.depositedAt;

  const handleSubmit = () => {
    const amt = parseFloat(amount);
    if (!amt || amt <= 0) {
      setFeedback({ ok: false, msg: 'Enter a valid amount' });
      return;
    }
    const result = tab === 'deposit' ? onDeposit(amt) : onWithdraw(amt);
    if (result.ok) {
      setFeedback({ ok: true, msg: tab === 'deposit' ? 'Deposit confirmed' : 'Withdrawal confirmed' });
      setAmount('');
    } else {
      setFeedback({ ok: false, msg: result.error || 'Transaction failed' });
    }
    setTimeout(() => setFeedback(null), 3500);
  };

  return (
    <div className="grid grid-cols-3 gap-6">
      <div className="col-span-2 rounded-md border p-6"
           style={{ borderColor: COLORS.border, background: COLORS.surface }}>
        <div className="flex items-start justify-between mb-5">
          <div>
            <div className="flex items-center gap-2 mb-1">
              <h2 className="text-[18px]" style={{ color: COLORS.text }}>{vault.name}</h2>
              <span className="px-2 py-0.5 text-[10px] rounded"
                    style={{ background: 'rgba(61,123,255,0.08)', color: COLORS.mint }}>
                Vault {vault.id}
              </span>
            </div>
            <p className="text-[13px] leading-relaxed max-w-xl" style={{ color: COLORS.textDim }}>
              {vault.desc}
            </p>
          </div>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-4 gap-3 mb-6">
          <MiniStat label="Net APY" value={`${vault.apy.toFixed(1)}%`} tone="mint" />
          <MiniStat label="TVL" value={fmtCompact(vault.tvl)} />
          <MiniStat label="Risk" value={vault.risk} tone={vault.risk === 'Low' ? 'green' : vault.risk === 'Medium' ? 'amber' : 'red'} />
          <MiniStat label="Lockup" value={vault.lockup.split(' ')[0]} />
        </div>

        <div style={{ height: 220 }}>
          <ResponsiveContainer width="100%" height="100%">
            <AreaChart data={vault.hist} margin={{ top: 5, right: 10, left: 0, bottom: 0 }}>
              <defs>
                <linearGradient id="vd" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="0%" stopColor={COLORS.mint} stopOpacity={0.2} />
                  <stop offset="100%" stopColor={COLORS.mint} stopOpacity={0} />
                </linearGradient>
              </defs>
              <CartesianGrid stroke={COLORS.border} vertical={false} />
              <XAxis dataKey="d" tick={{ fill: COLORS.textMute, fontSize: 10 }} stroke="transparent" />
              <YAxis orientation="right" tick={{ fill: COLORS.textMute, fontSize: 10 }} stroke="transparent"
                     tickFormatter={v => v.toFixed(2)} width={45} />
              <Tooltip contentStyle={{ background: COLORS.surface2, border: `1px solid ${COLORS.borderHi}`, borderRadius: 6, fontSize: 11 }}
                       labelStyle={{ color: COLORS.textDim }} />
              <Area type="monotone" dataKey="nav" stroke={COLORS.mint} strokeWidth={1.4}
                    fill="url(#vd)" isAnimationActive={false} dot={false} />
            </AreaChart>
          </ResponsiveContainer>
        </div>

        <div className="mt-6 pt-5 border-t grid grid-cols-4 gap-4 text-[11px]"
             style={{ borderColor: COLORS.border }}>
          <DetailItem label="Strategy chain" value={`CH-${String(vault.chain).padStart(2,'0')}`} />
          <DetailItem label="Lockup terms" value={vault.lockup} />
          <DetailItem label="Manager" value="JPM Onyx Systematic" />
          <DetailItem label="Inception" value="2024-08-14" />
        </div>
      </div>

      <div className="rounded-md border p-5 self-start"
           style={{ borderColor: COLORS.border, background: COLORS.surface }}>
        <div className="flex gap-1 mb-4 p-1 rounded-md" style={{ background: COLORS.bg }}>
          <button onClick={() => { setTab('deposit'); setAmount(''); setFeedback(null); }}
                  className="flex-1 py-1.5 text-[12px] rounded transition-all"
                  style={{ color: tab === 'deposit' ? COLORS.bg : COLORS.textDim, background: tab === 'deposit' ? COLORS.mint : 'transparent' }}>
            Deposit
          </button>
          <button onClick={() => { setTab('withdraw'); setAmount(''); setFeedback(null); }}
                  className="flex-1 py-1.5 text-[12px] rounded transition-all"
                  style={{ color: tab === 'withdraw' ? COLORS.bg : COLORS.textDim, background: tab === 'withdraw' ? COLORS.mint : 'transparent' }}>
            Withdraw
          </button>
        </div>

        <LabeledField label="Amount (USD)">
          <input type="text" value={amount} onChange={e => setAmount(e.target.value)} placeholder="0.00"
                 className="w-full bg-transparent text-[15px] tabular-nums outline-none placeholder-white/20"
                 style={{ color: COLORS.text }} />
        </LabeledField>

        <div className="flex items-center gap-1 mt-3">
          {[25, 50, 75, 100].map(p => {
            const base = tab === 'deposit' ? balance : userValue;
            return (
              <button key={p}
                      onClick={() => setAmount((base * p / 100).toFixed(2))}
                      className="flex-1 py-1.5 text-[11px] rounded-md tabular-nums"
                      style={{ color: COLORS.textDim, background: COLORS.bg }}>{p}%</button>
            );
          })}
        </div>

        <div className="mt-5 pt-4 border-t space-y-2 text-[11px]" style={{ borderColor: COLORS.border }}>
          <SummaryRow
            label={tab === 'deposit' ? 'Available to deposit' : 'Your vault value'}
            value={tab === 'deposit' ? `$${fmt(balance, 2)}` : (userValue > 0 ? `$${fmt(userValue, 2)}` : '$0.00')}
          />
          {userValue > 0 && (
            <>
              <SummaryRow label="Principal" value={`$${fmt(principal, 2)}`} />
              <SummaryRow label="Accrued yield"
                          value={accruedYield > 0 ? `+$${fmt(accruedYield, 2)}` : '$0.00'}
                          mint={accruedYield > 0} />
            </>
          )}
          <SummaryRow label="Projected 30d"
                      value={amount ? `+$${fmt(+amount * vault.apy / 100 / 12, 2)}` : '—'}
                      mint />
          <SummaryRow label="Management fee" value="0.50% annually" />
          <SummaryRow label="Performance fee" value="10% of returns" />
          <SummaryRow label="Lockup" value={vault.lockup} />
        </div>

        {feedback && (
          <div className="mt-3 px-3 py-2 rounded-md text-[11px]"
               style={{
                 background: feedback.ok ? 'rgba(31,178,107,0.1)' : 'rgba(237,112,136,0.1)',
                 color: feedback.ok ? COLORS.green : COLORS.red,
               }}>
            {feedback.msg}
          </div>
        )}

        <button onClick={handleSubmit}
                className="w-full mt-5 py-3 rounded-md text-[13px] font-medium transition-opacity disabled:opacity-40"
                style={{ color: COLORS.bg, background: COLORS.mint }}
                disabled={!amount}>
          {tab === 'deposit' ? 'Deposit to vault' : 'Request withdrawal'}
        </button>
      </div>
    </div>
  );
};

const MiniStat = ({ label, value, tone }) => {
  const toneColor = tone === 'mint' ? COLORS.mint : tone === 'green' ? COLORS.green
    : tone === 'amber' ? '#F5B041' : tone === 'red' ? COLORS.red : COLORS.text;
  return (
    <div className="px-3 py-2 rounded"
         style={{ background: COLORS.bg }}>
      <div className="text-[9px] uppercase tracking-wider mb-1" style={{ color: COLORS.textMute }}>{label}</div>
      <div className="text-[15px] tabular-nums" style={{ color: toneColor }}>{value}</div>
    </div>
  );
};

const DetailItem = ({ label, value }) => (
  <div>
    <div className="text-[9px] uppercase tracking-wider mb-1" style={{ color: COLORS.textMute }}>{label}</div>
    <div className="text-[12px]" style={{ color: COLORS.text }}>{value}</div>
  </div>
);

/* ════════════════════════════════════════════════════════════════════════════
   REFERRALS PAGE
   ════════════════════════════════════════════════════════════════════════════ */

const ReferralsPage = ({ user }) => {
  const [copied, setCopied] = useState(false);
  const code = user?.desk ? `JPM-${user.desk.replace(/[^A-Z0-9]/gi, '').toUpperCase()}` : 'JPM-ECM147';
  const onCopy = () => {
    navigator.clipboard?.writeText(`https://onyx.jpmorgan.com/r/${code}`);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };
  // Real user state — new accounts start with zero referrals. A real
  // implementation would store referrals in the account ledger.
  const referrals = [];
  const totalVol = 0;
  const totalRewards = 0;
  const tierColor = (t) => ({ Platinum: '#E5E4E2', Gold: '#F5B041', Silver: COLORS.textDim, Bronze: '#CD7F32' })[t];
  // Tier determined by total referred volume
  const currentTier = totalVol >= 240_000_000 ? 'Platinum' :
                      totalVol >= 50_000_000 ? 'Gold' :
                      totalVol >= 10_000_000 ? 'Silver' :
                      totalVol >= 1_000_000  ? 'Bronze' : 'Unranked';
  const nextTierThreshold = currentTier === 'Unranked' ? 1_000_000 :
                            currentTier === 'Bronze'   ? 10_000_000 :
                            currentTier === 'Silver'   ? 50_000_000 :
                            currentTier === 'Gold'     ? 240_000_000 : null;
  const nextTierLabel = currentTier === 'Unranked' ? 'Bronze' :
                        currentTier === 'Bronze'   ? 'Silver' :
                        currentTier === 'Silver'   ? 'Gold' :
                        currentTier === 'Gold'     ? 'Platinum' : null;

  return (
    <div className="flex-1 min-h-0 overflow-auto">
      <div className="max-w-[1400px] mx-auto px-8 py-8">
        <div className="flex items-baseline justify-between mb-8">
          <div>
            <h1 className="text-[22px] font-medium" style={{ color: COLORS.text }}>Referrals</h1>
            <p className="text-[12px] mt-1" style={{ color: COLORS.textMute }}>Earn 50bps of every referred desk's volume · paid in JPM Coin</p>
          </div>
        </div>

        <div className="grid grid-cols-3 gap-4 mb-8">
          <div className="col-span-2 rounded-md border p-6"
               style={{ borderColor: COLORS.borderHi, background: COLORS.surface }}>
            <div className="flex items-center justify-between mb-4">
              <div>
                <div className="text-[11px] mb-2" style={{ color: COLORS.textMute }}>Your referral link</div>
                <div className="flex items-center gap-2">
                  <code className="px-3 py-2 rounded border text-[13px] tabular-nums"
                        style={{ borderColor: COLORS.border, background: COLORS.bg, color: COLORS.mint }}>
                    https://onyx.jpmorgan.com/r/{code}
                  </code>
                  <button onClick={onCopy}
                          className="px-3 py-2 rounded-md text-[12px] flex items-center gap-1.5 transition-all"
                          style={{
                            background: copied ? 'rgba(31,178,107,0.15)' : COLORS.surface2,
                            color: copied ? COLORS.green : COLORS.text,
                          }}>
                    {copied ? <Check size={12} /> : <Copy size={12} />}
                    {copied ? 'Copied' : 'Copy'}
                  </button>
                </div>
              </div>
              <div className="text-right">
                <div className="text-[11px]" style={{ color: COLORS.textMute }}>Current tier</div>
                <div className="flex items-center gap-1.5 mt-1">
                  <Award size={14} style={{ color: tierColor(currentTier) ?? COLORS.textMute }} />
                  <span className="text-[16px]"
                        style={{ color: tierColor(currentTier) ?? COLORS.textMute }}>
                    {currentTier}
                  </span>
                </div>
                {nextTierThreshold && (
                  <div className="text-[10px] mt-0.5" style={{ color: COLORS.textMute }}>
                    {fmtCompact(nextTierThreshold - totalVol)} more to {nextTierLabel}
                  </div>
                )}
              </div>
            </div>

            <div className="pt-4 border-t" style={{ borderColor: COLORS.border }}>
              <div className="flex justify-between text-[11px] mb-2">
                <span style={{ color: COLORS.textMute }}>Progress to Platinum</span>
                <span className="tabular-nums" style={{ color: COLORS.text }}>
                  {fmtCompact(totalVol)} / $240.0M
                </span>
              </div>
              <div className="h-2 rounded-full overflow-hidden" style={{ background: COLORS.bg }}>
                <div className="h-full rounded-full transition-all"
                     style={{ width: `${Math.min(100, (totalVol / 240_000_000) * 100)}%`, background: COLORS.mint }} />
              </div>
              <div className="flex justify-between text-[10px] mt-2" style={{ color: COLORS.textMute }}>
                <span>Bronze ($1M)</span>
                <span>Silver ($10M)</span>
                <span>Gold ($50M)</span>
                <span>Platinum ($240M)</span>
              </div>
            </div>
          </div>

          <div className="rounded-md border p-6"
               style={{ borderColor: COLORS.borderHi, background: COLORS.surface }}>
            <div className="text-[11px] mb-2" style={{ color: COLORS.textMute }}>Total rewards earned</div>
            <div className="text-[28px] tabular-nums" style={{ color: COLORS.mint }}>
              ${totalRewards.toLocaleString()}
            </div>
            <div className="text-[11px] mt-1" style={{ color: COLORS.textDim }}>Paid in JPM Coin · 30d rolling</div>
            <div className="mt-4 pt-4 border-t space-y-2 text-[11px]" style={{ borderColor: COLORS.border }}>
              <SummaryRow label="Referred desks" value={`${referrals.length} active`} />
              <SummaryRow label="Their volume (30d)" value={fmtCompact(totalVol)} />
              <SummaryRow label="Your rate" value={`50 bps · ${currentTier} tier`} mint />
              <SummaryRow label="Next payout" value="Tomorrow · 00:00 UTC" />
            </div>
          </div>
        </div>

        <div className="rounded-md border"
             style={{ borderColor: COLORS.borderHi, background: COLORS.surface }}>
          <div className="px-5 py-3 border-b text-[13px] flex items-center justify-between"
               style={{ borderColor: COLORS.border, color: COLORS.text }}>
            <span>Referred desks</span>
            <span className="text-[11px]" style={{ color: COLORS.textMute }}>{referrals.length} total</span>
          </div>
          {referrals.length === 0 ? (
            <div className="py-16 px-6 text-center">
              <Users size={28} className="mx-auto mb-3" style={{ color: COLORS.textMute }} />
              <div className="text-[14px] mb-1.5" style={{ color: COLORS.text }}>No referrals yet</div>
              <div className="text-[12px] max-w-sm mx-auto" style={{ color: COLORS.textMute }}>
                Share your referral link above. When another desk joins Onyx using your link and starts trading, their volume appears here and you earn 50bps in rewards.
              </div>
            </div>
          ) : (
            <table className="imo-data-table w-full text-[12px] tabular-nums">
              <thead>
                <tr>
                  {['Desk','LEI','Joined','Tier','30d volume','Your reward']
                    .map((h, i) => <TH key={h} right={i >= 4}>{h}</TH>)}
                </tr>
              </thead>
              <tbody>
                {referrals.map((r, i) => (
                  <tr key={i} className="border-t hover:bg-white/[0.02]"
                      style={{ borderColor: COLORS.border }}>
                    <td className="px-4 py-2.5" style={{ color: COLORS.text }}>{r.name}</td>
                    <td className="px-4 py-2.5 text-[11px]" style={{ color: COLORS.textDim }}>{r.lei}</td>
                    <td className="px-4 py-2.5" style={{ color: COLORS.textDim }}>{r.joined}</td>
                    <td className="px-4 py-2.5">
                      <span className="flex items-center gap-1.5">
                        <Award size={11} style={{ color: tierColor(r.tier) }} />
                        <span style={{ color: tierColor(r.tier) }}>{r.tier}</span>
                      </span>
                    </td>
                    <td className="px-4 py-2.5 text-right" style={{ color: COLORS.text }}>{fmtCompact(r.vol)}</td>
                    <td className="px-4 py-2.5 text-right" style={{ color: COLORS.mint }}>${r.rewards.toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>
    </div>
  );
};

/* ════════════════════════════════════════════════════════════════════════════
   LEADERBOARD PAGE
   ════════════════════════════════════════════════════════════════════════════ */

const LeaderboardPage = ({ user, account }) => {
  const [metric, setMetric] = useState('pnl');
  const [period, setPeriod] = useState('30d');
  const settings = loadSettings();
  const optedOut = settings.showOnLeaderboard === false;

  // Only real signed-in users appear. Volume/PnL/ROI/Sharpe are computed from
  // the account's trade history; all zero until the user actually trades.
  // If user opted out via Settings, hide their entry.
  const desk = (user && !optedOut)
    ? {
        rank: 1,
        name: `@${user.username} · ${user.desk}`,
        lei: user.lei,
        pnl30:  account?.realizedPnl30d ?? 0,
        vol30:  account?.volume30d ?? 0,
        roi:    0,
        sharpe: 0,
        streak: 0,
        self: true,
      }
    : null;

  const metricCols = {
    pnl:    { label: 'PnL ($)',      key: 'pnl30',  fmt: v => `$${v.toLocaleString()}` },
    vol:    { label: 'Volume',       key: 'vol30',  fmt: v => fmtCompact(v) },
    roi:    { label: 'ROI (%)',      key: 'roi',    fmt: v => `${v.toFixed(1)}%` },
    sharpe: { label: 'Sharpe',       key: 'sharpe', fmt: v => v.toFixed(2) },
  };

  return (
    <div className="flex-1 min-h-0 overflow-auto">
      <div className="max-w-[1400px] mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="flex items-baseline justify-between gap-4 mb-8 flex-wrap">
          <div className="min-w-0">
            <h1 className="text-[22px] font-medium" style={{ color: COLORS.text }}>Leaderboard</h1>
            <p className="text-[12px] mt-1" style={{ color: COLORS.textMute }}>
              Ranked by signed-in desk activity · stats update with every fill
            </p>
          </div>
          <div className="flex items-center gap-2 flex-wrap">
            <div className="flex gap-0.5 p-0.5 rounded-md" style={{ background: COLORS.surface }}>
              {Object.entries(metricCols).map(([k, v]) => (
                <button key={k} onClick={() => setMetric(k)}
                        className="px-3 py-1.5 text-[12px] rounded transition-all"
                        style={{
                          color: metric === k ? COLORS.bg : COLORS.textDim,
                          background: metric === k ? COLORS.mint : 'transparent',
                        }}>{v.label}</button>
              ))}
            </div>
            <div className="flex gap-0.5 p-0.5 rounded-md" style={{ background: COLORS.surface }}>
              {['24h', '7d', '30d', 'YTD'].map(p => (
                <button key={p} onClick={() => setPeriod(p)}
                        className="px-2.5 py-1.5 text-[12px] rounded transition-colors"
                        style={{
                          color: period === p ? COLORS.text : COLORS.textDim,
                          background: period === p ? COLORS.surface2 : 'transparent',
                        }}>{p}</button>
              ))}
            </div>
          </div>
        </div>

        {/* Challenges — themed weekly missions with rewards. Click to join.
            Each challenge has progress, finalize date, and a reward stack
            (XP + premium feature trial + cash bonus credits). */}
        {(() => {
          const CHALLENGES = [
            {
              id: 'streak-7',
              theme: 'Discipline',
              icon: '🔥',
              title: 'Trade 7 days in a row',
              desc: 'Place at least one trade per session day for a full week.',
              progress: account?.streak ?? 0,
              target: 7,
              unit: 'days',
              reward: { xp: 250, perks: ['+7d Pro features trial', '$10 in paper credits'] },
              endsIn: '4 days left',
              accent: '#FF8855',
            },
            {
              id: 'paper-pnl',
              theme: 'Performance',
              icon: '📈',
              title: 'Hit +$1,000 paper PnL',
              desc: 'Realize at least $1,000 of profit this period across any markets.',
              progress: Math.max(0, account?.realizedPnl30d ?? 0),
              target: 1000,
              unit: 'USD',
              reward: { xp: 500, perks: ['Trader badge · Bronze', '$25 in paper credits'] },
              endsIn: '12 days left',
              accent: '#1FB26B',
            },
            {
              id: 'diversify',
              theme: 'Strategy',
              icon: '🎯',
              title: 'Diversify across 5 sectors',
              desc: 'Open positions in 5 different sectors (Tech, Energy, Health, Financials, Consumer).',
              progress: Math.min(5, (account?.positions ?? []).length),
              target: 5,
              unit: 'sectors',
              reward: { xp: 200, perks: ['Strategist badge', '$15 in paper credits'] },
              endsIn: '6 days left',
              accent: '#7AC8FF',
            },
            {
              id: 'predict-3',
              theme: 'Forecast',
              icon: '🔮',
              title: 'Win 3 prediction markets',
              desc: 'Hold winning shares in 3 prediction markets at resolution.',
              progress: 0,
              target: 3,
              unit: 'wins',
              reward: { xp: 350, perks: ['Oracle badge', '$15 in paper credits'] },
              endsIn: '18 days left',
              accent: '#E07AFC',
            },
          ];
          // Read joined state from localStorage
          const joinedKey = `imo_challenges_joined:${user?.username ?? 'guest'}`;
          let joined = [];
          try { joined = JSON.parse(localStorage.getItem(joinedKey) ?? '[]'); } catch {}
          const toggleJoin = (challengeId) => {
            const next = joined.includes(challengeId)
              ? joined.filter(x => x !== challengeId)
              : [...joined, challengeId];
            try { localStorage.setItem(joinedKey, JSON.stringify(next)); } catch {}
            // Force re-render
            setMetric(m => m);
          };
          return (
            <section className="mb-10">
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-2">
                  <span className="text-[10.5px] uppercase tracking-wider font-semibold"
                        style={{ color: COLORS.mint, letterSpacing: '0.08em' }}>
                    Weekly challenges
                  </span>
                  <span className="text-[10px] px-1.5 py-0.5 rounded-full"
                        style={{ background: 'rgba(255,184,77,0.15)', color: '#FFB84D' }}>
                    {CHALLENGES.length} active
                  </span>
                </div>
                <span className="text-[10.5px]" style={{ color: COLORS.textMute }}>
                  Themed missions · earn XP, badges, and trial perks
                </span>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                {CHALLENGES.map(c => {
                  const pct = Math.min(100, (c.progress / c.target) * 100);
                  const complete = c.progress >= c.target;
                  const isJoined = joined.includes(c.id);
                  return (
                    <div key={c.id}
                         className="rounded-lg border p-4 transition-all hover:border-white/[0.12]"
                         style={{
                           background: COLORS.surface,
                           borderColor: complete ? c.accent + '88' : COLORS.border,
                           boxShadow: complete ? `0 0 0 1px ${c.accent}22 inset` : 'none',
                         }}>
                      <div className="flex items-start justify-between gap-3 mb-2">
                        <div className="flex items-center gap-2 min-w-0">
                          <div className="flex-shrink-0 w-7 h-7 rounded flex items-center justify-center"
                               style={{ background: `${c.accent}1A`, color: c.accent }}>
                            {(() => {
                              // Map challenge id/theme to a professional
                              // lucide icon. Falls back to Sparkles if
                              // nothing matches.
                              const id = c.id ?? '';
                              const theme = (c.theme ?? '').toLowerCase();
                              if (id.includes('streak') || theme.includes('discipline')) return <Flame size={16} />;
                              if (id.includes('pnl') || theme.includes('performance'))   return <TrendingUp size={16} />;
                              if (id.includes('diversify') || theme.includes('strategy')) return <Target size={16} />;
                              if (id.includes('predict') || theme.includes('forecast'))   return <Telescope size={16} />;
                              if (theme.includes('community'))                            return <Users size={16} />;
                              if (theme.includes('research'))                             return <Search size={16} />;
                              if (theme.includes('compete') || theme.includes('challenge')) return <Trophy size={16} />;
                              return <Sparkles size={16} />;
                            })()}
                          </div>
                          <div className="min-w-0">
                            <div className="text-[9.5px] uppercase tracking-wider mb-0.5"
                                 style={{ color: c.accent, letterSpacing: '0.08em' }}>
                              {c.theme}
                            </div>
                            <div className="text-[13px] font-medium leading-tight"
                                 style={{ color: COLORS.text }}>
                              {c.title}
                            </div>
                          </div>
                        </div>
                        {complete ? (
                          <span className="text-[10px] px-2 py-0.5 rounded-full whitespace-nowrap"
                                style={{ background: c.accent + '22', color: c.accent }}>
                            ✓ Complete
                          </span>
                        ) : (
                          <span className="text-[9.5px] whitespace-nowrap"
                                style={{ color: COLORS.textMute }}>
                            {c.endsIn}
                          </span>
                        )}
                      </div>
                      <div className="text-[11px] mb-3 leading-snug"
                           style={{ color: COLORS.textDim }}>
                        {c.desc}
                      </div>
                      {/* Progress */}
                      <div className="mb-2">
                        <div className="flex items-center justify-between text-[10.5px] mb-1 tabular-nums">
                          <span style={{ color: COLORS.textMute }}>Progress</span>
                          <span style={{ color: complete ? c.accent : COLORS.text }}>
                            {c.unit === 'USD'
                              ? `$${c.progress.toLocaleString()} / $${c.target.toLocaleString()}`
                              : `${c.progress} / ${c.target} ${c.unit}`}
                          </span>
                        </div>
                        <div className="h-1.5 rounded-full overflow-hidden"
                             style={{ background: COLORS.surface2 }}>
                          <div className="h-full rounded-full transition-all"
                               style={{
                                 width: `${pct}%`,
                                 background: complete ? c.accent : c.accent + 'CC',
                               }} />
                        </div>
                      </div>
                      {/* Rewards */}
                      <div className="flex items-center justify-between gap-2 pt-2 border-t"
                           style={{ borderColor: COLORS.border }}>
                        <div className="flex items-center gap-2 min-w-0 flex-1">
                          <span className="text-[10px]"
                                style={{ color: '#FFD24A' }}>+{c.reward.xp} XP</span>
                          <span style={{ color: COLORS.textMute }}>·</span>
                          <span className="text-[10px] truncate"
                                style={{ color: COLORS.textDim }}
                                title={c.reward.perks.join(', ')}>
                            {c.reward.perks[0]}
                          </span>
                        </div>
                        <button onClick={() => toggleJoin(c.id)}
                                disabled={complete}
                                className="px-2.5 py-1 rounded text-[10.5px] font-medium transition-all whitespace-nowrap"
                                style={{
                                  background: isJoined ? 'transparent' : c.accent,
                                  color: isJoined ? c.accent : '#FFFFFF',
                                  border: `1px solid ${c.accent}`,
                                  opacity: complete ? 0.5 : 1,
                                  cursor: complete ? 'default' : 'pointer',
                                }}>
                          {complete ? 'Done' : isJoined ? 'Joined' : 'Join'}
                        </button>
                      </div>
                    </div>
                  );
                })}
              </div>
            </section>
          );
        })()}

        {/* (nothing — kept original spacing) */}
        {false && (
          <div />
        )}

        {!desk ? (
          <div className="rounded-md border p-10 text-center"
               style={{ borderColor: COLORS.border, background: COLORS.surface }}>
            <Trophy size={32} className="mx-auto mb-3" style={{ color: COLORS.textMute }} />
            <div className="text-[14px] mb-1" style={{ color: COLORS.text }}>
              No desks on the board yet
            </div>
            <div className="text-[12px] max-w-md mx-auto" style={{ color: COLORS.textMute }}>
              Sign in to appear on the leaderboard. Your PnL, volume, ROI, and Sharpe will
              update as you trade.
            </div>
          </div>
        ) : (
          <>
            <div className="grid grid-cols-1 gap-4 mb-8 max-w-md">
              <div
                className="px-6 py-5 rounded-md border relative overflow-hidden"
                style={{ borderColor: COLORS.mint, background: COLORS.surface }}
              >
                <Trophy size={64} className="absolute -top-4 -right-4 opacity-[0.07]" style={{ color: '#F5B041' }} />
                <div className="flex items-center gap-2 mb-3">
                  <div className="w-7 h-7 rounded flex items-center justify-center text-[12px] font-medium"
                       style={{ background: '#F5B04122', color: '#F5B041' }}>
                    #1
                  </div>
                  <span className="px-1.5 py-0.5 text-[9px] rounded"
                        style={{ background: 'rgba(61,123,255,0.1)', color: COLORS.mint }}>Your desk</span>
                </div>
                <div className="text-[15px] mb-1 truncate" style={{ color: COLORS.text }} title={desk.name}>{desk.name}</div>
                <div className="text-[10px] mb-3 tabular-nums truncate" style={{ color: COLORS.textMute }} title={desk.lei}>{desk.lei}</div>
                <div className="flex items-baseline gap-2">
                  <span className="text-[22px] tabular-nums"
                        style={{ color: desk.pnl30 > 0 ? COLORS.green : desk.pnl30 < 0 ? COLORS.red : COLORS.text }}>
                    {metricCols[metric].fmt(desk[metricCols[metric].key])}
                  </span>
                  <span className="text-[11px]" style={{ color: COLORS.textMute }}>{period}</span>
                </div>
                {desk.pnl30 === 0 && desk.vol30 === 0 && (
                  <div className="text-[11px] mt-3" style={{ color: COLORS.textMute }}>
                    No activity yet — place a trade to start your streak
                  </div>
                )}
              </div>
            </div>

            <div className="rounded-md border overflow-hidden"
                 style={{ borderColor: COLORS.border, background: COLORS.surface }}>
              <div className="overflow-x-auto">
                <table className="imo-data-table w-full text-[12px] tabular-nums" style={{ minWidth: 780 }}>
                  <thead>
                    <tr>
                      {['Rank','Desk','LEI','PnL (30d)','Volume (30d)','ROI','Sharpe','Streak']
                        .map((h, i) => <TH key={h} right={i >= 3}>{h}</TH>)}
                    </tr>
                  </thead>
                  <tbody>
                    <tr
                      className="border-t hover:bg-white/[0.02] transition-colors"
                      style={{
                        borderColor: COLORS.border,
                        background: 'rgba(61,123,255,0.03)',
                      }}
                    >
                      <td className="px-4 py-3 whitespace-nowrap" style={{ color: COLORS.textDim }}>#{desk.rank}</td>
                      <td className="px-4 py-3 whitespace-nowrap">
                        <div className="flex items-center gap-2">
                          <span style={{ color: COLORS.text }}>{desk.name}</span>
                          <span className="text-[10px] px-1.5 py-0.5 rounded"
                                style={{ background: 'rgba(61,123,255,0.1)', color: COLORS.mint }}>You</span>
                        </div>
                      </td>
                      <td className="px-4 py-3 text-[11px] whitespace-nowrap" style={{ color: COLORS.textDim }}>{desk.lei}</td>
                      <td className="px-4 py-3 text-right whitespace-nowrap"
                          style={{ color: desk.pnl30 > 0 ? COLORS.green : desk.pnl30 < 0 ? COLORS.red : COLORS.text }}>
                        {desk.pnl30 > 0 ? '+' : ''}${desk.pnl30.toLocaleString()}
                      </td>
                      <td className="px-4 py-3 text-right whitespace-nowrap" style={{ color: COLORS.text }}>
                        {desk.vol30 === 0 ? '$0' : fmtCompact(desk.vol30)}
                      </td>
                      <td className="px-4 py-3 text-right whitespace-nowrap"
                          style={{ color: desk.roi > 0 ? COLORS.green : desk.roi < 0 ? COLORS.red : COLORS.text }}>
                        {desk.roi > 0 ? '+' : ''}{desk.roi.toFixed(1)}%
                      </td>
                      <td className="px-4 py-3 text-right whitespace-nowrap" style={{ color: COLORS.text }}>{desk.sharpe.toFixed(2)}</td>
                      <td className="px-4 py-3 text-right whitespace-nowrap">
                        {desk.streak > 0 ? (
                          <span className="text-[11px] px-2 py-0.5 rounded"
                                style={{ background: 'rgba(31,178,107,0.12)', color: COLORS.green }}>
                            {desk.streak} green days
                          </span>
                        ) : (
                          <span style={{ color: COLORS.textMute }}>—</span>
                        )}
                      </td>
                    </tr>
                  </tbody>
                </table>
              </div>
              <div className="px-4 py-3 border-t text-[11px] text-center"
                   style={{ borderColor: COLORS.border, color: COLORS.textMute }}>
                Leaderboard only shows real desks. Other desks will appear here as they onboard.
              </div>
            </div>
          </>
        )}
      </div>
    </div>
  );
};

/* ════════════════════════════════════════════════════════════════════════════
   DOCS PAGE
   ════════════════════════════════════════════════════════════════════════════ */

const DOCS_SECTIONS = [
  { id: 'intro',      title: 'Introduction',           items: ['What is Onyx', 'For whom', 'Quickstart', 'Onboarding'] },
  { id: 'arch',       title: 'Architecture',           items: ['Chainweb topology', 'Sequencer', 'HotStuff BFT', 'Pact contracts', 'Latency budget'] },
  { id: 'trading',    title: 'Trading',                items: ['Order types', 'Leverage & margin', 'Funding', 'Liquidation', 'Trading hours'] },
  { id: 'instruments',title: 'Instruments',            items: ['Crypto perpetuals', 'Oil derivatives', 'Contract specs', 'Listing process'] },
  { id: 'api',        title: 'API reference',         items: ['WebSocket protocol', 'REST endpoints', 'Authentication', 'Rate limits', 'Error codes'] },
  { id: 'compliance', title: 'Compliance',             items: ['KYC / LEI', 'Position limits', 'Surveillance', 'Reg reporting', 'Audit trail'] },
  { id: 'settlement', title: 'Settlement',             items: ['JPM Coin', 'Cross-chain SPV', 'Insurance fund', 'Delivery'] },
  { id: 'vaults',     title: 'Vaults',                 items: ['OLP', 'OEN', 'OLM', 'Risk disclosures'] },
  { id: 'security',   title: 'Security',               items: ['mTLS & X.509', 'Key management', 'Incident response', 'Bug bounty'] },
  { id: 'governance', title: 'Governance',             items: ['Validator set', 'Listing approval', 'Parameter changes', 'Emergency halt'] },
  { id: 'faq',        title: 'FAQ',                    items: ['Common questions', 'Troubleshooting', 'Contacts'] },
];

const DocsPage = () => {
  const [section, setSection] = useState('intro');
  return (
    <div className="flex-1 min-h-0 flex">
      <aside className="w-64 border-r overflow-y-auto shrink-0"
             style={{ borderColor: COLORS.border, background: COLORS.bg }}>
        <div className="p-5">
          <div className="text-[11px] uppercase tracking-wider mb-4" style={{ color: COLORS.textMute }}>
            Documentation
          </div>
          {DOCS_SECTIONS.map(s => (
            <div key={s.id} className="mb-4">
              <button onClick={() => setSection(s.id)}
                      className="text-[13px] mb-2 block transition-colors"
                      style={{ color: section === s.id ? COLORS.mint : COLORS.text }}>
                {s.title}
              </button>
              <div className="flex flex-col gap-1 pl-3 border-l"
                   style={{ borderColor: COLORS.border }}>
                {s.items.map((item, i) => (
                  <button key={i}
                          onClick={() => {
                            // Jump to the parent section, then scroll to the
                            // sub-item heading if it exists in the doc page
                            setSection(s.id);
                            setTimeout(() => {
                              const main = document.querySelector('main');
                              if (!main) return;
                              const headings = main.querySelectorAll('h2, h3, h4');
                              for (const h of headings) {
                                if (h.textContent?.trim().toLowerCase().includes(item.toLowerCase())) {
                                  h.scrollIntoView({ behavior: 'smooth', block: 'start' });
                                  break;
                                }
                              }
                            }, 50);
                          }}
                          className="text-[12px] text-left py-0.5 transition-colors hover:text-white"
                          style={{ color: COLORS.textDim }}>
                    {item}
                  </button>
                ))}
              </div>
            </div>
          ))}
        </div>
      </aside>

      <main className="flex-1 min-h-0 overflow-y-auto">
        <div className="max-w-3xl mx-auto px-10 py-10">
          {section === 'intro' && <DocsIntro />}
          {section === 'arch' && <DocsArch />}
          {section === 'trading' && <DocsTrading />}
          {section === 'instruments' && <DocsInstruments />}
          {section === 'api' && <DocsApi />}
          {section === 'compliance' && <DocsCompliance />}
          {section === 'settlement' && <DocsSettlement />}
          {section === 'vaults' && <DocsVaults />}
          {section === 'security' && <DocsSecurity />}
          {section === 'governance' && <DocsGovernance />}
          {section === 'faq' && <DocsFaq />}
        </div>
      </main>
    </div>
  );
};

