const DISCUSSION_TIME_FILTERS = [
  { id: 'today', label: 'Today',    hours: 24 },
  { id: 'week',  label: 'This week',hours: 24 * 7 },
  { id: 'month', label: 'This month',hours: 24 * 30 },
  { id: 'all',   label: 'All time', hours: Infinity },
];

const relTime = (iso) => {
  const dt = (Date.now() - new Date(iso).getTime()) / 3600000;
  if (dt < 1)   return `${Math.floor(dt * 60)}m ago`;
  if (dt < 24)  return `${Math.floor(dt)}h ago`;
  if (dt < 168) return `${Math.floor(dt / 24)}d ago`;
  return `${Math.floor(dt / 168)}w ago`;
};

// Sort options — Best (default), Hot (recent + votes), New (time desc), Top (votes only)
const DISCUSSION_SORTS = [
  { id: 'best', label: 'Best' },
  { id: 'hot',  label: 'Hot'  },
  { id: 'new',  label: 'New'  },
  { id: 'top',  label: 'Top'  },
];

// Mock subscribed communities for the left sidebar
const DISCUSSION_COMMUNITIES = [
  { id: 'onyx',        name: 'o/onyx',         icon: '◆', color: COLORS.mint },
  { id: 'macro',       name: 'o/macro' },
  { id: 'options',     name: 'o/options',      icon: 'Ω' },
  { id: 'crypto',      name: 'o/crypto',       icon: '₿' },
  { id: 'technicals',  name: 'o/technicals' },
  { id: 'commodities', name: 'o/commodities' },
  { id: 'tools',       name: 'o/tools',        icon: '⚙️' },
];

const DiscussionPage = ({ account }) => {
  const [filter, setFilter] = useState('all');       // time filter
  const [sort, setSort]     = useState('best');      // sort option
  const [search, setSearch] = useState('');
  const [feedMode, setFeedMode] = useState('home');  // 'home' | 'popular' | 'news' | 'explore'
  const [communityTag, setCommunityTag] = useState(null); // community filter e.g. 'macro', 'crypto'
  const [userPosts, setUserPosts] = useState(() => {
    try {
      return JSON.parse(localStorage.getItem('imo_discuss_userposts') ?? '[]');
    } catch { return []; }
  });
  const [userCommunities, setUserCommunities] = useState([]); // [{ id, name, icon }]
  const [creatingCommunity, setCreatingCommunity] = useState(false);
  const [votes, setVotes]         = useState({});
  const [composing, setComposing] = useState(false);
  const [openPostId, setOpenPostId] = useState(null); // inline-expanded post
  const [userComments, setUserComments] = useState({}); // { postId: [comment] }
  // Profile modal state — when set, shows UserProfileModal for that handle
  const [viewedProfile, setViewedProfile] = useState(null);
  const postRefs = useRef({}); // { postId: DOM element } — for scrollIntoView

  // Persist user-created posts so they survive reload + accept quick-posts
  // from widgets via the imo:discuss-quickpost custom event.
  useEffect(() => {
    try { localStorage.setItem('imo_discuss_userposts', JSON.stringify(userPosts.slice(0, 100))); } catch {}
  }, [userPosts]);
  useEffect(() => {
    const handler = (e) => {
      const post = e?.detail?.post;
      if (!post) return;
      setUserPosts(p => [post, ...p]);
    };
    window.addEventListener('imo:discuss-quickpost', handler);
    return () => window.removeEventListener('imo:discuss-quickpost', handler);
  }, []);

  const cutoff = DISCUSSION_TIME_FILTERS.find(f => f.id === filter)?.hours ?? Infinity;
  const cutoffMs = Date.now() - cutoff * 3600000;

  // All posts (mocked + user-created) with votes applied
  const allPosts = useMemo(() => {
    const combined = [...DISCUSSION_POSTS, ...userPosts];
    return combined.map(p => ({
      ...p,
      votes: p.votes + (votes[p.id] ?? 0),
    }));
  }, [userPosts, votes]);

  // Filtered + sorted feed. Mode can override sort/filter (e.g. Popular
  // forces sort=top, News filters to tag=news). Community tag further
  // narrows the feed when user clicks a community in the left sidebar.
  const feed = useMemo(() => {
    let list = allPosts.filter(p => p.pinned || new Date(p.ts).getTime() >= cutoffMs);

    // Feed-mode filter (News filters to news-tagged posts)
    if (feedMode === 'news') {
      list = list.filter(p => p.tag === 'news');
    }

    // Community filter (e.g. o/macro → only macro-tagged posts)
    if (communityTag && communityTag !== 'onyx') {
      list = list.filter(p => p.tag === communityTag);
    }

    if (search.trim()) {
      const q = search.trim().toLowerCase();
      list = list.filter(p =>
        p.title.toLowerCase().includes(q) ||
        p.body?.toLowerCase().includes(q) ||
        p.author.toLowerCase().includes(q) ||
        p.tag?.toLowerCase().includes(q)
      );
    }

    // Determine effective sort — Popular feed forces top
    const effectiveSort = feedMode === 'popular' ? 'top' : sort;

    list.sort((a, b) => {
      // Pinned always on top (unless actively searching or in News/Popular)
      if (!search.trim() && feedMode === 'home' && !communityTag) {
        if (a.pinned && !b.pinned) return -1;
        if (b.pinned && !a.pinned) return 1;
      }
      if (effectiveSort === 'new') return new Date(b.ts) - new Date(a.ts);
      if (effectiveSort === 'top') return b.votes - a.votes;
      if (effectiveSort === 'hot') {
        const ageHrsA = (Date.now() - new Date(a.ts)) / 3.6e6;
        const ageHrsB = (Date.now() - new Date(b.ts)) / 3.6e6;
        return (b.votes / (ageHrsB + 2)) - (a.votes / (ageHrsA + 2));
      }
      // 'best' — hybrid: weighted votes with mild age penalty
      const ageA = (Date.now() - new Date(a.ts)) / 3.6e6;
      const ageB = (Date.now() - new Date(b.ts)) / 3.6e6;
      return (b.votes - ageB * 0.5) - (a.votes - ageA * 0.5);
    });
    return list;
  }, [allPosts, cutoffMs, search, sort, feedMode, communityTag]);

  // "Recent posts" for right sidebar — latest 6 by timestamp, no filters
  const recentPosts = useMemo(
    () => [...allPosts].sort((a, b) => new Date(b.ts) - new Date(a.ts)).slice(0, 6),
    [allPosts]
  );

  const handleVote = (postId, direction) => {
    setVotes(prev => ({
      ...prev,
      [postId]: prev[postId] === direction ? 0 : direction,
    }));
  };

  const handleSubmit = ({ title, body, tag, media }) => {
    const pid = `user_${Date.now()}`;
    setUserPosts(prev => [{
      id: pid,
      title: title.trim(),
      body: body.trim(),
      author: account?.username ?? 'you',
      votes: 1,
      ts: new Date().toISOString(),
      tag: tag || 'general',
      comments: [],
      media: media ?? null,
    }, ...prev]);
    setVotes(prev => ({ ...prev, [pid]: 1 }));
    setComposing(false);
  };

  // Add a comment to a post (kept in userComments, merged during render)
  const handleAddComment = (postId, body) => {
    const cid = `uc_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`;
    const comment = {
      id: cid,
      author: account?.username ?? 'you',
      body: body.trim(),
      votes: 1,
      ts: new Date().toISOString(),
      replies: [],
    };
    setUserComments(prev => ({
      ...prev,
      [postId]: [comment, ...(prev[postId] ?? [])],
    }));
  };

  // Helper: comment count (flat + nested) for a post
  const countComments = (post) => {
    const mocks = post.comments ?? [];
    const user  = userComments[post.id] ?? [];
    const countRec = (arr) =>
      arr.reduce((n, c) => n + 1 + countRec(c.replies ?? []), 0);
    return countRec(mocks) + countRec(user);
  };

  return (
    <div className="flex-1 min-h-0 flex relative" style={{ background: COLORS.bg }}>
      {/* Left sidebar — communities */}
      <aside className="w-56 border-r shrink-0 overflow-y-auto hidden md:block"
             style={{ borderColor: COLORS.border, background: COLORS.bg }}>
        <div className="p-4">
          <div className="text-[10px] uppercase tracking-wider mb-2"
               style={{ color: COLORS.textMute }}>Feeds</div>
          <SidebarLink
            icon="🏠" label="Home"
            active={feedMode === 'home' && !communityTag}
            onClick={() => { setFeedMode('home'); setCommunityTag(null); setSearch(''); }}
          />
          <SidebarLink
            icon="⬆️" label="Popular"
            active={feedMode === 'popular'}
            onClick={() => { setFeedMode('popular'); setCommunityTag(null); setSearch(''); }}
          />
          <SidebarLink
            icon="📰" label="News"
            active={feedMode === 'news'}
            onClick={() => { setFeedMode('news'); setCommunityTag(null); setSearch(''); }}
          />
          <SidebarLink
            icon="🔭" label="Explore"
            active={feedMode === 'explore'}
            onClick={() => { setFeedMode('explore'); setCommunityTag(null); setSearch(''); }}
          />

          <div className="mt-5 pt-4 border-t" style={{ borderColor: COLORS.border }}>
            <div className="text-[10px] uppercase tracking-wider mb-2"
                 style={{ color: COLORS.textMute }}>Communities</div>
            {DISCUSSION_COMMUNITIES.map(c => (
              <SidebarLink
                key={c.id}
                icon={c.icon}
                label={c.name}
                active={communityTag === c.id}
                onClick={() => { setCommunityTag(c.id); setFeedMode('home'); setSearch(''); }}
              />
            ))}
            {userCommunities.map(c => (
              <SidebarLink
                key={c.id}
                icon={c.icon}
                label={c.name}
                active={communityTag === c.id}
                onClick={() => { setCommunityTag(c.id); setFeedMode('home'); setSearch(''); }}
              />
            ))}
          </div>

          <button
            onClick={() => setCreatingCommunity(true)}
            className="mt-4 w-full flex items-center gap-2 px-3 py-2 rounded-md text-[12px] border transition-colors hover:bg-white/[0.03]"
            style={{ borderColor: COLORS.border, color: COLORS.textDim }}>
            <Plus size={12} />
            Start a community
          </button>
        </div>
      </aside>

      {/* Center feed */}
      <div className="flex-1 min-h-0 flex flex-col min-w-0">
        {/* Top bar: search + sort. Now horizontally scrollable on
            narrow viewports — the cluster of search + sort + filter
            buttons could overflow at narrow widths and clip the time
            filter on the right. shrink-0 on each cluster keeps them
            from being squeezed mid-scroll. */}
        <div className="flex items-center gap-3 px-6 py-3 border-b shrink-0 overflow-x-auto imo-thin-scrollbar"
             style={{ borderColor: COLORS.border }}>
          <div className="relative flex-1 min-w-[180px] max-w-xl shrink-0">
            <Search size={13} className="absolute left-3 top-1/2 -translate-y-1/2"
                    style={{ color: COLORS.textMute }} />
            <input
              value={search}
              onChange={e => setSearch(e.target.value)}
              placeholder="Search discussions, tags, authors..."
              className="w-full pl-9 pr-3 py-2 rounded-full text-[13px] outline-none"
              style={{ background: COLORS.surface, color: COLORS.text, border: `1px solid ${COLORS.border}` }}
            />
          </div>

          {/* Sort dropdown */}
          <div className="flex items-center gap-1 shrink-0">
            {DISCUSSION_SORTS.map(s => (
              <button key={s.id} onClick={() => setSort(s.id)}
                      className="px-2.5 py-1 rounded-md text-[11px] transition-colors whitespace-nowrap"
                      style={{
                        color: sort === s.id ? COLORS.text : COLORS.textDim,
                        background: sort === s.id ? COLORS.surface : 'transparent',
                      }}>{s.label}</button>
            ))}
          </div>

          <div className="w-px h-4 mx-1 shrink-0" style={{ background: COLORS.border }} />

          {/* Time filter — only applies for new/top/best */}
          <div className="flex items-center gap-1 shrink-0">
            {DISCUSSION_TIME_FILTERS.map(f => (
              <button key={f.id} onClick={() => setFilter(f.id)}
                      className="px-2 py-1 rounded-md text-[11px] transition-colors whitespace-nowrap"
                      style={{
                        color: filter === f.id ? COLORS.text : COLORS.textDim,
                        background: filter === f.id ? COLORS.surface : 'transparent',
                      }}>{f.label}</button>
            ))}
          </div>
        </div>

        {/* Feed scroll */}
        <div className="flex-1 min-h-0 overflow-y-auto">
          <div className="max-w-3xl mx-auto px-6 py-5 space-y-2.5">
            {feed.length === 0 ? (
              <div className="text-center py-20 text-[13px]" style={{ color: COLORS.textMute }}>
                {search ? `No posts matching "${search}"` : 'No posts for this time range.'}
              </div>
            ) : feed.map(post => (
              <div
                key={post.id}
                ref={(el) => { if (el) postRefs.current[post.id] = el; }}
              >
                <DiscussionPost
                  post={post}
                  userVote={votes[post.id] ?? 0}
                  onVote={handleVote}
                  isOpen={openPostId === post.id}
                  onToggleOpen={() => setOpenPostId(openPostId === post.id ? null : post.id)}
                  commentCount={countComments(post)}
                  userComments={userComments[post.id] ?? []}
                  onAddComment={handleAddComment}
                  currentUser={account?.username ?? 'you'}
                  onViewProfile={setViewedProfile}
                />
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Right sidebar — Recent Posts */}
      <aside className="w-72 border-l shrink-0 overflow-y-auto hidden lg:block"
             style={{ borderColor: COLORS.border, background: COLORS.bg }}>
        <div className="p-4">
          <div className="flex items-center justify-between mb-3">
            <span className="text-[10px] uppercase tracking-wider"
                  style={{ color: COLORS.textMute }}>Recent Posts</span>
            <button
              onClick={() => {
                // Recent Posts is a simple latest-6 list, but "Clear" is most
                // useful as a way to reset search & filters so the user sees
                // the unfiltered feed (mirrors how Discord/Reddit "Clear" acts).
                setSearch('');
                setFilter('all');
                setFeedMode('home');
                setCommunityTag(null);
                setOpenPostId(null);
              }}
              className="text-[10px] hover:underline"
                    style={{ color: COLORS.mintDim }}>Clear</button>
          </div>
          <div className="space-y-3">
            {recentPosts.map(p => (
              <button
                key={p.id}
                onClick={() => {
                  // Reset all filters so the post is guaranteed visible,
                  // then expand it and scroll it into view.
                  setSearch('');
                  setFilter('all');
                  setFeedMode('home');
                  setCommunityTag(null);
                  setOpenPostId(p.id);
                  // Wait a tick for the feed to re-render, then scroll
                  setTimeout(() => {
                    const el = postRefs.current[p.id];
                    if (el?.scrollIntoView) {
                      el.scrollIntoView({ behavior: 'smooth', block: 'center' });
                    }
                  }, 80);
                }}
                className="w-full text-left p-2 rounded-md transition-colors hover:bg-white/[0.03]"
              >
                <div className="flex items-center gap-2 mb-1 text-[10px]"
                     style={{ color: COLORS.textMute }}>
                  <span>o/{p.tag ?? 'general'}</span>
                  <span>·</span>
                  <span>{relTime(p.ts)}</span>
                </div>
                <div className="text-[12px] leading-snug line-clamp-2"
                     style={{ color: COLORS.text }}>
                  {p.title}
                </div>
                <div className="text-[10px] mt-1 tabular-nums"
                     style={{ color: COLORS.textMute }}>
                  {p.votes >= 1000 ? `${(p.votes / 1000).toFixed(1)}k` : p.votes} upvotes
                  {' · '}
                  {countComments(p)} comments
                </div>
              </button>
            ))}
          </div>
        </div>
      </aside>

      {/* FAB — new post */}
      <button
        onClick={() => setComposing(true)}
        className="absolute bottom-6 right-6 w-14 h-14 rounded-full flex items-center justify-center shadow-lg transition-transform"
        style={{ background: COLORS.mint, color: COLORS.bg, zIndex: 20 }}
        title="Start a new discussion"
      >
        <Plus size={24} />
      </button>

      {composing && (
        <NewPostModal onSubmit={handleSubmit} onClose={() => setComposing(false)} />
      )}

      {creatingCommunity && (
        <StartCommunityModal
          onSubmit={({ name }) => {
            // Generate id from kebab-case name; collide-proof with random suffix
            const baseId = name.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '').slice(0, 20);
            const existingIds = new Set([
              ...DISCUSSION_COMMUNITIES.map(c => c.id),
              ...userCommunities.map(c => c.id),
            ]);
            let finalId = baseId;
            let n = 2;
            while (existingIds.has(finalId)) {
              finalId = `${baseId}-${n}`;
              n++;
            }
            // Pick a relevant emoji based on the name; default to a generic icon
            const lc = name.toLowerCase();
            let icon = '⊙';
            if (/(stock|equity|equit)/.test(lc))   icon = '📈';
            else if (/(option|deriv|future)/.test(lc)) icon = 'Ω';
            else if (/(crypto|btc|eth|coin)/.test(lc)) icon = '₿';
            else if (/(macro|fed|cpi|gdp)/.test(lc)) icon = '📊';
            else if (/(oil|energy|gas|comm)/.test(lc)) icon = '🛢';
            else if (/(news|earn)/.test(lc)) icon = '📰';
            else if (/(tool|code|dev)/.test(lc)) icon = '⚙️';
            const newCommunity = {
              id: finalId,
              name: `o/${finalId}`,
              icon,
            };
            setUserCommunities(prev => [...prev, newCommunity]);
            setCommunityTag(finalId);    // Jump to the new community
            setFeedMode('home');
            setSearch('');
            setCreatingCommunity(false);
          }}
          onClose={() => setCreatingCommunity(false)}
        />
      )}
      {viewedProfile && (
        <React.Suspense fallback={null}>
          <UserProfileModal handle={viewedProfile} onClose={() => setViewedProfile(null)} />
        </React.Suspense>
      )}
    </div>
  );
};

const SidebarLink = ({ icon, label, active, onClick }) => (
  <button
    onClick={onClick}
    className="w-full flex items-center gap-2.5 px-3 py-1.5 rounded-md text-[13px] text-left transition-colors mb-0.5 hover:bg-white/[0.03]"
    style={{
      color: active ? COLORS.text : COLORS.textDim,
      background: active ? COLORS.surface : 'transparent',
    }}>
    <span className="text-[14px]">{icon}</span>
    <span className="truncate">{label}</span>
  </button>
);

// Reddit-style post card with inline expansion for comments
const DiscussionPost = ({
  post, userVote, onVote, isOpen, onToggleOpen,
  commentCount, userComments, onAddComment, currentUser,
  onViewProfile,
}) => {
  return (
    <div className="rounded-md border transition-colors"
         style={{
           background: post.pinned ? 'rgba(61,123,255,0.03)' : COLORS.surface,
           borderColor: post.pinned ? COLORS.mint : COLORS.border,
         }}>
      <div className="p-4 flex gap-3">
        {/* Vote column */}
        <div className="flex flex-col items-center gap-0.5 w-10 shrink-0">
          <button onClick={() => onVote(post.id, 1)}
                  className="p-1 rounded hover:bg-white/[0.05] transition-colors"
                  title="Upvote">
            <ChevronUp
              size={18}
              style={{
                color: userVote === 1 ? COLORS.green : COLORS.textMute,
                fill:  userVote === 1 ? COLORS.green : 'none',
              }}
            />
          </button>
          <span className="text-[12px] font-medium tabular-nums"
                style={{
                  color: userVote === 1 ? COLORS.green :
                         userVote === -1 ? COLORS.red : COLORS.text,
                }}>
            {post.votes >= 1000 ? `${(post.votes / 1000).toFixed(1)}k` : post.votes}
          </span>
          <button onClick={() => onVote(post.id, -1)}
                  className="p-1 rounded hover:bg-white/[0.05] transition-colors"
                  title="Downvote">
            <ChevronDown
              size={18}
              style={{
                color: userVote === -1 ? COLORS.red : COLORS.textMute,
                fill:  userVote === -1 ? COLORS.red : 'none',
              }}
            />
          </button>
        </div>

        {/* Content */}
        <div className="flex-1 min-w-0 cursor-pointer" onClick={onToggleOpen}>
          <div className="flex items-center gap-2 mb-1.5 text-[11px]"
               style={{ color: COLORS.textMute }}>
            {post.pinned && (
              <span className="px-1.5 py-0.5 rounded text-[9px] uppercase tracking-wider"
                    style={{ background: COLORS.mint, color: COLORS.bg }}>
                Pinned Daily
              </span>
            )}
            {post.tag && !post.pinned && (
              <span className="px-1.5 py-0.5 rounded text-[9px] uppercase tracking-wider"
                    style={{ background: COLORS.surface2, color: COLORS.textDim }}>
                o/{post.tag}
              </span>
            )}
            <button onClick={(e) => { e.stopPropagation(); onViewProfile?.(`@${post.author}`); }}
                    className="hover:underline"
                    style={{ color: post.authorFlair === 'mod' ? COLORS.mint : COLORS.textMute }}>
              u/{post.author}{post.authorFlair === 'mod' ? ' · mod' : ''}
            </button>
            <span>·</span>
            <span>{relTime(post.ts)}</span>
          </div>
          <h3 className="text-[15px] font-medium mb-1.5" style={{ color: COLORS.text }}>
            {post.title}
          </h3>
          {post.body && (
            <p className={`text-[13px] mb-2 ${isOpen ? '' : 'line-clamp-3'}`}
               style={{ color: COLORS.textDim }}>
              {post.body}
            </p>
          )}
          {/* Inline media render — image or video attached to user posts */}
          {post.media && (
            <div className="rounded-md overflow-hidden border mb-2"
                 style={{ borderColor: COLORS.border, maxWidth: 480 }}
                 onClick={(e) => e.stopPropagation()}>
              {post.media.type === 'video' ? (
                <video src={post.media.url} controls className="w-full max-h-96 object-contain bg-black" />
              ) : (
                <img src={post.media.url} alt={post.media.name ?? 'attached'}
                     className="w-full max-h-96 object-contain bg-black" />
              )}
            </div>
          )}
          <div className="flex items-center gap-4 text-[11px]"
               style={{ color: COLORS.textMute }}>
            <span className="flex items-center gap-1 hover:underline">
              <Activity size={11} />
              {commentCount} comment{commentCount === 1 ? '' : 's'}
            </span>
            <span>{isOpen ? 'Collapse' : 'Expand'}</span>
          </div>
        </div>
      </div>

      {/* Inline comments section */}
      {isOpen && (
        <div className="border-t px-4 py-4"
             style={{ borderColor: COLORS.border }}>
          {/* New comment box */}
          <CommentComposer
            onSubmit={(body) => onAddComment(post.id, body)}
            currentUser={currentUser}
          />

          {/* Thread */}
          <div className="mt-4 space-y-3">
            {[...userComments, ...(post.comments ?? [])].length === 0 ? (
              <div className="text-[11px] py-4 text-center"
                   style={{ color: COLORS.textMute }}>
                No comments yet. Be the first.
              </div>
            ) : (
              [...userComments, ...(post.comments ?? [])].map(c => (
                <CommentNode key={c.id} comment={c} depth={0} onViewProfile={onViewProfile} />
              ))
            )}
          </div>
        </div>
      )}
    </div>
  );
};

// Single comment node — recursive to render replies
const CommentNode = ({ comment, depth, onViewProfile }) => {
  const [vote, setVote] = useState(0);
  const score = (comment.votes ?? 0) + vote;

  return (
    <div style={{ marginLeft: depth * 16 }}>
      <div className="flex gap-2.5">
        {/* Vote thumb line on the left */}
        <div className="flex flex-col items-center gap-0.5 w-6 shrink-0">
          <button onClick={() => setVote(v => v === 1 ? 0 : 1)}
                  className="p-0.5 rounded hover:bg-white/[0.05]">
            <ChevronUp size={14}
                       style={{
                         color: vote === 1 ? COLORS.green : COLORS.textMute,
                         fill:  vote === 1 ? COLORS.green : 'none',
                       }} />
          </button>
          <span className="text-[10px] tabular-nums"
                style={{
                  color: vote === 1 ? COLORS.green :
                         vote === -1 ? COLORS.red : COLORS.textDim,
                }}>
            {score}
          </span>
          <button onClick={() => setVote(v => v === -1 ? 0 : -1)}
                  className="p-0.5 rounded hover:bg-white/[0.05]">
            <ChevronDown size={14}
                         style={{
                           color: vote === -1 ? COLORS.red : COLORS.textMute,
                           fill:  vote === -1 ? COLORS.red : 'none',
                         }} />
          </button>
        </div>
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2 text-[10px] mb-1"
               style={{ color: COLORS.textMute }}>
            <button onClick={(e) => { e.stopPropagation(); onViewProfile?.(`@${comment.author}`); }}
                    className="hover:underline"
                    style={{ color: COLORS.textDim }}>u/{comment.author}</button>
            <span>·</span>
            <span>{relTime(comment.ts)}</span>
          </div>
          <p className="text-[12.5px] leading-relaxed whitespace-pre-wrap"
             style={{ color: COLORS.text }}>
            {comment.body}
          </p>
          <button
            onClick={() => {
              // Find the open comment composer and focus its textarea, then
              // pre-fill with the @mention so the reply chain is obvious
              const composer = document.querySelector('[data-comment-composer] textarea');
              if (composer) {
                if (!composer.value.startsWith(`@${comment.author}`)) {
                  composer.value = `@${comment.author} `;
                  // Trigger a React change event so controlled state updates
                  const setter = Object.getOwnPropertyDescriptor(window.HTMLTextAreaElement.prototype, 'value').set;
                  setter.call(composer, `@${comment.author} `);
                  composer.dispatchEvent(new Event('input', { bubbles: true }));
                }
                composer.focus();
                composer.setSelectionRange(composer.value.length, composer.value.length);
                composer.scrollIntoView({ behavior: 'smooth', block: 'center' });
              }
            }}
            className="text-[10px] mt-1 hover:underline"
                  style={{ color: COLORS.textMute }}>
            Reply
          </button>
        </div>
      </div>
      {/* Nested replies */}
      {(comment.replies ?? []).length > 0 && (
        <div className="mt-2 pl-4 border-l space-y-2"
             style={{ borderColor: COLORS.border }}>
          {comment.replies.map(r => (
            <CommentNode key={r.id} comment={r} depth={depth + 1} onViewProfile={onViewProfile} />
          ))}
        </div>
      )}
    </div>
  );
};

const CommentComposer = ({ onSubmit, currentUser }) => {
  const [body, setBody] = useState('');
  const canSubmit = body.trim().length > 0;

  const handleSubmit = () => {
    if (!canSubmit) return;
    onSubmit(body);
    setBody('');
  };

  return (
    <div data-comment-composer className="rounded-md border p-2"
         style={{ background: COLORS.bg, borderColor: COLORS.border }}>
      <textarea
        value={body}
        onChange={e => setBody(e.target.value.slice(0, 2000))}
        placeholder={`Comment as ${currentUser}...`}
        rows={2}
        className="w-full px-2 py-1.5 text-[12.5px] outline-none resize-none bg-transparent"
        style={{ color: COLORS.text }}
      />
      <div className="flex items-center justify-between mt-1">
        <span className="text-[9px]" style={{ color: COLORS.textMute }}>
          {body.length}/2000
        </span>
        <button
          onClick={handleSubmit}
          disabled={!canSubmit}
          className="px-3 py-1 rounded-md text-[11px] font-medium transition-opacity disabled:opacity-40"
          style={{ background: COLORS.mint, color: COLORS.bg }}
        >
          Comment
        </button>
      </div>
    </div>
  );
};


