/* ════════════════════════════════════════════════════════════════════════════
   OPTIONS ORDER MODAL — click a price in the chain to land here
   ════════════════════════════════════════════════════════════════════════════ */

// Ticket modal rendered when the user clicks a call/put price in the
// OptionsChain. Shows the contract specs and lets them pick number of
// contracts. Simplified buy-only flow; selling (writing) options is a
// much bigger complexity leap (margin requirements, early assignment)
// and is out of scope for this demo.
const OptionsOrderModal = ({ payload, account, onConfirm, onClose }) => {
  const { underlying, type, strike, expiryDays, premium, spot } = payload;
  const [contracts, setContracts] = useState(1);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState(null);
  const [done, setDone] = useState(false);

  // 100 shares per US-style contract; cost is straightforward.
  const totalCost = premium * contracts * 100;
  const balance = account?.balance ?? 0;
  const canAfford = totalCost <= balance;

  // Break-even at expiration: call profits when spot > strike + premium,
  // put profits when spot < strike - premium.
  const breakEven = type === 'call' ? strike + premium : strike - premium;
  const breakEvenMove = ((breakEven - spot) / spot) * 100;

  // Max loss on a long option is 100% of the premium paid (the option
  // expires worthless). Max gain is effectively uncapped for calls, and
  // (strike × 100 - premium × 100) × contracts for puts.
  const maxLoss = totalCost;
  const maxGain = type === 'call'
    ? '∞ (uncapped)'
    : `$${fmt((strike * 100 * contracts) - totalCost, 2)}`;

  const handleConfirm = async () => {
    if (!canAfford || submitting) return;
    setSubmitting(true);
    setError(null);
    await new Promise(r => setTimeout(r, 400)); // mock fill latency
    const result = onConfirm({ contracts });
    if (!result?.ok) {
      setError(result?.error || 'Trade failed');
      setSubmitting(false);
      return;
    }
    setDone(true);
    setSubmitting(false);
  };

  const typeColor = type === 'call' ? COLORS.green : COLORS.red;

  return (
    <>
      <div className="fixed inset-0 z-40" style={{ background: 'rgba(0,0,0,0.6)' }} onClick={onClose} />
      <div
        className="fixed left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 z-50 w-[460px] rounded-md border overflow-hidden"
        style={{ background: COLORS.surface, borderColor: COLORS.borderHi }}
      >
        {/* Header */}
        <div className="flex items-center justify-between p-4 border-b"
             style={{ borderColor: COLORS.border }}>
          <div>
            <div className="text-[15px] font-medium" style={{ color: COLORS.text }}>
              Option trade ticket
            </div>
            <div className="text-[11px]" style={{ color: COLORS.textMute }}>
              Buy to open · {underlying.id}
            </div>
          </div>
          <button onClick={onClose} className="p-1.5 rounded hover:bg-white/[0.05]">
            <X size={16} style={{ color: COLORS.textDim }} />
          </button>
        </div>

        {done ? (
          <div className="p-6 text-center">
            <div className="w-12 h-12 rounded-full flex items-center justify-center mx-auto mb-3"
                 style={{ background: 'rgba(31,178,107,0.1)' }}>
              <Check size={22} style={{ color: COLORS.green }} />
            </div>
            <div className="text-[15px] mb-1" style={{ color: COLORS.text }}>
              Order filled
            </div>
            <div className="text-[12px] mb-4" style={{ color: COLORS.textMute }}>
              {contracts} {underlying.id} {expiryDays}d {fmt(strike, underlying.dec)} {type.toUpperCase()} @ ${premium.toFixed(2)}
            </div>
            <button
              onClick={onClose}
              className="px-4 py-2 rounded-md text-[13px]"
              style={{ background: COLORS.mint, color: COLORS.bg }}
            >Done</button>
          </div>
        ) : (
          <div className="p-4 space-y-4">
            {/* Contract summary */}
            <div className="rounded-md border p-3 space-y-1.5"
                 style={{ background: COLORS.bg, borderColor: COLORS.border }}>
              <div className="flex items-center justify-between">
                <span className="text-[12px]" style={{ color: COLORS.textMute }}>Contract</span>
                <span className="text-[13px] tabular-nums" style={{ color: COLORS.text }}>
                  {underlying.id} {expiryDays}d{' '}
                  <span style={{ color: typeColor, fontWeight: 500 }}>
                    {fmt(strike, underlying.dec)} {type.toUpperCase()}
                  </span>
                </span>
              </div>
              <div className="flex items-center justify-between">
                <span className="text-[12px]" style={{ color: COLORS.textMute }}>Premium</span>
                <span className="text-[13px] tabular-nums" style={{ color: COLORS.text }}>
                  ${premium.toFixed(2)} × 100 shares
                </span>
              </div>
              <div className="flex items-center justify-between">
                <span className="text-[12px]" style={{ color: COLORS.textMute }}>Underlying spot</span>
                <span className="text-[13px] tabular-nums" style={{ color: COLORS.text }}>
                  {fmt(spot, underlying.dec)}
                </span>
              </div>
              <div className="flex items-center justify-between">
                <span className="text-[12px]" style={{ color: COLORS.textMute }}>Break-even at expiry</span>
                <span className="text-[13px] tabular-nums" style={{ color: COLORS.text }}>
                  {fmt(breakEven, underlying.dec)}
                  <span className="ml-1.5 text-[11px]" style={{ color: COLORS.textMute }}>
                    ({breakEvenMove >= 0 ? '+' : ''}{breakEvenMove.toFixed(1)}%)
                  </span>
                </span>
              </div>
            </div>

            {/* Size */}
            <div>
              <div className="flex items-center justify-between mb-1.5">
                <span className="text-[12px]" style={{ color: COLORS.textMute }}>Contracts</span>
                <span className="text-[11px] tabular-nums" style={{ color: COLORS.textMute }}>
                  1 contract = 100 shares
                </span>
              </div>
              <div className="flex items-center gap-2">
                <button
                  onClick={() => setContracts(n => Math.max(1, n - 1))}
                  className="w-8 h-8 rounded border flex items-center justify-center"
                  style={{ borderColor: COLORS.border, color: COLORS.text }}
                ><Minus size={14} /></button>
                <input
                  type="number"
                  min="1"
                  value={contracts}
                  onChange={e => {
                    const n = parseInt(e.target.value) || 1;
                    setContracts(Math.max(1, n));
                  }}
                  className="flex-1 px-3 py-1.5 rounded-md text-[14px] tabular-nums text-center outline-none"
                  style={{ background: COLORS.bg, color: COLORS.text, border: `1px solid ${COLORS.border}` }}
                />
                <button
                  onClick={() => setContracts(n => n + 1)}
                  className="w-8 h-8 rounded border flex items-center justify-center"
                  style={{ borderColor: COLORS.border, color: COLORS.text }}
                ><Plus size={14} /></button>
              </div>
            </div>

            {/* Cost summary */}
            <div className="rounded-md p-3 space-y-1.5"
                 style={{ background: 'rgba(61,123,255,0.06)', border: `1px solid ${canAfford ? COLORS.border : COLORS.red}` }}>
              <div className="flex items-center justify-between">
                <span className="text-[12px]" style={{ color: COLORS.textMute }}>Total cost</span>
                <span className="text-[16px] tabular-nums" style={{ color: COLORS.text }}>
                  ${fmt(totalCost, 2)}
                </span>
              </div>
              <div className="flex items-center justify-between">
                <span className="text-[11px]" style={{ color: COLORS.textMute }}>Available balance</span>
                <span className="text-[11px] tabular-nums"
                      style={{ color: canAfford ? COLORS.textDim : COLORS.red }}>
                  ${fmt(balance, 2)}
                </span>
              </div>
              <div className="flex items-center justify-between">
                <span className="text-[11px]" style={{ color: COLORS.textMute }}>Max loss · Max gain</span>
                <span className="text-[11px] tabular-nums" style={{ color: COLORS.textDim }}>
                  ${fmt(maxLoss, 2)} · {maxGain}
                </span>
              </div>
            </div>

            {error && (
              <div className="px-3 py-2 rounded-md text-[11px]"
                   style={{ background: 'rgba(237,112,136,0.08)', color: COLORS.red }}>
                {error}
              </div>
            )}

            {!canAfford && !error && (
              <div className="px-3 py-2 rounded-md text-[11px]"
                   style={{ background: 'rgba(237,112,136,0.08)', color: COLORS.red }}>
                Insufficient balance for this trade.
              </div>
            )}

            <button
              onClick={handleConfirm}
              disabled={!canAfford || submitting}
              className="w-full py-2.5 rounded-md text-[14px] font-medium transition-opacity disabled:opacity-40"
              style={{ background: typeColor, color: COLORS.bg }}
            >
              {submitting ? 'Submitting…' : `Buy ${contracts} contract${contracts === 1 ? '' : 's'}`}
            </button>

            <div className="text-[9px] text-center" style={{ color: COLORS.textMute }}>
              This is a simulated environment. Pricing uses Black-Scholes theoretical values.
            </div>
          </div>
        )}
      </div>
    </>
  );
};

