// Compact swap panel for the Deposit modal. Same logic as the standalone
// SwapPage but tighter layout suitable for the modal width.
const DepositSwapPanel = () => {
  const [tokenIn, setTokenIn]   = useState(SWAP_TOKENS.find(t => t.id === 'USDC'));
  const [tokenOut, setTokenOut] = useState(SWAP_TOKENS.find(t => t.id === 'ETH'));
  const [amountIn, setAmountIn] = useState('');
  const [slippage, setSlippage] = useState(0.5);
  const [pickerOpen, setPickerOpen] = useState(null);
  const [feedback, setFeedback] = useState(null);

  const numericIn = parseFloat(amountIn) || 0;
  const lpFee = lpFeeFor(tokenIn, tokenOut);
  const grossOut = numericIn * (tokenIn.priceUsd / tokenOut.priceUsd);
  const amountOut = grossOut * (1 - lpFee);
  const minReceived = amountOut * (1 - slippage / 100);

  const handleFlip = () => { setTokenIn(tokenOut); setTokenOut(tokenIn); setAmountIn(''); };
  const handleSwap = () => {
    if (!numericIn || numericIn <= 0) return setFeedback({ ok: false, msg: 'Enter an amount' });
    setFeedback({ ok: true, msg: `Swap submitted: ${numericIn} ${tokenIn.id} → ${amountOut.toFixed(6)} ${tokenOut.id}` });
    setAmountIn('');
    setTimeout(() => setFeedback(null), 4000);
  };

  return (
    <div className="space-y-3">
      {/* You pay */}
      <div className="rounded-md border p-3"
           style={{ background: COLORS.bg, borderColor: COLORS.border }}>
        <div className="text-[10px] uppercase tracking-wider mb-1.5" style={{ color: COLORS.textMute }}>
          You pay
        </div>
        <div className="flex items-center gap-2">
          <input type="text" value={amountIn}
                 onChange={e => setAmountIn(e.target.value.replace(/[^0-9.]/g, ''))}
                 placeholder="0"
                 className="flex-1 bg-transparent text-[22px] tabular-nums outline-none placeholder-white/15 min-w-0"
                 style={{ color: COLORS.text }} />
          <button onClick={() => setPickerOpen('in')}
                  className="flex items-center gap-2 px-2.5 py-1.5 rounded-full transition-colors hover:bg-white/[0.05] shrink-0"
                  style={{ background: COLORS.surface2 }}>
            <div className="w-5 h-5 rounded-full flex items-center justify-center text-[10px]"
                 style={{ background: COLORS.bg, color: COLORS.mint }}>
              {tokenIn.icon || tokenIn.id.slice(0, 1)}
            </div>
            <span className="text-[13px] font-medium" style={{ color: COLORS.text }}>{tokenIn.id}</span>
            <ChevronDown size={12} style={{ color: COLORS.textDim }} />
          </button>
        </div>
        <div className="text-[10px] mt-1 tabular-nums" style={{ color: COLORS.textMute }}>
          ≈ ${(numericIn * tokenIn.priceUsd).toLocaleString(undefined, { maximumFractionDigits: 2 })}
        </div>
      </div>

      {/* Flip */}
      <div className="flex justify-center -my-2 relative z-10">
        <button onClick={handleFlip}
                className="w-8 h-8 rounded-full flex items-center justify-center transition-all hover:rotate-180"
                style={{ background: COLORS.surface, border: `2px solid ${COLORS.bg}`, color: COLORS.textDim }}>
          <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor"
               strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <path d="M7 10l5 5 5-5" />
          </svg>
        </button>
      </div>

      {/* You receive */}
      <div className="rounded-md border p-3"
           style={{ background: COLORS.bg, borderColor: COLORS.border }}>
        <div className="text-[10px] uppercase tracking-wider mb-1.5" style={{ color: COLORS.textMute }}>
          You receive
        </div>
        <div className="flex items-center gap-2">
          <input type="text" value={numericIn > 0 ? amountOut.toFixed(6) : ''} readOnly placeholder="0"
                 className="flex-1 bg-transparent text-[22px] tabular-nums outline-none placeholder-white/15 min-w-0"
                 style={{ color: COLORS.text }} />
          <button onClick={() => setPickerOpen('out')}
                  className="flex items-center gap-2 px-2.5 py-1.5 rounded-full transition-colors hover:bg-white/[0.05] shrink-0"
                  style={{ background: COLORS.surface2 }}>
            <div className="w-5 h-5 rounded-full flex items-center justify-center text-[10px]"
                 style={{ background: COLORS.bg, color: COLORS.mint }}>
              {tokenOut.icon || tokenOut.id.slice(0, 1)}
            </div>
            <span className="text-[13px] font-medium" style={{ color: COLORS.text }}>{tokenOut.id}</span>
            <ChevronDown size={12} style={{ color: COLORS.textDim }} />
          </button>
        </div>
        <div className="text-[10px] mt-1 tabular-nums" style={{ color: COLORS.textMute }}>
          ≈ ${(amountOut * tokenOut.priceUsd).toLocaleString(undefined, { maximumFractionDigits: 2 })}
        </div>
      </div>

      {/* Slippage + summary */}
      <div className="flex items-center justify-between text-[11px]">
        <span style={{ color: COLORS.textMute }}>Slippage tolerance</span>
        <div className="flex items-center gap-1">
          {[0.1, 0.5, 1.0].map(s => (
            <button key={s} onClick={() => setSlippage(s)}
                    className="px-2 py-0.5 rounded text-[10px] tabular-nums"
                    style={{ background: slippage === s ? COLORS.mint : COLORS.bg,
                             color: slippage === s ? COLORS.bg : COLORS.textDim }}>
              {s}%
            </button>
          ))}
        </div>
      </div>

      {numericIn > 0 && (
        <div className="rounded-md px-3 py-2 space-y-1 text-[10.5px]"
             style={{ background: COLORS.bg, border: `1px solid ${COLORS.border}` }}>
          <SummaryRow label="Rate" value={`1 ${tokenIn.id} ≈ ${(tokenIn.priceUsd / tokenOut.priceUsd).toFixed(6)} ${tokenOut.id}`} />
          <SummaryRow label="Min received" value={`${minReceived.toFixed(6)} ${tokenOut.id}`} />
          <SummaryRow label="LP fee" value={`${(lpFee * 100).toFixed(2)}%`} />
          <SummaryRow label="Settlement" value="~4ms" mint />
        </div>
      )}

      {feedback && (
        <div className="px-3 py-2 rounded-md text-[11px]"
             style={{ background: feedback.ok ? 'rgba(31,178,107,0.1)' : 'rgba(237,112,136,0.1)',
                      color: feedback.ok ? COLORS.green : COLORS.red }}>
          {feedback.msg}
        </div>
      )}

      <button onClick={handleSwap}
              disabled={!numericIn || numericIn <= 0}
              className="w-full py-3 rounded-md text-[13px] font-medium transition-opacity disabled:opacity-40"
              style={{ background: COLORS.mint, color: COLORS.bg }}>
        {!numericIn || numericIn <= 0 ? 'Enter amount'
          : `Swap ${tokenIn.id} for ${tokenOut.id}`}
      </button>

      <SwapTokenSelector open={pickerOpen === 'in'} current={tokenIn} exclude={tokenOut}
                         onSelect={setTokenIn} onClose={() => setPickerOpen(null)} />
      <SwapTokenSelector open={pickerOpen === 'out'} current={tokenOut} exclude={tokenIn}
                         onSelect={setTokenOut} onClose={() => setPickerOpen(null)} />
    </div>
  );
};

// Digital wallet panel for the Deposit modal. Generates a deterministic 0x
// address from the user's desk ID so the same desk always sees the same
// address (consistent UX across sessions). Displays as a copyable address
// + on-chain QR code rendered as inline SVG.
const DigitalWalletPanel = ({ user, onCopy, copied, amount, setAmount }) => {
  const [tab, setTab] = useState('receive'); // 'receive' | 'send'

  // Generate a deterministic address from the desk ID. Real wallets would
  // derive a key pair via BIP32; we simulate with a stable hash.
  const walletAddress = useMemo(() => {
    const seed = (user?.desk ?? 'GUEST') + (user?.lei ?? '');
    let hash = 0;
    for (let i = 0; i < seed.length; i++) {
      hash = ((hash << 5) - hash + seed.charCodeAt(i)) | 0;
    }
    // Build a 40-char hex string by stretching the hash with simple LCG
    let s = '';
    let h = Math.abs(hash);
    for (let i = 0; i < 40; i++) {
      h = (h * 1103515245 + 12345) & 0x7fffffff;
      s += (h & 0xf).toString(16);
    }
    return '0x' + s;
  }, [user?.desk, user?.lei]);

  const shortAddr = `${walletAddress.slice(0, 8)}...${walletAddress.slice(-6)}`;

  // Build a simple QR-style SVG. This is NOT a real QR encoder — it renders
  // a deterministic-looking grid pattern from the address hash. For a real
  // wallet you'd use a library like qrcode-svg. The pattern still looks
  // legitimate enough for the demo and is fully self-contained (no deps).
  const qrCells = useMemo(() => {
    const size = 25;
    const cells = [];
    let h = 0;
    for (let i = 0; i < walletAddress.length; i++) {
      h = ((h << 5) - h + walletAddress.charCodeAt(i)) | 0;
    }
    for (let y = 0; y < size; y++) {
      for (let x = 0; x < size; x++) {
        // Three corners are finder patterns (always filled)
        const inFinderTL = x < 7 && y < 7;
        const inFinderTR = x >= size - 7 && y < 7;
        const inFinderBL = x < 7 && y >= size - 7;
        if (inFinderTL || inFinderTR || inFinderBL) {
          // Finder pattern: filled outer ring + inner block
          const isOuter = (
            (x === 0 || x === 6 || y === 0 || y === 6) ||
            (inFinderTR && (x === size - 7 || x === size - 1 || y === 0 || y === 6)) ||
            (inFinderBL && (x === 0 || x === 6 || y === size - 7 || y === size - 1))
          );
          const isInner = (
            (x >= 2 && x <= 4 && y >= 2 && y <= 4) ||
            (inFinderTR && x >= size - 5 && x <= size - 3 && y >= 2 && y <= 4) ||
            (inFinderBL && x >= 2 && x <= 4 && y >= size - 5 && y <= size - 3)
          );
          cells.push({ x, y, on: isOuter || isInner });
        } else {
          // Pseudo-random pattern from the address hash
          h = (h * 1103515245 + x * 7 + y * 13) & 0x7fffffff;
          cells.push({ x, y, on: (h & 0x3) === 0 || (h & 0xc) === 0 });
        }
      }
    }
    return cells;
  }, [walletAddress]);

  return (
    <div className="space-y-4">
      {/* Receive / Send segmented control */}
      <div className="flex gap-1 p-1 rounded-md" style={{ background: COLORS.bg }}>
        <button onClick={() => setTab('receive')}
                className="flex-1 py-1.5 text-[12px] rounded transition-all"
                style={{
                  color: tab === 'receive' ? COLORS.bg : COLORS.textDim,
                  background: tab === 'receive' ? COLORS.mint : 'transparent',
                }}>
          Receive
        </button>
        <button onClick={() => setTab('send')}
                className="flex-1 py-1.5 text-[12px] rounded transition-all"
                style={{
                  color: tab === 'send' ? COLORS.bg : COLORS.textDim,
                  background: tab === 'send' ? COLORS.mint : 'transparent',
                }}>
          Send
        </button>
      </div>

      {tab === 'receive' && (
        <>
          <div className="flex flex-col items-center gap-3 px-4 py-5 rounded-md"
               style={{ background: COLORS.bg, border: `1px solid ${COLORS.border}` }}>
            <div className="text-[10px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>
              Your deposit address (Onyx CH-0)
            </div>

            {/* QR code */}
            <div className="p-3 rounded-md" style={{ background: '#FFFFFF' }}>
              <svg width="160" height="160" viewBox="0 0 25 25" shapeRendering="crispEdges">
                {qrCells.map((c, i) => c.on && (
                  <rect key={i} x={c.x} y={c.y} width="1" height="1" fill="#000" />
                ))}
              </svg>
            </div>

            {/* Address */}
            <div className="w-full">
              <div className="flex items-center gap-2">
                <code className="flex-1 text-[10.5px] tabular-nums break-all px-2.5 py-2 rounded"
                      style={{ background: COLORS.surface2, color: COLORS.mint }}>
                  {walletAddress}
                </code>
                <button onClick={() => onCopy(walletAddress)}
                        className="px-3 py-2 rounded text-[11px] flex items-center gap-1.5 shrink-0 transition-colors"
                        style={{ background: copied ? 'rgba(31,178,107,0.15)' : COLORS.surface2,
                                 color: copied ? COLORS.green : COLORS.text }}>
                  {copied ? <Check size={11} /> : <Copy size={11} />}
                  {copied ? 'Copied' : 'Copy'}
                </button>
              </div>
            </div>
          </div>

          <LabeledField label="Amount to credit (USD)">
            <div className="flex items-center justify-between">
              <input type="text" value={amount} onChange={e => setAmount(e.target.value)}
                     placeholder="0.00"
                     className="flex-1 bg-transparent text-[18px] tabular-nums outline-none placeholder-white/20"
                     style={{ color: COLORS.text }} />
              <span className="text-[12px]" style={{ color: COLORS.textMute }}>USDC / ETH</span>
            </div>
          </LabeledField>

          <div className="flex items-center gap-1">
            {[100_000, 1_000_000, 10_000_000, 'Max'].map((p, i) => (
              <button key={i}
                      onClick={() => setAmount(p === 'Max' ? '50000000' : String(p))}
                      className="flex-1 py-1.5 text-[11px] rounded-md tabular-nums"
                      style={{ color: COLORS.textDim, background: COLORS.bg }}>
                {p === 'Max' ? 'Max' : fmtCompact(p)}
              </button>
            ))}
          </div>

          <div className="pt-3 border-t space-y-2" style={{ borderColor: COLORS.border }}>
            <SummaryRow label="Address" value={shortAddr} />
            <SummaryRow label="Network" value="Onyx CH-0 (Kadena)" />
            <SummaryRow label="Confirmations needed" value="1 (BFT finality)" mint />
            <SummaryRow label="Network fee" value="$0.00" />
          </div>

          <div className="text-[10px] leading-relaxed px-3 py-2.5 rounded-md"
               style={{ background: 'rgba(245,176,65,0.06)', border: `1px solid rgba(245,176,65,0.2)`, color: '#F5B041' }}>
            ⚠ Send only USDC or ETH on Onyx CH-0. Tokens sent on other networks will be lost.
          </div>
        </>
      )}

      {tab === 'send' && (
        <>
          <LabeledField label="Recipient address">
            <input type="text" placeholder="0x..."
                   className="w-full bg-transparent text-[12px] tabular-nums outline-none placeholder-white/20"
                   style={{ color: COLORS.text }} />
          </LabeledField>

          <LabeledField label="Amount (USD)">
            <input type="text" value={amount} onChange={e => setAmount(e.target.value)}
                   placeholder="0.00"
                   className="w-full bg-transparent text-[18px] tabular-nums outline-none placeholder-white/20"
                   style={{ color: COLORS.text }} />
          </LabeledField>

          <div className="pt-3 border-t space-y-2" style={{ borderColor: COLORS.border }}>
            <SummaryRow label="From" value={shortAddr} />
            <SummaryRow label="Network" value="Onyx CH-0" />
            <SummaryRow label="Network fee" value="$0.00" />
            <SummaryRow label="Estimated time" value="~4ms (BFT finality)" />
          </div>

          <div className="text-[10px] leading-relaxed px-3 py-2.5 rounded-md"
               style={{ background: COLORS.bg, border: `1px solid ${COLORS.border}`, color: COLORS.textMute }}>
            Sending withdraws funds from your Onyx account to the specified address. Verify the address carefully — transactions are final.
          </div>
        </>
      )}
    </div>
  );
};

// ─── EscrowSetup — group commitment pool with finalize date + threshold ──
//
// Modeled on the "USDC group commitment" flow from the reference image.
// User defines a target amount and finalize date; invites contributors;
// each contributor's pledge is held in escrow until either:
//   - The target is met before the finalize date → creator can close the
//     pool, funds disperse to the recipient.
//   - The finalize date passes without hitting target → all contributors
//     are refunded automatically.
//
// HONEST SCOPE: this is a UI/state mock — pledges are tracked in
// localStorage only, not on-chain. Wiring to a real Solana/EVM escrow
// contract would require:
//   1. A program/contract address (out of scope for this PR)
//   2. Wallet connection (already integrated for USDC method — reuse it)
//   3. RPC submission of pledge transactions on click
// Those are 1-2 days of integration work; the UI flow here is the part
// that needs design first, which is what this component delivers.
const EscrowSetup = ({ user, onCreate }) => {
  const [step, setStep] = useState('config'); // 'config' | 'invite' | 'review'
  const [purpose, setPurpose] = useState('');
  const [recipient, setRecipient] = useState('');
  const [targetAmount, setTargetAmount] = useState('');
  const [minContributors, setMinContributors] = useState(2);
  const [finalizeDate, setFinalizeDate] = useState(() => {
    // Default: 7 days from now
    const d = new Date();
    d.setDate(d.getDate() + 7);
    return d.toISOString().slice(0, 10);
  });
  const [invitees, setInvitees] = useState([]);
  const [inviteInput, setInviteInput] = useState('');
  const [myPledge, setMyPledge] = useState('');

  const targetNum = parseFloat(targetAmount) || 0;
  const myPledgeNum = parseFloat(myPledge) || 0;
  const daysUntilFinalize = Math.max(0, Math.ceil(
    (new Date(finalizeDate).getTime() - Date.now()) / (1000 * 60 * 60 * 24)
  ));

  const addInvitee = () => {
    const trimmed = inviteInput.trim();
    if (!trimmed) return;
    if (invitees.includes(trimmed)) {
      setInviteInput('');
      return;
    }
    setInvitees([...invitees, trimmed]);
    setInviteInput('');
  };

  const removeInvitee = (i) => setInvitees(invitees.filter((_, idx) => idx !== i));

  const create = () => {
    onCreate({
      id: `escrow_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
      creator: user?.username,
      purpose,
      recipient,
      targetAmount: targetNum,
      minContributors,
      finalizeDate,
      invitees,
      pledges: myPledgeNum > 0 ? [{
        contributor: user?.username,
        amount: myPledgeNum,
        ts: Date.now(),
      }] : [],
      status: 'open', // 'open' | 'funded' | 'refunded' | 'closed'
      createdAt: Date.now(),
    });
  };

  // Step 1 — pool configuration
  if (step === 'config') {
    return (
      <div className="space-y-4">
        <div className="px-4 py-3 rounded-md flex items-start gap-3"
             style={{ background: 'rgba(61,123,255,0.06)', border: `1px solid ${COLORS.mint}33` }}>
          <div className="text-[16px] mt-0.5" style={{ color: COLORS.mint }}>⊞</div>
          <div className="flex-1">
            <div className="text-[12.5px] font-medium mb-1" style={{ color: COLORS.text }}>
              Group escrow account
            </div>
            <div className="text-[10.5px] leading-relaxed" style={{ color: COLORS.textDim }}>
              Pool funds with friends or coworkers toward a shared goal.
              Funds are held in escrow until the target is met. If the
              finalize date passes without hitting target, every contributor
              gets refunded automatically.
            </div>
          </div>
        </div>

        <LabeledField label="What is this pool for?">
          <input value={purpose}
                 onChange={e => setPurpose(e.target.value)}
                 placeholder="e.g. Bachelor party fund, group lottery pool, surprise gift…"
                 className="w-full bg-transparent text-[13px] outline-none placeholder-white/20"
                 style={{ color: COLORS.text }} />
        </LabeledField>

        <LabeledField label="Recipient (who receives funds when met)">
          <input value={recipient}
                 onChange={e => setRecipient(e.target.value)}
                 placeholder="@username, email, or wallet address"
                 className="w-full bg-transparent text-[13px] outline-none placeholder-white/20"
                 style={{ color: COLORS.text }} />
        </LabeledField>

        <div className="grid grid-cols-2 gap-3">
          <LabeledField label="Target amount (USDC)">
            <div className="flex items-center justify-between">
              <input type="text" value={targetAmount}
                     onChange={e => setTargetAmount(e.target.value)}
                     placeholder="0.00"
                     className="flex-1 bg-transparent text-[16px] tabular-nums outline-none placeholder-white/20"
                     style={{ color: COLORS.text }} />
              <span className="text-[11px]" style={{ color: COLORS.textMute }}>USDC</span>
            </div>
          </LabeledField>

          <LabeledField label="Min contributors required">
            <input type="number" min="1" value={minContributors}
                   onChange={e => setMinContributors(Math.max(1, parseInt(e.target.value) || 1))}
                   className="w-full bg-transparent text-[16px] tabular-nums outline-none"
                   style={{ color: COLORS.text }} />
          </LabeledField>
        </div>

        <LabeledField label="Finalize date">
          <div className="flex items-center justify-between">
            <input type="date" value={finalizeDate}
                   onChange={e => setFinalizeDate(e.target.value)}
                   min={new Date().toISOString().slice(0, 10)}
                   className="flex-1 bg-transparent text-[13px] tabular-nums outline-none"
                   style={{ color: COLORS.text, colorScheme: 'dark' }} />
            <span className="text-[11px]" style={{ color: COLORS.textMute }}>
              {daysUntilFinalize}d from now
            </span>
          </div>
        </LabeledField>

        <button onClick={() => {
                  if (!purpose || !targetAmount || targetNum <= 0) return;
                  setStep('invite');
                }}
                disabled={!purpose || !targetAmount || targetNum <= 0}
                className="w-full mt-2 py-3 rounded-md text-[13px] font-medium transition-all disabled:opacity-30 disabled:cursor-not-allowed"
                style={{ color: '#FFFFFF', background: COLORS.mint }}>
          Continue → Invite people
        </button>
      </div>
    );
  }

  // Step 2 — invite contributors + initial pledge
  if (step === 'invite') {
    return (
      <div className="space-y-4">
        <div className="flex items-center gap-3">
          <button onClick={() => setStep('config')}
                  className="text-[11px]"
                  style={{ color: COLORS.textMute }}>← Back</button>
          <div className="text-[10.5px] uppercase tracking-wider"
               style={{ color: COLORS.mint, letterSpacing: '0.08em' }}>
            Step 2 of 3 · Invite
          </div>
        </div>

        <LabeledField label="Invite by username, email, or wallet">
          <div className="flex items-center gap-2">
            <input value={inviteInput}
                   onChange={e => setInviteInput(e.target.value)}
                   onKeyDown={e => { if (e.key === 'Enter') { e.preventDefault(); addInvitee(); } }}
                   placeholder="@username or email"
                   className="flex-1 bg-transparent text-[13px] outline-none placeholder-white/20"
                   style={{ color: COLORS.text }} />
            <button onClick={addInvitee}
                    className="px-3 py-1 rounded text-[11.5px]"
                    style={{ background: COLORS.surface2, color: COLORS.mint }}>
              + Add
            </button>
          </div>
        </LabeledField>

        {invitees.length > 0 && (
          <div className="px-4 py-3 rounded-md space-y-1.5"
               style={{ background: COLORS.bg, border: `1px solid ${COLORS.border}` }}>
            <div className="text-[10.5px] uppercase tracking-wider mb-1"
                 style={{ color: COLORS.textMute }}>
              {invitees.length} {invitees.length === 1 ? 'invitee' : 'invitees'}
            </div>
            {invitees.map((inv, i) => (
              <div key={i} className="flex items-center justify-between text-[12px]">
                <span style={{ color: COLORS.text }}>{inv}</span>
                <button onClick={() => removeInvitee(i)}
                        className="text-[16px] leading-none"
                        style={{ color: COLORS.textMute }}>×</button>
              </div>
            ))}
          </div>
        )}

        <LabeledField label="Your initial pledge (optional)">
          <div className="flex items-center justify-between">
            <input type="text" value={myPledge}
                   onChange={e => setMyPledge(e.target.value)}
                   placeholder="0.00"
                   className="flex-1 bg-transparent text-[16px] tabular-nums outline-none placeholder-white/20"
                   style={{ color: COLORS.text }} />
            <span className="text-[11px]" style={{ color: COLORS.textMute }}>USDC</span>
          </div>
        </LabeledField>

        <div className="grid grid-cols-2 gap-2">
          <button onClick={() => setStep('config')}
                  className="py-2.5 rounded-md text-[12.5px] transition-all hover:bg-white/[0.04]"
                  style={{ color: COLORS.textDim, background: COLORS.bg, border: `1px solid ${COLORS.border}` }}>
            Back
          </button>
          <button onClick={() => setStep('review')}
                  className="py-2.5 rounded-md text-[12.5px] font-medium transition-all"
                  style={{ color: '#FFFFFF', background: COLORS.mint }}>
            Continue → Review
          </button>
        </div>
      </div>
    );
  }

  // Step 3 — review + create
  return (
    <div className="space-y-3">
      <div className="flex items-center gap-3 mb-1">
        <button onClick={() => setStep('invite')}
                className="text-[11px]"
                style={{ color: COLORS.textMute }}>← Back</button>
        <div className="text-[10.5px] uppercase tracking-wider"
             style={{ color: COLORS.mint, letterSpacing: '0.08em' }}>
          Step 3 of 3 · Review
        </div>
      </div>

      <div className="px-5 py-4 rounded-md space-y-3"
           style={{ background: COLORS.bg, border: `1px solid ${COLORS.border}` }}>
        <div className="flex items-baseline justify-between">
          <span className="text-[10.5px] uppercase tracking-wider"
                style={{ color: COLORS.textMute }}>Target</span>
          <span className="text-[20px] font-medium tabular-nums"
                style={{ color: COLORS.text }}>
            ${targetNum.toLocaleString()}
            <span className="text-[11px] ml-1" style={{ color: COLORS.textMute }}>USDC</span>
          </span>
        </div>

        <div className="h-px" style={{ background: COLORS.border }} />

        <div className="space-y-1.5 text-[11.5px]">
          <div className="flex justify-between">
            <span style={{ color: COLORS.textMute }}>Purpose</span>
            <span style={{ color: COLORS.text, maxWidth: '60%' }} className="text-right truncate">{purpose}</span>
          </div>
          <div className="flex justify-between">
            <span style={{ color: COLORS.textMute }}>Recipient</span>
            <span style={{ color: COLORS.text, maxWidth: '60%' }} className="text-right truncate">
              {recipient || '— (set on creation)'}
            </span>
          </div>
          <div className="flex justify-between">
            <span style={{ color: COLORS.textMute }}>Min contributors</span>
            <span style={{ color: COLORS.text }}>{minContributors}</span>
          </div>
          <div className="flex justify-between">
            <span style={{ color: COLORS.textMute }}>Finalize on</span>
            <span style={{ color: COLORS.text }}>
              {new Date(finalizeDate).toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' })}
              <span className="ml-1" style={{ color: COLORS.textMute }}>({daysUntilFinalize}d)</span>
            </span>
          </div>
          <div className="flex justify-between">
            <span style={{ color: COLORS.textMute }}>Invitees</span>
            <span style={{ color: COLORS.text }}>{invitees.length}</span>
          </div>
          {myPledgeNum > 0 && (
            <div className="flex justify-between">
              <span style={{ color: COLORS.textMute }}>Your pledge</span>
              <span style={{ color: COLORS.green }}>${myPledgeNum.toLocaleString()}</span>
            </div>
          )}
        </div>
      </div>

      <div className="text-[10.5px] leading-relaxed px-1"
           style={{ color: COLORS.textMute }}>
        On creation, invitees will receive a link. Each contributor pledges
        their share into escrow. If target is hit by {new Date(finalizeDate).toLocaleDateString()},
        you can close the pool and disperse to {recipient || 'the recipient'}.
        Otherwise, all pledges refund automatically.
      </div>

      <button onClick={create}
              className="w-full py-3 rounded-md text-[13px] font-medium transition-all"
              style={{ color: '#FFFFFF', background: COLORS.mint }}>
        Create escrow pool
      </button>
    </div>
  );
};

const DepositModal = ({ onClose, user, onDeposit }) => {
  const [method, setMethod] = useState('jpmc');
  const [amount, setAmount] = useState('');
  const [copied, setCopied] = useState(false);
  const [done, setDone] = useState(false);

  const copy = (text) => {
    navigator.clipboard?.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleConfirm = () => {
    // Wire transfers are out-of-band — no instant credit
    if (method === 'wire') { setDone(true); return; }
    const n = parseFloat(amount);
    if (!isFinite(n) || n <= 0) return;
    // For wallet method, treat the same as jpmc — credits instantly to the
    // user's account ledger. Real implementation would observe the chain
    // for an incoming transfer to the user's deposit address.
    onDeposit?.(n, method);
    setDone(true);
  };

  return (
    <>
      <div className="fixed inset-0 z-40" style={{ background: 'rgba(0,0,0,0.55)', backdropFilter: 'blur(4px)' }} onClick={onClose} />
      <div
        className="fixed top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 z-50 w-[640px] max-h-[90vh] rounded-xl overflow-hidden flex flex-col"
        style={{
          // Stripe-style: layered gradient surface + soft outer glow
          background: `linear-gradient(180deg, ${COLORS.surface} 0%, ${COLORS.bg} 100%)`,
          border: `1px solid ${COLORS.borderHi}`,
          boxShadow: '0 30px 80px rgba(0,0,0,0.5), 0 0 0 1px rgba(255,255,255,0.04) inset',
        }}
      >
        {/* Stripe-style header — no harsh border, uses subtle gradient bg.
            Title is large and confident; subtitle gets quiet treatment. */}
        <div className="px-7 pt-6 pb-5"
             style={{ background: `linear-gradient(180deg, rgba(61,123,255,0.04) 0%, transparent 100%)` }}>
          <div className="flex items-start justify-between">
            <div>
              <div className="text-[10px] uppercase tracking-[1.5px] mb-1.5"
                   style={{ color: COLORS.mint, fontWeight: 600 }}>
                IMO Capital
              </div>
              <div className="text-[22px] font-medium leading-tight" style={{ color: COLORS.text, letterSpacing: '-0.01em' }}>
                Add funds to your account
              </div>
              <div className="text-[12px] mt-1.5 truncate" style={{ color: COLORS.textMute }}>
                {user ? `${user.desk} · LEI ${user.lei}` : 'Choose a method to credit your trading balance'}
              </div>
            </div>
            <button onClick={onClose}
                    className="w-8 h-8 rounded-md flex items-center justify-center transition-colors hover:bg-white/[0.05]"
                    style={{ color: COLORS.textDim }}>
              <X size={16} />
            </button>
          </div>
        </div>

        {done ? (
          <div className="px-6 py-10 text-center">
            <div className="w-12 h-12 mx-auto rounded-full flex items-center justify-center mb-4"
                 style={{ background: 'rgba(31,178,107,0.15)' }}>
              <Check size={24} style={{ color: COLORS.green }} />
            </div>
            <div className="text-[16px] mb-1" style={{ color: COLORS.text }}>
              {method === 'wire' ? 'Wire instructions sent'
              : method === 'escrow' ? 'Escrow pool created'
              : 'Deposit credited'}
            </div>
            <div className="text-[12px] max-w-sm mx-auto mb-5" style={{ color: COLORS.textDim }}>
              {method === 'jpmc' && `$${Number(amount).toLocaleString()} credited to your account. Available to trade now.`}
              {method === 'usdc' && `$${Number(amount).toLocaleString()} bridged from USDC and credited to your account.`}
              {method === 'wallet' && `$${Number(amount).toLocaleString()} received from your wallet. Funds available to trade now.`}
              {method === 'wire' && `Wire instructions have been emailed to your desk settlement contact. Funds will post after receipt (1 business day).`}
              {method === 'escrow' && `Your group pool is live. Invitees will receive a link to pledge. Pool refunds automatically if target isn't met by the finalize date.`}
            </div>
            <button onClick={onClose}
                    className="px-4 py-2 text-[13px] rounded-md"
                    style={{ background: COLORS.mint, color: COLORS.bg }}>
              Close
            </button>
          </div>
        ) : (
          <div className="p-6 overflow-y-auto">
            <div className="text-[10px] uppercase tracking-wider mb-2.5" style={{ color: COLORS.textMute }}>
              Choose deposit method
            </div>
            <div className="grid grid-cols-3 gap-2 mb-5">
              <DepositMethod id="jpmc"   label="JPM Coin"    sub="Instant · T+0"  active={method === 'jpmc'}   onClick={() => setMethod('jpmc')} />
              <DepositMethod id="usdc"   label="USDC bridge" sub="~5 min · Chain"  active={method === 'usdc'}   onClick={() => setMethod('usdc')} />
              <DepositMethod id="wallet" label="Wallet"      sub="0x address · QR" active={method === 'wallet'} onClick={() => setMethod('wallet')} />
              <DepositMethod id="swap"   label="Swap"        sub="Token to token" active={method === 'swap'}   onClick={() => setMethod('swap')} />
              <DepositMethod id="wire"   label="Wire"        sub="1 business day" active={method === 'wire'}   onClick={() => setMethod('wire')} />
              <DepositMethod id="escrow" label="Escrow"      sub="Group deposit"  active={method === 'escrow'} onClick={() => setMethod('escrow')} />
            </div>

            {method === 'jpmc' && (
              <>
                <LabeledField label="Amount (USD)">
                  <div className="flex items-center justify-between">
                    <input type="text" value={amount} onChange={e => setAmount(e.target.value)}
                           placeholder="0.00"
                           className="flex-1 bg-transparent text-[18px] tabular-nums outline-none placeholder-white/20"
                           style={{ color: COLORS.text }} />
                    <span className="text-[12px]" style={{ color: COLORS.textMute }}>JPMC</span>
                  </div>
                </LabeledField>

                <div className="flex items-center gap-1 mt-3">
                  {[100_000, 1_000_000, 10_000_000, 'Max'].map((p, i) => (
                    <button key={i}
                            onClick={() => setAmount(p === 'Max' ? '50000000' : String(p))}
                            className="flex-1 py-1.5 text-[11px] rounded-md tabular-nums"
                            style={{ color: COLORS.textDim, background: COLORS.bg }}>
                      {p === 'Max' ? 'Max' : fmtCompact(p)}
                    </button>
                  ))}
                </div>

                <div className="mt-5 pt-5 border-t space-y-2" style={{ borderColor: COLORS.border }}>
                  <SummaryRow label="Source wallet" value="JPM Coin Treasury · 0x4a2f…8b91" />
                  <SummaryRow label="Destination" value="ECM-147 · CH-0" mint />
                  <SummaryRow label="Network fee" value="$0.00" />
                  <SummaryRow label="Estimated time" value="~4ms (BFT finality)" />
                </div>
              </>
            )}

            {method === 'usdc' && (
              <>
                <LabeledField label="Amount (USDC)">
                  <input type="text" value={amount} onChange={e => setAmount(e.target.value)}
                         placeholder="0.00"
                         className="w-full bg-transparent text-[18px] tabular-nums outline-none placeholder-white/20"
                         style={{ color: COLORS.text }} />
                </LabeledField>

                <div className="mt-4 px-4 py-3 rounded-md"
                     style={{ background: COLORS.bg, border: `1px solid ${COLORS.border}` }}>
                  <div className="text-[11px] mb-2" style={{ color: COLORS.textMute }}>Bridge deposit address</div>
                  <div className="flex items-center justify-between gap-2">
                    <code className="text-[12px] tabular-nums" style={{ color: COLORS.mint }}>
                      0x4a2f8b91c3d7e5f60198a234567890abcdef1234
                    </code>
                    <button onClick={() => copy('0x4a2f8b91c3d7e5f60198a234567890abcdef1234')}
                            className="shrink-0 px-2 py-1 rounded text-[11px] flex items-center gap-1"
                            style={{ background: COLORS.surface2, color: COLORS.text }}>
                      {copied ? <Check size={11} /> : <Copy size={11} />}
                      {copied ? 'Copied' : 'Copy'}
                    </button>
                  </div>
                </div>

                <div className="mt-4 px-4 py-3 rounded-md border-l-2"
                     style={{ background: 'rgba(245,176,65,0.05)', borderColor: '#F5B041' }}>
                  <div className="text-[12px]" style={{ color: COLORS.text }}>
                    Send only USDC (Ethereum mainnet or Arbitrum) to this address. Funds auto-bridge to JPM Coin at 1:1 in ~5 minutes.
                  </div>
                </div>
              </>
            )}

            {method === 'wallet' && (
              <DigitalWalletPanel
                user={user}
                onCopy={copy}
                copied={copied}
                amount={amount}
                setAmount={setAmount}
              />
            )}

            {method === 'swap' && (
              <DepositSwapPanel account={{ balance: 0 }} />
            )}

            {method === 'escrow' && (
              <EscrowSetup user={user} onCreate={(payload) => {
                // Persist the new pool. Each pool is keyed by id and stored
                // under the creator's namespace so it survives reload.
                try {
                  const key = `imo_escrow_pools:${user?.username ?? 'anon'}`;
                  const existing = JSON.parse(localStorage.getItem(key) ?? '[]');
                  const next = [...existing, payload];
                  localStorage.setItem(key, JSON.stringify(next));
                } catch {}
                setDone(true);
              }} />
            )}

            {method === 'wire' && (
              <div className="space-y-3">
                <div className="px-4 py-3 rounded-md" style={{ background: COLORS.bg, border: `1px solid ${COLORS.border}` }}>
                  <div className="text-[11px] mb-1" style={{ color: COLORS.textMute }}>Beneficiary</div>
                  <div className="text-[13px]" style={{ color: COLORS.text }}>J.P. Morgan Chase Bank, N.A.</div>
                </div>
                <div className="grid grid-cols-2 gap-3">
                  <div className="px-4 py-3 rounded-md" style={{ background: COLORS.bg, border: `1px solid ${COLORS.border}` }}>
                    <div className="text-[11px] mb-1" style={{ color: COLORS.textMute }}>SWIFT</div>
                    <div className="text-[13px] tabular-nums" style={{ color: COLORS.text }}>CHASUS33</div>
                  </div>
                  <div className="px-4 py-3 rounded-md" style={{ background: COLORS.bg, border: `1px solid ${COLORS.border}` }}>
                    <div className="text-[11px] mb-1" style={{ color: COLORS.textMute }}>ABA / Routing</div>
                    <div className="text-[13px] tabular-nums" style={{ color: COLORS.text }}>021000021</div>
                  </div>
                </div>
                <div className="px-4 py-3 rounded-md" style={{ background: COLORS.bg, border: `1px solid ${COLORS.border}` }}>
                  <div className="text-[11px] mb-1" style={{ color: COLORS.textMute }}>Account · Reference</div>
                  <div className="flex items-center justify-between">
                    <div className="text-[13px] tabular-nums" style={{ color: COLORS.text }}>
                      4847-02910 · ONYX-ECM147
                    </div>
                    <button onClick={() => copy('4847-02910 · ONYX-ECM147')}
                            className="px-2 py-1 rounded text-[11px] flex items-center gap-1"
                            style={{ background: COLORS.surface2, color: COLORS.text }}>
                      {copied ? <Check size={11} /> : <Copy size={11} />}
                    </button>
                  </div>
                </div>
                <div className="text-[11px]" style={{ color: COLORS.textMute }}>
                  Funds will credit your Onyx account 1 business day after receipt. Include the reference exactly as shown.
                </div>
              </div>
            )}

            {method !== 'swap' && method !== 'escrow' && (
              <button
                onClick={handleConfirm}
                disabled={method !== 'wire' && !amount}
                className="w-full mt-5 py-3 rounded-md text-[13px] font-medium transition-all disabled:opacity-30 disabled:cursor-not-allowed"
                style={{ color: COLORS.bg, background: COLORS.mint }}
              >
                {method === 'jpmc'   ? 'Confirm deposit'
                : method === 'usdc'  ? 'I have sent the USDC'
                : method === 'wallet' ? 'Confirm wallet deposit'
                : 'Email wire instructions'}
              </button>
            )}
          </div>
        )}
      </div>
    </>
  );
};

