// Group the series for left-pane rendering.
const DBNOMICS_GROUPS = (() => {
  const map = new Map();
  for (const s of DBNOMICS_SERIES) {
    if (!map.has(s.group)) map.set(s.group, []);
    map.get(s.group).push(s);
  }
  return Array.from(map.entries()).map(([group, items]) => ({ group, items }));
})();

// Macro alerts storage key — list of { id, seriesId, op, threshold,
// label, lastTriggered }. Checked on each MacroPage mount: if any
// active alert's series has crossed its threshold relative to its
// previous-known state, fire a window event that spawns a toast.
// SPAs can't run a true cron, so this is "best-effort polling on
// page visit" rather than push notifications.
const MACRO_ALERTS_KEY = 'imo_macro_alerts';
const loadMacroAlerts = () => {
  try {
    const raw = localStorage.getItem(MACRO_ALERTS_KEY);
    return raw ? JSON.parse(raw) : [];
  } catch { return []; }
};
const saveMacroAlerts = (alerts) => {
  try { localStorage.setItem(MACRO_ALERTS_KEY, JSON.stringify(alerts)); } catch {}
  // Push the updated list to the service worker so it can poll
  // even when the tab is closed. Best-effort; fails silently if SW
  // isn't registered yet.
  try {
    if (typeof navigator !== 'undefined' && navigator.serviceWorker?.controller) {
      navigator.serviceWorker.controller.postMessage({
        type: 'imo:alerts-set',
        alerts,
      });
    }
  } catch {}
};

// Service worker registration — call once on app boot. Returns
// the registration so callers can request periodicsync. We don't
// register on browsers that don't support SWs (Safari iOS<16.4
// without permission, etc.) — degraded behavior is the previous
// "polling on revisit" path which still works.
const registerMacroAlertsSW = async () => {
  if (typeof navigator === 'undefined' || !navigator.serviceWorker) return null;
  try {
    const reg = await navigator.serviceWorker.register('/imo-macro-sw.js');
    // Push the latest alerts as soon as the controller is active
    const sendAlerts = () => {
      if (navigator.serviceWorker.controller) {
        navigator.serviceWorker.controller.postMessage({
          type: 'imo:alerts-set',
          alerts: loadMacroAlerts(),
        });
      }
    };
    if (navigator.serviceWorker.controller) sendAlerts();
    else navigator.serviceWorker.addEventListener('controllerchange', sendAlerts, { once: true });
    return reg;
  } catch (e) {
    console.warn('[macro-sw] register failed', e?.message);
    return null;
  }
};

// Request notification permission AND ask for periodic background
// sync (Chromium only). Returns 'granted' | 'denied' | 'unsupported'.
const enableMacroAlertNotifications = async () => {
  if (typeof Notification === 'undefined') return 'unsupported';
  let perm = Notification.permission;
  if (perm === 'default') {
    try { perm = await Notification.requestPermission(); } catch { perm = 'denied'; }
  }
  if (perm !== 'granted') return perm;
  // Try to register periodic background sync — Chromium-only, requires
  // site engagement. Failure is silent; the SW still polls on activate.
  try {
    const reg = await navigator.serviceWorker.ready;
    if ('periodicSync' in reg) {
      // Permission API check first — the periodic-background-sync
      // permission must be granted.
      const status = await navigator.permissions.query({ name: 'periodic-background-sync' });
      if (status.state === 'granted') {
        await reg.periodicSync.register('imo-macro-alerts', {
          minInterval: 60 * 60 * 1000, // 1 hour
        });
      }
    }
  } catch (e) {
    // Non-fatal — alerts still work via in-page polling
  }
  return 'granted';
};

// Phase 3o.95 (file split, batch 7): series math DSL evaluator extracted
// to src/lib/quant/series-math-dsl.js — computeMathSeries.

// ════════════════════════════════════════════════════════════════════
// CUSTOM ALERT BUILDER
// ════════════════════════════════════════════════════════════════════
//
// Users define alert conditions; the evaluator runs them every N
// minutes against the canonical instrument list. Alerts that fire
// log to a feed (in-page) and trigger a browser Notification when
// permission is granted.
//
// Alert shape:
//   {
//     id: string (uuid),
//     name: string (user-provided label),
//     symbol: string (uppercase ticker),
//     conditionType: 'price-above' | 'price-below' | 'price-cross-up' | 'price-cross-down'
//                  | 'percent-move' | 'volume-spike' | 'rsi-above' | 'rsi-below'
//                  | 'breakout-high' | 'breakdown-low' | 'macd-cross',
//     params: { ... } (condition-specific),
//     enabled: bool,
//     cooldownMinutes: int (suppress repeated fires),
//     createdAt: ms,
//     lastFiredAt: ms | null,
//     fireCount: int,
//   }
//
// Storage: localStorage key `imo_alerts` for the alert defs;
//          `imo_alert_history` for the rolling log of fires.
//
// Evaluation: a single setInterval polls Polygon for the latest bars
// of all unique alert symbols, then evaluates each enabled alert
// against the fresh data. A fired alert respects its own cooldown
// (default 60 min) so the user isn't spammed by chatter near a level.

const ALERTS_KEY = 'imo_alerts';
const ALERT_HISTORY_KEY = 'imo_alert_history';

// Hoisted helper — request browser notification permission. Idempotent;
// returns silently if already granted or denied. Used by Alerts, Scanner,
// and any other surface that wants to fire Notifications on events.
const requestNotifPermission = async () => {
  if (typeof Notification === 'undefined') return;
  if (Notification.permission === 'default') {
    try { await Notification.requestPermission(); } catch {}
  }
};

// Each condition type — its params schema + display label + evaluator.
const ALERT_CONDITIONS = [
  {
    id: 'price-above',
    label: 'Price crosses above level',
    paramFields: [{ id: 'level', label: 'Level ($)', kind: 'number' }],
    evaluate: (bars, params) => {
      if (bars.length < 2) return null;
      const cur = bars[bars.length - 1].close;
      const prev = bars[bars.length - 2].close;
      const lvl = Number(params.level);
      if (!Number.isFinite(lvl)) return null;
      if (prev < lvl && cur >= lvl) return `Price crossed above $${lvl.toFixed(2)} (now $${cur.toFixed(2)})`;
      return null;
    },
  },
  {
    id: 'price-below',
    label: 'Price crosses below level',
    paramFields: [{ id: 'level', label: 'Level ($)', kind: 'number' }],
    evaluate: (bars, params) => {
      if (bars.length < 2) return null;
      const cur = bars[bars.length - 1].close;
      const prev = bars[bars.length - 2].close;
      const lvl = Number(params.level);
      if (!Number.isFinite(lvl)) return null;
      if (prev > lvl && cur <= lvl) return `Price crossed below $${lvl.toFixed(2)} (now $${cur.toFixed(2)})`;
      return null;
    },
  },
  {
    id: 'percent-move',
    label: 'Percent move from N days ago',
    paramFields: [
      { id: 'pct',  label: '% threshold', kind: 'number' },
      { id: 'days', label: 'Days back',   kind: 'number' },
    ],
    evaluate: (bars, params) => {
      const days = Math.max(1, Math.floor(Number(params.days) || 1));
      const pct = Number(params.pct);
      if (!Number.isFinite(pct) || bars.length < days + 1) return null;
      const cur = bars[bars.length - 1].close;
      const past = bars[bars.length - 1 - days].close;
      const move = ((cur - past) / past) * 100;
      if (Math.abs(move) >= Math.abs(pct) && Math.sign(move) === Math.sign(pct)) {
        return `${days}-day move = ${move.toFixed(2)}% (threshold ${pct >= 0 ? '+' : ''}${pct}%)`;
      }
      return null;
    },
  },
  {
    id: 'volume-spike',
    label: 'Volume spike (Nx average)',
    paramFields: [
      { id: 'multiplier', label: 'Multiplier (e.g. 3 for 3×)', kind: 'number' },
    ],
    evaluate: (bars, params) => {
      const mul = Number(params.multiplier);
      if (!Number.isFinite(mul) || bars.length < 21) return null;
      const recent = bars[bars.length - 1].volume;
      const avg = bars.slice(-21, -1).reduce((s, b) => s + (b.volume || 0), 0) / 20;
      if (avg <= 0) return null;
      const ratio = recent / avg;
      if (ratio >= mul) return `Volume ${ratio.toFixed(1)}× the 20-day average (threshold ${mul}×)`;
      return null;
    },
  },
  {
    id: 'rsi-above',
    label: 'RSI above threshold',
    paramFields: [
      { id: 'threshold', label: 'Threshold (e.g. 70)', kind: 'number' },
      { id: 'period',    label: 'RSI period',           kind: 'number' },
    ],
    evaluate: (bars, params) => {
      const period = Math.floor(Number(params.period) || 14);
      const th = Number(params.threshold);
      if (!Number.isFinite(th) || bars.length < period + 1) return null;
      let gains = 0, losses = 0;
      for (let i = bars.length - period; i < bars.length; i++) {
        const diff = bars[i].close - bars[i - 1].close;
        if (diff > 0) gains += diff;
        else          losses -= diff;
      }
      const avgG = gains / period;
      const avgL = losses / period;
      if (avgL === 0) return null;
      const rsi = 100 - 100 / (1 + avgG / avgL);
      if (rsi >= th) return `RSI(${period}) = ${rsi.toFixed(1)} (above ${th})`;
      return null;
    },
  },
  {
    id: 'rsi-below',
    label: 'RSI below threshold',
    paramFields: [
      { id: 'threshold', label: 'Threshold (e.g. 30)', kind: 'number' },
      { id: 'period',    label: 'RSI period',           kind: 'number' },
    ],
    evaluate: (bars, params) => {
      const period = Math.floor(Number(params.period) || 14);
      const th = Number(params.threshold);
      if (!Number.isFinite(th) || bars.length < period + 1) return null;
      let gains = 0, losses = 0;
      for (let i = bars.length - period; i < bars.length; i++) {
        const diff = bars[i].close - bars[i - 1].close;
        if (diff > 0) gains += diff;
        else          losses -= diff;
      }
      const avgG = gains / period;
      const avgL = losses / period;
      if (avgL === 0) return null;
      const rsi = 100 - 100 / (1 + avgG / avgL);
      if (rsi <= th) return `RSI(${period}) = ${rsi.toFixed(1)} (below ${th})`;
      return null;
    },
  },
  {
    id: 'breakout-high',
    label: 'Breakout — N-day high',
    paramFields: [{ id: 'window', label: 'Window (days)', kind: 'number' }],
    evaluate: (bars, params) => {
      const w = Math.max(2, Math.floor(Number(params.window) || 20));
      if (bars.length < w + 1) return null;
      const cur = bars[bars.length - 1].close;
      const hi = Math.max(...bars.slice(-w - 1, -1).map(b => b.high));
      if (cur > hi) return `Closed above ${w}-day high $${hi.toFixed(2)} (now $${cur.toFixed(2)})`;
      return null;
    },
  },
  {
    id: 'breakdown-low',
    label: 'Breakdown — N-day low',
    paramFields: [{ id: 'window', label: 'Window (days)', kind: 'number' }],
    evaluate: (bars, params) => {
      const w = Math.max(2, Math.floor(Number(params.window) || 20));
      if (bars.length < w + 1) return null;
      const cur = bars[bars.length - 1].close;
      const lo = Math.min(...bars.slice(-w - 1, -1).map(b => b.low));
      if (cur < lo) return `Closed below ${w}-day low $${lo.toFixed(2)} (now $${cur.toFixed(2)})`;
      return null;
    },
  },
];

// AlertsPage — full CRUD over alerts + the live log of fires.
const AlertsPage = ({ account, setPage, setActive }) => {
  const [alerts, setAlerts] = useState(() => {
    try { return JSON.parse(localStorage.getItem(ALERTS_KEY) || '[]'); } catch { return []; }
  });
  const [history, setHistory] = useState(() => {
    try { return JSON.parse(localStorage.getItem(ALERT_HISTORY_KEY) || '[]'); } catch { return []; }
  });
  const [draftSymbol, setDraftSymbol] = useState('');
  const [draftName, setDraftName] = useState('');
  const [draftCondition, setDraftCondition] = useState('price-above');
  const [draftParams, setDraftParams] = useState({});
  const [draftCooldown, setDraftCooldown] = useState(60);
  const [evalStatus, setEvalStatus] = useState('idle'); // idle | running | error
  const [lastEvalAt, setLastEvalAt] = useState(null);

  // Browser notification permission state — surfaced as a status panel
  // so users can explicitly grant/test/diagnose notifications. The
  // permission state can be 'default' (never asked), 'granted',
  // 'denied', or 'unsupported' on browsers without Notification API.
  const [notifPerm, setNotifPerm] = useState(() => {
    if (typeof Notification === 'undefined') return 'unsupported';
    return Notification.permission || 'default';
  });
  // Re-poll permission state on focus/visibility change so we pick up
  // user-initiated changes via browser settings
  useEffect(() => {
    const update = () => {
      if (typeof Notification === 'undefined') {
        setNotifPerm('unsupported');
      } else {
        setNotifPerm(Notification.permission || 'default');
      }
    };
    document.addEventListener('visibilitychange', update);
    window.addEventListener('focus', update);
    return () => {
      document.removeEventListener('visibilitychange', update);
      window.removeEventListener('focus', update);
    };
  }, []);
  const requestNotif = useCallback(async () => {
    if (typeof Notification === 'undefined') return;
    try {
      const result = await Notification.requestPermission();
      setNotifPerm(result);
    } catch {
      setNotifPerm(Notification.permission || 'denied');
    }
  }, []);
  const testNotif = useCallback(() => {
    if (typeof Notification === 'undefined' || Notification.permission !== 'granted') return;
    try {
      const n = new Notification('Onyx Terminal · test notification', {
        body: 'Browser notifications are working. You\'ll see one of these whenever an alert fires.',
        tag: 'imo-test',
        icon: '/imo-icon.png',
      });
      // Auto-close test notif after 5s
      setTimeout(() => { try { n.close(); } catch {} }, 5000);
    } catch (e) {
      console.warn('[notif test]', e?.message);
    }
  }, []);

  // Persist
  useEffect(() => {
    try { localStorage.setItem(ALERTS_KEY, JSON.stringify(alerts)); } catch {}
  }, [alerts]);
  useEffect(() => {
    try { localStorage.setItem(ALERT_HISTORY_KEY, JSON.stringify(history.slice(0, 200))); } catch {}
  }, [history]);

  const addAlert = () => {
    if (!draftSymbol || !draftName) return;
    const sym = draftSymbol.toUpperCase().trim();
    if (!sym) return;
    const newAlert = {
      id: 'a_' + Math.random().toString(36).slice(2, 12),
      name: draftName.trim(),
      symbol: sym,
      conditionType: draftCondition,
      params: { ...draftParams },
      enabled: true,
      cooldownMinutes: Math.max(5, Math.floor(Number(draftCooldown) || 60)),
      createdAt: Date.now(),
      lastFiredAt: null,
      fireCount: 0,
    };
    setAlerts(prev => [...prev, newAlert]);
    setDraftName('');
    setDraftParams({});
  };

  const removeAlert = (id) => setAlerts(prev => prev.filter(a => a.id !== id));
  const toggleAlert = (id) => setAlerts(prev => prev.map(a =>
    a.id === id ? { ...a, enabled: !a.enabled } : a));
  const clearHistory = () => setHistory([]);

  // Evaluator — runs every 5 minutes when there are enabled alerts
  const evaluateAlerts = useCallback(async () => {
    const enabledAlerts = alerts.filter(a => a.enabled);
    if (enabledAlerts.length === 0) return;
    setEvalStatus('running');
    try {
      const symbols = Array.from(new Set(enabledAlerts.map(a => a.symbol)));
      const barsBySymbol = {};
      await Promise.all(symbols.map(async (sym) => {
        try {
          const data = await fetchPolygonAggs(sym, '3M', 'day', 1);
          if (data && data.length > 0) barsBySymbol[sym] = data;
        } catch {}
      }));
      const newHistory = [];
      const updatedAlerts = alerts.map(a => {
        if (!a.enabled) return a;
        const bars = barsBySymbol[a.symbol];
        if (!bars) return a;
        const cooldownMs = (a.cooldownMinutes || 60) * 60 * 1000;
        if (a.lastFiredAt && Date.now() - a.lastFiredAt < cooldownMs) return a;
        const cond = ALERT_CONDITIONS.find(c => c.id === a.conditionType);
        if (!cond) return a;
        try {
          const message = cond.evaluate(bars, a.params);
          if (message) {
            newHistory.push({
              id: 'h_' + Math.random().toString(36).slice(2, 12),
              alertId: a.id,
              alertName: a.name,
              symbol: a.symbol,
              conditionType: a.conditionType,
              message,
              firedAt: Date.now(),
            });
            // Browser notification
            if (typeof Notification !== 'undefined' && Notification.permission === 'granted') {
              try {
                new Notification(`[${a.symbol}] ${a.name}`, { body: message, tag: a.id });
              } catch {}
            }
            return { ...a, lastFiredAt: Date.now(), fireCount: (a.fireCount || 0) + 1 };
          }
        } catch (e) {
          console.warn('[AlertsPage.evaluate]', a.symbol, e?.message);
        }
        return a;
      });
      if (newHistory.length > 0) {
        setHistory(prev => [...newHistory, ...prev].slice(0, 200));
        setAlerts(updatedAlerts);
      }
      setLastEvalAt(Date.now());
      setEvalStatus('idle');
    } catch (e) {
      setEvalStatus('error');
    }
  }, [alerts]);

  // Background evaluator — every 5 min while page is mounted
  useEffect(() => {
    if (alerts.filter(a => a.enabled).length === 0) return undefined;
    const interval = setInterval(evaluateAlerts, 5 * 60 * 1000);
    // Also fire one immediately
    evaluateAlerts();
    return () => clearInterval(interval);
  }, [alerts, evaluateAlerts]);

  // Server-side sync: push the watchlist of alert symbols to the
  // scanner service so alerts evaluate 24/7 even when this page is
  // closed. Only price/RSI/breakout-style alerts map cleanly to the
  // scanner's SETUP_RULES (e.g. breakout-high → bull-breakout).
  // Custom-only conditions like volume-spike with custom multiplier
  // stay client-side.
  const SCANNER_BASE = import.meta.env.VITE_SCANNER_API_URL || '';
  const SCANNER_TOKEN = import.meta.env.VITE_BACKEND_AUTH_TOKEN || '';
  const [serverSyncStatus, setServerSyncStatus] = useState('idle'); // idle | syncing | ok | error
  const serverUserId = useMemo(() => {
    try {
      let id = localStorage.getItem('imo_scanner_user_id');
      if (!id) {
        id = 'sp_' + Math.random().toString(36).slice(2, 12);
        localStorage.setItem('imo_scanner_user_id', id);
      }
      return id;
    } catch { return 'anonymous'; }
  }, []);
  // Map our alert condition types to SETUP_RULES IDs (for the subset
  // that the scanner can handle natively). Conditions not in this
  // map stay client-side.
  const ALERT_TO_SETUP_RULE = {
    'breakout-high':  'bull-breakout',
    'breakdown-low':  'bear-breakdown',
    'rsi-below':      'oversold-bounce',
    'rsi-above':      'overbought-fade',
    'volume-spike':   'volume-thrust',
  };
  const syncToServer = useCallback(async () => {
    if (!SCANNER_BASE) {
      setServerSyncStatus('error');
      return;
    }
    setServerSyncStatus('syncing');
    try {
      const enabled = alerts.filter(a => a.enabled);
      const tickers = Array.from(new Set(enabled.map(a => a.symbol)));
      const rules = Array.from(new Set(
        enabled.map(a => ALERT_TO_SETUP_RULE[a.conditionType]).filter(Boolean)
      ));
      const muted = []; // could derive from disabled ticker:rule combinations later
      const headers = { 'Content-Type': 'application/json' };
      if (SCANNER_TOKEN) headers.Authorization = `Bearer ${SCANNER_TOKEN}`;
      const response = await fetch(
        `${SCANNER_BASE.replace(/\/$/, '')}/watchlist/${encodeURIComponent(serverUserId)}`,
        {
          method: 'POST',
          headers,
          body: JSON.stringify({
            tickers,
            rules: rules.length > 0 ? rules : ['bull-breakout', 'bear-breakdown', 'oversold-bounce'],
            scan_every_minutes: 15,
            alert_threshold_score: 60,
            muted,
          }),
        }
      );
      if (!response.ok) throw new Error(`HTTP ${response.status}`);
      setServerSyncStatus('ok');
      setTimeout(() => setServerSyncStatus('idle'), 3000);
    } catch (e) {
      setServerSyncStatus('error');
      setTimeout(() => setServerSyncStatus('idle'), 4000);
    }
  }, [alerts, SCANNER_BASE, SCANNER_TOKEN, serverUserId]);

  const conditionDef = ALERT_CONDITIONS.find(c => c.id === draftCondition);
  const conditionLabel = (id) => ALERT_CONDITIONS.find(c => c.id === id)?.label || id;
  const enabledCount = alerts.filter(a => a.enabled).length;

  return (
    <div className="flex-1 min-h-0 overflow-auto">
      <div className="max-w-[1400px] mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="mb-6">
          <h1 className="text-[22px] font-medium" style={{ color: COLORS.text }}>Custom Alerts</h1>
          <p className="text-[12px] mt-1" style={{ color: COLORS.textMute }}>
            Define alert conditions; evaluator runs every 5 minutes and fires browser notifications when conditions are met.
            {' '}{enabledCount} of {alerts.length} alert{alerts.length === 1 ? '' : 's'} active.
            {lastEvalAt && (
              <span className="ml-2">
                Last evaluated: {new Date(lastEvalAt).toLocaleTimeString()}
                {evalStatus === 'running' && ' · running…'}
                {evalStatus === 'error' && ' · error'}
              </span>
            )}
          </p>
        </div>

        {/* Browser notification permission status — explicit panel so
            users can grant/diagnose/test. Without permission, alerts
            fire only via the in-app history log + sound (if any). */}
        <div className="rounded-md border p-3 mb-4"
             style={{
               borderColor: notifPerm === 'granted' ? `${COLORS.green}55`
                          : notifPerm === 'denied' ? `${COLORS.red}55`
                          : COLORS.border,
               background: notifPerm === 'granted' ? `${COLORS.green}08`
                         : notifPerm === 'denied' ? `${COLORS.red}08`
                         : COLORS.surface,
             }}>
          <div className="flex items-center justify-between flex-wrap gap-2">
            <div className="flex items-center gap-3">
              <Bell size={16}
                    style={{
                      color: notifPerm === 'granted' ? COLORS.green
                           : notifPerm === 'denied' ? COLORS.red
                           : notifPerm === 'unsupported' ? COLORS.textMute
                           : '#FFB84D',
                    }} />
              <div>
                <div className="text-[12px]" style={{ color: COLORS.text }}>
                  Browser notifications · {
                    notifPerm === 'granted'    ? <span style={{ color: COLORS.green }}>enabled</span>
                  : notifPerm === 'denied'     ? <span style={{ color: COLORS.red }}>blocked</span>
                  : notifPerm === 'unsupported'? <span style={{ color: COLORS.textMute }}>unsupported</span>
                  :                              <span style={{ color: '#FFB84D' }}>not requested yet</span>
                  }
                </div>
                <div className="text-[10.5px]" style={{ color: COLORS.textMute }}>
                  {notifPerm === 'granted'    && 'Alert fires + scanner hits + Form 4 detections will appear as system notifications even when this tab is in the background.'}
                  {notifPerm === 'denied'     && 'You\'ve blocked notifications for this site. To re-enable: click the lock/info icon in your browser address bar → Site settings → Notifications → Allow.'}
                  {notifPerm === 'default'    && 'Click "Enable" to allow Onyx to fire system notifications when alerts trigger. Notifications appear even when this tab is backgrounded.'}
                  {notifPerm === 'unsupported'&& 'Your browser doesn\'t support the Notification API. In-app history log + console events still work.'}
                </div>
              </div>
            </div>
            <div className="flex items-center gap-2">
              {notifPerm === 'default' && (
                <button type="button" onClick={requestNotif}
                        className="px-3 py-1.5 rounded text-[11.5px] font-medium hover:opacity-90"
                        style={{ background: COLORS.mint, color: COLORS.bg }}>
                  Enable notifications
                </button>
              )}
              {notifPerm === 'granted' && (
                <button type="button" onClick={testNotif}
                        className="px-3 py-1.5 rounded text-[11.5px] hover:opacity-90"
                        style={{ background: COLORS.bg, color: COLORS.green, border: `1px solid ${COLORS.green}55` }}>
                  Send test
                </button>
              )}
            </div>
          </div>
        </div>

        {/* Server-side sync — push the symbols to the scanner service
            so alerts evaluate 24/7 even when this page is closed.
            Only conditions that map to SETUP_RULES are evaluated by
            the scanner. */}
        {SCANNER_BASE && enabledCount > 0 && (
          <div className="rounded-md border p-3 mb-6"
               style={{ borderColor: COLORS.border, background: COLORS.surface }}>
            <div className="flex items-center justify-between flex-wrap gap-2">
              <div>
                <div className="text-[12px]" style={{ color: COLORS.text }}>
                  24/7 server-side evaluation
                </div>
                <div className="text-[10.5px]" style={{ color: COLORS.textMute }}>
                  Sync your watchlist to the backend scanner so alerts fire even with this page closed.
                  Only conditions that map to SETUP_RULES (breakouts, RSI extremes, volume spikes) are evaluated server-side; others stay client-side.
                </div>
              </div>
              <button type="button"
                      onClick={syncToServer}
                      disabled={serverSyncStatus === 'syncing'}
                      className="px-3 py-1.5 rounded text-[11.5px] inline-flex items-center gap-1.5 hover:opacity-90 disabled:opacity-40"
                      style={{
                        background: serverSyncStatus === 'ok' ? COLORS.green
                                  : serverSyncStatus === 'error' ? COLORS.red
                                  : `${COLORS.mint}1A`,
                        color: serverSyncStatus === 'ok' || serverSyncStatus === 'error' ? COLORS.bg : COLORS.mint,
                        border: `1px solid ${serverSyncStatus === 'error' ? COLORS.red : COLORS.mint}`,
                      }}>
                {serverSyncStatus === 'syncing'
                  ? <RefreshCw size={11} className="animate-spin" />
                  : <Send size={11} />}
                {serverSyncStatus === 'ok' ? 'Synced ✓'
                  : serverSyncStatus === 'error' ? 'Failed'
                  : serverSyncStatus === 'syncing' ? 'Syncing…'
                  :                                  'Sync to server'}
              </button>
            </div>
          </div>
        )}

        {/* Builder card */}
        <div className="rounded-md border p-4 mb-6"
             style={{ borderColor: COLORS.border, background: COLORS.surface }}>
          <div className="text-[10px] uppercase tracking-wider mb-3" style={{ color: COLORS.textMute }}>
            Create new alert
          </div>
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-3">
            <div>
              <div className="text-[9.5px] uppercase tracking-wider mb-1" style={{ color: COLORS.textMute }}>Symbol</div>
              <input type="text" value={draftSymbol}
                     onChange={(e) => setDraftSymbol(e.target.value.toUpperCase())}
                     placeholder="AAPL"
                     className="w-full px-2 py-1.5 rounded text-[11.5px] outline-none uppercase"
                     style={{ background: COLORS.bg, color: COLORS.text, border: `1px solid ${COLORS.border}` }} />
            </div>
            <div>
              <div className="text-[9.5px] uppercase tracking-wider mb-1" style={{ color: COLORS.textMute }}>Alert name</div>
              <input type="text" value={draftName}
                     onChange={(e) => setDraftName(e.target.value)}
                     placeholder="AAPL above 200"
                     className="w-full px-2 py-1.5 rounded text-[11.5px] outline-none"
                     style={{ background: COLORS.bg, color: COLORS.text, border: `1px solid ${COLORS.border}` }} />
            </div>
            <div>
              <div className="text-[9.5px] uppercase tracking-wider mb-1" style={{ color: COLORS.textMute }}>Condition</div>
              <select value={draftCondition}
                      onChange={(e) => { setDraftCondition(e.target.value); setDraftParams({}); }}
                      className="w-full px-2 py-1.5 rounded text-[11.5px] outline-none"
                      style={{ background: COLORS.bg, color: COLORS.text, border: `1px solid ${COLORS.border}`, colorScheme: 'dark' }}>
                {ALERT_CONDITIONS.map(c => (
                  <option key={c.id} value={c.id}>{c.label}</option>
                ))}
              </select>
            </div>
            <div>
              <div className="text-[9.5px] uppercase tracking-wider mb-1" style={{ color: COLORS.textMute }}>Cooldown (min)</div>
              <input type="number" value={draftCooldown} min="5" step="5"
                     onChange={(e) => setDraftCooldown(Math.max(5, Number(e.target.value) || 60))}
                     className="w-full px-2 py-1.5 rounded text-[11.5px] outline-none tabular-nums"
                     style={{ background: COLORS.bg, color: COLORS.text, border: `1px solid ${COLORS.border}` }} />
            </div>
          </div>

          {/* Condition-specific params */}
          {conditionDef && conditionDef.paramFields.length > 0 && (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-3 mt-3">
              {conditionDef.paramFields.map(f => (
                <div key={f.id}>
                  <div className="text-[9.5px] uppercase tracking-wider mb-1" style={{ color: COLORS.textMute }}>{f.label}</div>
                  <input type={f.kind === 'number' ? 'number' : 'text'}
                         value={draftParams[f.id] ?? ''}
                         onChange={(e) => setDraftParams(p => ({ ...p, [f.id]: e.target.value }))}
                         className="w-full px-2 py-1.5 rounded text-[11.5px] outline-none tabular-nums"
                         style={{ background: COLORS.bg, color: COLORS.text, border: `1px solid ${COLORS.border}` }} />
                </div>
              ))}
            </div>
          )}

          <div className="mt-3 flex items-center gap-2">
            <button type="button"
                    onClick={async () => {
                      await requestNotifPermission();
                      addAlert();
                    }}
                    disabled={!draftSymbol || !draftName}
                    className="px-3 py-1.5 rounded text-[11.5px] font-medium inline-flex items-center gap-1.5 hover:opacity-90 disabled:opacity-40"
                    style={{ background: COLORS.mint, color: COLORS.bg }}>
              <Plus size={11} />
              Add alert
            </button>
            <button type="button"
                    onClick={evaluateAlerts}
                    disabled={enabledCount === 0 || evalStatus === 'running'}
                    className="px-3 py-1.5 rounded text-[11.5px] inline-flex items-center gap-1.5 hover:bg-white/[0.04] disabled:opacity-40"
                    style={{ color: COLORS.textDim, border: `1px solid ${COLORS.border}` }}>
              <RefreshCw size={11} className={evalStatus === 'running' ? 'animate-spin' : ''} />
              Evaluate now
            </button>
          </div>
        </div>

        {/* Active alerts */}
        <div className="rounded-md border mb-6"
             style={{ borderColor: COLORS.border, background: COLORS.surface }}>
          <div className="px-3 py-2 border-b text-[10px] uppercase tracking-wider"
               style={{ borderColor: COLORS.border, color: COLORS.textMute }}>
            Active alerts ({alerts.length})
          </div>
          {alerts.length === 0 ? (
            <div className="p-6 text-center">
              <Bell size={28} style={{ color: COLORS.textMute, margin: '0 auto 12px' }} />
              <div className="text-[12px]" style={{ color: COLORS.text }}>No alerts configured</div>
              <div className="text-[10.5px] mt-1" style={{ color: COLORS.textMute }}>Create one above to start monitoring.</div>
            </div>
          ) : (
            <div>
              {alerts.map(a => (
                <div key={a.id}
                     className="px-3 py-2 flex items-center gap-3 border-b last:border-b-0"
                     style={{ borderColor: COLORS.border, opacity: a.enabled ? 1 : 0.55 }}>
                  <button type="button"
                          onClick={() => toggleAlert(a.id)}
                          className="shrink-0 w-7 h-4 rounded-full relative transition-colors"
                          style={{ background: a.enabled ? COLORS.mint : COLORS.border }}>
                    <span className="absolute top-0.5 w-3 h-3 rounded-full bg-white transition-all"
                          style={{ left: a.enabled ? '14px' : '2px' }} />
                  </button>
                  <div className="flex-1 min-w-0">
                    <div className="text-[12px] flex items-baseline gap-2 flex-wrap">
                      <span className="font-medium" style={{ color: COLORS.text }}>{a.name}</span>
                      <button type="button"
                              onClick={() => {
                                const inst = INSTRUMENTS.find(i => i.id?.startsWith(a.symbol + '-') || i.id === a.symbol || i.symbol === a.symbol);
                                if (inst && setActive) setActive(inst);
                                if (setPage) setPage('trade');
                              }}
                              className="text-[10.5px] hover:underline"
                              style={{ color: COLORS.mint }}>
                        {a.symbol}
                      </button>
                    </div>
                    <div className="text-[10.5px]" style={{ color: COLORS.textMute }}>
                      {conditionLabel(a.conditionType)} · {Object.entries(a.params || {}).map(([k, v]) => `${k}=${v}`).join(', ')}
                      {' · cooldown '}{a.cooldownMinutes}m
                      {a.fireCount > 0 && (
                        <span className="ml-2">· fired {a.fireCount}× last {new Date(a.lastFiredAt).toLocaleString()}</span>
                      )}
                    </div>
                  </div>
                  <button type="button"
                          onClick={() => removeAlert(a.id)}
                          className="shrink-0 p-1 rounded hover:bg-white/[0.04]"
                          title="Delete alert"
                          style={{ color: COLORS.textMute }}>
                    <Trash2 size={11} />
                  </button>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Recent fires */}
        <div className="rounded-md border"
             style={{ borderColor: COLORS.border, background: COLORS.surface }}>
          <div className="px-3 py-2 border-b flex items-center justify-between"
               style={{ borderColor: COLORS.border }}>
            <span className="text-[10px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>
              Alert log ({history.length})
            </span>
            {history.length > 0 && (
              <button type="button"
                      onClick={clearHistory}
                      className="text-[10px] hover:underline"
                      style={{ color: COLORS.textMute }}>
                Clear
              </button>
            )}
          </div>
          {history.length === 0 ? (
            <div className="p-6 text-center text-[11px]" style={{ color: COLORS.textMute }}>
              No alerts have fired yet. Active alerts evaluate every 5 minutes.
            </div>
          ) : (
            <div>
              {history.slice(0, 50).map(h => (
                <div key={h.id}
                     className="px-3 py-2 border-b last:border-b-0"
                     style={{ borderColor: COLORS.border }}>
                  <div className="flex items-baseline justify-between flex-wrap gap-1">
                    <div className="text-[11.5px]">
                      <span style={{ color: COLORS.text, fontWeight: 500 }}>{h.symbol}</span>
                      <span className="ml-2" style={{ color: COLORS.textDim }}>{h.alertName}</span>
                    </div>
                    <div className="text-[10px] tabular-nums" style={{ color: COLORS.textMute }}>
                      {new Date(h.firedAt).toLocaleString()}
                    </div>
                  </div>
                  <div className="text-[10.5px] mt-0.5" style={{ color: COLORS.textDim }}>
                    {h.message}
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

// ════════════════════════════════════════════════════════════════════
// STRATEGIES PAGE
// ════════════════════════════════════════════════════════════════════
//
// Hub for portfolio-construction + discovery tools that don't fit
// neatly under Risk, Trade, or Quant Lab. Three sub-tabs:
//
//   1. Black-Litterman optimizer — combine market equilibrium + views
//      to produce optimal weights
//   2. Pairs trading screener — find cointegrated pairs from a
//      configurable universe
//   3. Sector rotation — momentum-based ranking of SPDR sector ETFs
//   4. Smart money — curated 13F holdings for major hedge funds
//
// Each tab renders independently. Data fetching is on-demand to keep
// initial page load fast.


// StrategiesPage
const StrategiesPage = ({ account, portfolioSource, setPage, setActive }) => {
  const [tab, setTab] = useState('blacklitterman'); // blacklitterman | pairs | rotation | smartmoney

  return (
    <div className="flex-1 min-h-0 overflow-auto">
      <div className="max-w-[1400px] mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="mb-6">
          <h1 className="text-[22px] font-medium" style={{ color: COLORS.text }}>Strategies</h1>
          <p className="text-[12px] mt-1" style={{ color: COLORS.textMute }}>
            Portfolio construction + discovery tools. Black-Litterman optimizer for view-aware allocation,
            pairs screener for cointegrated stat-arb candidates, sector rotation for momentum-based
            tilting, and curated 13F holdings for institutional flow tracking.
          </p>
        </div>

        {/* Sub-tabs */}
        <div role="tablist" aria-label="Strategies sections"
             className="flex items-center gap-1 mb-4 border-b" style={{ borderColor: COLORS.border }}>
          {[
            { id: 'blacklitterman', label: 'Black-Litterman' },
            { id: 'riskparity',     label: 'Risk Parity' },
            { id: 'pairs',          label: 'Pairs screener' },
            { id: 'rotation',       label: 'Sector rotation' },
            { id: 'smartmoney',     label: 'Smart money (13F)' },
            { id: 'insiders',       label: 'Insider trades' },
            { id: 'shorts',         label: 'Short interest' },
            { id: 'fundamentals',   label: 'Fundamentals' },
            { id: 'analysts',       label: 'Analyst ratings' },
            { id: 'aiconsensus',    label: 'AI vs Street' },
            { id: 'multistrat',     label: 'Multi-strategy backtest' },
          ].map(t => (
            <button key={t.id} type="button"
                    role="tab"
                    aria-selected={tab === t.id}
                    aria-controls={`strategies-panel-${t.id}`}
                    id={`strategies-tab-${t.id}`}
                    tabIndex={tab === t.id ? 0 : -1}
                    onClick={() => setTab(t.id)}
                    className="px-3 py-2 text-[12px] transition-colors relative focus:outline-none focus:ring-1 focus:ring-inset rounded-sm"
                    style={{ color: tab === t.id ? COLORS.text : COLORS.textDim }}>
              {t.label}
              {tab === t.id && (
                <span className="absolute bottom-0 left-0 right-0 h-0.5" style={{ background: COLORS.mint }} />
              )}
            </button>
          ))}
        </div>

        {tab === 'blacklitterman' && <BlackLittermanTab account={account} portfolioSource={portfolioSource} />}
        {tab === 'riskparity'     && <RiskParityTab account={account} portfolioSource={portfolioSource} />}
        {tab === 'pairs'          && <PairsScreenerTab setActive={setActive} setPage={setPage} />}
        {tab === 'rotation'       && <SectorRotationTab setActive={setActive} setPage={setPage} />}
        {tab === 'smartmoney'     && <SmartMoneyTab setActive={setActive} setPage={setPage} />}
        {tab === 'insiders'       && <InsiderTradesTab setActive={setActive} setPage={setPage} />}
        {tab === 'shorts'         && <ShortInterestTab setActive={setActive} setPage={setPage} />}
        {tab === 'fundamentals'   && <FundamentalsTab setActive={setActive} setPage={setPage} />}
        {tab === 'analysts'       && <AnalystRatingsTab setActive={setActive} setPage={setPage} />}
        {tab === 'aiconsensus'    && <AIvsAnalystConsensusTab setActive={setActive} setPage={setPage} />}
        {tab === 'multistrat'     && <MultiStrategyBacktestTab account={account} portfolioSource={portfolioSource} setActive={setActive} setPage={setPage} />}
      </div>
    </div>
  );
};

// BlackLittermanTab — runs BL on the user's current holdings + their views
// RiskParityTab — equal-risk-contribution allocation
// ShortInterestTab — curated short interest data with squeeze risk score
const ShortInterestTab = ({ setActive, setPage }) => {
  const [sortBy, setSortBy] = useState('squeezeRisk'); // squeezeRisk | pctOfFloat | daysToCover | recentChange
  const [sortDir, setSortDir] = useState('desc');
  // Live Polygon /short-interest overlay — fetches per ticker, merges
  // shares short / DTC / recent change. % of float requires a separate
  // float fetch (ticker details share count); we approximate from the
  // curated dataset's float when live data alone doesn't include it.
  const [liveData, setLiveData] = useState({});
  const [liveStatus, setLiveStatus] = useState('idle'); // idle | loading | ok | error
  const [liveProgress, setLiveProgress] = useState(0);

  const refreshLive = useCallback(async () => {
    setLiveStatus('loading');
    setLiveProgress(0);
    try {
      const tickers = CURATED_SHORT_INTEREST.map(e => e.ticker);
      const collected = {};
      const batchSize = 4;
      for (let i = 0; i < tickers.length; i += batchSize) {
        const batch = tickers.slice(i, i + batchSize);
        const results = await Promise.all(batch.map(async t => {
          try {
            const si = await fetchPolygonShortInterest(t);
            return { ticker: t, si };
          } catch {
            return null;
          }
        }));
        for (const r of results) {
          if (r && r.si) collected[r.ticker] = r.si;
        }
        setLiveData({ ...collected });
        setLiveProgress(Math.min(1, (i + batchSize) / tickers.length));
        await new Promise(resolve => setTimeout(resolve, 150));
      }
      setLiveStatus(Object.keys(collected).length > 0 ? 'ok' : 'error');
    } catch (e) {
      console.warn('[ShortInterestTab.refreshLive]', e?.message);
      setLiveStatus('error');
    }
  }, []);

  const enriched = useMemo(() => {
    return CURATED_SHORT_INTEREST.map(e => {
      const live = liveData[e.ticker];
      const merged = live ? {
        ...e,
        // Live values override curated where available
        sharesShort: (live.sharesShort > 0 ? live.sharesShort / 1e6 : e.sharesShort),
        daysToCover: live.daysToCover > 0 ? live.daysToCover : e.daysToCover,
        recentChange: live.recentChange != null ? live.recentChange * 100 : e.recentChange,
        // % of float comes from curated since /short-interest doesn't include float
        // Live settlement date overrides "as of" interpretation
        _settlementDate: live.settlementDate,
        _isLive: true,
      } : { ...e, _isLive: false };
      return {
        ...merged,
        squeezeRisk: computeSqueezeRisk(merged),
      };
    });
  }, [liveData]);

  const sorted = useMemo(() => {
    return enriched.slice().sort((a, b) => {
      const sign = sortDir === 'desc' ? -1 : 1;
      const av = a[sortBy] ?? 0;
      const bv = b[sortBy] ?? 0;
      return sign * (av - bv);
    });
  }, [enriched, sortBy, sortDir]);

  const liveCount = useMemo(() => Object.keys(liveData).length, [liveData]);

  const toggleSort = (col) => {
    if (sortBy === col) setSortDir(d => d === 'desc' ? 'asc' : 'desc');
    else { setSortBy(col); setSortDir('desc'); }
  };

  const SortHeader = ({ id, label, align = 'right' }) => (
    <th className={`${align === 'right' ? 'text-right' : 'text-left'} px-2 py-1.5 cursor-pointer select-none`}
        onClick={() => toggleSort(id)}>
      {label}
      {sortBy === id && (
        <span className="ml-1" style={{ color: COLORS.mint }}>
          {sortDir === 'desc' ? '↓' : '↑'}
        </span>
      )}
    </th>
  );

  return (
    <div className="space-y-4">
      <div className="rounded-md border p-3"
           style={{ borderColor: COLORS.border, background: COLORS.surface }}>
        <div className="flex items-baseline justify-between mb-2 flex-wrap gap-2">
          <div className="text-[10px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>
            About short interest
          </div>
          <div className="flex items-center gap-2">
            {liveCount > 0 && (
              <span className="text-[10px] uppercase tracking-wider px-1.5 py-0.5 rounded inline-flex items-center gap-1"
                    style={{ background: `${COLORS.green}1A`, color: COLORS.green, border: `1px solid ${COLORS.green}55` }}>
                <span className="rounded-full" style={{ width: 5, height: 5, background: COLORS.green }} />
                {liveCount}/{CURATED_SHORT_INTEREST.length} live
              </span>
            )}
            <button type="button"
                    onClick={refreshLive}
                    disabled={liveStatus === 'loading'}
                    className="px-2.5 py-1 rounded text-[10.5px] inline-flex items-center gap-1.5 hover:opacity-90 disabled:opacity-40"
                    style={{ background: `${COLORS.mint}1A`, color: COLORS.mint, border: `1px solid ${COLORS.mint}` }}>
              <RefreshCw size={10} className={liveStatus === 'loading' ? 'animate-spin' : ''} />
              {liveStatus === 'loading'
                ? `Loading… ${(liveProgress * 100).toFixed(0)}%`
                : liveStatus === 'ok' ? 'Refresh live data'
                : liveStatus === 'error' ? 'Retry'
                : 'Pull live data'}
            </button>
          </div>
        </div>
        <p className="text-[11px]" style={{ color: COLORS.textDim }}>
          FINRA publishes short-interest data twice per month, ~8 business days after settlement. Key metrics:
          <strong> shares short</strong> (raw count), <strong>% of float</strong> (% of tradeable shares sold short),
          <strong> days to cover</strong> (shares short ÷ avg daily volume — how many days to close all shorts at
          normal volume). High % of float + high DTC + rising trend = setup for a short squeeze if a positive
          catalyst hits. The <strong>Squeeze Risk score</strong> is a 0-100 composite combining these three factors;
          higher = more squeeze potential.
          {' '}<strong>Live integration via Polygon /short-interest</strong> — the "Pull live data" button fetches
          actual FINRA bi-monthly settlement data per ticker; % of float remains from the curated source since
          it requires float share counts that aren't in the short-interest endpoint.
        </p>
      </div>

      {/* Top squeeze candidates */}
      <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-2">
        {sorted.slice(0, 4).map((e, idx) => {
          const tone = e.squeezeRisk >= 75 ? COLORS.red
                     : e.squeezeRisk >= 50 ? '#FFB84D'
                     :                       COLORS.text;
          return (
            <div key={idx} className="rounded border p-2"
                 style={{ borderColor: COLORS.border, background: COLORS.surface }}>
              <div className="flex items-baseline justify-between">
                <button type="button"
                        onClick={() => {
                          const inst = INSTRUMENTS.find(i => i.id?.startsWith(e.ticker + '-') || i.id === e.ticker || i.symbol === e.ticker);
                          if (inst && setActive) setActive(inst);
                          if (setPage) setPage('trade');
                        }}
                        className="text-[12px] font-medium hover:underline"
                        style={{ color: COLORS.text }}>
                  {e.ticker}
                </button>
                <span className="tabular-nums text-[12px] font-medium" style={{ color: tone }}>
                  {e.squeezeRisk}
                </span>
              </div>
              <div className="text-[9.5px] mt-0.5" style={{ color: COLORS.textMute }}>
                {e.pctOfFloat.toFixed(1)}% float · {e.daysToCover.toFixed(1)}d to cover
              </div>
            </div>
          );
        })}
      </div>

      {/* Full table */}
      <div className="rounded-md border"
           style={{ borderColor: COLORS.border, background: COLORS.surface }}>
        <div className="overflow-x-auto">
          <table className="w-full text-[11px] tabular-nums">
            <thead>
              <tr style={{ color: COLORS.textMute, background: COLORS.bg }}>
                <SortHeader id="ticker"        label="Ticker"          align="left" />
                <th className="text-left px-2">Sector</th>
                <SortHeader id="sharesShort"   label="Shares short (M)"  />
                <SortHeader id="pctOfFloat"    label="% of float"        />
                <SortHeader id="daysToCover"   label="DTC"               />
                <SortHeader id="recentChange"  label="2w change"         />
                <SortHeader id="squeezeRisk"   label="Squeeze risk"      />
                <th className="text-left px-2">Notes</th>
              </tr>
            </thead>
            <tbody>
              {sorted.map((e, idx) => {
                const riskTone = e.squeezeRisk >= 75 ? COLORS.red
                               : e.squeezeRisk >= 50 ? '#FFB84D'
                               :                       COLORS.text;
                const changeTone = e.recentChange >= 1 ? COLORS.red
                                 : e.recentChange >= 0 ? '#FFB84D'
                                 :                        COLORS.green;
                return (
                  <tr key={idx} style={{ borderTop: `1px solid ${COLORS.border}` }}>
                    <td className="px-2 py-1.5">
                      <div className="flex items-center gap-1.5">
                        {e._isLive && (
                          <span className="rounded-full" style={{ width: 5, height: 5, background: COLORS.green, flexShrink: 0 }}
                                title={`Live data · settlement ${e._settlementDate}`} />
                        )}
                        <button type="button"
                                onClick={() => {
                                  const inst = INSTRUMENTS.find(i => i.id?.startsWith(e.ticker + '-') || i.id === e.ticker || i.symbol === e.ticker);
                                  if (inst && setActive) setActive(inst);
                                  if (setPage) setPage('trade');
                                }}
                                className="font-medium hover:underline"
                                style={{ color: COLORS.text }}>
                          {e.ticker}
                        </button>
                      </div>
                    </td>
                    <td className="px-2 text-[10.5px]" style={{ color: COLORS.textMute }}>{e.sector}</td>
                    <td className="text-right px-2" style={{ color: COLORS.textDim }}>
                      {e.sharesShort.toFixed(1)}
                    </td>
                    <td className="text-right px-2"
                        style={{ color: e.pctOfFloat >= 25 ? COLORS.red : e.pctOfFloat >= 15 ? '#FFB84D' : COLORS.text }}>
                      {e.pctOfFloat.toFixed(1)}%
                    </td>
                    <td className="text-right px-2"
                        style={{ color: e.daysToCover >= 5 ? COLORS.red : e.daysToCover >= 3 ? '#FFB84D' : COLORS.text }}>
                      {e.daysToCover.toFixed(1)}d
                    </td>
                    <td className="text-right px-2" style={{ color: changeTone }}>
                      {e.recentChange >= 0 ? '+' : ''}{e.recentChange.toFixed(1)}%
                    </td>
                    <td className="text-right px-2" style={{ color: riskTone, fontWeight: 500 }}>
                      {e.squeezeRisk}
                    </td>
                    <td className="px-2 text-[10.5px]" style={{ color: COLORS.textMute }}>{e.notes}</td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      <div className="text-[10px] px-2" style={{ color: COLORS.textDim }}>
        <strong>Squeeze risk formula</strong>: min(50, %float × 1.0) + min(30, DTC × 4) + max(0, min(20, change × 8)) — out of 100.
        Names with <strong>≥75 score</strong> are squeeze setups but are also <strong>extremely volatile</strong>: short squeezes
        end as fast as they start, often with retracements that wipe out late-comers. Position sizing matters more here than direction.
      </div>
    </div>
  );
};

// FundamentalsTab — multi-filter screener on curated ratios dataset
const FundamentalsTab = ({ setActive, setPage }) => {
  const [filters, setFilters] = useState({
    sector: 'all',
    maxPE: '',
    minROE: '',
    minDivYield: '',
    minFCFYield: '',
    maxDebtToEquity: '',
    minMarketCap: '',
  });
  const [sortBy, setSortBy] = useState('marketCap');
  const [sortDir, setSortDir] = useState('desc');
  // Live data overlay — fetches Polygon /financials for the curated
  // ticker set and merges. When a ticker has live data, those numbers
  // override the curated snapshot. Click "Refresh live" to re-fetch.
  const [liveData, setLiveData] = useState({});
  const [liveStatus, setLiveStatus] = useState('idle'); // idle | loading | ok | error
  const [liveProgress, setLiveProgress] = useState(0);

  const refreshLive = useCallback(async () => {
    setLiveStatus('loading');
    setLiveProgress(0);
    try {
      const tickers = Object.keys(CURATED_FUNDAMENTALS).map(t => t.replace('_', '.'));
      const collected = {};
      const batchSize = 5;
      for (let i = 0; i < tickers.length; i += batchSize) {
        const batch = tickers.slice(i, i + batchSize);
        const results = await Promise.all(batch.map(async t => {
          try {
            const [fin, det] = await Promise.all([
              fetchPolygonFinancials(t),
              fetchPolygonTickerDetails(t),
            ]);
            // We need a current price proxy; pull last bar
            const bars = await fetchPolygonAggs(t, '1M', 'day', 1).catch(() => null);
            const lastClose = bars && bars.length > 0 ? bars[bars.length - 1].close : null;
            if (!fin || !det || !lastClose) return null;
            const derived = deriveFundamentalsFromPolygon(fin, det, lastClose);
            return { ticker: t, derived };
          } catch {
            return null;
          }
        }));
        for (const r of results) {
          if (r && r.derived) collected[r.ticker] = r.derived;
        }
        setLiveData({ ...collected });
        setLiveProgress(Math.min(1, (i + batchSize) / tickers.length));
      }
      setLiveStatus('ok');
    } catch (e) {
      console.warn('[FundamentalsTab.refreshLive]', e?.message);
      setLiveStatus('error');
    }
  }, []);

  const sectors = useMemo(() => {
    const s = new Set();
    for (const v of Object.values(CURATED_FUNDAMENTALS)) s.add(v.sector);
    return ['all', ...Array.from(s).sort()];
  }, []);

  const filtered = useMemo(() => {
    const entries = Object.entries(CURATED_FUNDAMENTALS).map(([ticker, v]) => {
      const tickerKey = ticker.replace('_', '.');
      const live = liveData[tickerKey];
      // When live data is available, use it; fall back to curated for fields
      // that Polygon doesn't provide (e.g. divYield, peg, sector if generic)
      const merged = live ? {
        ...v,
        ...Object.fromEntries(Object.entries(live).filter(([k, val]) =>
          val != null && !k.startsWith('_')
        )),
        sector: (live.sector && live.sector !== 'Unknown') ? live.sector : v.sector,
        _isLive: true,
      } : { ...v, _isLive: false };
      return { ticker: tickerKey, ...merged };
    });
    return entries.filter(e => {
      if (filters.sector !== 'all' && e.sector !== filters.sector) return false;
      if (filters.maxPE && e.pe > Number(filters.maxPE)) return false;
      if (filters.minROE && e.roe < Number(filters.minROE)) return false;
      if (filters.minDivYield && e.divYield < Number(filters.minDivYield)) return false;
      if (filters.minFCFYield && e.fcfYield < Number(filters.minFCFYield)) return false;
      if (filters.maxDebtToEquity && e.debtToEquity > Number(filters.maxDebtToEquity)) return false;
      if (filters.minMarketCap && e.marketCap < Number(filters.minMarketCap)) return false;
      return true;
    }).sort((a, b) => {
      const sign = sortDir === 'desc' ? -1 : 1;
      return sign * ((a[sortBy] ?? 0) - (b[sortBy] ?? 0));
    });
  }, [filters, sortBy, sortDir, liveData]);

  const liveCount = useMemo(() => Object.keys(liveData).length, [liveData]);

  const toggleSort = (col) => {
    if (sortBy === col) setSortDir(d => d === 'desc' ? 'asc' : 'desc');
    else { setSortBy(col); setSortDir('desc'); }
  };

  const SortHeader = ({ id, label, align = 'right' }) => (
    <th className={`${align === 'right' ? 'text-right' : 'text-left'} px-2 py-1.5 cursor-pointer select-none`}
        onClick={() => toggleSort(id)}>
      {label}
      {sortBy === id && (
        <span className="ml-1" style={{ color: COLORS.mint }}>{sortDir === 'desc' ? '↓' : '↑'}</span>
      )}
    </th>
  );

  const filterField = (id, label, placeholder) => (
    <div>
      <div className="text-[9.5px] uppercase tracking-wider mb-1" style={{ color: COLORS.textMute }}>{label}</div>
      <input type="number" value={filters[id]} placeholder={placeholder}
             onChange={(e) => setFilters(f => ({ ...f, [id]: e.target.value }))}
             className="w-full px-2 py-1.5 rounded text-[11px] outline-none tabular-nums"
             style={{ background: COLORS.bg, color: COLORS.text, border: `1px solid ${COLORS.border}` }} />
    </div>
  );

  return (
    <div className="space-y-4">
      <div className="rounded-md border p-3"
           style={{ borderColor: COLORS.border, background: COLORS.surface }}>
        <div className="flex items-baseline justify-between mb-2 flex-wrap gap-2">
          <div className="text-[10px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>
            Fundamentals screener
          </div>
          <div className="flex items-center gap-2">
            {liveCount > 0 && (
              <span className="text-[10px] uppercase tracking-wider px-1.5 py-0.5 rounded inline-flex items-center gap-1"
                    style={{ background: `${COLORS.green}1A`, color: COLORS.green, border: `1px solid ${COLORS.green}55` }}>
                <span className="rounded-full" style={{ width: 5, height: 5, background: COLORS.green }} />
                {liveCount}/{Object.keys(CURATED_FUNDAMENTALS).length} live
              </span>
            )}
            <button type="button"
                    onClick={refreshLive}
                    disabled={liveStatus === 'loading'}
                    className="px-2.5 py-1 rounded text-[10.5px] inline-flex items-center gap-1.5 hover:opacity-90 disabled:opacity-40"
                    style={{ background: `${COLORS.mint}1A`, color: COLORS.mint, border: `1px solid ${COLORS.mint}` }}>
              {liveStatus === 'loading'
                ? <RefreshCw size={10} className="animate-spin" />
                : <RefreshCw size={10} />}
              {liveStatus === 'loading'
                ? `Loading… ${(liveProgress * 100).toFixed(0)}%`
                : liveStatus === 'ok' ? 'Refresh live data'
                : liveStatus === 'error' ? 'Retry'
                : 'Pull live data'}
            </button>
          </div>
        </div>
        <p className="text-[11px]" style={{ color: COLORS.textDim }}>
          Multi-filter discovery on {Object.keys(CURATED_FUNDAMENTALS).length} curated tickers across {sectors.length - 1} sectors.
          Combine filters to find names matching your criteria — e.g., "low P/E + high ROE + dividend ≥ 2%" finds value names with quality earnings.
          Click any column to sort. Click <strong>"Pull live data"</strong> to fetch real Polygon /financials and overlay onto curated values
          (live data marked with green dot · fields Polygon doesn't have like dividend yield + PEG fall back to curated).
        </p>
      </div>

      {/* Filter grid */}
      <div className="rounded-md border p-3"
           style={{ borderColor: COLORS.border, background: COLORS.surface }}>
        <div className="text-[10px] uppercase tracking-wider mb-2" style={{ color: COLORS.textMute }}>
          Filters · {filtered.length} matches
        </div>
        <div className="grid grid-cols-2 sm:grid-cols-4 lg:grid-cols-7 gap-2">
          <div>
            <div className="text-[9.5px] uppercase tracking-wider mb-1" style={{ color: COLORS.textMute }}>Sector</div>
            <select value={filters.sector}
                    onChange={(e) => setFilters(f => ({ ...f, sector: e.target.value }))}
                    className="w-full px-2 py-1.5 rounded text-[11px] outline-none"
                    style={{ background: COLORS.bg, color: COLORS.text, border: `1px solid ${COLORS.border}`, colorScheme: 'dark' }}>
              {sectors.map(s => <option key={s} value={s}>{s}</option>)}
            </select>
          </div>
          {filterField('maxPE',           'Max P/E',         '< 30')}
          {filterField('minROE',          'Min ROE %',       '> 15')}
          {filterField('minDivYield',     'Min div yield %', '> 2')}
          {filterField('minFCFYield',     'Min FCF yield %', '> 4')}
          {filterField('maxDebtToEquity', 'Max D/E',         '< 1.0')}
          {filterField('minMarketCap',    'Min cap ($B)',    '> 50')}
        </div>
      </div>

      {/* Results table */}
      <div className="rounded-md border"
           style={{ borderColor: COLORS.border, background: COLORS.surface }}>
        <div className="overflow-x-auto">
          <table className="w-full text-[11px] tabular-nums">
            <thead>
              <tr style={{ color: COLORS.textMute, background: COLORS.bg }}>
                <SortHeader id="ticker" label="Ticker" align="left" />
                <th className="text-left px-2">Sector</th>
                <SortHeader id="marketCap" label="Cap ($B)" />
                <SortHeader id="pe"        label="P/E" />
                <SortHeader id="ps"        label="P/S" />
                <SortHeader id="pb"        label="P/B" />
                <SortHeader id="peg"       label="PEG" />
                <SortHeader id="roe"       label="ROE %" />
                <SortHeader id="roic"      label="ROIC %" />
                <SortHeader id="divYield"  label="Div %" />
                <SortHeader id="fcfYield"  label="FCF Yld %" />
                <SortHeader id="debtToEquity" label="D/E" />
                <SortHeader id="grossMargin" label="GM %" />
                <SortHeader id="opMargin"  label="OM %" />
              </tr>
            </thead>
            <tbody>
              {filtered.map((e, idx) => (
                <tr key={idx} style={{ borderTop: `1px solid ${COLORS.border}` }}>
                  <td className="px-2 py-1.5">
                    <div className="flex items-center gap-1.5">
                      {e._isLive && (
                        <span className="rounded-full" style={{ width: 5, height: 5, background: COLORS.green }}
                              title="Live data from Polygon /financials" />
                      )}
                      <button type="button"
                              onClick={() => {
                                const inst = INSTRUMENTS.find(i => i.id?.startsWith(e.ticker + '-') || i.id === e.ticker || i.symbol === e.ticker);
                                if (inst && setActive) setActive(inst);
                                if (setPage) setPage('trade');
                              }}
                              className="font-medium hover:underline"
                              style={{ color: COLORS.text }}>
                        {e.ticker}
                      </button>
                    </div>
                  </td>
                  <td className="px-2 text-[10.5px]" style={{ color: COLORS.textMute }}>{e.sector}</td>
                  <td className="text-right px-2" style={{ color: COLORS.text }}>{e.marketCap.toFixed(0)}</td>
                  <td className="text-right px-2" style={{ color: e.pe < 15 ? COLORS.green : e.pe > 40 ? COLORS.red : COLORS.text }}>
                    {e.pe.toFixed(1)}
                  </td>
                  <td className="text-right px-2" style={{ color: COLORS.textDim }}>{e.ps.toFixed(1)}</td>
                  <td className="text-right px-2" style={{ color: COLORS.textDim }}>{e.pb >= 100 ? '—' : e.pb.toFixed(1)}</td>
                  <td className="text-right px-2" style={{ color: e.peg < 1.5 ? COLORS.green : e.peg > 3 ? COLORS.red : COLORS.text }}>
                    {e.peg.toFixed(2)}
                  </td>
                  <td className="text-right px-2" style={{ color: e.roe >= 30 ? COLORS.green : e.roe < 10 ? COLORS.red : COLORS.text }}>
                    {e.roe >= 100 ? '99+' : e.roe.toFixed(1)}
                  </td>
                  <td className="text-right px-2" style={{ color: e.roic >= 20 ? COLORS.green : COLORS.text }}>
                    {e.roic.toFixed(1)}
                  </td>
                  <td className="text-right px-2" style={{ color: e.divYield >= 3 ? COLORS.green : COLORS.textDim }}>
                    {e.divYield.toFixed(2)}
                  </td>
                  <td className="text-right px-2" style={{ color: e.fcfYield >= 5 ? COLORS.green : e.fcfYield < 0 ? COLORS.red : COLORS.text }}>
                    {e.fcfYield.toFixed(1)}
                  </td>
                  <td className="text-right px-2" style={{ color: e.debtToEquity > 2 ? COLORS.red : e.debtToEquity < 0.5 ? COLORS.green : COLORS.text }}>
                    {e.debtToEquity.toFixed(2)}
                  </td>
                  <td className="text-right px-2" style={{ color: COLORS.textDim }}>{e.grossMargin.toFixed(0)}</td>
                  <td className="text-right px-2" style={{ color: COLORS.textDim }}>{e.opMargin.toFixed(0)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      <div className="text-[10px] px-2" style={{ color: COLORS.textDim }}>
        <strong>Color coding</strong>: P/E green &lt;15 / red &gt;40 (value vs growth bias).
        ROE green ≥30 / red &lt;10 (high return on equity = quality).
        FCF yield green ≥5% / red &lt;0 (cash-generative vs cash-burning).
        D/E green &lt;0.5 / red &gt;2 (financial leverage). Numbers are <strong>trailing 12-month</strong>; forward estimates would tell a different story for cyclicals/turnarounds.
      </div>
    </div>
  );
};

// AnalystRatingsTab — buy/hold/sell consensus + price targets
const AnalystRatingsTab = ({ setActive, setPage }) => {
  const [sortBy, setSortBy] = useState('upside');
  const [sortDir, setSortDir] = useState('desc');

  const enriched = useMemo(() => {
    return Object.entries(CURATED_ANALYST_RATINGS).map(([ticker, r]) => {
      const sentiment = computeAnalystSentiment(r);
      return { ticker, ...r, ...sentiment };
    });
  }, []);

  const sorted = useMemo(() => {
    return enriched.slice().sort((a, b) => {
      const sign = sortDir === 'desc' ? -1 : 1;
      return sign * ((a[sortBy] ?? 0) - (b[sortBy] ?? 0));
    });
  }, [enriched, sortBy, sortDir]);

  const toggleSort = (col) => {
    if (sortBy === col) setSortDir(d => d === 'desc' ? 'asc' : 'desc');
    else { setSortBy(col); setSortDir('desc'); }
  };

  const SortHeader = ({ id, label, align = 'right' }) => (
    <th className={`${align === 'right' ? 'text-right' : 'text-left'} px-2 py-1.5 cursor-pointer select-none`}
        onClick={() => toggleSort(id)}>
      {label}
      {sortBy === id && (
        <span className="ml-1" style={{ color: COLORS.mint }}>{sortDir === 'desc' ? '↓' : '↑'}</span>
      )}
    </th>
  );

  return (
    <div className="space-y-4">
      <div className="rounded-md border p-3"
           style={{ borderColor: COLORS.border, background: COLORS.surface }}>
        <div className="text-[10px] uppercase tracking-wider mb-2" style={{ color: COLORS.textMute }}>
          Analyst ratings consensus
        </div>
        <p className="text-[11px]" style={{ color: COLORS.textDim }}>
          Sell-side consensus across {enriched.length} curated tickers. Buy/Hold/Sell counts aggregate ratings from major banks
          (GS, MS, JPM, BAC, etc.). Price target = mean of analyst targets; range = low/high. <strong>Upside %</strong> = (target − current) / current.
          <strong> Bull case</strong> = upside to highest target; <strong>bear case</strong> = downside to lowest. Curated dataset; live integration via
          Refinitiv/Bloomberg/Zacks is on the deferred list. Sell-side consensus has well-documented optimistic bias (more buys than sells across the universe);
          treat as one input among many, not as truth.
        </p>
      </div>

      {/* Strong-buy candidates summary */}
      <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-2">
        {sorted.slice(0, 4).map((e, idx) => {
          const consColor = e.consensus === 'Strong Buy' ? COLORS.green
                          : e.consensus === 'Buy'        ? '#7AC8FF'
                          : e.consensus === 'Hold'       ? COLORS.text
                          : e.consensus === 'Sell'       ? '#FFB84D'
                          :                                COLORS.red;
          return (
            <div key={idx} className="rounded border p-2" style={{ borderColor: COLORS.border, background: COLORS.surface }}>
              <div className="flex items-baseline justify-between">
                <button type="button"
                        onClick={() => {
                          const inst = INSTRUMENTS.find(i => i.id?.startsWith(e.ticker + '-') || i.id === e.ticker || i.symbol === e.ticker);
                          if (inst && setActive) setActive(inst);
                          if (setPage) setPage('trade');
                        }}
                        className="text-[12px] font-medium hover:underline"
                        style={{ color: COLORS.text }}>
                  {e.ticker}
                </button>
                <span className="tabular-nums text-[12px] font-medium"
                      style={{ color: e.upside >= 0 ? COLORS.green : COLORS.red }}>
                  {e.upside >= 0 ? '+' : ''}{(e.upside ?? 0).toFixed(1)}%
                </span>
              </div>
              <div className="text-[9.5px] mt-0.5" style={{ color: consColor }}>
                {e.consensus} · ${e.priceTarget} target
              </div>
            </div>
          );
        })}
      </div>

      {/* Full table */}
      <div className="rounded-md border"
           style={{ borderColor: COLORS.border, background: COLORS.surface }}>
        <div className="overflow-x-auto">
          <table className="w-full text-[11px] tabular-nums">
            <thead>
              <tr style={{ color: COLORS.textMute, background: COLORS.bg }}>
                <SortHeader id="ticker"       label="Ticker"      align="left" />
                <SortHeader id="total"        label="Analysts" />
                <th className="text-right px-2">Buy</th>
                <th className="text-right px-2">Hold</th>
                <th className="text-right px-2">Sell</th>
                <th className="text-left px-2">Consensus</th>
                <SortHeader id="currentPrice" label="Current" />
                <SortHeader id="priceTarget"  label="Target" />
                <SortHeader id="upside"       label="Upside %" />
                <SortHeader id="bullCase"     label="Bull %" />
                <SortHeader id="bearCase"     label="Bear %" />
                <th className="text-left px-2">Range</th>
              </tr>
            </thead>
            <tbody>
              {sorted.map((e, idx) => {
                const consColor = e.consensus === 'Strong Buy' ? COLORS.green
                                : e.consensus === 'Buy'        ? '#7AC8FF'
                                : e.consensus === 'Hold'       ? COLORS.text
                                : e.consensus === 'Sell'       ? '#FFB84D'
                                :                                COLORS.red;
                const upside = e.upside;
                return (
                  <tr key={idx} style={{ borderTop: `1px solid ${COLORS.border}` }}>
                    <td className="px-2 py-1.5">
                      <button type="button"
                              onClick={() => {
                                const inst = INSTRUMENTS.find(i => i.id?.startsWith(e.ticker + '-') || i.id === e.ticker || i.symbol === e.ticker);
                                if (inst && setActive) setActive(inst);
                                if (setPage) setPage('trade');
                              }}
                              className="font-medium hover:underline"
                              style={{ color: COLORS.text }}>
                        {e.ticker}
                      </button>
                    </td>
                    <td className="text-right px-2" style={{ color: COLORS.textMute }}>{e.total}</td>
                    <td className="text-right px-2" style={{ color: COLORS.green }}>{e.buy}</td>
                    <td className="text-right px-2" style={{ color: COLORS.textDim }}>{e.hold}</td>
                    <td className="text-right px-2" style={{ color: COLORS.red }}>{e.sell}</td>
                    <td className="px-2 text-[10.5px] uppercase tracking-wider" style={{ color: consColor }}>
                      {e.consensus}
                    </td>
                    <td className="text-right px-2" style={{ color: COLORS.text }}>${e.currentPrice}</td>
                    <td className="text-right px-2" style={{ color: COLORS.textDim }}>${e.priceTarget}</td>
                    <td className="text-right px-2 font-medium"
                        style={{ color: upside >= 15 ? COLORS.green : upside >= 0 ? COLORS.text : COLORS.red }}>
                      {upside >= 0 ? '+' : ''}{(upside ?? 0).toFixed(1)}%
                    </td>
                    <td className="text-right px-2" style={{ color: COLORS.green }}>
                      +{(e.bullCase ?? 0).toFixed(0)}%
                    </td>
                    <td className="text-right px-2" style={{ color: COLORS.red }}>
                      {(e.bearCase ?? 0).toFixed(0)}%
                    </td>
                    <td className="px-2 text-[10.5px]" style={{ color: COLORS.textDim }}>
                      ${e.low}-${e.high}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

// AIvsAnalystConsensusTab — Phase 3o.85
// Joins AI-generated trade ideas (stored in localStorage by the AI
// trade-idea generator) with curated sell-side analyst ratings.
// The crux is dispersion: when AI and the Street agree, the signal is
// stronger but the alpha is smaller (it's already priced); when they
// disagree, there's either alpha to harvest or a warning being missed.
//
// Four signal types:
//   AGREE-BULL     Both bullish — high-conviction long
//   AGREE-BEAR     Both bearish — high-conviction short / avoid
//   CONTRA-AI-BULL AI bullish, Street bearish/neutral — contrarian long
//                  (AI sees something Street might be missing, OR Street
//                  is rationally cautious; resolution is empirical)
//   CONTRA-AI-BEAR AI bearish, Street bullish — risk-off warning
//                  (AI flags risk Street consensus is missing)
//
// The table sorts CONTRA cases first (largest disagreement first)
// because those are the most actionable rows. AGREE cases follow,
// then NEUTRAL.
const AIvsAnalystConsensusTab = ({ setActive, setPage }) => {
  const [aiIdeas, setAiIdeas] = useState([]);
  const [refreshKey, setRefreshKey] = useState(0);

  useEffect(() => {
    try {
      const raw = localStorage.getItem('imo_ai_trade_ideas');
      if (raw) {
        const parsed = JSON.parse(raw);
        if (Array.isArray(parsed)) setAiIdeas(parsed);
      }
    } catch {}
  }, [refreshKey]);

  const rows = useMemo(
    () => computeAIvsAnalystConsensus(aiIdeas, CURATED_ANALYST_RATINGS),
    [aiIdeas]
  );

  const counts = useMemo(() => {
    const c = { 'AGREE-BULL': 0, 'AGREE-BEAR': 0, 'CONTRA-AI-BULL': 0, 'CONTRA-AI-BEAR': 0, 'NEUTRAL': 0 };
    for (const r of rows) c[r.signal] = (c[r.signal] || 0) + 1;
    return c;
  }, [rows]);

  const SIGNAL_TONE = {
    'AGREE-BULL':     { color: COLORS.green,      label: 'Agree · bull',      kind: 'agree' },
    'AGREE-BEAR':     { color: COLORS.red,        label: 'Agree · bear',      kind: 'agree' },
    'CONTRA-AI-BULL': { color: COLORS.chartGold,  label: 'Contra · AI bull',  kind: 'contra' },
    'CONTRA-AI-BEAR': { color: COLORS.chartAmber, label: 'Contra · AI bear',  kind: 'contra' },
    'NEUTRAL':        { color: COLORS.textDim,    label: 'Neutral',           kind: 'neutral' },
  };

  return (
    <div className="space-y-4">
      <div className="rounded-md border p-3"
           style={{ borderColor: COLORS.border, background: COLORS.surface }}>
        <div className="flex items-baseline justify-between mb-2 flex-wrap gap-2">
          <div>
            <div className="text-[10px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>
              AI vs Street consensus
            </div>
            <div className="text-[10.5px] mt-0.5" style={{ color: COLORS.textDim }}>
              Cross-references AI-generated trade ideas (from the AI Idea Generator) with sell-side
              analyst ratings · {aiIdeas.length} AI ideas · {Object.keys(CURATED_ANALYST_RATINGS).length} rated tickers
            </div>
          </div>
          <button type="button"
                  onClick={() => setRefreshKey(k => k + 1)}
                  className="text-[10.5px] hover:underline"
                  style={{ color: COLORS.mint }}>
            refresh
          </button>
        </div>
        <p className="text-[11px]" style={{ color: COLORS.textDim }}>
          AI bias is the net long − short fraction across recent AI ideas per ticker.
          Street bias is (buys − sells) / total ratings. We classify rows as
          <strong style={{ color: COLORS.green }}> AGREE</strong> when both sides lean the same
          direction with conviction (|bias| &gt; 0.20), or
          <strong style={{ color: COLORS.chartGold }}> CONTRA</strong> when they diverge.
          Contra-AI-bull = AI bullish, Street not (potential alpha or AI overreach);
          Contra-AI-bear = AI bearish, Street bullish (warning Street is missing).
        </p>
      </div>

      {/* Summary chips */}
      <div className="flex items-center gap-2 flex-wrap">
        {Object.entries(SIGNAL_TONE).map(([k, t]) => (
          <div key={k} className="rounded border px-2 py-1 text-[10.5px] flex items-center gap-1.5"
               style={{ borderColor: `${t.color}55`, background: `${t.color}08` }}>
            <span className="inline-block w-2 h-2 rounded-full" style={{ background: t.color }} />
            <span style={{ color: t.color }}>{t.label}</span>
            <span className="tabular-nums" style={{ color: COLORS.text, fontWeight: 500 }}>
              {counts[k] || 0}
            </span>
          </div>
        ))}
      </div>

      {/* Empty state */}
      {rows.length === 0 && (
        <div className="rounded-md border p-6 text-center"
             style={{ borderColor: COLORS.border, background: COLORS.surface }}>
          <div className="text-[12px]" style={{ color: COLORS.text }}>
            No overlap between AI ideas and rated tickers yet
          </div>
          <div className="text-[11px] mt-1" style={{ color: COLORS.textMute }}>
            Generate AI trade ideas (via the BottomPanel "AI ideas" tab on a covered ticker like AAPL,
            MSFT, NVDA, etc.) and they'll appear here once joined with analyst ratings.
          </div>
        </div>
      )}

      {/* Main table */}
      {rows.length > 0 && (
        <div className="rounded-md border"
             style={{ borderColor: COLORS.border, background: COLORS.surface }}>
          <div className="overflow-x-auto">
            <table className="w-full text-[11px] tabular-nums">
              <thead>
                <tr style={{ color: COLORS.textMute, background: COLORS.bg }}>
                  <th className="text-left px-2 py-1.5">Ticker</th>
                  <th className="text-left px-2">Signal</th>
                  <th className="text-right px-2">AI bias</th>
                  <th className="text-right px-2">AI L/S/N</th>
                  <th className="text-right px-2">Street bias</th>
                  <th className="text-right px-2">B/H/S</th>
                  <th className="text-right px-2">Disagreement</th>
                  <th className="text-right px-2">Upside</th>
                  <th className="text-right px-2">Target</th>
                </tr>
              </thead>
              <tbody>
                {rows.map(r => {
                  const tone = SIGNAL_TONE[r.signal] || SIGNAL_TONE.NEUTRAL;
                  return (
                    <tr key={r.sym}
                        className="border-t hover:bg-white/5 transition-colors"
                        style={{ borderColor: COLORS.border }}>
                      <td className="px-2 py-1.5" style={{ color: COLORS.text, fontWeight: 500 }}>
                        {r.sym}
                      </td>
                      <td className="px-2">
                        <span className="text-[9.5px] uppercase tracking-wider px-1.5 py-0.5 rounded"
                              style={{
                                background: `${tone.color}1A`,
                                color: tone.color,
                                border: `1px solid ${tone.color}33`,
                              }}>
                          {tone.label}
                        </span>
                      </td>
                      <td className="text-right px-2"
                          style={{ color: r.aiBias >= 0 ? COLORS.green : COLORS.red, fontWeight: 500 }}>
                        {r.aiBias >= 0 ? '+' : ''}{r.aiBias.toFixed(2)}
                      </td>
                      <td className="text-right px-2" style={{ color: COLORS.textDim }}>
                        {r.aiLong}/{r.aiShort}/{r.aiNeutral}
                      </td>
                      <td className="text-right px-2"
                          style={{ color: r.streetBias >= 0 ? COLORS.green : COLORS.red, fontWeight: 500 }}>
                        {r.streetBias >= 0 ? '+' : ''}{r.streetBias.toFixed(2)}
                      </td>
                      <td className="text-right px-2" style={{ color: COLORS.textDim }}>
                        {r.buyCount}/{r.holdCount}/{r.sellCount}
                      </td>
                      <td className="text-right px-2"
                          style={{
                            color: tone.kind === 'contra' ? tone.color : COLORS.textDim,
                            fontWeight: tone.kind === 'contra' ? 600 : 400,
                          }}>
                        {r.disagreement >= 0 ? '+' : ''}{r.disagreement.toFixed(2)}
                      </td>
                      <td className="text-right px-2"
                          style={{ color: r.upside >= 0 ? COLORS.green : COLORS.red }}>
                        {r.upside >= 0 ? '+' : ''}{(r.upside * 100).toFixed(1)}%
                      </td>
                      <td className="text-right px-2" style={{ color: COLORS.text }}>
                        {r.priceTarget != null ? `$${r.priceTarget}` : '—'}
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
          <div className="px-3 py-2 text-[9.5px]" style={{ color: COLORS.textDim }}>
            <strong>Interpretation</strong>: <span style={{ color: COLORS.green }}>AGREE-BULL</span> rows
            are high-conviction longs but typically priced in. <span style={{ color: COLORS.red }}>AGREE-BEAR</span> rows
            warrant avoiding/shorting. <span style={{ color: COLORS.chartGold }}>CONTRA-AI-BULL</span> rows are
            where alpha lives if your AI is right and the Street is anchored. <span style={{ color: COLORS.chartAmber }}>CONTRA-AI-BEAR</span> rows
            are red flags Street consensus may be missing — review your fundamentals carefully before holding.
            <strong> Caveat</strong>: AI bias quality depends on AI idea quality (garbage-in / garbage-out);
            Street consensus has well-documented optimistic bias (more buys than sells). Both signals are
            inputs, not truth. Use as a sanity check on positions, not as an instant trading rule.
          </div>
        </div>
      )}
    </div>
  );
};

const RiskParityTab = ({ account, portfolioSource }) => {
  const holdings = useMemo(() => {
    if (portfolioSource?.source === 'broker' && portfolioSource.positions?.length > 0) {
      return portfolioSource.positions.map(p => ({
        symbol: p.symbol,
        qty: Number(p.qty) || 0,
        mark: Number(p.mark) || 0,
      }));
    }
    const positions = account?.positions ?? [];
    return positions.map(p => {
      const sym = p.instrument?.id?.split('-')[0] ?? p.symbol ?? '';
      const sign = p.side === 'short' ? -1 : 1;
      const qty = sign * (Number(p.size) || 0);
      const mark = Number(p.markPrice) || Number(p.entryPrice) || 0;
      return { symbol: sym, qty, mark };
    }).filter(h => h.symbol && h.qty !== 0);
  }, [portfolioSource, account]);

  const [returnsBySymbol, setReturnsBySymbol] = useState({});
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (holdings.length === 0) return;
    setLoading(true);
    Promise.all(holdings.map(h => fetchPolygonAggs(h.symbol, '6M', 'day', 1).catch(() => null)))
      .then(results => {
        const map = {};
        for (let i = 0; i < holdings.length; i++) {
          const data = results[i];
          if (!data || data.length < 5) continue;
          const closes = data.map(d => d.close).filter(c => c > 0);
          const rets = [];
          for (let k = 1; k < closes.length; k++) {
            rets.push((closes[k] - closes[k - 1]) / closes[k - 1]);
          }
          map[holdings[i].symbol] = rets;
        }
        setReturnsBySymbol(map);
      })
      .finally(() => setLoading(false));
  }, [holdings]);

  const augmented = useMemo(() => holdings.map(h => ({
    ...h,
    returns: returnsBySymbol[h.symbol] || [],
  })), [holdings, returnsBySymbol]);

  const result = useMemo(() => runRiskParity({ holdings: augmented }), [augmented]);

  if (holdings.length < 2) {
    return (
      <div className="rounded-md border p-6 text-center"
           style={{ borderColor: COLORS.border, background: COLORS.surface }}>
        <Activity size={28} style={{ color: COLORS.textMute, margin: '0 auto 12px' }} />
        <div className="text-[13px] mb-1" style={{ color: COLORS.text }}>Need at least 2 positions</div>
        <div className="text-[11px]" style={{ color: COLORS.textMute }}>
          Risk parity allocates capital so each position contributes equally to portfolio variance.
          Open a few positions first.
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      <div className="rounded-md border p-3"
           style={{ borderColor: COLORS.border, background: COLORS.surface }}>
        <div className="text-[10px] uppercase tracking-wider mb-2" style={{ color: COLORS.textMute }}>
          About Risk Parity
        </div>
        <p className="text-[11px]" style={{ color: COLORS.textDim }}>
          Allocates capital so every position contributes <strong>equally</strong> to portfolio variance.
          Low-vol positions get more dollars; high-vol positions get fewer. Unlike Black-Litterman this
          requires <strong>no view on returns</strong> — it's a pure risk-balancing approach. Used by
          Bridgewater (All-Weather) and many systematic risk-parity funds. Iterative algorithm:
          w_i ← w_i · (1/n) / RC_i, repeated until risk contributions converge to 1/n each.
          {loading && <span className="ml-2" style={{ color: COLORS.textMute }}>· loading return history…</span>}
        </p>
      </div>

      {result.error && (
        <div className="rounded-md border p-3 text-[11px]"
             style={{ borderColor: COLORS.red, color: COLORS.red, background: 'rgba(255,85,119,0.06)' }}>
          {result.error}
        </div>
      )}

      {!result.error && result.suggestions.length > 0 && (
        <>
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-2">
            <div className="rounded border p-3" style={{ borderColor: COLORS.border, background: COLORS.surface }}>
              <div className="text-[9.5px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>Portfolio vol (ann)</div>
              <div className="tabular-nums text-[14px] font-medium" style={{ color: COLORS.text }}>
                {(result.portfolioVol * 100).toFixed(2)}%
              </div>
            </div>
            <div className="rounded border p-3" style={{ borderColor: COLORS.border, background: COLORS.surface }}>
              <div className="text-[9.5px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>Iterations</div>
              <div className="tabular-nums text-[14px]" style={{ color: COLORS.text }}>
                {result.iterations}
              </div>
            </div>
            <div className="rounded border p-3" style={{ borderColor: COLORS.border, background: COLORS.surface }}>
              <div className="text-[9.5px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>Convergence</div>
              <div className="text-[12px]" style={{ color: result.converged ? COLORS.green : '#FFB84D' }}>
                {result.converged ? 'Converged' : 'Max iters'}
              </div>
            </div>
            <div className="rounded border p-3" style={{ borderColor: COLORS.border, background: COLORS.surface }}>
              <div className="text-[9.5px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>Target RC</div>
              <div className="tabular-nums text-[14px]" style={{ color: COLORS.text }}>
                {(100 / result.suggestions.length).toFixed(1)}%
              </div>
            </div>
          </div>

          <div className="rounded-md border p-3"
               style={{ borderColor: COLORS.border, background: COLORS.surface }}>
            <div className="text-[10px] uppercase tracking-wider mb-2" style={{ color: COLORS.textMute }}>
              Risk-parity allocation vs current
            </div>
            <div className="overflow-x-auto rounded border" style={{ borderColor: COLORS.border }}>
              <table className="w-full text-[11px] tabular-nums">
                <thead>
                  <tr style={{ color: COLORS.textMute, background: COLORS.bg }}>
                    <th className="text-left px-2 py-1.5">Symbol</th>
                    <th className="text-right px-2">Current weight</th>
                    <th className="text-right px-2">RP weight</th>
                    <th className="text-right px-2">Risk contrib</th>
                    <th className="text-right px-2">Δ</th>
                  </tr>
                </thead>
                <tbody>
                  {result.suggestions.map((s, idx) => (
                    <tr key={idx} style={{ borderTop: `1px solid ${COLORS.border}` }}>
                      <td className="px-2 py-1" style={{ color: COLORS.text, fontWeight: 500 }}>{s.symbol}</td>
                      <td className="text-right px-2" style={{ color: COLORS.textDim }}>
                        {(s.currentWeight * 100).toFixed(1)}%
                      </td>
                      <td className="text-right px-2" style={{ color: COLORS.text }}>
                        {(s.optimalWeight * 100).toFixed(1)}%
                      </td>
                      <td className="text-right px-2" style={{ color: COLORS.textDim }}>
                        {(s.riskContribution * 100).toFixed(1)}%
                      </td>
                      <td className="text-right px-2"
                          style={{ color: s.deltaPct >= 0 ? COLORS.green : COLORS.red, fontWeight: 500 }}>
                        {s.deltaPct >= 0 ? '+' : ''}{s.deltaPct.toFixed(1)}%
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
            <div className="text-[10px] mt-2" style={{ color: COLORS.textDim }}>
              Risk contribution shows each position's % of total portfolio variance under the RP weights — should be near {(100 / result.suggestions.length).toFixed(1)}% (1/n).
              Δ &gt; 0 means RP wants more weight; Δ &lt; 0 means trim. RP-optimal portfolios usually shift dollars from
              high-vol concentrators (often growth tech) into low-vol diversifiers (utilities, staples, bonds).
            </div>
          </div>

          {/* Vol-targeting overlay — scale leverage to hit target portfolio vol */}
          <VolTargetingPanel result={result} holdings={holdings} />
        </>
      )}
    </div>
  );
};

// VolTargetingPanel — given a risk-parity portfolio with realized vol σ_p,
// scales leverage to hit a target portfolio volatility σ_target.
// Leverage = σ_target / σ_p, applied uniformly to all positions.
//
// Use cases:
//   Target 10% portfolio vol → matches typical 60/40 benchmark vol
//   Target 15% portfolio vol → matches SPY long-term vol
//   Target 8% portfolio vol → conservative income-style book
//
// If portfolio vol < target → suggested leverage > 1 (margin needed)
// If portfolio vol > target → suggested leverage < 1 (hold cash)
const VolTargetingPanel = ({ result, holdings }) => {
  const [targetVol, setTargetVol] = useState(10); // % annualized

  const targeting = useMemo(() => {
    if (!result || result.error || !result.portfolioVol || result.portfolioVol <= 0) return null;
    const portfolioVolPct = result.portfolioVol * 100;
    const leverage = targetVol / portfolioVolPct;
    // Compute total portfolio MV
    const totalMV = holdings.reduce((s, h) => s + Math.abs((h.qty || 0) * (h.mark || 0)), 0);
    if (totalMV <= 0) return null;
    const targetMV = totalMV * leverage;
    const cashAdjustment = targetMV - totalMV;
    // Per-position scaled qty
    const scaledPositions = result.suggestions.map(sug => {
      const holding = holdings.find(h => h.symbol === sug.symbol);
      if (!holding || holding.mark <= 0) return null;
      // Target weight (unleveraged) × leverage = leveraged target weight
      const currentMV = Math.abs(holding.qty * holding.mark);
      const targetUnleveragedMV = totalMV * (sug.targetWeight || 0);
      const targetLeveredMV = targetUnleveragedMV * leverage;
      const targetQty = targetLeveredMV / holding.mark;
      const qtyDelta = targetQty - Math.abs(holding.qty);
      return {
        symbol: sug.symbol,
        currentQty: Math.abs(holding.qty),
        targetQty,
        qtyDelta,
        currentMV,
        targetMV: targetLeveredMV,
        weightChange: (targetLeveredMV - currentMV) / totalMV * 100,
      };
    }).filter(Boolean);
    return {
      portfolioVolPct,
      targetVol,
      leverage,
      totalMV,
      targetMV,
      cashAdjustment,
      scaledPositions,
    };
  }, [result, holdings, targetVol]);

  if (!targeting) return null;

  const isLeveraged = targeting.leverage > 1.05;
  const isCash = targeting.leverage < 0.95;
  const formatMoney = (v) => Math.abs(v) >= 1e6
    ? `$${(v / 1e6).toFixed(2)}M`
    : `$${v.toLocaleString(undefined, { maximumFractionDigits: 0 })}`;

  return (
    <div className="rounded-md border p-3" style={{ borderColor: COLORS.border, background: COLORS.surface }}>
      <div className="flex items-baseline justify-between mb-3 flex-wrap gap-2">
        <div>
          <div className="text-[10px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>
            Volatility targeting
          </div>
          <div className="text-[10.5px] mt-0.5" style={{ color: COLORS.textDim }}>
            Scale leverage to hit a target portfolio vol. RP base vol:
            <strong style={{ color: COLORS.text, marginLeft: 4 }}>
              {targeting.portfolioVolPct.toFixed(2)}%
            </strong> annualized.
          </div>
        </div>
        <div className="flex items-center gap-2">
          <span className="text-[9.5px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>Target vol:</span>
          {[6, 8, 10, 12, 15, 20].map(v => (
            <button key={v} type="button" onClick={() => setTargetVol(v)}
                    className="px-1.5 py-0.5 rounded text-[10.5px] transition-colors"
                    style={{
                      background: targetVol === v ? `${COLORS.mint}1A` : COLORS.bg,
                      color: targetVol === v ? COLORS.mint : COLORS.textDim,
                      border: `1px solid ${targetVol === v ? COLORS.mint : COLORS.border}`,
                    }}>
              {v}%
            </button>
          ))}
        </div>
      </div>

      {/* Summary cards */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-2 mb-3">
        <div className="rounded border p-2"
             style={{
               borderColor: isLeveraged ? `${COLORS.red}55` : isCash ? `${COLORS.green}55` : COLORS.border,
               background: isLeveraged ? `${COLORS.red}05` : isCash ? `${COLORS.green}05` : COLORS.bg,
             }}>
          <div className="text-[9.5px] uppercase tracking-wider"
               style={{ color: isLeveraged ? COLORS.red : isCash ? COLORS.green : COLORS.textMute }}>
            Suggested leverage
          </div>
          <div className="tabular-nums text-[14px] font-medium"
               style={{ color: isLeveraged ? COLORS.red : isCash ? COLORS.green : COLORS.text }}>
            {targeting.leverage.toFixed(2)}x
          </div>
          <div className="text-[9.5px]" style={{ color: COLORS.textMute }}>
            {isLeveraged ? 'borrow to amplify' : isCash ? 'hold cash' : 'no change'}
          </div>
        </div>
        <div className="rounded border p-2" style={{ borderColor: COLORS.border, background: COLORS.bg }}>
          <div className="text-[9.5px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>
            Current MV
          </div>
          <div className="tabular-nums text-[14px] font-medium" style={{ color: COLORS.text }}>
            {formatMoney(targeting.totalMV)}
          </div>
          <div className="text-[9.5px]" style={{ color: COLORS.textMute }}>
            unlevered base
          </div>
        </div>
        <div className="rounded border p-2" style={{ borderColor: COLORS.border, background: COLORS.bg }}>
          <div className="text-[9.5px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>
            Target MV
          </div>
          <div className="tabular-nums text-[14px] font-medium" style={{ color: COLORS.chartGold }}>
            {formatMoney(targeting.targetMV)}
          </div>
          <div className="text-[9.5px]" style={{ color: COLORS.textMute }}>
            after leverage
          </div>
        </div>
        <div className="rounded border p-2" style={{ borderColor: COLORS.border, background: COLORS.bg }}>
          <div className="text-[9.5px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>
            Adjustment
          </div>
          <div className="tabular-nums text-[14px] font-medium"
               style={{ color: targeting.cashAdjustment >= 0 ? COLORS.red : COLORS.green }}>
            {targeting.cashAdjustment >= 0 ? '+' : '−'}{formatMoney(Math.abs(targeting.cashAdjustment))}
          </div>
          <div className="text-[9.5px]" style={{ color: COLORS.textMute }}>
            {targeting.cashAdjustment >= 0 ? 'borrow to add' : 'reduce by'}
          </div>
        </div>
      </div>

      {/* Per-position scaled trades */}
      {targeting.scaledPositions.length > 0 && (
        <div className="rounded border" style={{ borderColor: COLORS.border, background: COLORS.bg }}>
          <div className="px-3 py-1.5 text-[10px] uppercase tracking-wider"
               style={{ color: COLORS.textMute, borderBottom: `1px solid ${COLORS.border}` }}>
            Per-position scaling
          </div>
          <table className="w-full text-[10.5px] tabular-nums">
            <thead>
              <tr style={{ color: COLORS.textMute }}>
                <th className="text-left px-3 py-1">Symbol</th>
                <th className="text-right px-2">Current qty</th>
                <th className="text-right px-2">Target qty</th>
                <th className="text-right px-2">Δ qty</th>
                <th className="text-right px-3">Weight Δ</th>
              </tr>
            </thead>
            <tbody>
              {targeting.scaledPositions.map(p => (
                <tr key={p.symbol} style={{ borderTop: `1px solid ${COLORS.border}` }}>
                  <td className="px-3 py-1" style={{ color: COLORS.text, fontWeight: 500 }}>{p.symbol}</td>
                  <td className="text-right px-2" style={{ color: COLORS.textDim }}>
                    {p.currentQty.toFixed(p.currentQty < 10 ? 2 : 0)}
                  </td>
                  <td className="text-right px-2" style={{ color: COLORS.text }}>
                    {p.targetQty.toFixed(p.targetQty < 10 ? 2 : 0)}
                  </td>
                  <td className="text-right px-2"
                      style={{ color: p.qtyDelta >= 0 ? COLORS.green : COLORS.red, fontWeight: 500 }}>
                    {p.qtyDelta >= 0 ? '+' : ''}{p.qtyDelta.toFixed(p.qtyDelta < 10 ? 2 : 0)}
                  </td>
                  <td className="text-right px-3"
                      style={{
                        color: Math.abs(p.weightChange) > 5 ? COLORS.chartGold : COLORS.textDim,
                        fontWeight: Math.abs(p.weightChange) > 5 ? 500 : 400,
                      }}>
                    {p.weightChange >= 0 ? '+' : ''}{p.weightChange.toFixed(1)}%
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      <div className="text-[10px] mt-2" style={{ color: COLORS.textDim }}>
        <strong>Vol targeting</strong> applies a uniform leverage factor (
        {targeting.leverage.toFixed(2)}x) to all RP-weighted positions to hit the target vol.
        <strong> Pros</strong>: stable risk profile across regimes; comparable to benchmark vol.
        <strong> Cons</strong>: uses realized vol which lags actual vol regime changes — can
        over-leverage entering a high-vol regime (especially around earnings, macro events).
        <strong> Margin/borrow costs</strong>: leverage &gt; 1 incurs financing costs (broker
        margin rates 5-12%). Risk-parity vol-targeted strategies typically need 1.5-2x leverage
        in low-vol regimes — sustained financing drags down realized returns.
      </div>
    </div>
  );
};

// InsiderTradesTab — recent Form 4 insider activity
const InsiderTradesTab = ({ setActive, setPage }) => {
  const [filterType, setFilterType] = useState('all'); // all | buys | sells
  // Live SEC integration: each curated ticker fetches its recent Form 4
  // filings from SEC submissions JSON. The curated dataset stays as the
  // detail source; SEC links provide "verify on SEC" + recent filing
  // dates as a freshness indicator.
  const [liveFilings, setLiveFilings] = useState({}); // ticker → recent Form 4 list
  const [liveStatus, setLiveStatus] = useState('idle'); // idle | loading | ok | error
  const [liveProgress, setLiveProgress] = useState(0);
  // Parsed Form 4 transactions keyed by accession URL
  const [parsedTransactions, setParsedTransactions] = useState({});
  const [parsedCount, setParsedCount] = useState(0);

  const refreshLive = useCallback(async () => {
    setLiveStatus('loading');
    setLiveProgress(0);
    try {
      const tickers = Array.from(new Set(CURATED_INSIDER_TRADES.map(t => t.ticker)));
      const collected = {};
      const batchSize = 4; // SEC fair-access — gentle batching
      for (let i = 0; i < tickers.length; i += batchSize) {
        const batch = tickers.slice(i, i + batchSize);
        const results = await Promise.all(batch.map(async t => {
          const cik = CIK_BY_TICKER[t.replace('.', '')] || CIK_BY_TICKER[t];
          if (!cik) return null;
          try {
            const filings = await fetchSecFilingsByCIK(cik, '4', 8);
            return { ticker: t, filings };
          } catch {
            return null;
          }
        }));
        for (const r of results) {
          if (r && r.filings && r.filings.length > 0) collected[r.ticker] = r.filings;
        }
        setLiveFilings({ ...collected });
        setLiveProgress(Math.min(1, (i + batchSize) / tickers.length));
        // SEC rate limit etiquette
        await new Promise(resolve => setTimeout(resolve, 200));
      }
      setLiveStatus('ok');
      // Phase 2: parse the most recent Form 4 from each ticker for actual transaction data
      let parsed = {};
      let count = 0;
      const allFilingUrls = [];
      for (const tk of Object.keys(collected)) {
        const filings = collected[tk] || [];
        // Take just the most recent filing per ticker to keep parse load reasonable
        if (filings.length > 0) allFilingUrls.push({ ticker: tk, url: filings[0].url, accession: filings[0].accession });
      }
      for (let i = 0; i < allFilingUrls.length; i += 3) {
        const batch = allFilingUrls.slice(i, i + 3);
        const results = await Promise.all(batch.map(async ({ ticker, url, accession }) => {
          try {
            const data = await parseSecForm4(url);
            return { ticker, accession, data };
          } catch {
            return null;
          }
        }));
        for (const r of results) {
          if (r && r.data) {
            parsed[r.accession] = { ...r.data, _ticker: r.ticker, _url: allFilingUrls.find(f => f.accession === r.accession)?.url };
            count++;
          }
        }
        setParsedTransactions({ ...parsed });
        setParsedCount(count);
        await new Promise(resolve => setTimeout(resolve, 250));
      }
    } catch (e) {
      console.warn('[InsiderTradesTab.refreshLive]', e?.message);
      setLiveStatus('error');
    }
  }, []);

  // Combined trades = curated + live-parsed (deduped where possible)
  const filtered = useMemo(() => {
    // Merge in any live-parsed transactions
    const liveTrades = [];
    for (const accession of Object.keys(parsedTransactions)) {
      const p = parsedTransactions[accession];
      for (const t of (p.transactions || [])) {
        liveTrades.push({
          ticker: p._ticker || p.issuerSymbol,
          insider: p.insiderName,
          role: p.insiderRole || (p.isOfficer ? 'Officer' : p.isDirector ? 'Director' : ''),
          type: t.type,
          shares: t.shares,
          pricePerShare: t.price,
          date: t.date,
          form: '4',
          notes: `Code ${t.code} · ${t.acquired === 'A' ? 'Acquired' : 'Disposed'}`,
          _live: true,
          _url: p._url,
        });
      }
    }
    let trades = liveTrades.length > 0 ? liveTrades : CURATED_INSIDER_TRADES;
    if (filterType === 'buys') trades = trades.filter(t => t.type === 'buy');
    else if (filterType === 'sells') trades = trades.filter(t => t.type === 'sell');
    return trades.slice().sort((a, b) => new Date(b.date) - new Date(a.date));
  }, [filterType, parsedTransactions]);

  // Compute cluster scores per ticker (which tickers have most insider activity)
  const clusterScores = useMemo(() => {
    const byTicker = {};
    const sourceTrades = parsedCount > 0
      ? filtered // use the live merge
      : CURATED_INSIDER_TRADES;
    for (const t of sourceTrades) {
      if (!byTicker[t.ticker]) byTicker[t.ticker] = [];
      byTicker[t.ticker].push(t);
    }
    return Object.entries(byTicker).map(([ticker, trades]) => ({
      ticker,
      score: computeInsiderClusterScore(trades),
      buys: trades.filter(t => t.type === 'buy').length,
      sells: trades.filter(t => t.type === 'sell').length,
    })).sort((a, b) => b.score - a.score);
  }, [filtered, parsedCount]);

  // Compute insider transaction velocity per ticker — net flow,
  // buyer/seller counts, cluster signal, velocity vs prior window.
  // Uses the merged live + curated trades dataset.
  const velocityByTicker = useMemo(() => {
    const byTicker = {};
    for (const t of filtered) {
      if (!byTicker[t.ticker]) byTicker[t.ticker] = [];
      // Adapt to the velocity primitive's expected shape
      const value = (Number(t.shares) || 0) * (Number(t.pricePerShare) || 0);
      const acquired = t.type === 'buy' ? 'A' : 'D';
      // Try to extract code from notes ("Code P · Acquired" → "P")
      let code = '';
      if (t.notes) {
        const m = t.notes.match(/Code\s+([A-Z])/);
        if (m) code = m[1];
      }
      byTicker[t.ticker].push({
        date: t.date,
        code,
        shares: Number(t.shares) || 0,
        price: Number(t.pricePerShare) || 0,
        value,
        acquired,
        insiderName: t.insider,
      });
    }
    const out = {};
    for (const ticker of Object.keys(byTicker)) {
      out[ticker] = computeInsiderVelocity(byTicker[ticker], 90);
    }
    return out;
  }, [filtered]);

  // Sort tickers by velocity-weighted insider sentiment for top-of-tab display.
  // Score = sign(netFlow) × log(|netFlow|) × clusterBoost
  const velocityRanking = useMemo(() => {
    return Object.entries(velocityByTicker)
      .filter(([, v]) => v && v.transactionCount >= 1)
      .map(([ticker, v]) => {
        const sign = v.netFlow >= 0 ? 1 : -1;
        const magnitude = Math.log10(Math.max(1, Math.abs(v.netFlow)));
        const clusterBoost = v.clusterSignal ? 1.5 : 1;
        const velocityBoost = v.velocityRatio > 1.5 ? 1.3 : 1;
        return { ticker, velocity: v, score: sign * magnitude * clusterBoost * velocityBoost };
      })
      .sort((a, b) => Math.abs(b.score) - Math.abs(a.score));
  }, [velocityByTicker]);

  const liveTickerCount = useMemo(() => Object.keys(liveFilings).length, [liveFilings]);

  return (
    <div className="space-y-4">
      <div className="rounded-md border p-3"
           style={{ borderColor: COLORS.border, background: COLORS.surface }}>
        <div className="flex items-baseline justify-between mb-2 flex-wrap gap-2">
          <div className="text-[10px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>
            About Form 4 insider trades
          </div>
          <div className="flex items-center gap-2">
            {liveTickerCount > 0 && (
              <span className="text-[10px] uppercase tracking-wider px-1.5 py-0.5 rounded inline-flex items-center gap-1"
                    style={{ background: `${COLORS.green}1A`, color: COLORS.green, border: `1px solid ${COLORS.green}55` }}>
                <span className="rounded-full" style={{ width: 5, height: 5, background: COLORS.green }} />
                {parsedCount > 0 ? `${parsedCount} live filings parsed` : `${liveTickerCount} tickers · live links`}
              </span>
            )}
            <button type="button"
                    onClick={refreshLive}
                    disabled={liveStatus === 'loading'}
                    className="px-2.5 py-1 rounded text-[10.5px] inline-flex items-center gap-1.5 hover:opacity-90 disabled:opacity-40"
                    style={{ background: `${COLORS.mint}1A`, color: COLORS.mint, border: `1px solid ${COLORS.mint}` }}>
              {liveStatus === 'loading'
                ? <RefreshCw size={10} className="animate-spin" />
                : <RefreshCw size={10} />}
              {liveStatus === 'loading'
                ? `Loading… ${(liveProgress * 100).toFixed(0)}%`
                : liveStatus === 'ok' ? 'Refresh SEC'
                : liveStatus === 'error' ? 'Retry'
                : 'Pull live SEC data'}
            </button>
          </div>
        </div>
        <p className="text-[11px]" style={{ color: COLORS.textDim }}>
          Form 4 must be filed within 2 business days of any insider transaction (directors, officers, 10%+
          owners). Insider <strong>buys</strong> are highly informative — insiders rarely buy except when
          they expect upside. Insider <strong>sells</strong> are weaker signals: could be diversification,
          taxes, or pre-arranged 10b5-1 plans, not necessarily a bearish view.
          {' '}<strong>Live SEC EDGAR integration available</strong> — the "Pull live SEC data" button fetches recent Form 4 filings from <code>data.sec.gov/submissions</code> and parses XML transactions for share counts, prices, and codes. Curated dataset stays as fallback when SEC is unreachable or rate-limited.
        </p>
      </div>

      {/* Cluster score summary */}
      <div className="rounded-md border p-3"
           style={{ borderColor: COLORS.border, background: COLORS.surface }}>
        <div className="text-[10px] uppercase tracking-wider mb-2" style={{ color: COLORS.textMute }}>
          Insider conviction · 90-day decayed score (buys weighted 1.5x sells)
        </div>
        <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-2">
          {clusterScores.slice(0, 8).map((c, idx) => {
            const tone = c.score >= 70 ? COLORS.green
                       : c.score >= 40 ? COLORS.text
                       :                  COLORS.red;
            return (
              <div key={idx} className="rounded border p-2"
                   style={{ borderColor: COLORS.border, background: COLORS.bg }}>
                <div className="flex items-baseline justify-between">
                  <button type="button"
                          onClick={() => {
                            const inst = INSTRUMENTS.find(i => i.id?.startsWith(c.ticker + '-') || i.id === c.ticker || i.symbol === c.ticker);
                            if (inst && setActive) setActive(inst);
                            if (setPage) setPage('trade');
                          }}
                          className="text-[12px] font-medium hover:underline"
                          style={{ color: COLORS.text }}>
                    {c.ticker}
                  </button>
                  <span className="tabular-nums text-[12px] font-medium" style={{ color: tone }}>
                    {c.score.toFixed(0)}
                  </span>
                </div>
                <div className="text-[9.5px] mt-0.5" style={{ color: COLORS.textMute }}>
                  {c.buys > 0 && <span style={{ color: COLORS.green }}>{c.buys} buy{c.buys > 1 ? 's' : ''}</span>}
                  {c.buys > 0 && c.sells > 0 && ' · '}
                  {c.sells > 0 && <span style={{ color: COLORS.red }}>{c.sells} sell{c.sells > 1 ? 's' : ''}</span>}
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {/* Insider transaction velocity — net flow + cluster signal +
          velocity ratio per ticker. Closer to Lakonishok-Lee 2001
          methodology than the simple cluster score above. */}
      {velocityRanking.length > 0 && (
        <div className="rounded-md border"
             style={{ borderColor: COLORS.border, background: COLORS.surface }}>
          <div className="px-3 py-2 flex items-baseline justify-between flex-wrap gap-2"
               style={{ borderBottom: `1px solid ${COLORS.border}` }}>
            <div>
              <div className="text-[10px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>
                Insider transaction velocity · 90-day window
              </div>
              <div className="text-[11px] mt-0.5" style={{ color: COLORS.textDim }}>
                Net dollar flow + cluster detection (≥3 distinct buyers) + velocity vs prior 90d. Lakonishok-Lee
                cluster signals historically predict ~5-7% excess returns over 12 months.
              </div>
            </div>
          </div>
          <div className="overflow-x-auto" style={{ maxHeight: 340 }}>
            <table className="w-full text-[11px] tabular-nums">
              <thead style={{ position: 'sticky', top: 0, background: COLORS.bg, zIndex: 1 }}>
                <tr style={{ color: COLORS.textMute }}>
                  <th className="text-left px-2 py-1.5">Ticker</th>
                  <th className="text-right px-2">Net Flow</th>
                  <th className="text-right px-2">Buys $</th>
                  <th className="text-right px-2">Sells $</th>
                  <th className="text-right px-2">Buyers</th>
                  <th className="text-right px-2">OM Buys</th>
                  <th className="text-right px-2">Velocity</th>
                  <th className="text-left px-2">Signal</th>
                </tr>
              </thead>
              <tbody>
                {velocityRanking.slice(0, 16).map((r, idx) => {
                  const v = r.velocity;
                  const flowTone = v.netFlow >= 100000 ? COLORS.green
                                 : v.netFlow > 0 ? '#7AC8FF'
                                 : v.netFlow >= -100000 ? COLORS.textDim
                                 :                  COLORS.red;
                  const velTone = v.velocityRatio >= 2 ? COLORS.mint
                                : v.velocityRatio >= 1.3 ? '#7AC8FF'
                                : v.velocityRatio < 0.5 ? COLORS.textMute
                                :                          COLORS.textDim;
                  // Signal label
                  let signal = '—';
                  let signalTone = COLORS.textMute;
                  if (v.clusterSignal && v.netFlow > 0) {
                    signal = '★ Cluster buy';
                    signalTone = COLORS.green;
                  } else if (v.openMarketBuys >= 1 && v.netFlow > 0) {
                    signal = 'Open-market buying';
                    signalTone = COLORS.green;
                  } else if (v.netFlow > 0) {
                    signal = 'Net buying';
                    signalTone = '#7AC8FF';
                  } else if (v.sellerCount >= 3 && v.netFlow < -100000) {
                    signal = 'Cluster selling';
                    signalTone = COLORS.red;
                  } else if (v.netFlow < -100000) {
                    signal = 'Net selling';
                    signalTone = COLORS.red;
                  }
                  return (
                    <tr key={idx} style={{ borderTop: `1px solid ${COLORS.border}` }}>
                      <td className="px-2 py-1">
                        <button type="button"
                                onClick={() => {
                                  const inst = INSTRUMENTS.find(i => i.id?.startsWith(r.ticker + '-') || i.id === r.ticker || i.symbol === r.ticker);
                                  if (inst && setActive) setActive(inst);
                                  if (setPage) setPage('trade');
                                }}
                                className="hover:underline"
                                style={{ color: COLORS.text, fontWeight: 500 }}>
                          {r.ticker}
                        </button>
                      </td>
                      <td className="text-right px-2"
                          style={{ color: flowTone, fontWeight: 500 }}>
                        {v.netFlow >= 0 ? '+' : '−'}${Math.abs(v.netFlow) >= 1e6
                          ? `${(Math.abs(v.netFlow) / 1e6).toFixed(2)}M`
                          : `${(Math.abs(v.netFlow) / 1e3).toFixed(0)}K`}
                      </td>
                      <td className="text-right px-2"
                          style={{ color: v.buyDollars > 0 ? COLORS.green : COLORS.textMute }}>
                        ${v.buyDollars >= 1e6
                          ? `${(v.buyDollars / 1e6).toFixed(2)}M`
                          : `${(v.buyDollars / 1e3).toFixed(0)}K`}
                      </td>
                      <td className="text-right px-2"
                          style={{ color: v.sellDollars > 0 ? COLORS.red : COLORS.textMute }}>
                        ${v.sellDollars >= 1e6
                          ? `${(v.sellDollars / 1e6).toFixed(2)}M`
                          : `${(v.sellDollars / 1e3).toFixed(0)}K`}
                      </td>
                      <td className="text-right px-2"
                          style={{ color: v.buyerCount >= 3 ? COLORS.green : COLORS.textDim }}>
                        {v.buyerCount}/{v.sellerCount}
                      </td>
                      <td className="text-right px-2"
                          style={{ color: v.openMarketBuys >= 1 ? COLORS.green : COLORS.textMute, fontWeight: v.openMarketBuys >= 1 ? 500 : 400 }}>
                        {v.openMarketBuys}
                      </td>
                      <td className="text-right px-2" style={{ color: velTone }}>
                        {v.velocityRatio === 99 ? '∞'
                         : v.velocityRatio === 0 ? '—'
                         : `${v.velocityRatio.toFixed(1)}x`}
                      </td>
                      <td className="px-2 text-[10px]"
                          style={{ color: signalTone, fontWeight: signal !== '—' ? 500 : 400 }}>
                        {signal}
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
          <div className="px-3 py-2 text-[10px]"
               style={{ color: COLORS.textDim, borderTop: `1px solid ${COLORS.border}` }}>
            <strong>Net flow</strong> excludes tax-withholding (F), grants (A), and option exercises (M) — these aren't real market signals.
            <strong> OM buys</strong> = open-market purchases (code P), the cleanest bullish signal — insiders rarely buy with personal cash unless they expect upside.
            <strong> Cluster signal</strong> requires ≥3 distinct buyers in the window. Active velocity (&gt;1.5x) often precedes news.
          </div>
        </div>
      )}

      {/* Derivative activity summary — RSU vests, option grants, exercises.
          Only renders when live SEC parsing has supplied derivative data.
          Not as signal-rich as open-market buys/sells but shows the
          composition of insider compensation events. */}
      {(() => {
        const allDerivatives = [];
        for (const accession of Object.keys(parsedTransactions)) {
          const p = parsedTransactions[accession];
          if (!p.derivatives || p.derivatives.length === 0) continue;
          for (const d of p.derivatives) {
            allDerivatives.push({
              ...d,
              ticker: p._ticker || p.issuerSymbol,
              insider: p.insiderName,
              role: p.insiderRole || '',
            });
          }
        }
        if (allDerivatives.length === 0) return null;
        // Bucket by type
        const byType = {};
        for (const d of allDerivatives) {
          if (!byType[d.type]) byType[d.type] = { count: 0, totalShares: 0 };
          byType[d.type].count++;
          byType[d.type].totalShares += d.shares;
        }
        const TYPE_LABELS = {
          'rsu-grant': 'RSU grants',
          'rsu-vest':  'RSU vests',
          'rsu-other': 'RSU activity',
          'option-grant':    'Option grants',
          'option-exercise': 'Option exercises',
          'option-other':    'Option activity',
          'tax-withhold':    'Tax withholding',
          'derivative-other':'Other derivatives',
        };
        return (
          <div className="rounded-md border p-3"
               style={{ borderColor: COLORS.border, background: COLORS.surface }}>
            <div className="flex items-baseline justify-between mb-2">
              <div className="text-[10px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>
                Derivative table activity · live SEC
              </div>
              <div className="text-[9.5px]" style={{ color: COLORS.textMute }}>
                {allDerivatives.length} events · {Object.keys(byType).length} types
              </div>
            </div>
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-2">
              {Object.entries(byType)
                .sort((a, b) => b[1].count - a[1].count)
                .slice(0, 8)
                .map(([type, agg]) => (
                  <div key={type} className="rounded border p-2"
                       style={{ borderColor: COLORS.border, background: COLORS.bg }}>
                    <div className="text-[9.5px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>
                      {TYPE_LABELS[type] || type}
                    </div>
                    <div className="tabular-nums text-[12px] mt-0.5" style={{ color: COLORS.text }}>
                      {agg.count}× · {agg.totalShares >= 1e6
                        ? `${(agg.totalShares / 1e6).toFixed(1)}M`
                        : `${(agg.totalShares / 1e3).toFixed(0)}K`} sh
                    </div>
                  </div>
                ))}
            </div>
            <div className="text-[10px] mt-2" style={{ color: COLORS.textDim }}>
              <strong>Compensation events</strong>, not directional bets. RSU vests + option exercises are routine — the signal is in the open-market P/S transactions in the table below.
              {' '}<strong>Tax withholding</strong> (code F) is automatic share withholding on RSU vest dates; not a discretionary sale.
            </div>
          </div>
        );
      })()}

      {/* Filters */}
      <div className="flex items-center gap-1.5">
        {[
          { id: 'all',   label: 'All' },
          { id: 'buys',  label: 'Buys only' },
          { id: 'sells', label: 'Sells only' },
        ].map(f => (
          <button key={f.id} type="button"
                  onClick={() => setFilterType(f.id)}
                  className="px-2.5 py-1 rounded text-[11px] transition-colors"
                  style={{
                    background: filterType === f.id ? `${COLORS.mint}1A` : COLORS.bg,
                    color: filterType === f.id ? COLORS.mint : COLORS.textDim,
                    border: `1px solid ${filterType === f.id ? COLORS.mint : COLORS.border}`,
                  }}>
            {f.label}
          </button>
        ))}
      </div>

      {/* Trades list */}
      <div className="rounded-md border"
           style={{ borderColor: COLORS.border, background: COLORS.surface }}>
        <div className="overflow-x-auto">
          <table className="w-full text-[11px] tabular-nums">
            <thead>
              <tr style={{ color: COLORS.textMute, background: COLORS.bg }}>
                <th className="text-left px-2 py-1.5">Date</th>
                <th className="text-left px-2">Ticker</th>
                <th className="text-left px-2">Insider</th>
                <th className="text-left px-2">Type</th>
                <th className="text-right px-2">Shares</th>
                <th className="text-right px-2">Price</th>
                <th className="text-right px-2">Value</th>
                <th className="text-left px-2">Notes</th>
              </tr>
            </thead>
            <tbody>
              {filtered.map((t, idx) => {
                const value = t.shares * t.pricePerShare;
                const tone = t.type === 'buy' ? COLORS.green : COLORS.red;
                return (
                  <tr key={idx} style={{ borderTop: `1px solid ${COLORS.border}` }}>
                    <td className="px-2 py-1" style={{ color: COLORS.textDim }}>{t.date}</td>
                    <td className="px-2 py-1">
                      <button type="button"
                              onClick={() => {
                                const inst = INSTRUMENTS.find(i => i.id?.startsWith(t.ticker + '-') || i.id === t.ticker || i.symbol === t.ticker);
                                if (inst && setActive) setActive(inst);
                                if (setPage) setPage('trade');
                              }}
                              className="font-medium hover:underline"
                              style={{ color: COLORS.text }}>
                        {t.ticker}
                      </button>
                    </td>
                    <td className="px-2 py-1" style={{ color: COLORS.text }}>
                      {t.insider} <span className="text-[10px]" style={{ color: COLORS.textMute }}>· {t.role}</span>
                    </td>
                    <td className="px-2 py-1">
                      <span className="text-[10.5px] uppercase tracking-wider px-1.5 py-0.5 rounded font-medium"
                            style={{ background: `${tone}20`, color: tone }}>
                        {t.type}
                      </span>
                    </td>
                    <td className="text-right px-2" style={{ color: COLORS.textDim }}>
                      {t.shares.toLocaleString()}
                    </td>
                    <td className="text-right px-2" style={{ color: COLORS.textDim }}>
                      ${t.pricePerShare.toFixed(2)}
                    </td>
                    <td className="text-right px-2" style={{ color: tone, fontWeight: 500 }}>
                      ${(value / 1e6).toFixed(2)}M
                    </td>
                    <td className="px-2 py-1 text-[10.5px]" style={{ color: COLORS.textMute }}>
                      <div className="flex items-center gap-1.5">
                        {t._live && (
                          <span className="rounded-full" style={{ width: 5, height: 5, background: COLORS.green, flexShrink: 0 }}
                                title="Live SEC filing data" />
                        )}
                        <span className="truncate">{t.notes}</span>
                        {t._url && (
                          <a href={t._url} target="_blank" rel="noopener noreferrer"
                             className="hover:underline"
                             style={{ color: COLORS.mint, fontSize: 9, flexShrink: 0 }}
                             title="View Form 4 on SEC EDGAR">
                            ↗ SEC
                          </a>
                        )}
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
      {/* Insider cluster-buy backtester — checks if cluster-buy signal
          historically led to forward returns. */}
      <InsiderClusterBuyBacktester />
    </div>
  );
};

// InsiderClusterBuyBacktester — historical efficacy test for the cluster-
// buy signal. For each ticker in the SP500 / curated universe, it:
//   1. Looks up Form 4 insider buy clusters in the past N years (≥3
//      distinct insiders buying within a 90-day window)
//   2. For each cluster signal, measures forward returns at 1m / 3m /
//      6m / 12m relative to SPY benchmark
//   3. Computes hit-rate (% of signals with positive excess return) +
//      average outperformance + worst case
//
// Limitations: SEC EDGAR rate-limited at 10 req/s, so we cap at 20
// tickers and take a few seconds per run. The Lakonishok-Lee 2001 study
// used 12-year windows and full SP500 — our shorter sample is indicative
// not definitive.
const INSIDER_BACKTEST_TICKERS_DEFAULT = [
  'AAPL', 'MSFT', 'GOOGL', 'AMZN', 'NVDA', 'META', 'TSLA', 'JPM',
  'V', 'WMT', 'PG', 'JNJ', 'XOM', 'BAC', 'KO', 'PEP', 'DIS', 'CSCO',
  'NFLX', 'AMD',
];
const InsiderClusterBuyBacktester = () => {
  const [tickerList, setTickerList] = useState(INSIDER_BACKTEST_TICKERS_DEFAULT.join(', '));
  const [running, setRunning] = useState(false);
  const [progress, setProgress] = useState(0);
  const [results, setResults] = useState(null);
  const [error, setError] = useState(null);

  const runBacktest = useCallback(async () => {
    const tickers = tickerList.split(',').map(t => t.trim().toUpperCase()).filter(Boolean).slice(0, 20);
    if (tickers.length === 0) {
      setError('Provide at least 1 ticker');
      return;
    }
    setRunning(true);
    setError(null);
    setProgress(0);
    setResults(null);
    const allSignals = []; // each: { ticker, clusterDate, fwdReturn1m, fwdReturn3m, ... }
    try {
      for (let i = 0; i < tickers.length; i++) {
        const ticker = tickers[i];
        setProgress((i / tickers.length) * 100);
        const cik = CIK_BY_TICKER[ticker];
        if (!cik) continue;
        try {
          // Pull Form 4 history (more entries for backtest)
          const filings = await fetchSecFilingsByCIK(cik, '4', 80);
          if (!filings || filings.length === 0) continue;
          // Fetch transactions per filing (all in parallel-light; SEC is rate-limited
          // so we batch with delay)
          const allTxns = [];
          for (const f of filings.slice(0, 40)) {
            try {
              const txns = await parseSecForm4(f.url);
              if (txns?.transactions) {
                for (const t of txns.transactions) {
                  if (!t.date) continue;
                  allTxns.push({ ...t, filing: f, _date: new Date(t.date).getTime() });
                }
              }
            } catch {}
            // SEC fair-access pacing
            await new Promise(r => setTimeout(r, 80));
          }
          if (allTxns.length === 0) continue;
          // Sort by date
          allTxns.sort((a, b) => a._date - b._date);
          // Detect cluster-buy events: ≥3 distinct insiders buying within
          // 90-day rolling window (with non-market codes filtered out)
          const buys = allTxns.filter(t =>
            t.acquiredDisposed === 'A' && // Acquired
            !['F', 'M', 'A', 'G'].includes(t.transactionCode) // exclude non-market
          );
          if (buys.length === 0) continue;
          // Walk through, find first cluster moment
          const clusterEvents = [];
          for (let j = 0; j < buys.length; j++) {
            const window = buys.filter(b =>
              b._date <= buys[j]._date && b._date > buys[j]._date - 90 * 86400000
            );
            const distinctInsiders = new Set(window.map(b => b.insider || b.reportingPerson));
            if (distinctInsiders.size >= 3) {
              clusterEvents.push({
                date: buys[j]._date,
                insiderCount: distinctInsiders.size,
                txnCount: window.length,
              });
              break; // first cluster only — avoid multiple from same window
            }
          }
          if (clusterEvents.length === 0) continue;
          // For each cluster event, fetch forward returns
          const tickerBars = await fetchPolygonAggs(ticker, '5Y', 'day', 1).catch(() => null);
          const spyBars = await fetchPolygonAggs('SPY', '5Y', 'day', 1).catch(() => null);
          if (!tickerBars || !spyBars) continue;
          const findClose = (bars, ts) => {
            for (let k = 0; k < bars.length; k++) {
              if (new Date(bars[k].date).getTime() >= ts) return { idx: k, close: bars[k].close };
            }
            return null;
          };
          for (const event of clusterEvents) {
            const eventDay = findClose(tickerBars, event.date);
            const eventDaySpy = findClose(spyBars, event.date);
            if (!eventDay || !eventDaySpy) continue;
            const horizons = [
              { days: 21, label: '1m' },
              { days: 63, label: '3m' },
              { days: 126, label: '6m' },
              { days: 252, label: '12m' },
            ];
            const fwdReturns = {};
            for (const h of horizons) {
              const targetIdx = eventDay.idx + h.days;
              const targetIdxSpy = eventDaySpy.idx + h.days;
              if (targetIdx >= tickerBars.length || targetIdxSpy >= spyBars.length) {
                fwdReturns[h.label] = null;
                continue;
              }
              const tickerRet = (tickerBars[targetIdx].close - eventDay.close) / eventDay.close;
              const spyRet = (spyBars[targetIdxSpy].close - eventDaySpy.close) / eventDaySpy.close;
              fwdReturns[h.label] = {
                ticker: tickerRet,
                spy: spyRet,
                excess: tickerRet - spyRet,
              };
            }
            allSignals.push({
              ticker,
              date: new Date(event.date).toISOString().slice(0, 10),
              insiderCount: event.insiderCount,
              fwdReturns,
            });
          }
        } catch (e) {
          console.warn(`[InsiderBacktest] ${ticker}:`, e?.message);
        }
        // Update intermediate progress
        setResults({ signals: [...allSignals], complete: false });
      }
      setProgress(100);
      // Aggregate stats
      const aggregates = {};
      for (const horizon of ['1m', '3m', '6m', '12m']) {
        const data = allSignals.map(s => s.fwdReturns[horizon]).filter(r => r != null);
        if (data.length === 0) continue;
        const tickerRets = data.map(d => d.ticker);
        const excessRets = data.map(d => d.excess);
        const wins = excessRets.filter(r => r > 0).length;
        const meanExcess = excessRets.reduce((s, r) => s + r, 0) / excessRets.length;
        const meanTicker = tickerRets.reduce((s, r) => s + r, 0) / tickerRets.length;
        // Best / worst
        const sorted = excessRets.slice().sort((a, b) => a - b);
        aggregates[horizon] = {
          n: data.length,
          meanExcess,
          meanTicker,
          hitRate: (wins / data.length) * 100,
          worst: sorted[0],
          best: sorted[sorted.length - 1],
          median: sorted[Math.floor(sorted.length / 2)],
        };
      }
      setResults({ signals: allSignals, aggregates, complete: true });
    } catch (e) {
      setError(e?.message || 'Backtest failed');
    } finally {
      setRunning(false);
    }
  }, [tickerList]);

  return (
    <div className="rounded-md border p-3"
         style={{ borderColor: COLORS.border, background: COLORS.surface }}>
      <div className="flex items-baseline justify-between mb-3 flex-wrap gap-2">
        <div>
          <div className="text-[10px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>
            Cluster-buy backtester
          </div>
          <div className="text-[10.5px] mt-0.5" style={{ color: COLORS.textDim }}>
            Test if ≥3 distinct insider buys in 90 days predict outperformance
            (Lakonishok-Lee 2001 baseline). 5Y price history vs SPY benchmark.
          </div>
        </div>
      </div>

      {/* Inputs */}
      <div className="flex gap-2 items-end mb-3 flex-wrap">
        <div className="flex-1 min-w-0">
          <div className="text-[9.5px] uppercase tracking-wider mb-1" style={{ color: COLORS.textMute }}>
            Tickers (comma-separated, max 20)
          </div>
          <textarea value={tickerList}
                    onChange={(e) => setTickerList(e.target.value.toUpperCase())}
                    rows={2}
                    className="w-full px-2 py-1.5 rounded text-[11px] outline-none uppercase font-mono resize-y"
                    style={{ background: COLORS.bg, color: COLORS.text, border: `1px solid ${COLORS.border}` }} />
        </div>
        <button type="button" onClick={runBacktest}
                disabled={running}
                className="px-3 py-1.5 rounded text-[11.5px] font-medium hover:opacity-90 disabled:opacity-40 inline-flex items-center gap-1.5"
                style={{ background: COLORS.mint, color: COLORS.bg }}>
          <Play size={11} />
          {running ? `Running… ${Math.round(progress)}%` : 'Run backtest'}
        </button>
      </div>

      {error && (
        <div className="rounded p-2 text-[11px] mb-3"
             style={{ background: 'rgba(255,85,119,0.06)', color: COLORS.red, border: `1px solid ${COLORS.red}55` }}>
          {error}
        </div>
      )}

      {results && results.signals && results.signals.length > 0 && (
        <>
          {/* Aggregate results */}
          {results.aggregates && (
            <div className="rounded-md border mb-3" style={{ borderColor: COLORS.border, background: COLORS.bg }}>
              <div className="px-3 py-1.5 text-[10px] uppercase tracking-wider"
                   style={{ color: COLORS.textMute, borderBottom: `1px solid ${COLORS.border}` }}>
                Aggregate forward returns · {results.signals.length} cluster events
              </div>
              <table className="w-full text-[10.5px] tabular-nums">
                <thead>
                  <tr style={{ color: COLORS.textMute }}>
                    <th className="text-left px-3 py-1.5">Horizon</th>
                    <th className="text-right px-2">N signals</th>
                    <th className="text-right px-2">Hit rate</th>
                    <th className="text-right px-2">Mean ticker ret</th>
                    <th className="text-right px-2">Mean excess vs SPY</th>
                    <th className="text-right px-2">Median excess</th>
                    <th className="text-right px-3">Range</th>
                  </tr>
                </thead>
                <tbody>
                  {['1m', '3m', '6m', '12m'].map(h => {
                    const a = results.aggregates[h];
                    if (!a) return null;
                    return (
                      <tr key={h} style={{ borderTop: `1px solid ${COLORS.border}` }}>
                        <td className="px-3 py-1" style={{ color: COLORS.text, fontWeight: 500 }}>{h}</td>
                        <td className="text-right px-2" style={{ color: COLORS.textDim }}>{a.n}</td>
                        <td className="text-right px-2"
                            style={{ color: a.hitRate > 55 ? COLORS.green : a.hitRate < 45 ? COLORS.red : COLORS.text }}>
                          {a.hitRate.toFixed(0)}%
                        </td>
                        <td className="text-right px-2"
                            style={{ color: a.meanTicker > 0 ? COLORS.green : COLORS.red }}>
                          {a.meanTicker >= 0 ? '+' : ''}{(a.meanTicker * 100).toFixed(1)}%
                        </td>
                        <td className="text-right px-2"
                            style={{
                              color: a.meanExcess > 0.02 ? COLORS.green
                                   : a.meanExcess > 0 ? '#7AC8FF'
                                   : a.meanExcess < -0.02 ? COLORS.red : COLORS.text,
                              fontWeight: 500,
                            }}>
                          {a.meanExcess >= 0 ? '+' : ''}{(a.meanExcess * 100).toFixed(1)}%
                        </td>
                        <td className="text-right px-2" style={{ color: COLORS.textDim }}>
                          {a.median >= 0 ? '+' : ''}{(a.median * 100).toFixed(1)}%
                        </td>
                        <td className="text-right px-3 text-[10px]" style={{ color: COLORS.textMute }}>
                          {(a.worst * 100).toFixed(0)}% to {a.best >= 0 ? '+' : ''}{(a.best * 100).toFixed(0)}%
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}

          {/* Per-signal table — first 15 */}
          <div className="rounded-md border" style={{ borderColor: COLORS.border, background: COLORS.bg }}>
            <div className="px-3 py-1.5 text-[10px] uppercase tracking-wider"
                 style={{ color: COLORS.textMute, borderBottom: `1px solid ${COLORS.border}` }}>
              Recent cluster signals · {Math.min(15, results.signals.length)} of {results.signals.length}
            </div>
            <div className="overflow-x-auto" style={{ maxHeight: 280 }}>
              <table className="w-full text-[10.5px] tabular-nums">
                <thead style={{ position: 'sticky', top: 0, background: COLORS.bg }}>
                  <tr style={{ color: COLORS.textMute }}>
                    <th className="text-left px-3 py-1.5">Ticker</th>
                    <th className="text-left px-2">Cluster date</th>
                    <th className="text-right px-2">Insiders</th>
                    <th className="text-right px-2">1m excess</th>
                    <th className="text-right px-2">3m excess</th>
                    <th className="text-right px-2">6m excess</th>
                    <th className="text-right px-3">12m excess</th>
                  </tr>
                </thead>
                <tbody>
                  {results.signals.slice(-15).reverse().map((s, i) => (
                    <tr key={i} style={{ borderTop: `1px solid ${COLORS.border}` }}>
                      <td className="px-3 py-1" style={{ color: COLORS.text, fontWeight: 500 }}>
                        {s.ticker}
                      </td>
                      <td className="px-2 text-[10px]" style={{ color: COLORS.textDim }}>{s.date}</td>
                      <td className="text-right px-2" style={{ color: COLORS.text }}>
                        {s.insiderCount}
                      </td>
                      {['1m', '3m', '6m', '12m'].map(h => {
                        const r = s.fwdReturns[h];
                        if (!r) return <td key={h} className="text-right px-2" style={{ color: COLORS.textMute }}>—</td>;
                        return (
                          <td key={h} className="text-right px-2"
                              style={{ color: r.excess > 0 ? COLORS.green : COLORS.red }}>
                            {r.excess >= 0 ? '+' : ''}{(r.excess * 100).toFixed(1)}%
                          </td>
                        );
                      })}
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </>
      )}

      <div className="text-[10px] mt-2" style={{ color: COLORS.textDim }}>
        <strong>Hit rate</strong>: % of cluster signals followed by positive excess return vs SPY.
        Random would be 50%; meaningful skill is 55%+ sustained. <strong>Mean excess</strong>:
        average outperformance per signal — original Lakonishok-Lee 2001 finding was +5-7% at
        12 months. Modern markets have weaker but still positive results.
        <strong> Caveats</strong>: SEC rate limits cap us at 20 tickers. Cluster events are first-occurrence
        only per ticker (not all clusters); sample sizes are smaller than academic studies. 10b5-1 plan
        trades aren't filtered (Polygon Form 4 doesn't tag this) — would dampen the signal further.
      </div>
    </div>
  );
};

// MultiStrategyBacktestTab — combines signals from Black-Litterman /
// Risk Parity / Equal-Weight / Momentum into a unified portfolio
// backtest with walk-forward methodology to avoid lookahead bias.
//
// Walk-forward design:
//   1. Split history into 6 folds
//   2. For each fold N: estimate strategy weights using folds 1..N-1
//   3. Apply those weights to fold N (out-of-sample)
//   4. Concatenate fold N OOS returns into the full equity curve
//
// This avoids the classic backtest cheat where weights are optimized
// using the SAME data they're tested on (which always shows great
// results but is meaningless out-of-sample).
const MultiStrategyBacktestTab = ({ account, portfolioSource, setActive, setPage }) => {
  // Resolve current holdings the same way other tabs do
  const holdings = useMemo(() => {
    if (portfolioSource?.source === 'broker' && portfolioSource.positions?.length > 0) {
      return portfolioSource.positions.map(p => ({
        symbol: p.symbol,
        qty: Number(p.qty) || 0,
        mark: Number(p.mark) || 0,
      }));
    }
    const positions = account?.positions ?? [];
    return positions.map(p => {
      const sym = p.instrument?.id?.split('-')[0] ?? p.symbol ?? '';
      return {
        symbol: sym,
        qty: Number(p.qty) || 0,
        mark: Number(p.mark) || 0,
      };
    }).filter(h => h.symbol && h.qty !== 0 && h.mark > 0);
  }, [account, portfolioSource]);

  const [returnsBySymbol, setReturnsBySymbol] = useState({});
  const [loading, setLoading] = useState(false);
  const [enabledStrategies, setEnabledStrategies] = useState({
    equalWeight: true,
    marketCap:   true,
    riskParity:  true,
    momentum:    true,
    blackLitterman: false, // requires views, more complex
  });
  const [folds, setFolds] = useState(6);
  const [rebalanceFreq, setRebalanceFreq] = useState(21); // every N bars

  // Pull 1-year of daily returns for each holding
  useEffect(() => {
    if (holdings.length < 2) return undefined;
    let cancelled = false;
    setLoading(true);
    const symbols = holdings.map(h => h.symbol);
    Promise.all(symbols.map(s =>
      fetchPolygonAggs(s, '1Y', 'day', 1).catch(() => null)
    )).then(results => {
      if (cancelled) return;
      const map = {};
      for (let i = 0; i < symbols.length; i++) {
        const data = results[i];
        if (!data || data.length < 30) continue;
        const closes = data.map(d => d.close).filter(c => c > 0);
        const rets = [];
        for (let k = 1; k < closes.length; k++) {
          rets.push((closes[k] - closes[k - 1]) / closes[k - 1]);
        }
        map[symbols[i]] = rets;
      }
      setReturnsBySymbol(map);
    }).finally(() => {
      if (!cancelled) setLoading(false);
    });
    return () => { cancelled = true; };
  }, [holdings]);

  // Run the walk-forward backtest
  const result = useMemo(() => {
    const symbols = holdings.map(h => h.symbol).filter(s => returnsBySymbol[s]?.length >= 30);
    if (symbols.length < 2) {
      return { error: 'Need at least 2 holdings with sufficient return history' };
    }
    const minLen = Math.min(...symbols.map(s => returnsBySymbol[s].length));
    if (minLen < 60) {
      return { error: `Need ≥60 bars of history (have ${minLen})` };
    }
    const series = symbols.map(s => returnsBySymbol[s].slice(-minLen));
    const n = symbols.length;
    const T = minLen;
    const foldSize = Math.floor(T / folds);
    if (foldSize < 10) {
      return { error: 'Fold size too small; reduce folds or get more history' };
    }
    // Strategy weight calculators — each takes a "training window"
    // (n × T_train matrix of returns) and returns weights vector.
    const calcWeights = {
      equalWeight: (training) => Array(training.length).fill(1 / training.length),
      marketCap: (training) => {
        // Use current MV as proxy (constant weights)
        const mvs = holdings.map(h => Math.abs(h.qty * h.mark) || 1);
        const ord = symbols.map(s => holdings.findIndex(h => h.symbol === s));
        const mvOrdered = ord.map(i => mvs[i]);
        const tot = mvOrdered.reduce((a, b) => a + b, 0);
        return mvOrdered.map(v => v / tot);
      },
      riskParity: (training) => {
        // Weights inversely proportional to volatility
        const vols = training.map(s => {
          const m = s.reduce((a, b) => a + b, 0) / s.length;
          const v = s.reduce((a, b) => a + (b - m) ** 2, 0) / s.length;
          return Math.sqrt(v);
        });
        const invVols = vols.map(v => v > 0 ? 1 / v : 0);
        const sum = invVols.reduce((a, b) => a + b, 0);
        return sum > 0 ? invVols.map(v => v / sum) : invVols.map(() => 1 / training.length);
      },
      momentum: (training) => {
        // Long top-half momentum, equal-weight (zero short)
        const lookback = Math.min(63, training[0].length); // 3-month momentum
        const momentums = training.map(s => {
          const slice = s.slice(-lookback);
          return slice.reduce((a, b) => a * (1 + b), 1) - 1;
        });
        const sortedIdx = momentums
          .map((m, i) => ({ m, i }))
          .sort((a, b) => b.m - a.m)
          .slice(0, Math.ceil(training.length / 2))
          .map(x => x.i);
        const w = Array(training.length).fill(0);
        const wt = 1 / sortedIdx.length;
        for (const idx of sortedIdx) w[idx] = wt;
        return w;
      },
      blackLitterman: (training) => {
        // Run BL with no views (just implied equilibrium based on
        // the training window's covariance structure)
        const mvs = holdings.map(h => Math.abs(h.qty * h.mark) || 1);
        const aug = symbols.map((s, i) => {
          const idx = holdings.findIndex(h => h.symbol === s);
          return {
            symbol: s,
            qty: holdings[idx]?.qty || 1,
            mark: holdings[idx]?.mark || 1,
            returns: training[i],
          };
        });
        const blRes = runBlackLitterman({ holdings: aug, views: [], delta: 2.5, tau: 0.05 });
        if (blRes.error) {
          return Array(training.length).fill(1 / training.length);
        }
        return symbols.map(s => blRes.optimalWeights[s] || 0);
      },
    };

    // Walk-forward equity curves — one per enabled strategy
    const enabledStrats = Object.keys(enabledStrategies).filter(s => enabledStrategies[s]);
    if (enabledStrats.length === 0) {
      return { error: 'Enable at least one strategy' };
    }
    const equityCurves = {};
    const oosReturns = {};
    for (const strat of enabledStrats) {
      const oosRets = [];
      for (let foldIdx = 1; foldIdx < folds; foldIdx++) {
        // Training data = bars 0..(foldIdx * foldSize - 1)
        const trainEnd = foldIdx * foldSize;
        const training = series.map(s => s.slice(0, trainEnd));
        const weights = calcWeights[strat](training);
        // Apply weights with periodic rebalancing inside the OOS fold
        const oosStart = trainEnd;
        const oosEnd = Math.min(T, (foldIdx + 1) * foldSize);
        for (let t = oosStart; t < oosEnd; t++) {
          // Optional rebalance: refresh weights every rebalanceFreq bars
          // by extending training data into the OOS fold up to t (still OK
          // because we're using past info to set weights at time t)
          const useWeights = (rebalanceFreq > 0 && (t - oosStart) > 0 && (t - oosStart) % rebalanceFreq === 0)
            ? calcWeights[strat](series.map(s => s.slice(0, t)))
            : weights;
          let portRet = 0;
          for (let i = 0; i < n; i++) {
            portRet += useWeights[i] * series[i][t];
          }
          oosRets.push(portRet);
        }
      }
      // Build equity curve
      const equity = [1];
      for (const r of oosRets) {
        equity.push(equity[equity.length - 1] * (1 + r));
      }
      equityCurves[strat] = equity;
      oosReturns[strat] = oosRets;
    }

    // Compute summary stats per strategy
    const stats = {};
    for (const strat of enabledStrats) {
      const rets = oosReturns[strat];
      if (rets.length === 0) continue;
      const mean = rets.reduce((a, b) => a + b, 0) / rets.length;
      const variance = rets.reduce((a, b) => a + (b - mean) ** 2, 0) / rets.length;
      const std = Math.sqrt(variance);
      const annRet = mean * 252 * 100;
      const annVol = std * Math.sqrt(252) * 100;
      const sharpe = std > 0 ? (mean / std) * Math.sqrt(252) : 0;
      // Max drawdown
      const eq = equityCurves[strat];
      let peak = eq[0], maxDD = 0;
      for (const v of eq) {
        if (v > peak) peak = v;
        const dd = peak > 0 ? (v - peak) / peak : 0;
        if (dd < maxDD) maxDD = dd;
      }
      stats[strat] = {
        annRet, annVol, sharpe,
        maxDD: maxDD * 100,
        finalReturn: (eq[eq.length - 1] - 1) * 100,
        winRate: rets.filter(r => r > 0).length / rets.length * 100,
        n: rets.length,
      };
    }

    return {
      strategies: enabledStrats,
      equityCurves,
      stats,
      foldSize,
      totalBars: T,
      symbols,
      error: null,
    };
  }, [holdings, returnsBySymbol, enabledStrategies, folds, rebalanceFreq]);

  const STRAT_LABELS = {
    equalWeight: 'Equal Weight',
    marketCap:   'Market Cap',
    riskParity:  'Risk Parity',
    momentum:    'Momentum (3M)',
    blackLitterman: 'Black-Litterman',
  };
  const STRAT_COLORS = {
    equalWeight: COLORS.textDim,
    marketCap:   '#7AC8FF',
    riskParity:  COLORS.mint,
    momentum:    COLORS.green,
    blackLitterman: COLORS.chartGold,
  };

  return (
    <div className="space-y-4">
      <div className="rounded-md border p-3"
           style={{ borderColor: COLORS.border, background: COLORS.surface }}>
        <div className="text-[10px] uppercase tracking-wider mb-2" style={{ color: COLORS.textMute }}>
          Multi-strategy walk-forward backtest
        </div>
        <p className="text-[11px]" style={{ color: COLORS.textDim }}>
          Compares 5 portfolio construction strategies on your current holdings using <strong>walk-forward methodology</strong>: weights are estimated on a training window and applied out-of-sample to the next fold; the OOS returns are stitched into the full equity curve. This avoids the lookahead bias of standard backtests where weights are optimized on the same data they're evaluated on.
          {' '}<strong>Equal Weight</strong> is the unbeatable benchmark — most "smart" strategies fail to outperform it net of frictions.
        </p>
      </div>

      {/* Controls */}
      <div className="rounded-md border p-3"
           style={{ borderColor: COLORS.border, background: COLORS.surface }}>
        <div className="text-[10px] uppercase tracking-wider mb-2" style={{ color: COLORS.textMute }}>
          Strategies enabled
        </div>
        <div className="flex flex-wrap gap-2 mb-3">
          {Object.keys(STRAT_LABELS).map(s => (
            <label key={s} className="inline-flex items-center gap-1.5 cursor-pointer select-none">
              <input type="checkbox" checked={enabledStrategies[s]}
                     onChange={(e) => setEnabledStrategies(p => ({ ...p, [s]: e.target.checked }))}
                     className="cursor-pointer" />
              <span className="text-[11px]"
                    style={{ color: enabledStrategies[s] ? STRAT_COLORS[s] : COLORS.textMute,
                             fontWeight: enabledStrategies[s] ? 500 : 400 }}>
                {STRAT_LABELS[s]}
              </span>
            </label>
          ))}
        </div>
        <div className="flex flex-wrap items-center gap-3 text-[11px]" style={{ color: COLORS.textDim }}>
          <span>Walk-forward folds:</span>
          <input type="number" value={folds} min="3" max="12" step="1"
                 onChange={(e) => setFolds(Math.max(3, Math.min(12, parseInt(e.target.value, 10) || 6)))}
                 className="w-14 px-2 py-0.5 rounded outline-none tabular-nums"
                 style={{ background: COLORS.bg, color: COLORS.text, border: `1px solid ${COLORS.border}` }} />
          <span>Rebalance every:</span>
          <input type="number" value={rebalanceFreq} min="0" max="63" step="1"
                 onChange={(e) => setRebalanceFreq(Math.max(0, Math.min(63, parseInt(e.target.value, 10) || 0)))}
                 className="w-14 px-2 py-0.5 rounded outline-none tabular-nums"
                 style={{ background: COLORS.bg, color: COLORS.text, border: `1px solid ${COLORS.border}` }} />
          <span>bars (0 = no rebal)</span>
          {loading && <span style={{ color: COLORS.textMute }}>· loading return history…</span>}
        </div>
      </div>

      {/* Result */}
      {result.error && (
        <div className="rounded-md border p-3 text-[11px]"
             style={{ borderColor: COLORS.red, color: COLORS.red, background: 'rgba(255,85,119,0.06)' }}>
          {result.error}
        </div>
      )}

      {!result.error && result.stats && Object.keys(result.stats).length > 0 && (
        <>
          {/* Stats table */}
          <div className="rounded-md border p-3"
               style={{ borderColor: COLORS.border, background: COLORS.surface }}>
            <div className="text-[10px] uppercase tracking-wider mb-2" style={{ color: COLORS.textMute }}>
              Out-of-sample performance · {result.totalBars} bars · {result.symbols.length} positions
            </div>
            <div className="overflow-x-auto rounded border" style={{ borderColor: COLORS.border }}>
              <table className="w-full text-[11px] tabular-nums">
                <thead>
                  <tr style={{ color: COLORS.textMute, background: COLORS.bg }}>
                    <th className="text-left px-2 py-1.5">Strategy</th>
                    <th className="text-right px-2">Total return</th>
                    <th className="text-right px-2">Annualized</th>
                    <th className="text-right px-2">Vol (ann)</th>
                    <th className="text-right px-2">Sharpe</th>
                    <th className="text-right px-2">Max DD</th>
                    <th className="text-right px-2">Win rate</th>
                    <th className="text-right px-2">N bars</th>
                  </tr>
                </thead>
                <tbody>
                  {result.strategies
                    .map(s => ({ s, ...result.stats[s] }))
                    .sort((a, b) => b.sharpe - a.sharpe)
                    .map((row, idx) => (
                      <tr key={row.s} style={{ borderTop: `1px solid ${COLORS.border}` }}>
                        <td className="px-2 py-1">
                          <span className="inline-flex items-center gap-1.5">
                            <span style={{ width: 8, height: 8, borderRadius: 2, background: STRAT_COLORS[row.s], display: 'inline-block' }} />
                            <span style={{ color: COLORS.text, fontWeight: idx === 0 ? 600 : 400 }}>
                              {STRAT_LABELS[row.s]}
                            </span>
                            {idx === 0 && (
                              <span className="text-[9px] uppercase tracking-wider px-1 rounded"
                                    style={{ background: `${COLORS.green}20`, color: COLORS.green }}>
                                Best
                              </span>
                            )}
                          </span>
                        </td>
                        <td className="text-right px-2"
                            style={{ color: row.finalReturn >= 0 ? COLORS.green : COLORS.red, fontWeight: 500 }}>
                          {row.finalReturn >= 0 ? '+' : ''}{row.finalReturn.toFixed(2)}%
                        </td>
                        <td className="text-right px-2"
                            style={{ color: row.annRet >= 0 ? COLORS.green : COLORS.red }}>
                          {row.annRet >= 0 ? '+' : ''}{row.annRet.toFixed(2)}%
                        </td>
                        <td className="text-right px-2" style={{ color: COLORS.textDim }}>
                          {row.annVol.toFixed(1)}%
                        </td>
                        <td className="text-right px-2"
                            style={{ color: row.sharpe >= 1 ? COLORS.green : row.sharpe >= 0 ? COLORS.text : COLORS.red, fontWeight: 500 }}>
                          {row.sharpe.toFixed(2)}
                        </td>
                        <td className="text-right px-2" style={{ color: COLORS.red }}>
                          {row.maxDD.toFixed(1)}%
                        </td>
                        <td className="text-right px-2" style={{ color: COLORS.textDim }}>
                          {row.winRate.toFixed(0)}%
                        </td>
                        <td className="text-right px-2" style={{ color: COLORS.textMute }}>
                          {row.n}
                        </td>
                      </tr>
                    ))}
                </tbody>
              </table>
            </div>
          </div>

          {/* Equity curve chart */}
          <div className="rounded-md border p-3"
               style={{ borderColor: COLORS.border, background: COLORS.surface }}>
            <div className="text-[10px] uppercase tracking-wider mb-2" style={{ color: COLORS.textMute }}>
              Equity curves · all OOS folds concatenated
            </div>
            <svg viewBox="0 0 800 240" preserveAspectRatio="none" style={{ width: '100%', height: 220 }}>
              {(() => {
                const padT = 8, padB = 22, padL = 50, padR = 8;
                const innerW = 800 - padL - padR;
                const innerH = 240 - padT - padB;
                const allEquities = result.strategies.map(s => result.equityCurves[s]);
                const maxLen = Math.max(...allEquities.map(e => e.length));
                let minV = Infinity, maxV = -Infinity;
                for (const eq of allEquities) {
                  for (const v of eq) {
                    if (v < minV) minV = v;
                    if (v > maxV) maxV = v;
                  }
                }
                const padV = (maxV - minV) * 0.05;
                minV -= padV; maxV += padV;
                const xScale = (i) => padL + (innerW * i) / Math.max(1, maxLen - 1);
                const yScale = (v) => padT + innerH * (1 - (v - minV) / (maxV - minV));
                // Y axis ticks
                const yTicks = 5;
                const ticks = [];
                for (let i = 0; i <= yTicks; i++) {
                  const v = minV + ((maxV - minV) * i) / yTicks;
                  ticks.push({ y: yScale(v), v });
                }
                return (
                  <>
                    {ticks.map((t, i) => (
                      <line key={i} x1={padL} y1={t.y} x2={800 - padR} y2={t.y}
                            stroke={COLORS.border} strokeDasharray="2 4" />
                    ))}
                    {ticks.map((t, i) => (
                      <text key={`yl-${i}`} x={padL - 6} y={t.y + 3}
                            fontSize="9" fill={COLORS.textMute} textAnchor="end" fontFamily="ui-monospace">
                        {((t.v - 1) * 100).toFixed(0)}%
                      </text>
                    ))}
                    {/* Zero line */}
                    <line x1={padL} y1={yScale(1)} x2={800 - padR} y2={yScale(1)}
                          stroke={COLORS.borderHi} strokeWidth="0.5" />
                    {/* Strategy curves */}
                    {result.strategies.map(strat => {
                      const eq = result.equityCurves[strat];
                      const path = eq.map((v, i) =>
                        `${i === 0 ? 'M' : 'L'} ${xScale(i)} ${yScale(v)}`).join(' ');
                      return (
                        <path key={strat} d={path}
                              fill="none" stroke={STRAT_COLORS[strat]}
                              strokeWidth="1.4" strokeLinejoin="round" />
                      );
                    })}
                  </>
                );
              })()}
            </svg>
            {/* Legend */}
            <div className="mt-2 flex flex-wrap gap-3">
              {result.strategies.map(s => (
                <div key={s} className="inline-flex items-center gap-1.5 text-[10.5px]" style={{ color: COLORS.textDim }}>
                  <span style={{ width: 12, height: 2, background: STRAT_COLORS[s], display: 'inline-block' }} />
                  {STRAT_LABELS[s]}
                </div>
              ))}
            </div>
          </div>
        </>
      )}

      <div className="text-[10px]" style={{ color: COLORS.textDim }}>
        <strong>Walk-forward methodology</strong> splits the {result.totalBars || 0}-bar history into {folds} folds.
        For fold N, weights are estimated using folds 1..N-1 (training) and applied to fold N (out-of-sample).
        OOS returns are concatenated to form the equity curve. <strong>Equal weight</strong> is the unbeatable benchmark — most strategies fail to outperform it net of trading costs (which this simulation doesn't model — add ~0.10-0.20% per round-trip for realistic frictions).
        <strong> Sharpe</strong>: &gt;1.0 reasonable, &gt;1.5 strong, &gt;2.0 institutional-quality. <strong>Max DD</strong> matters more than annual return for compounding over time.
      </div>

      {/* Backtest save / compare panel — persists named runs to localStorage
          for cross-session comparison. */}
      <BacktestPersistencePanel
        currentResult={result}
        currentConfig={{
          symbols: holdings.map(h => h.symbol),
          folds,
          rebalanceFreq,
          enabledStrategies,
        }} />
    </div>
  );
};

// BacktestPersistencePanel — save / load / compare named backtest runs.
const BACKTESTS_STORAGE_KEY = 'imo_backtests';
const BacktestPersistencePanel = ({ currentResult, currentConfig }) => {
  const [saved, setSaved] = useState(() => {
    try {
      const raw = localStorage.getItem(BACKTESTS_STORAGE_KEY);
      return raw ? JSON.parse(raw) : [];
    } catch { return []; }
  });
  const [name, setName] = useState('');
  const [compareIds, setCompareIds] = useState([]);

  // Persist
  useEffect(() => {
    try { localStorage.setItem(BACKTESTS_STORAGE_KEY, JSON.stringify(saved)); } catch {}
  }, [saved]);

  // Save current run as named entry
  const saveCurrent = useCallback(() => {
    if (!currentResult || currentResult.error) return;
    const trimmedName = name.trim() || `Backtest ${new Date().toISOString().slice(0, 16).replace('T', ' ')}`;
    const id = `bt_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
    // Strategy summary metrics — keep the data lean (no full equity curves
    // on save; localStorage has 5-10MB caps and we want to be polite)
    const metrics = {};
    for (const stratName of Object.keys(currentResult.strategies || {})) {
      const s = currentResult.strategies[stratName];
      if (!s) continue;
      metrics[stratName] = {
        cagr: s.cagr,
        sharpe: s.sharpe,
        maxDrawdown: s.maxDrawdown,
        finalValue: s.finalValue,
        trades: s.trades,
      };
    }
    setSaved(prev => [
      {
        id, name: trimmedName, ts: Date.now(),
        symbols: currentConfig.symbols,
        folds: currentConfig.folds,
        rebalanceFreq: currentConfig.rebalanceFreq,
        enabledStrategies: { ...currentConfig.enabledStrategies },
        metrics,
        totalBars: currentResult.totalBars,
      },
      ...prev,
    ].slice(0, 50)); // cap at 50
    setName('');
  }, [currentResult, currentConfig, name]);

  const deleteSaved = (id) => setSaved(prev => prev.filter(s => s.id !== id));
  const toggleCompare = (id) => {
    setCompareIds(prev =>
      prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id].slice(-3) // max 3
    );
  };

  // Comparison runs
  const compared = useMemo(() => saved.filter(s => compareIds.includes(s.id)), [saved, compareIds]);

  return (
    <div className="rounded-md border p-3 mt-3"
         style={{ borderColor: COLORS.border, background: COLORS.surface }}>
      <div className="flex items-baseline justify-between mb-2 flex-wrap gap-2">
        <div>
          <div className="text-[10px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>
            Saved backtests · cross-session persistence
          </div>
          <div className="text-[10.5px] mt-0.5" style={{ color: COLORS.textDim }}>
            Save current run with a label, compare up to 3 saved runs side-by-side.
            {saved.length > 0 ? ` ${saved.length} saved.` : ' No saved runs yet.'}
          </div>
        </div>
      </div>

      {/* Save controls */}
      <div className="flex gap-2 items-end mb-3 flex-wrap">
        <div className="flex-1 min-w-0">
          <div className="text-[9.5px] uppercase tracking-wider mb-1" style={{ color: COLORS.textMute }}>
            Name (optional)
          </div>
          <input type="text" value={name}
                 onChange={(e) => setName(e.target.value)}
                 placeholder="e.g. Q4 tech basket, momentum 8 folds"
                 className="w-full px-2 py-1 rounded text-[12px] outline-none"
                 style={{ background: COLORS.bg, color: COLORS.text, border: `1px solid ${COLORS.border}` }} />
        </div>
        <button type="button" onClick={saveCurrent}
                disabled={!currentResult || currentResult.error}
                className="px-3 py-1.5 rounded text-[11.5px] font-medium hover:opacity-90 disabled:opacity-40 inline-flex items-center gap-1.5"
                style={{ background: `${COLORS.mint}1A`, color: COLORS.mint, border: `1px solid ${COLORS.mint}` }}>
          <Plus size={11} />
          Save current
        </button>
      </div>

      {/* Saved list */}
      {saved.length > 0 && (
        <div className="rounded border mb-3" style={{ borderColor: COLORS.border, background: COLORS.bg }}>
          <div className="overflow-x-auto" style={{ maxHeight: 240 }}>
            <table className="w-full text-[10.5px] tabular-nums">
              <thead style={{ position: 'sticky', top: 0, background: COLORS.bg, zIndex: 1 }}>
                <tr style={{ color: COLORS.textMute, borderBottom: `1px solid ${COLORS.border}` }}>
                  <th className="text-left px-2 py-1.5">Name</th>
                  <th className="text-right px-2">Symbols</th>
                  <th className="text-right px-2">Folds</th>
                  <th className="text-right px-2">Bars</th>
                  <th className="text-right px-2">Best CAGR</th>
                  <th className="text-right px-2">Best Sharpe</th>
                  <th className="text-right px-2">Saved</th>
                  <th className="text-right px-2">Compare</th>
                  <th className="text-right px-2"></th>
                </tr>
              </thead>
              <tbody>
                {saved.map(s => {
                  const stratEntries = Object.entries(s.metrics || {});
                  const bestCagr = stratEntries.reduce((b, [k, v]) =>
                    (v?.cagr || 0) > (b?.cagr || -Infinity) ? { name: k, ...v } : b, null);
                  const bestSharpe = stratEntries.reduce((b, [k, v]) =>
                    (v?.sharpe || 0) > (b?.sharpe || -Infinity) ? { name: k, ...v } : b, null);
                  const isCompared = compareIds.includes(s.id);
                  return (
                    <tr key={s.id} style={{ borderTop: `1px solid ${COLORS.border}`,
                                            background: isCompared ? `${COLORS.mint}08` : 'transparent' }}>
                      <td className="px-2 py-1" style={{ color: COLORS.text, fontWeight: 500 }}>
                        {s.name}
                      </td>
                      <td className="text-right px-2" style={{ color: COLORS.textDim }}>
                        {s.symbols?.length || 0}
                      </td>
                      <td className="text-right px-2" style={{ color: COLORS.textDim }}>{s.folds}</td>
                      <td className="text-right px-2" style={{ color: COLORS.textDim }}>{s.totalBars || '—'}</td>
                      <td className="text-right px-2"
                          style={{ color: bestCagr?.cagr > 0 ? COLORS.green : COLORS.red }}>
                        {bestCagr ? `${(bestCagr.cagr * 100).toFixed(1)}%` : '—'}
                      </td>
                      <td className="text-right px-2"
                          style={{ color: bestSharpe?.sharpe > 1 ? COLORS.green : COLORS.text }}>
                        {bestSharpe ? bestSharpe.sharpe.toFixed(2) : '—'}
                      </td>
                      <td className="text-right px-2 text-[10px]" style={{ color: COLORS.textMute }}>
                        {new Date(s.ts).toLocaleDateString()}
                      </td>
                      <td className="text-right px-2">
                        <button type="button" onClick={() => toggleCompare(s.id)}
                                className="px-1.5 py-0.5 rounded text-[10px] hover:opacity-80"
                                style={{
                                  background: isCompared ? `${COLORS.mint}1A` : COLORS.bg,
                                  color: isCompared ? COLORS.mint : COLORS.textDim,
                                  border: `1px solid ${isCompared ? COLORS.mint : COLORS.border}`,
                                }}>
                          {isCompared ? '✓' : '+'}
                        </button>
                      </td>
                      <td className="text-right px-2">
                        <button type="button" onClick={() => deleteSaved(s.id)}
                                className="px-1.5 py-0.5 rounded text-[10px] hover:opacity-80"
                                style={{ background: COLORS.bg, color: COLORS.red, border: `1px solid ${COLORS.red}33` }}
                                title="Delete">
                          <Trash2 size={9} />
                        </button>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Comparison view */}
      {compared.length >= 2 && (() => {
        // Collect strategy names across compared runs
        const allStrategies = new Set();
        for (const c of compared) {
          for (const s of Object.keys(c.metrics || {})) allStrategies.add(s);
        }
        const stratList = Array.from(allStrategies).sort();
        return (
          <div className="rounded border" style={{ borderColor: `${COLORS.mint}55`, background: `${COLORS.mint}05` }}>
            <div className="px-3 py-1.5 text-[10px] uppercase tracking-wider"
                 style={{ color: COLORS.mint, borderBottom: `1px solid ${COLORS.border}` }}>
              Comparison · {compared.length} runs
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-[10.5px] tabular-nums">
                <thead>
                  <tr style={{ color: COLORS.textMute, background: COLORS.bg }}>
                    <th className="text-left px-2 py-1.5">Strategy</th>
                    <th className="text-left px-2">Metric</th>
                    {compared.map(c => (
                      <th key={c.id} className="text-right px-2" title={c.name}>
                        {c.name.length > 16 ? c.name.slice(0, 14) + '…' : c.name}
                      </th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {stratList.map((strat) =>
                    [['cagr', 'CAGR %', v => `${(v * 100).toFixed(1)}%`],
                     ['sharpe', 'Sharpe', v => v.toFixed(2)],
                     ['maxDrawdown', 'Max DD %', v => `−${(v * 100).toFixed(1)}%`]].map(([key, label, fmt]) => (
                      <tr key={`${strat}-${key}`} style={{ borderTop: `1px solid ${COLORS.border}` }}>
                        <td className="px-2 py-1" style={{ color: COLORS.text, fontWeight: 500 }}>
                          {strat === 'equalWeight' ? 'Equal weight'
                           : strat === 'marketCap' ? 'Mkt cap'
                           : strat === 'riskParity' ? 'Risk parity'
                           : strat === 'momentum' ? 'Momentum'
                           : strat === 'blackLitterman' ? 'Black-Litterman'
                           : strat}
                        </td>
                        <td className="px-2 text-[10px]" style={{ color: COLORS.textDim }}>{label}</td>
                        {compared.map(c => {
                          const v = c.metrics?.[strat]?.[key];
                          if (v == null) return <td key={c.id} className="text-right px-2" style={{ color: COLORS.textMute }}>—</td>;
                          // Find best across compared runs
                          const allVals = compared.map(cc => cc.metrics?.[strat]?.[key]).filter(x => x != null);
                          const isBest = key === 'maxDrawdown'
                            ? v === Math.min(...allVals)
                            : v === Math.max(...allVals);
                          return (
                            <td key={c.id} className="text-right px-2"
                                style={{
                                  color: isBest ? COLORS.green : COLORS.text,
                                  fontWeight: isBest ? 500 : 400,
                                }}>
                              {fmt(v)}
                            </td>
                          );
                        })}
                      </tr>
                    ))
                  )}
                </tbody>
              </table>
            </div>
            <div className="px-3 py-1.5 text-[10px]"
                 style={{ borderTop: `1px solid ${COLORS.border}`, color: COLORS.textDim }}>
              Best metric per row highlighted in green. Compare up to 3 runs at once.
            </div>
          </div>
        );
      })()}
    </div>
  );
};

const BlackLittermanTab = ({ account, portfolioSource }) => {
  const holdings = useMemo(() => {
    if (portfolioSource?.source === 'broker' && portfolioSource.positions?.length > 0) {
      return portfolioSource.positions.map(p => ({
        symbol: p.symbol,
        qty: Number(p.qty) || 0,
        mark: Number(p.mark) || 0,
      }));
    }
    const positions = account?.positions ?? [];
    return positions.map(p => {
      const sym = p.instrument?.id?.split('-')[0] ?? p.symbol ?? '';
      const sign = p.side === 'short' ? -1 : 1;
      const qty = sign * (Number(p.size) || 0);
      const mark = Number(p.markPrice) || Number(p.entryPrice) || 0;
      return { symbol: sym, qty, mark };
    }).filter(h => h.symbol && h.qty !== 0);
  }, [portfolioSource, account]);

  const [returnsBySymbol, setReturnsBySymbol] = useState({});
  const [loading, setLoading] = useState(false);
  const [views, setViews] = useState([]); // [{type, tickers, magnitudePct, confidencePct}]
  const [delta, setDelta] = useState(2.5);
  const [tau, setTau] = useState(0.05);
  const [useShrinkage, setUseShrinkage] = useState(false);
  const [draftView, setDraftView] = useState({
    type: 'absolute', tickerLong: '', tickerShort: '',
    magnitudePct: 5, confidencePct: 50,
  });

  useEffect(() => {
    if (holdings.length === 0) return;
    setLoading(true);
    Promise.all(holdings.map(h => fetchPolygonAggs(h.symbol, '6M', 'day', 1).catch(() => null)))
      .then(results => {
        const map = {};
        for (let i = 0; i < holdings.length; i++) {
          const data = results[i];
          if (!data || data.length < 5) continue;
          const closes = data.map(d => d.close).filter(c => c > 0);
          const rets = [];
          for (let k = 1; k < closes.length; k++) {
            rets.push((closes[k] - closes[k - 1]) / closes[k - 1]);
          }
          map[holdings[i].symbol] = rets;
        }
        setReturnsBySymbol(map);
      })
      .finally(() => setLoading(false));
  }, [holdings]);

  const augmented = useMemo(() => holdings.map(h => ({
    ...h,
    returns: returnsBySymbol[h.symbol] || [],
  })), [holdings, returnsBySymbol]);

  const blResult = useMemo(() => runBlackLitterman({ holdings: augmented, views, delta, tau, useShrinkage }),
    [augmented, views, delta, tau, useShrinkage]);

  const addView = () => {
    if (draftView.type === 'absolute') {
      if (!draftView.tickerLong) return;
      setViews(prev => [...prev, {
        type: 'absolute',
        tickers: [draftView.tickerLong.toUpperCase()],
        magnitudePct: Number(draftView.magnitudePct),
        confidencePct: Number(draftView.confidencePct),
      }]);
    } else {
      if (!draftView.tickerLong || !draftView.tickerShort) return;
      setViews(prev => [...prev, {
        type: 'relative',
        tickers: [draftView.tickerLong.toUpperCase(), draftView.tickerShort.toUpperCase()],
        magnitudePct: Number(draftView.magnitudePct),
        confidencePct: Number(draftView.confidencePct),
      }]);
    }
    setDraftView({ ...draftView, tickerLong: '', tickerShort: '' });
  };

  const removeView = (idx) => setViews(prev => prev.filter((_, i) => i !== idx));

  if (holdings.length < 2) {
    return (
      <div className="rounded-md border p-6 text-center"
           style={{ borderColor: COLORS.border, background: COLORS.surface }}>
        <Telescope size={28} style={{ color: COLORS.textMute, margin: '0 auto 12px' }} />
        <div className="text-[13px] mb-1" style={{ color: COLORS.text }}>Need at least 2 positions</div>
        <div className="text-[11px]" style={{ color: COLORS.textMute }}>
          Black-Litterman optimization combines market equilibrium with your views to produce optimal portfolio weights. Open a few positions first, then come back to add views.
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      <div className="rounded-md border p-3"
           style={{ borderColor: COLORS.border, background: COLORS.surface }}>
        <div className="text-[10px] uppercase tracking-wider mb-2" style={{ color: COLORS.textMute }}>
          About Black-Litterman
        </div>
        <p className="text-[11px]" style={{ color: COLORS.textDim }}>
          Reverse-engineers implied returns from the current portfolio (the returns the market must expect given the weights),
          then blends them with your subjective views to produce a posterior expected-return vector.
          The posterior runs through mean-variance optimization to give weights — but unlike vanilla MVO, BL doesn't
          collapse to extreme weights when expected returns are slightly off, because the prior keeps things anchored to
          the current allocation. <strong>Add views below</strong> to see how the optimizer suggests rebalancing.
        </p>
      </div>

      {/* View builder */}
      <div className="rounded-md border p-3"
           style={{ borderColor: COLORS.border, background: COLORS.surface }}>
        <div className="text-[10px] uppercase tracking-wider mb-2" style={{ color: COLORS.textMute }}>
          Add a view ({views.length} active)
        </div>
        <div className="grid grid-cols-1 sm:grid-cols-5 gap-2 items-end">
          <div>
            <div className="text-[9.5px] uppercase tracking-wider mb-1" style={{ color: COLORS.textMute }}>Type</div>
            <select value={draftView.type}
                    onChange={(e) => setDraftView(d => ({ ...d, type: e.target.value }))}
                    className="w-full px-2 py-1.5 rounded text-[11px] outline-none"
                    style={{ background: COLORS.bg, color: COLORS.text, border: `1px solid ${COLORS.border}`, colorScheme: 'dark' }}>
              <option value="absolute">Absolute (X returns Y%)</option>
              <option value="relative">Relative (X outperforms Y by Z%)</option>
            </select>
          </div>
          <div>
            <div className="text-[9.5px] uppercase tracking-wider mb-1" style={{ color: COLORS.textMute }}>Long</div>
            <input type="text" value={draftView.tickerLong}
                   onChange={(e) => setDraftView(d => ({ ...d, tickerLong: e.target.value.toUpperCase() }))}
                   placeholder="AAPL"
                   className="w-full px-2 py-1.5 rounded text-[11px] outline-none uppercase"
                   style={{ background: COLORS.bg, color: COLORS.text, border: `1px solid ${COLORS.border}` }} />
          </div>
          <div style={{ visibility: draftView.type === 'relative' ? 'visible' : 'hidden' }}>
            <div className="text-[9.5px] uppercase tracking-wider mb-1" style={{ color: COLORS.textMute }}>vs Short</div>
            <input type="text" value={draftView.tickerShort}
                   onChange={(e) => setDraftView(d => ({ ...d, tickerShort: e.target.value.toUpperCase() }))}
                   placeholder="MSFT"
                   className="w-full px-2 py-1.5 rounded text-[11px] outline-none uppercase"
                   style={{ background: COLORS.bg, color: COLORS.text, border: `1px solid ${COLORS.border}` }} />
          </div>
          <div>
            <div className="text-[9.5px] uppercase tracking-wider mb-1" style={{ color: COLORS.textMute }}>Magnitude (%)</div>
            <input type="number" value={draftView.magnitudePct}
                   onChange={(e) => setDraftView(d => ({ ...d, magnitudePct: e.target.value }))}
                   className="w-full px-2 py-1.5 rounded text-[11px] outline-none tabular-nums"
                   style={{ background: COLORS.bg, color: COLORS.text, border: `1px solid ${COLORS.border}` }} />
          </div>
          <div>
            <div className="text-[9.5px] uppercase tracking-wider mb-1" style={{ color: COLORS.textMute }}>Confidence (%)</div>
            <input type="number" value={draftView.confidencePct} min="1" max="99"
                   onChange={(e) => setDraftView(d => ({ ...d, confidencePct: e.target.value }))}
                   className="w-full px-2 py-1.5 rounded text-[11px] outline-none tabular-nums"
                   style={{ background: COLORS.bg, color: COLORS.text, border: `1px solid ${COLORS.border}` }} />
          </div>
        </div>
        <button type="button"
                onClick={addView}
                className="mt-3 px-3 py-1.5 rounded text-[11.5px] inline-flex items-center gap-1.5 hover:opacity-90"
                style={{ background: COLORS.mint, color: COLORS.bg }}>
          <Plus size={11} />
          Add view
        </button>

        {/* Active views */}
        {views.length > 0 && (
          <div className="mt-3 space-y-1">
            {views.map((v, idx) => (
              <div key={idx} className="flex items-center justify-between text-[11px] px-2 py-1 rounded"
                   style={{ background: COLORS.bg, border: `1px solid ${COLORS.border}` }}>
                <span style={{ color: COLORS.text }}>
                  {v.type === 'absolute'
                    ? `${v.tickers[0]} returns ${v.magnitudePct >= 0 ? '+' : ''}${v.magnitudePct}%`
                    : `${v.tickers[0]} outperforms ${v.tickers.slice(1).join(', ')} by ${v.magnitudePct}%`}
                  <span className="ml-2" style={{ color: COLORS.textMute }}>({v.confidencePct}% conf)</span>
                </span>
                <button type="button"
                        onClick={() => removeView(idx)}
                        className="p-0.5 hover:text-red-400"
                        style={{ color: COLORS.textMute }}>
                  <X size={10} />
                </button>
              </div>
            ))}
          </div>
        )}

        {/* δ + τ params */}
        <div className="mt-3 flex items-center gap-3 text-[11px] flex-wrap" style={{ color: COLORS.textDim }}>
          <span>δ (risk aversion):</span>
          <input type="number" value={delta} step="0.5" min="1" max="10"
                 onChange={(e) => setDelta(Number(e.target.value) || 2.5)}
                 className="w-16 px-2 py-0.5 rounded outline-none tabular-nums"
                 style={{ background: COLORS.bg, color: COLORS.text, border: `1px solid ${COLORS.border}` }} />
          <span>τ (prior scale):</span>
          <input type="number" value={tau} step="0.005" min="0.005" max="1"
                 onChange={(e) => setTau(Number(e.target.value) || 0.05)}
                 className="w-20 px-2 py-0.5 rounded outline-none tabular-nums"
                 style={{ background: COLORS.bg, color: COLORS.text, border: `1px solid ${COLORS.border}` }} />
          <label className="inline-flex items-center gap-1.5 cursor-pointer select-none"
                 title="Shrinks sample covariance toward identity-scaled-by-mean-variance using Ledoit-Wolf optimal intensity">
            <input type="checkbox" checked={useShrinkage}
                   onChange={(e) => setUseShrinkage(e.target.checked)}
                   className="cursor-pointer" />
            <span style={{ color: useShrinkage ? COLORS.mint : COLORS.textDim, fontWeight: useShrinkage ? 500 : 400 }}>
              Ledoit-Wolf shrinkage
              {useShrinkage && blResult.shrinkageIntensity != null && (
                <span className="ml-1 tabular-nums" style={{ color: COLORS.mint }}>
                  α={blResult.shrinkageIntensity.toFixed(3)}
                </span>
              )}
            </span>
          </label>
          <span style={{ color: COLORS.textMute }}>{loading ? 'loading return history…' : ''}</span>
        </div>
      </div>

      {/* Results */}
      {blResult.error && (
        <div className="rounded-md border p-3 text-[11px]"
             style={{ borderColor: COLORS.red, color: COLORS.red, background: 'rgba(255,85,119,0.06)' }}>
          {blResult.error}
        </div>
      )}
      {!blResult.error && blResult.symbols && (
        <div className="rounded-md border p-3"
             style={{ borderColor: COLORS.border, background: COLORS.surface }}>
          <div className="text-[10px] uppercase tracking-wider mb-2" style={{ color: COLORS.textMute }}>
            Optimal weights vs current
          </div>
          <div className="overflow-x-auto rounded border" style={{ borderColor: COLORS.border }}>
            <table className="w-full text-[11px] tabular-nums">
              <thead>
                <tr style={{ color: COLORS.textMute, background: COLORS.bg }}>
                  <th className="text-left px-2 py-1.5">Symbol</th>
                  <th className="text-right px-2">Implied (%)</th>
                  <th className="text-right px-2">Posterior (%)</th>
                  <th className="text-right px-2">Current</th>
                  <th className="text-right px-2">Optimal</th>
                  <th className="text-right px-2">Δ</th>
                </tr>
              </thead>
              <tbody>
                {blResult.suggestions.map((s, idx) => {
                  const impl = blResult.impliedReturns[s.symbol];
                  const post = blResult.posteriorReturns[s.symbol];
                  return (
                    <tr key={idx} style={{ borderTop: `1px solid ${COLORS.border}` }}>
                      <td className="px-2 py-1" style={{ color: COLORS.text, fontWeight: 500 }}>{s.symbol}</td>
                      <td className="text-right px-2" style={{ color: COLORS.textDim }}>{(impl ?? 0).toFixed(1)}%</td>
                      <td className="text-right px-2"
                          style={{ color: post >= impl ? COLORS.green : COLORS.red }}>
                        {(post ?? 0).toFixed(1)}%
                      </td>
                      <td className="text-right px-2" style={{ color: COLORS.textDim }}>
                        {(s.currentWeight * 100).toFixed(1)}%
                      </td>
                      <td className="text-right px-2" style={{ color: COLORS.text }}>
                        {(s.optimalWeight * 100).toFixed(1)}%
                      </td>
                      <td className="text-right px-2"
                          style={{ color: s.deltaPct >= 0 ? COLORS.green : COLORS.red, fontWeight: 500 }}>
                        {s.deltaPct >= 0 ? '+' : ''}{s.deltaPct.toFixed(1)}%
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
          <div className="text-[10px] mt-2" style={{ color: COLORS.textDim }}>
            <strong>Implied</strong> = annualized return the market is "saying" given the current weights at risk-aversion δ. <strong>Posterior</strong> = those returns blended with your views via the BL formula. <strong>Δ</strong> = how the optimizer wants to shift your allocation. Positive = add weight; negative = trim.
          </div>
        </div>
      )}
    </div>
  );
};

// PairsScreenerTab — find cointegrated pairs in a configurable universe
const PairsScreenerTab = ({ setActive, setPage }) => {
  const [universeStr, setUniverseStr] = useState('AAPL,MSFT,GOOGL,AMZN,META,NVDA,TSLA,JPM,BAC,WMT,V,MA,XOM,CVX,KO,PEP,JNJ,UNH,PFE,MRK');
  const [confidence, setConfidence] = useState(95);
  const [running, setRunning] = useState(false);
  const [result, setResult] = useState([]);
  const [error, setError] = useState(null);
  // Pair trade plan: when user selects a pair, build a complete plan
  // with z-score history + signals + backtest
  const [selectedPair, setSelectedPair] = useState(null); // { symY, symX, ySeries, xSeries }
  const [planParams, setPlanParams] = useState({ entryZ: 2.0, exitZ: 0.5, stopZ: 4.0, lookback: 60 });
  // Cache the price series for the universe so we don't re-fetch when
  // user clicks "Build plan" for different pairs after one screen
  const [seriesCache, setSeriesCache] = useState({});

  const runScreen = useCallback(async () => {
    const tickers = universeStr.split(',').map(s => s.trim().toUpperCase()).filter(Boolean);
    if (tickers.length < 2) {
      setError('Need at least 2 tickers in universe');
      return;
    }
    if (tickers.length > 30) {
      setError('Universe too large (max 30) — ' + (tickers.length * (tickers.length - 1) / 2) + ' pairs would take a while');
      return;
    }
    setRunning(true);
    setError(null);
    try {
      // Fetch 6 months of daily bars for each ticker
      const fetched = await Promise.all(
        tickers.map(t => fetchPolygonAggs(t, '6M', 'day', 1).catch(() => null))
      );
      const priceSeries = {};
      for (let i = 0; i < tickers.length; i++) {
        const data = fetched[i];
        if (!data || data.length < 50) continue;
        priceSeries[tickers[i]] = data.map(d => d.close).filter(c => c > 0);
      }
      const pairs = findCointegratedPairs({
        priceSeriesBySymbol: priceSeries,
        confidencePct: confidence,
        maxPairs: 25,
      });
      setResult(pairs);
      setSeriesCache(priceSeries);
    } catch (e) {
      setError(e?.message || 'Screen failed');
    } finally {
      setRunning(false);
    }
  }, [universeStr, confidence]);

  return (
    <div className="space-y-4">
      <div className="rounded-md border p-3"
           style={{ borderColor: COLORS.border, background: COLORS.surface }}>
        <div className="text-[10px] uppercase tracking-wider mb-2" style={{ color: COLORS.textMute }}>
          Pairs screener · Engle-Granger cointegration test
        </div>
        <p className="text-[11px] mb-3" style={{ color: COLORS.textDim }}>
          Tests every pair (i, j) in the universe for cointegration via OLS hedge ratio + ADF on the spread.
          Pairs that pass the {confidence}% confidence threshold are reported with current Z-score (extremity)
          and half-life (mean-reversion speed). High |Z| + short half-life = actionable pair trade. Capped at
          30 tickers due to O(n²) complexity.
        </p>
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-2 mb-2">
          <div className="sm:col-span-2">
            <div className="flex items-baseline justify-between mb-1">
              <div className="text-[9.5px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>
                Universe (comma-separated tickers)
              </div>
              <div className="flex gap-1">
                {[
                  { id: 'megacap', label: 'Mega-cap', tickers: 'AAPL, MSFT, GOOGL, AMZN, NVDA, META, TSLA, BRK.B, AVGO, JPM' },
                  { id: 'banks',   label: 'Banks',    tickers: 'JPM, BAC, WFC, C, GS, MS, USB, PNC, TFC, COF' },
                  { id: 'tech',    label: 'Tech',     tickers: 'AAPL, MSFT, GOOGL, META, ORCL, CRM, ADBE, INTC, AMD, QCOM' },
                  { id: 'energy',  label: 'Energy',   tickers: 'XOM, CVX, COP, SLB, EOG, OXY, PSX, MPC, VLO, HES' },
                  { id: 'sectors', label: 'Sectors',  tickers: 'XLK, XLV, XLF, XLY, XLP, XLE, XLI, XLB, XLU, XLRE, XLC' },
                  { id: 'commodities', label: 'Commodities', tickers: 'GLD, SLV, USO, UNG, DBA, CORN, WEAT, COPX, PALL, PPLT' },
                ].map(p => (
                  <button key={p.id} type="button"
                          onClick={() => setUniverseStr(p.tickers)}
                          className="text-[9.5px] uppercase tracking-wider px-1.5 py-0.5 rounded hover:opacity-80"
                          style={{ background: COLORS.bg, color: COLORS.textDim, border: `1px solid ${COLORS.border}` }}
                          title={p.tickers}>
                    {p.label}
                  </button>
                ))}
              </div>
            </div>
            <textarea value={universeStr}
                      onChange={(e) => setUniverseStr(e.target.value.toUpperCase())}
                      rows={2}
                      className="w-full px-2 py-1.5 rounded text-[11px] outline-none uppercase font-mono resize-y"
                      style={{ background: COLORS.bg, color: COLORS.text, border: `1px solid ${COLORS.border}` }} />
          </div>
          <div>
            <div className="text-[9.5px] uppercase tracking-wider mb-1" style={{ color: COLORS.textMute }}>Confidence</div>
            <select value={confidence}
                    onChange={(e) => setConfidence(Number(e.target.value))}
                    className="w-full px-2 py-1.5 rounded text-[11px] outline-none"
                    style={{ background: COLORS.bg, color: COLORS.text, border: `1px solid ${COLORS.border}`, colorScheme: 'dark' }}>
              <option value={90}>90% (loose)</option>
              <option value={95}>95% (standard)</option>
              <option value={99}>99% (strict)</option>
            </select>
            <button type="button"
                    onClick={runScreen}
                    disabled={running}
                    className="mt-2 w-full px-3 py-1.5 rounded text-[11.5px] font-medium inline-flex items-center justify-center gap-1.5 hover:opacity-90 disabled:opacity-40"
                    style={{ background: COLORS.mint, color: COLORS.bg }}>
              <Play size={11} />
              {running ? 'Screening…' : 'Run screen'}
            </button>
          </div>
        </div>
        {error && (
          <div className="text-[11px] px-2 py-1 rounded"
               style={{ background: 'rgba(255,85,119,0.08)', color: COLORS.red, border: '1px solid rgba(255,85,119,0.30)' }}>
            {error}
          </div>
        )}
      </div>

      {result.length > 0 && (
        <div className="rounded-md border"
             style={{ borderColor: COLORS.border, background: COLORS.surface }}>
          <div className="px-3 py-2 border-b text-[10px] uppercase tracking-wider"
               style={{ borderColor: COLORS.border, color: COLORS.textMute }}>
            Cointegrated pairs ({result.length})
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-[11px] tabular-nums">
              <thead>
                <tr style={{ color: COLORS.textMute, background: COLORS.bg }}>
                  <th className="text-left px-2 py-1.5">Pair</th>
                  <th className="text-right px-2">β (hedge)</th>
                  <th className="text-right px-2">ADF</th>
                  <th className="text-right px-2">Z-score</th>
                  <th className="text-right px-2">Half-life</th>
                  <th className="text-right px-2">Trade</th>
                  <th className="text-right px-2">Plan</th>
                </tr>
              </thead>
              <tbody>
                {result.map((p, idx) => {
                  const isExtremeZ = Math.abs(p.zScore) >= 2;
                  const tradeAction = p.zScore >= 0
                    ? `Long ${p.symX}, Short ${p.symY}`
                    : `Long ${p.symY}, Short ${p.symX}`;
                  const isSelected = selectedPair?.symY === p.symY && selectedPair?.symX === p.symX;
                  return (
                    <tr key={idx} style={{ borderTop: `1px solid ${COLORS.border}`, background: isSelected ? `${COLORS.mint}08` : 'transparent' }}>
                      <td className="px-2 py-1.5" style={{ color: COLORS.text, fontWeight: 500 }}>
                        {p.symY} ↔ {p.symX}
                      </td>
                      <td className="text-right px-2" style={{ color: COLORS.textDim }}>
                        {p.beta.toFixed(3)}
                      </td>
                      <td className="text-right px-2" style={{ color: COLORS.textDim }}>
                        {p.adfStat.toFixed(2)}
                      </td>
                      <td className="text-right px-2"
                          style={{ color: isExtremeZ ? (p.zScore >= 0 ? COLORS.green : COLORS.red) : COLORS.text, fontWeight: isExtremeZ ? 500 : 400 }}>
                        {p.zScore >= 0 ? '+' : ''}{p.zScore.toFixed(2)}
                      </td>
                      <td className="text-right px-2" style={{ color: p.halfLife <= 10 ? COLORS.green : COLORS.textDim }}>
                        {p.halfLife.toFixed(1)}d
                      </td>
                      <td className="text-right px-2 text-[10.5px]"
                          style={{ color: isExtremeZ ? COLORS.mint : COLORS.textMute }}>
                        {isExtremeZ ? tradeAction : '—'}
                      </td>
                      <td className="text-right px-2">
                        <button type="button"
                                onClick={() => setSelectedPair({
                                  symY: p.symY,
                                  symX: p.symX,
                                  ySeries: seriesCache[p.symY] || [],
                                  xSeries: seriesCache[p.symX] || [],
                                })}
                                className="px-2 py-0.5 rounded text-[10px] hover:opacity-90"
                                style={{
                                  background: isSelected ? COLORS.mint : `${COLORS.mint}1A`,
                                  color: isSelected ? COLORS.bg : COLORS.mint,
                                  border: `1px solid ${COLORS.mint}55`,
                                }}>
                          {isSelected ? 'Selected' : 'Build'}
                        </button>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
          <div className="px-3 py-2 text-[10px]" style={{ color: COLORS.textDim, borderTop: `1px solid ${COLORS.border}` }}>
            Z &gt; +2 = spread is too wide → bet on convergence (long the underperformer, short the over).
            Z &lt; −2 = mirror.
            Half-life &lt; 10d = practical to trade; &gt; 30d = too slow, capital tied up.
          </div>

          {/* Hub analysis — tickers appearing in the most cointegrating pairs.
              Useful: a stock that pairs with everything in its sector is
              probably a "core" exposure for that sector — good benchmark
              candidate. */}
          {result.length >= 3 && (() => {
            const tickerCount = new Map();
            const tickerZSum = new Map();
            for (const p of result) {
              tickerCount.set(p.symX, (tickerCount.get(p.symX) || 0) + 1);
              tickerCount.set(p.symY, (tickerCount.get(p.symY) || 0) + 1);
              tickerZSum.set(p.symX, (tickerZSum.get(p.symX) || 0) + Math.abs(p.zScore));
              tickerZSum.set(p.symY, (tickerZSum.get(p.symY) || 0) + Math.abs(p.zScore));
            }
            const hubs = Array.from(tickerCount.entries())
              .map(([sym, count]) => ({
                sym,
                count,
                avgZ: (tickerZSum.get(sym) || 0) / count,
              }))
              .sort((a, b) => b.count - a.count)
              .slice(0, 8);
            const totalPairs = result.length;
            return (
              <div className="px-3 py-2" style={{ borderTop: `1px solid ${COLORS.border}` }}>
                <div className="text-[9.5px] uppercase tracking-wider mb-1.5" style={{ color: COLORS.textMute }}>
                  Hub tickers · most cointegrated
                </div>
                <div className="flex flex-wrap gap-1.5">
                  {hubs.map(h => (
                    <div key={h.sym} className="px-2 py-1 rounded text-[10.5px] flex items-baseline gap-1.5"
                         style={{ background: COLORS.bg, border: `1px solid ${COLORS.border}` }}>
                      <span style={{ color: COLORS.text, fontWeight: 500 }}>{h.sym}</span>
                      <span className="text-[9.5px]" style={{ color: COLORS.mint }}>
                        {h.count} pair{h.count === 1 ? '' : 's'}
                      </span>
                      {h.avgZ >= 1.5 && (
                        <span className="text-[9.5px]" style={{ color: COLORS.chartGold }}>
                          (|Z|̄ {h.avgZ.toFixed(1)})
                        </span>
                      )}
                    </div>
                  ))}
                </div>
                <div className="text-[10px] mt-1.5" style={{ color: COLORS.textDim }}>
                  Tickers cointegrating with many others (high count) are "core" exposures — good
                  candidates for sector hedges. Tickers with high average |Z| are currently extreme
                  vs many peers — selective opportunity set.
                </div>
              </div>
            );
          })()}
        </div>
      )}

      {/* Pair trade plan — z-score history, signals, backtest */}
      {selectedPair && (() => {
        const plan = buildPairTradePlan({
          ySeries: selectedPair.ySeries,
          xSeries: selectedPair.xSeries,
          ySymbol: selectedPair.symY,
          xSymbol: selectedPair.symX,
          entryZ: planParams.entryZ,
          exitZ:  planParams.exitZ,
          stopZ:  planParams.stopZ,
          lookback: planParams.lookback,
        });
        if (!plan) {
          return (
            <div className="rounded-md border p-3 text-[11px]"
                 style={{ borderColor: COLORS.red, color: COLORS.red, background: 'rgba(255,85,119,0.06)' }}>
              Cannot build plan — insufficient data for {selectedPair.symY}/{selectedPair.symX}.
            </div>
          );
        }
        const signalTone = plan.currentSignal.startsWith('enter-long')  ? COLORS.green
                         : plan.currentSignal.startsWith('enter-short') ? COLORS.red
                         : plan.currentSignal === 'flat / exit'         ? COLORS.mint
                         :                                                COLORS.textMute;
        const lastTrades = plan.closedTrades.slice(-5).reverse();
        return (
          <div className="rounded-md border p-3 space-y-3"
               style={{ borderColor: COLORS.mint + '55', background: COLORS.surface }}>
            <div className="flex items-baseline justify-between flex-wrap gap-2">
              <div>
                <div className="text-[10px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>
                  Pair trade plan · {plan.ySymbol} ↔ {plan.xSymbol}
                </div>
                <div className="text-[14px] font-medium mt-0.5" style={{ color: signalTone }}>
                  {plan.currentSignal === 'enter-long-spread'  ? `Long ${plan.ySymbol} / Short ${Math.abs(plan.beta).toFixed(2)}× ${plan.xSymbol}`
                   : plan.currentSignal === 'enter-short-spread' ? `Short ${plan.ySymbol} / Long ${Math.abs(plan.beta).toFixed(2)}× ${plan.xSymbol}`
                   : plan.currentSignal === 'flat / exit'        ? 'Spread near mean — exit / flat'
                   : plan.currentSignal === 'wait'               ? 'Waiting for entry signal'
                   :                                                'Insufficient data'}
                </div>
              </div>
              <button type="button" onClick={() => setSelectedPair(null)}
                      className="text-[10.5px] px-2 py-0.5 rounded hover:opacity-90"
                      style={{ background: COLORS.bg, color: COLORS.textMute, border: `1px solid ${COLORS.border}` }}>
                Close plan
              </button>
            </div>

            {/* Param controls */}
            <div className="rounded border p-2 flex flex-wrap items-center gap-3 text-[10.5px]"
                 style={{ borderColor: COLORS.border, background: COLORS.bg, color: COLORS.textDim }}>
              <span style={{ color: COLORS.textMute }}>Entry Z:</span>
              <input type="number" value={planParams.entryZ} step="0.1" min="0.5" max="5"
                     onChange={(e) => setPlanParams(p => ({ ...p, entryZ: Number(e.target.value) || 2.0 }))}
                     className="w-14 px-2 py-0.5 rounded outline-none tabular-nums"
                     style={{ background: COLORS.surface, color: COLORS.text, border: `1px solid ${COLORS.border}` }} />
              <span style={{ color: COLORS.textMute }}>Exit Z:</span>
              <input type="number" value={planParams.exitZ} step="0.1" min="0" max="2"
                     onChange={(e) => setPlanParams(p => ({ ...p, exitZ: Number(e.target.value) || 0.5 }))}
                     className="w-14 px-2 py-0.5 rounded outline-none tabular-nums"
                     style={{ background: COLORS.surface, color: COLORS.text, border: `1px solid ${COLORS.border}` }} />
              <span style={{ color: COLORS.textMute }}>Stop Z:</span>
              <input type="number" value={planParams.stopZ} step="0.5" min="2" max="10"
                     onChange={(e) => setPlanParams(p => ({ ...p, stopZ: Number(e.target.value) || 4.0 }))}
                     className="w-14 px-2 py-0.5 rounded outline-none tabular-nums"
                     style={{ background: COLORS.surface, color: COLORS.text, border: `1px solid ${COLORS.border}` }} />
              <span style={{ color: COLORS.textMute }}>Lookback:</span>
              <input type="number" value={planParams.lookback} step="10" min="20" max="252"
                     onChange={(e) => setPlanParams(p => ({ ...p, lookback: Number(e.target.value) || 60 }))}
                     className="w-14 px-2 py-0.5 rounded outline-none tabular-nums"
                     style={{ background: COLORS.surface, color: COLORS.text, border: `1px solid ${COLORS.border}` }} />
              <span style={{ color: COLORS.textMute }}>bars</span>
            </div>

            {/* Stats grid */}
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-2">
              <div className="rounded border p-2" style={{ borderColor: COLORS.border, background: COLORS.bg }}>
                <div className="text-[9.5px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>Hedge ratio β</div>
                <div className="tabular-nums text-[12px] font-medium" style={{ color: COLORS.text }}>
                  {plan.beta.toFixed(4)}
                </div>
                <div className="text-[9px]" style={{ color: COLORS.textMute }}>OLS log-price</div>
              </div>
              <div className="rounded border p-2" style={{ borderColor: COLORS.border, background: COLORS.bg }}>
                <div className="text-[9.5px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>Current Z</div>
                <div className="tabular-nums text-[12px] font-medium"
                     style={{ color: Math.abs(plan.currentZ) >= 2 ? (plan.currentZ >= 0 ? COLORS.green : COLORS.red) : COLORS.text }}>
                  {plan.currentZ != null ? `${plan.currentZ >= 0 ? '+' : ''}${plan.currentZ.toFixed(2)}` : '—'}
                </div>
                <div className="text-[9px]" style={{ color: COLORS.textMute }}>spread vs μ ± σ</div>
              </div>
              <div className="rounded border p-2" style={{ borderColor: COLORS.border, background: COLORS.bg }}>
                <div className="text-[9.5px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>Backtest trades</div>
                <div className="tabular-nums text-[12px] font-medium" style={{ color: COLORS.text }}>
                  {plan.backtest.trades}
                </div>
                <div className="text-[9px]" style={{ color: COLORS.textMute }}>
                  {plan.backtest.winRate.toFixed(0)}% wins
                </div>
              </div>
              <div className="rounded border p-2" style={{ borderColor: COLORS.border, background: COLORS.bg }}>
                <div className="text-[9.5px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>Avg hold</div>
                <div className="tabular-nums text-[12px] font-medium" style={{ color: COLORS.text }}>
                  {plan.backtest.avgBarsHeld.toFixed(1)} bars
                </div>
                <div className="text-[9px]" style={{ color: COLORS.textMute }}>
                  total PnL: {(plan.backtest.totalPnL * 100).toFixed(2)}%
                </div>
              </div>
            </div>

            {/* Z-score history plot with signal markers */}
            <div className="rounded border p-2" style={{ borderColor: COLORS.border, background: COLORS.bg }}>
              <div className="text-[10px] uppercase tracking-wider mb-2" style={{ color: COLORS.textMute }}>
                Z-score history · last {plan.zScores.length} bars
              </div>
              <svg viewBox="0 0 800 200" preserveAspectRatio="none" style={{ width: '100%', height: 180 }}>
                {(() => {
                  const padT = 10, padB = 22, padL = 40, padR = 10;
                  const innerW = 800 - padL - padR;
                  const innerH = 200 - padT - padB;
                  const validZ = plan.zScores.filter(z => z != null);
                  if (validZ.length === 0) return null;
                  let minZ = Math.min(...validZ, -planParams.entryZ - 1);
                  let maxZ = Math.max(...validZ, +planParams.entryZ + 1);
                  const range = Math.max(Math.abs(minZ), Math.abs(maxZ));
                  minZ = -range - 0.3; maxZ = +range + 0.3;
                  const xScale = (i) => padL + innerW * i / Math.max(1, plan.zScores.length - 1);
                  const yScale = (z) => padT + innerH * (1 - (z - minZ) / Math.max(0.001, maxZ - minZ));
                  // Path for z-scores (skip nulls)
                  let path = '';
                  let started = false;
                  for (let i = 0; i < plan.zScores.length; i++) {
                    if (plan.zScores[i] == null) { started = false; continue; }
                    path += `${started ? 'L' : 'M'} ${xScale(i)} ${yScale(plan.zScores[i])} `;
                    started = true;
                  }
                  return (
                    <>
                      {/* Threshold lines */}
                      {[+planParams.stopZ, +planParams.entryZ, +planParams.exitZ, 0,
                        -planParams.exitZ, -planParams.entryZ, -planParams.stopZ].map(thresh => {
                        const stroke = Math.abs(thresh) >= planParams.stopZ ? COLORS.red
                                     : Math.abs(thresh) >= planParams.entryZ ? COLORS.mint
                                     : Math.abs(thresh) > 0.01 ? COLORS.textMute
                                     :                            COLORS.borderHi;
                        return (
                          <g key={thresh}>
                            <line x1={padL} y1={yScale(thresh)} x2={800 - padR} y2={yScale(thresh)}
                                  stroke={stroke} strokeWidth={Math.abs(thresh) > 0.01 ? 0.5 : 1}
                                  strokeDasharray="3 3" opacity="0.7" />
                            <text x={padL - 4} y={yScale(thresh) + 3} fontSize="9"
                                  fill={stroke} textAnchor="end" fontFamily="ui-monospace">
                              {thresh >= 0 ? '+' : ''}{thresh.toFixed(1)}
                            </text>
                          </g>
                        );
                      })}
                      {/* Z-score path */}
                      <path d={path} fill="none" stroke="#7AC8FF" strokeWidth="1.2" />
                      {/* Signal markers */}
                      {plan.signals.map((s, i) => {
                        const fill = s.action.startsWith('enter-long')  ? COLORS.green
                                   : s.action.startsWith('enter-short') ? COLORS.red
                                   : s.action === 'stop'                ? COLORS.red
                                   :                                      COLORS.mint;
                        const isStop = s.action === 'stop';
                        return (
                          <circle key={i} cx={xScale(s.idx)} cy={yScale(s.z)} r={isStop ? 4 : 3}
                                  fill={fill} stroke={COLORS.bg} strokeWidth="1.2" />
                        );
                      })}
                    </>
                  );
                })()}
              </svg>
            </div>

            {/* Recent trades from backtest */}
            {lastTrades.length > 0 && (
              <div className="rounded border" style={{ borderColor: COLORS.border, background: COLORS.bg }}>
                <div className="px-3 py-1.5 text-[10px] uppercase tracking-wider"
                     style={{ color: COLORS.textMute, borderBottom: `1px solid ${COLORS.border}` }}>
                  Last {lastTrades.length} backtested trades
                </div>
                <div className="overflow-x-auto">
                  <table className="w-full text-[10.5px] tabular-nums">
                    <thead>
                      <tr style={{ color: COLORS.textMute }}>
                        <th className="text-left px-2 py-1">Action</th>
                        <th className="text-right px-2">Entry Z</th>
                        <th className="text-right px-2">Exit Z</th>
                        <th className="text-right px-2">Bars held</th>
                        <th className="text-right px-2">PnL %</th>
                      </tr>
                    </thead>
                    <tbody>
                      {lastTrades.map((t, i) => (
                        <tr key={i} style={{ borderTop: `1px solid ${COLORS.border}` }}>
                          <td className="px-2 py-1"
                              style={{ color: t.action === 'stop' ? COLORS.red
                                            : t.action.includes('long') ? COLORS.green
                                            :                              COLORS.text }}>
                            {t.action}
                          </td>
                          <td className="text-right px-2" style={{ color: COLORS.textDim }}>
                            {t.entryZ != null ? t.entryZ.toFixed(2) : '—'}
                          </td>
                          <td className="text-right px-2" style={{ color: COLORS.textDim }}>
                            {t.z.toFixed(2)}
                          </td>
                          <td className="text-right px-2" style={{ color: COLORS.textMute }}>
                            {t.barsHeld}
                          </td>
                          <td className="text-right px-2"
                              style={{ color: t.pnl >= 0 ? COLORS.green : COLORS.red, fontWeight: 500 }}>
                            {t.pnl >= 0 ? '+' : ''}{(t.pnl * 100).toFixed(2)}%
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            )}

            <div className="text-[10px]" style={{ color: COLORS.textDim }}>
              <strong>Pair trading rules</strong>: enter when |Z| ≥ entry threshold (spread is meaningfully extreme), exit when spread reverts to mean (|Z| ≤ exit), stop when |Z| ≥ stop threshold (cointegration likely broke). Backtest PnL is in log-spread units; real trading involves transaction costs, borrow fees on the short leg, and slippage. Cointegration relationships can decay; re-screen periodically.
            </div>
          </div>
        );
      })()}
    </div>
  );
};

// SectorRotationTab — momentum ranking of sector ETFs
const SectorRotationTab = ({ setActive, setPage }) => {
  const [priceSeriesBySymbol, setPriceSeriesBySymbol] = useState({});
  const [loading, setLoading] = useState(false);

  const refresh = useCallback(async () => {
    setLoading(true);
    try {
      const fetched = await Promise.all(
        SECTOR_ETFS.map(s => fetchPolygonAggs(s.symbol, '6M', 'day', 1).catch(() => null))
      );
      const map = {};
      for (let i = 0; i < SECTOR_ETFS.length; i++) {
        const data = fetched[i];
        if (data && data.length > 0) {
          map[SECTOR_ETFS[i].symbol] = data.map(d => d.close).filter(c => c > 0);
        }
      }
      setPriceSeriesBySymbol(map);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { refresh(); }, [refresh]);

  const ranked = useMemo(() => computeSectorMomentum(priceSeriesBySymbol), [priceSeriesBySymbol]);

  return (
    <div className="space-y-4">
      <div className="rounded-md border p-3"
           style={{ borderColor: COLORS.border, background: COLORS.surface }}>
        <div className="flex items-baseline justify-between mb-2 flex-wrap gap-2">
          <div className="text-[10px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>
            Sector momentum · 11 SPDR sector ETFs
          </div>
          <button type="button"
                  onClick={refresh}
                  disabled={loading}
                  className="text-[10.5px] hover:underline disabled:opacity-50"
                  style={{ color: COLORS.mint }}>
            {loading ? 'loading…' : 'refresh'}
          </button>
        </div>
        <p className="text-[11px]" style={{ color: COLORS.textDim }}>
          Composite momentum score = 0.20·1m + 0.35·3m + 0.45·6m. Top 3 = overweight (rotate into),
          bottom 3 = underweight (rotate out of). Persistent leaders typically continue leading for
          1-3 months; reversals occur at regime shifts (recession, rate cycle inflection, etc.).
        </p>
      </div>

      {ranked.length > 0 && (
        <div className="rounded-md border"
             style={{ borderColor: COLORS.border, background: COLORS.surface }}>
          <div className="overflow-x-auto">
            <table className="w-full text-[11px] tabular-nums">
              <thead>
                <tr style={{ color: COLORS.textMute, background: COLORS.bg }}>
                  <th className="text-left px-2 py-1.5">Rank</th>
                  <th className="text-left px-2">Sector</th>
                  <th className="text-right px-2">1m</th>
                  <th className="text-right px-2">3m</th>
                  <th className="text-right px-2">6m</th>
                  <th className="text-right px-2">Composite</th>
                  <th className="text-right px-2">Action</th>
                </tr>
              </thead>
              <tbody>
                {ranked.map((s, idx) => {
                  const recColor = s.recommendation === 'overweight' ? COLORS.green
                                 : s.recommendation === 'underweight' ? COLORS.red
                                 :                                       COLORS.textDim;
                  return (
                    <tr key={s.symbol} style={{ borderTop: `1px solid ${COLORS.border}` }}>
                      <td className="px-2 py-1.5" style={{ color: COLORS.textMute }}>{idx + 1}</td>
                      <td className="px-2 py-1.5">
                        <button type="button"
                                onClick={() => {
                                  const inst = INSTRUMENTS.find(i => i.id?.startsWith(s.symbol + '-') || i.id === s.symbol || i.symbol === s.symbol);
                                  if (inst && setActive) setActive(inst);
                                  if (setPage) setPage('trade');
                                }}
                                className="hover:underline"
                                style={{ color: COLORS.text, fontWeight: 500 }}>
                          {s.symbol}
                        </button>
                        <span className="ml-2 text-[10px]" style={{ color: COLORS.textMute }}>{s.label}</span>
                      </td>
                      <td className="text-right px-2" style={{ color: s.mom1m >= 0 ? COLORS.green : COLORS.red }}>
                        {s.mom1m >= 0 ? '+' : ''}{s.mom1m.toFixed(1)}%
                      </td>
                      <td className="text-right px-2" style={{ color: s.mom3m >= 0 ? COLORS.green : COLORS.red }}>
                        {s.mom3m >= 0 ? '+' : ''}{s.mom3m.toFixed(1)}%
                      </td>
                      <td className="text-right px-2" style={{ color: s.mom6m >= 0 ? COLORS.green : COLORS.red }}>
                        {s.mom6m >= 0 ? '+' : ''}{s.mom6m.toFixed(1)}%
                      </td>
                      <td className="text-right px-2"
                          style={{ color: s.composite >= 0 ? COLORS.green : COLORS.red, fontWeight: 500 }}>
                        {s.composite >= 0 ? '+' : ''}{s.composite.toFixed(1)}%
                      </td>
                      <td className="text-right px-2 text-[10px] uppercase tracking-wider"
                          style={{ color: recColor }}>
                        {s.recommendation}
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      )}
      {/* Sector rotation backtester */}
      <SectorRotationBacktester />

      {/* Auto-tilt: rebalance suggestions based on current momentum ranking */}
      <SectorAutoTiltPanel ranked={ranked} />
    </div>
  );
};

// SectorAutoTiltPanel — generates concrete portfolio tilt suggestions
// from current sector momentum ranking. Given the SectorRotationTab's
// momentum scores, computes recommended weight changes per sector ETF
// using a momentum-based overlay on top of equal-weight base.
//
// Algorithm:
//   1. Rank sectors by 3-month momentum
//   2. Top K sectors get OVER-weight (1/N + tilt%)
//   3. Bottom K sectors get UNDER-weight (1/N - tilt%)
//   4. Middle sectors stay at base 1/N
//   5. Compute $ trades vs equal-weight baseline at user-specified capital
//
// Conservative defaults: 5% tilt magnitude (institutional sleeve allocation
// tilt is typically 3-7%). Top K = 3, bottom K = 3.
const SectorAutoTiltPanel = ({ ranked }) => {
  const [tiltPct, setTiltPct] = useState(5); // % tilt magnitude
  const [topK, setTopK] = useState(3);
  const [capital, setCapital] = useState(100000);

  const tilt = useMemo(() => {
    if (!Array.isArray(ranked) || ranked.length < 6) return null;
    const N = ranked.length;
    const baseWeight = 1 / N;
    const tilted = ranked.map((s, idx) => {
      let weightDelta = 0;
      if (idx < topK) weightDelta = +tiltPct / 100; // overweight winners
      else if (idx >= N - topK) weightDelta = -tiltPct / 100; // underweight laggards
      return {
        ...s,
        rank: idx + 1,
        baseWeight,
        targetWeight: baseWeight + weightDelta,
        weightDelta,
        baseDollars: baseWeight * capital,
        targetDollars: (baseWeight + weightDelta) * capital,
        dollarDelta: weightDelta * capital,
      };
    });
    // Normalize to sum to 1 (the underweights get redistributed if too negative)
    const totalWeight = tilted.reduce((s, t) => s + t.targetWeight, 0);
    if (Math.abs(totalWeight - 1) > 0.001) {
      const norm = 1 / totalWeight;
      for (const t of tilted) {
        t.targetWeight *= norm;
        t.targetDollars = t.targetWeight * capital;
        t.dollarDelta = t.targetDollars - t.baseDollars;
      }
    }
    // Aggregate trade size
    const totalTurnover = tilted.reduce((s, t) => s + Math.abs(t.dollarDelta), 0) / 2;
    return { tilted, totalTurnover, baseWeight };
  }, [ranked, tiltPct, topK, capital]);

  if (!tilt) return null;

  const fmtMoney = (v) => {
    const abs = Math.abs(v);
    if (abs >= 1e6) return `${v < 0 ? '−' : '+'}$${(abs / 1e6).toFixed(2)}M`;
    if (abs >= 1e3) return `${v < 0 ? '−' : '+'}$${(abs / 1e3).toFixed(0)}K`;
    return `${v < 0 ? '−' : '+'}$${abs.toLocaleString(undefined, { maximumFractionDigits: 0 })}`;
  };

  return (
    <div className="rounded-md border p-3"
         style={{ borderColor: COLORS.border, background: COLORS.surface }}>
      <div className="flex items-baseline justify-between mb-3 flex-wrap gap-2">
        <div>
          <div className="text-[10px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>
            Auto-tilt suggestions · momentum overlay
          </div>
          <div className="text-[10.5px] mt-0.5" style={{ color: COLORS.textDim }}>
            Overweight top-{topK} momentum sectors, underweight bottom-{topK}; rest stays at 1/N base
          </div>
        </div>
      </div>

      {/* Inputs */}
      <div className="grid grid-cols-1 sm:grid-cols-3 gap-2 mb-3">
        <div>
          <div className="text-[9.5px] uppercase tracking-wider mb-1" style={{ color: COLORS.textMute }}>
            Tilt % per leader
          </div>
          <div className="flex gap-1">
            {[3, 5, 7, 10].map(t => (
              <button key={t} type="button" onClick={() => setTiltPct(t)}
                      className="flex-1 px-2 py-0.5 rounded text-[10.5px] hover:opacity-80"
                      style={{
                        background: tiltPct === t ? `${COLORS.mint}1A` : COLORS.bg,
                        color: tiltPct === t ? COLORS.mint : COLORS.textDim,
                        border: `1px solid ${tiltPct === t ? COLORS.mint : COLORS.border}`,
                      }}>
                {t}%
              </button>
            ))}
          </div>
        </div>
        <div>
          <div className="text-[9.5px] uppercase tracking-wider mb-1" style={{ color: COLORS.textMute }}>
            Top/bottom K
          </div>
          <div className="flex gap-1">
            {[2, 3, 4, 5].map(k => (
              <button key={k} type="button" onClick={() => setTopK(k)}
                      className="flex-1 px-2 py-0.5 rounded text-[10.5px] hover:opacity-80"
                      style={{
                        background: topK === k ? `${COLORS.mint}1A` : COLORS.bg,
                        color: topK === k ? COLORS.mint : COLORS.textDim,
                        border: `1px solid ${topK === k ? COLORS.mint : COLORS.border}`,
                      }}>
                {k}
              </button>
            ))}
          </div>
        </div>
        <div>
          <div className="text-[9.5px] uppercase tracking-wider mb-1" style={{ color: COLORS.textMute }}>
            Capital ($)
          </div>
          <input type="number" min="1000" step="1000"
                 value={capital}
                 onChange={(e) => setCapital(Math.max(1000, parseFloat(e.target.value) || 100000))}
                 className="w-full px-2 py-1 rounded text-[12px] outline-none tabular-nums"
                 style={{ background: COLORS.bg, color: COLORS.text, border: `1px solid ${COLORS.border}` }} />
        </div>
      </div>

      {/* Summary */}
      <div className="rounded border p-2 mb-3"
           style={{ borderColor: `${COLORS.mint}55`, background: `${COLORS.mint}05` }}>
        <div className="text-[10.5px]" style={{ color: COLORS.text }}>
          Total turnover: <strong style={{ color: COLORS.mint }}>{fmtMoney(tilt.totalTurnover).replace('+', '')}</strong>
          {' '}·{' '}
          Base weight: <strong>{(tilt.baseWeight * 100).toFixed(1)}%</strong> per sector
        </div>
      </div>

      {/* Per-sector tilt table */}
      <div className="overflow-x-auto rounded border" style={{ borderColor: COLORS.border }}>
        <table className="w-full text-[10.5px] tabular-nums">
          <thead>
            <tr style={{ color: COLORS.textMute, background: COLORS.bg }}>
              <th className="text-left px-3 py-1.5">Rank</th>
              <th className="text-left px-2">Sector</th>
              <th className="text-right px-2">3m mom</th>
              <th className="text-right px-2">Base wt</th>
              <th className="text-right px-2">Target wt</th>
              <th className="text-right px-2">Δ wt</th>
              <th className="text-right px-3">Dollar delta</th>
            </tr>
          </thead>
          <tbody>
            {tilt.tilted.map(s => (
              <tr key={s.symbol} style={{ borderTop: `1px solid ${COLORS.border}` }}>
                <td className="px-3 py-1" style={{ color: COLORS.textDim }}>
                  {s.rank}
                </td>
                <td className="px-2" style={{ color: COLORS.text, fontWeight: 500 }}>
                  {s.symbol}
                </td>
                <td className="text-right px-2"
                    style={{ color: s.mom3m >= 0 ? COLORS.green : COLORS.red }}>
                  {s.mom3m >= 0 ? '+' : ''}{s.mom3m.toFixed(1)}%
                </td>
                <td className="text-right px-2" style={{ color: COLORS.textDim }}>
                  {(s.baseWeight * 100).toFixed(1)}%
                </td>
                <td className="text-right px-2"
                    style={{
                      color: s.weightDelta > 0 ? COLORS.green
                           : s.weightDelta < 0 ? COLORS.red : COLORS.text,
                      fontWeight: s.weightDelta !== 0 ? 500 : 400,
                    }}>
                  {(s.targetWeight * 100).toFixed(1)}%
                </td>
                <td className="text-right px-2"
                    style={{
                      color: s.weightDelta > 0 ? COLORS.green
                           : s.weightDelta < 0 ? COLORS.red : COLORS.textMute,
                    }}>
                  {s.weightDelta > 0 ? '+' : ''}{(s.weightDelta * 100).toFixed(1)}%
                </td>
                <td className="text-right px-3"
                    style={{
                      color: s.dollarDelta > 0 ? COLORS.green
                           : s.dollarDelta < 0 ? COLORS.red : COLORS.textMute,
                      fontWeight: Math.abs(s.dollarDelta) > 1000 ? 500 : 400,
                    }}>
                  {Math.abs(s.dollarDelta) > 0.5 ? fmtMoney(s.dollarDelta) : '—'}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      <div className="text-[10px] mt-2" style={{ color: COLORS.textDim }}>
        <strong>Auto-tilt</strong> overlays a momentum bet on top of the equal-weight sector base.
        <strong> 5% tilt × 3 leaders + 3 laggards</strong> = 30% of capital is "active bet";
        70% stays neutral. <strong>Larger tilts (10%+)</strong> become aggressive — most institutional
        sleeves stay within 3-7% per sector. <strong>Caveats</strong>: momentum can fail at
        regime turns (March 2009 / 2020 — laggards became leaders fast). This is a STATIC snapshot;
        for dynamic backtest with rebalance frequency + transaction costs, see Sector Rotation
        Backtester above.
      </div>
    </div>
  );
};

// SectorRotationBacktester — simulates a momentum-based sector rotation
// strategy over historical data. Rules:
//   1. Every N months, rank all 11 sector ETFs by 3-month momentum
//   2. Hold equal-weight positions in the top K sectors
//   3. Optional regime filter: only hold long when SPY is above its
//      200-day SMA (otherwise hold cash / IEF bonds)
//   4. Compare cumulative return to buy-and-hold SPY
//
// This is a classic "tactical asset allocation" approach popularized by
// Mebane Faber, GLDIRT, and similar systematic frameworks. The momentum
// premium in cross-sectional sector data is well-documented but has
// degraded post-2008 — current decade returns weaker than long-term avg.
const SectorRotationBacktester = () => {
  const [period, setPeriod] = useState('3Y');
  const [rebalanceInterval, setRebalanceInterval] = useState(1); // months
  const [topK, setTopK] = useState(3);
  const [useRegimeFilter, setUseRegimeFilter] = useState(true);
  const [bars, setBars] = useState({}); // symbol → daily bars
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    setError(null);
    const symbols = [...SECTOR_ETFS.map(s => s.symbol), 'SPY', 'IEF'];
    Promise.all(symbols.map(s => fetchPolygonAggs(s, period, 'day', 1).catch(() => null)))
      .then(results => {
        if (cancelled) return;
        const map = {};
        for (let i = 0; i < symbols.length; i++) {
          if (results[i] && results[i].length > 0) map[symbols[i]] = results[i];
        }
        setBars(map);
      })
      .catch(e => { if (!cancelled) setError(e?.message || 'Failed to load'); })
      .finally(() => { if (!cancelled) setLoading(false); });
    return () => { cancelled = true; };
  }, [period]);

  const result = useMemo(() => {
    if (!bars.SPY || bars.SPY.length < 130) return null;
    // Build a unified date index from SPY (sectors should align)
    const spyBars = bars.SPY;
    const ief = bars.IEF || [];
    // Build close arrays per symbol aligned to SPY dates
    const closesBySym = {};
    closesBySym.SPY = spyBars.map(b => b.close);
    if (ief.length > 0) {
      // Align IEF to SPY dates by index (assume same trading-day cadence)
      const minLen = Math.min(spyBars.length, ief.length);
      closesBySym.IEF = ief.slice(-minLen).map(b => b.close);
    }
    for (const sec of SECTOR_ETFS) {
      const data = bars[sec.symbol];
      if (data && data.length >= spyBars.length - 5) {
        const offset = data.length - spyBars.length;
        closesBySym[sec.symbol] = data.slice(Math.max(0, offset)).map(b => b.close);
      }
    }
    // Walk forward day by day. Initial cash = $10,000. At each rebalance
    // boundary (every rebalanceInterval months ≈ 21*N days), recompute
    // top-K sectors and equal-weight allocate.
    const N = spyBars.length;
    if (N < 130) return null;
    let strategyValue = 10000;
    let buyHoldValue = 10000;
    let allocations = {}; // symbol → shares
    let buyHoldShares = strategyValue / closesBySym.SPY[100]; // start at day 100 to allow momentum lookback
    const startDay = 100;
    const rebalanceDays = rebalanceInterval * 21;
    let lastRebalance = startDay - 1; // force first rebalance at start
    let trades = 0;
    const equity = []; // {date, strategy, buyHold}
    for (let t = startDay; t < N; t++) {
      const date = spyBars[t].date;
      // Check rebalance trigger
      if (t - lastRebalance >= rebalanceDays) {
        // Compute 3-month momentum (63 trading days back) per sector
        const ranks = [];
        for (const sec of SECTOR_ETFS) {
          const closes = closesBySym[sec.symbol];
          if (!closes || t < 63) continue;
          const cur = closes[t];
          const past = closes[t - 63];
          if (cur && past && past > 0) {
            ranks.push({ symbol: sec.symbol, momentum: (cur - past) / past });
          }
        }
        ranks.sort((a, b) => b.momentum - a.momentum);
        // Regime filter: SPY > 200SMA?
        let inMarket = true;
        if (useRegimeFilter) {
          if (t >= 200) {
            const spyClose = closesBySym.SPY[t];
            const sma200 = closesBySym.SPY.slice(t - 200, t).reduce((s, c) => s + c, 0) / 200;
            inMarket = spyClose > sma200;
          }
        }
        // Liquidate current allocation at today's price
        let cash = 0;
        for (const sym of Object.keys(allocations)) {
          const px = closesBySym[sym]?.[t] || 0;
          cash += allocations[sym] * px;
          delete allocations[sym];
        }
        if (cash === 0) cash = strategyValue;
        // Allocate
        if (inMarket && ranks.length >= topK) {
          const slice = ranks.slice(0, topK);
          const perSlice = cash / topK;
          for (const r of slice) {
            const px = closesBySym[r.symbol]?.[t] || 0;
            if (px > 0) {
              allocations[r.symbol] = perSlice / px;
              trades++;
            }
          }
        } else if (closesBySym.IEF) {
          // Defensive: rotate to IEF (bonds)
          const iefPx = closesBySym.IEF[t] || 0;
          if (iefPx > 0) {
            allocations.IEF = cash / iefPx;
            trades++;
          }
        }
        lastRebalance = t;
      }
      // Mark to market
      let mtm = 0;
      for (const sym of Object.keys(allocations)) {
        const px = closesBySym[sym]?.[t] || 0;
        mtm += allocations[sym] * px;
      }
      strategyValue = mtm > 0 ? mtm : strategyValue;
      buyHoldValue = buyHoldShares * (closesBySym.SPY[t] || closesBySym.SPY[t - 1] || 0);
      // Sample equity curve every 5 days
      if (t % 5 === 0) {
        equity.push({ date, strategy: strategyValue, buyHold: buyHoldValue });
      }
    }
    // Compute summary stats
    const startVal = 10000;
    const totalDays = N - startDay;
    const yrs = totalDays / 252;
    const stratCAGR = yrs > 0 ? (Math.pow(strategyValue / startVal, 1 / yrs) - 1) * 100 : 0;
    const buyHoldCAGR = yrs > 0 ? (Math.pow(buyHoldValue / startVal, 1 / yrs) - 1) * 100 : 0;
    // Compute max drawdown for each
    const maxDD = (series) => {
      let peak = 0, maxDD = 0;
      for (const e of series) {
        if (e > peak) peak = e;
        const dd = (peak - e) / peak;
        if (dd > maxDD) maxDD = dd;
      }
      return maxDD * 100;
    };
    const stratMaxDD = maxDD(equity.map(e => e.strategy));
    const buyHoldMaxDD = maxDD(equity.map(e => e.buyHold));
    // Sharpe (annualized) — using equity curve sampled every 5 days
    const sharpe = (series) => {
      if (series.length < 10) return 0;
      const rets = [];
      for (let i = 1; i < series.length; i++) {
        rets.push((series[i] - series[i - 1]) / series[i - 1]);
      }
      const mean = rets.reduce((s, r) => s + r, 0) / rets.length;
      const variance = rets.reduce((s, r) => s + (r - mean) ** 2, 0) / rets.length;
      const std = Math.sqrt(variance);
      if (std === 0) return 0;
      // 5-day → 252/5 ≈ 50 periods/year
      const periodsPerYear = 252 / 5;
      return (mean / std) * Math.sqrt(periodsPerYear);
    };
    const stratSharpe = sharpe(equity.map(e => e.strategy));
    const buyHoldSharpe = sharpe(equity.map(e => e.buyHold));
    return {
      equity,
      strategyValue, buyHoldValue,
      stratCAGR, buyHoldCAGR,
      stratMaxDD, buyHoldMaxDD,
      stratSharpe, buyHoldSharpe,
      trades,
      excessReturn: stratCAGR - buyHoldCAGR,
    };
  }, [bars, rebalanceInterval, topK, useRegimeFilter]);

  return (
    <div className="rounded-md border p-3"
         style={{ borderColor: COLORS.border, background: COLORS.surface }}>
      <div className="flex items-baseline justify-between mb-3 flex-wrap gap-2">
        <div>
          <div className="text-[10px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>
            Sector rotation backtester
          </div>
          <div className="text-[11px] mt-0.5" style={{ color: COLORS.textDim }}>
            Top-K momentum strategy on 11 SPDR sectors with optional 200-SMA regime filter.
            Compared to SPY buy-and-hold.
          </div>
        </div>
      </div>
      {/* Controls */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-2 mb-3">
        <div>
          <div className="text-[9.5px] uppercase tracking-wider mb-1" style={{ color: COLORS.textMute }}>Period</div>
          <select value={period} onChange={(e) => setPeriod(e.target.value)}
                  className="w-full px-2 py-1 rounded text-[12px] outline-none"
                  style={{ background: COLORS.bg, color: COLORS.text, border: `1px solid ${COLORS.border}`, colorScheme: 'dark' }}>
            <option value="2Y">2 Years</option>
            <option value="3Y">3 Years</option>
            <option value="5Y">5 Years</option>
            <option value="10Y">10 Years</option>
          </select>
        </div>
        <div>
          <div className="text-[9.5px] uppercase tracking-wider mb-1" style={{ color: COLORS.textMute }}>Top K sectors</div>
          <select value={topK} onChange={(e) => setTopK(Number(e.target.value))}
                  className="w-full px-2 py-1 rounded text-[12px] outline-none"
                  style={{ background: COLORS.bg, color: COLORS.text, border: `1px solid ${COLORS.border}`, colorScheme: 'dark' }}>
            <option value={1}>Top 1</option>
            <option value={2}>Top 2</option>
            <option value={3}>Top 3</option>
            <option value={4}>Top 4</option>
            <option value={5}>Top 5</option>
          </select>
        </div>
        <div>
          <div className="text-[9.5px] uppercase tracking-wider mb-1" style={{ color: COLORS.textMute }}>Rebalance every</div>
          <select value={rebalanceInterval} onChange={(e) => setRebalanceInterval(Number(e.target.value))}
                  className="w-full px-2 py-1 rounded text-[12px] outline-none"
                  style={{ background: COLORS.bg, color: COLORS.text, border: `1px solid ${COLORS.border}`, colorScheme: 'dark' }}>
            <option value={1}>1 month</option>
            <option value={2}>2 months</option>
            <option value={3}>3 months (quarterly)</option>
            <option value={6}>6 months</option>
          </select>
        </div>
        <div>
          <div className="text-[9.5px] uppercase tracking-wider mb-1" style={{ color: COLORS.textMute }}>Regime filter</div>
          <button type="button" onClick={() => setUseRegimeFilter(!useRegimeFilter)}
                  className="w-full px-2 py-1 rounded text-[11px] inline-flex items-center justify-center gap-1.5"
                  style={{
                    background: useRegimeFilter ? `${COLORS.mint}1A` : COLORS.bg,
                    color: useRegimeFilter ? COLORS.mint : COLORS.textDim,
                    border: `1px solid ${useRegimeFilter ? COLORS.mint : COLORS.border}`,
                  }}>
            {useRegimeFilter ? '✓ ON · 200-SMA' : 'OFF'}
          </button>
        </div>
      </div>
      {loading && (
        <div className="text-[11px] py-3 text-center" style={{ color: COLORS.textMute }}>
          Loading sector + benchmark data…
        </div>
      )}
      {error && !loading && (
        <div className="rounded p-2 text-[11px]"
             style={{ background: 'rgba(255,85,119,0.06)', color: COLORS.red, border: `1px solid ${COLORS.red}55` }}>
          {error}
        </div>
      )}
      {!loading && !error && result && (
        <>
          {/* Comparison metrics */}
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-2 mb-3">
            <div className="rounded border p-2" style={{ borderColor: `${COLORS.mint}55`, background: `${COLORS.mint}08` }}>
              <div className="text-[9.5px] uppercase tracking-wider" style={{ color: COLORS.mint }}>Strategy CAGR</div>
              <div className="tabular-nums text-[14px] font-medium"
                   style={{ color: result.stratCAGR >= result.buyHoldCAGR ? COLORS.green : COLORS.red }}>
                {result.stratCAGR >= 0 ? '+' : ''}{result.stratCAGR.toFixed(2)}%
              </div>
              <div className="text-[9.5px]" style={{ color: COLORS.textMute }}>
                vs SPY {result.buyHoldCAGR >= 0 ? '+' : ''}{result.buyHoldCAGR.toFixed(2)}%
              </div>
            </div>
            <div className="rounded border p-2" style={{ borderColor: COLORS.border, background: COLORS.bg }}>
              <div className="text-[9.5px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>Excess return</div>
              <div className="tabular-nums text-[14px] font-medium"
                   style={{ color: result.excessReturn > 0 ? COLORS.green : COLORS.red }}>
                {result.excessReturn >= 0 ? '+' : ''}{result.excessReturn.toFixed(2)}%
              </div>
              <div className="text-[9.5px]" style={{ color: COLORS.textMute }}>
                CAGR delta
              </div>
            </div>
            <div className="rounded border p-2" style={{ borderColor: COLORS.border, background: COLORS.bg }}>
              <div className="text-[9.5px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>Max drawdown</div>
              <div className="tabular-nums text-[14px] font-medium"
                   style={{ color: result.stratMaxDD < result.buyHoldMaxDD ? COLORS.green : COLORS.red }}>
                −{result.stratMaxDD.toFixed(1)}%
              </div>
              <div className="text-[9.5px]" style={{ color: COLORS.textMute }}>
                SPY: −{result.buyHoldMaxDD.toFixed(1)}%
              </div>
            </div>
            <div className="rounded border p-2" style={{ borderColor: COLORS.border, background: COLORS.bg }}>
              <div className="text-[9.5px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>Sharpe</div>
              <div className="tabular-nums text-[14px] font-medium"
                   style={{ color: result.stratSharpe > result.buyHoldSharpe ? COLORS.green : COLORS.red }}>
                {result.stratSharpe.toFixed(2)}
              </div>
              <div className="text-[9.5px]" style={{ color: COLORS.textMute }}>
                SPY: {result.buyHoldSharpe.toFixed(2)} · {result.trades} trades
              </div>
            </div>
          </div>
          {/* Equity curve */}
          {result.equity.length > 5 && (
            <div className="rounded border p-3" style={{ borderColor: COLORS.border, background: COLORS.bg }}>
              <div className="flex items-baseline justify-between mb-2">
                <div className="text-[10px] uppercase tracking-wider" style={{ color: COLORS.textMute }}>
                  Equity curves · $10K start
                </div>
                <div className="flex gap-3 text-[9.5px]" style={{ color: COLORS.textDim }}>
                  <span><span style={{ color: COLORS.mint }}>━</span> Strategy</span>
                  <span><span style={{ color: COLORS.chartGold }}>━</span> SPY buy-hold</span>
                </div>
              </div>
              <svg viewBox="0 0 800 200" preserveAspectRatio="none" style={{ width: '100%', height: 180 }}>
                {(() => {
                  const padT = 12, padB = 24, padL = 50, padR = 12;
                  const innerW = 800 - padL - padR;
                  const innerH = 200 - padT - padB;
                  const stratVals = result.equity.map(e => e.strategy);
                  const bhVals = result.equity.map(e => e.buyHold);
                  const allVals = [...stratVals, ...bhVals];
                  const minV = Math.min(...allVals);
                  const maxV = Math.max(...allVals);
                  const yScale = (v) => padT + innerH * (1 - (v - minV) / Math.max(0.01, maxV - minV));
                  const xScale = (i) => padL + (innerW * i) / Math.max(1, result.equity.length - 1);
                  const stratPath = stratVals.map((v, i) => `${i === 0 ? 'M' : 'L'} ${xScale(i)} ${yScale(v)}`).join(' ');
                  const bhPath = bhVals.map((v, i) => `${i === 0 ? 'M' : 'L'} ${xScale(i)} ${yScale(v)}`).join(' ');
                  return (
                    <>
                      {/* $10K line */}
                      <line x1={padL} y1={yScale(10000)} x2={800 - padR} y2={yScale(10000)}
                            stroke={COLORS.borderHi} strokeDasharray="2 4" strokeWidth="0.5" />
                      <text x={padL - 4} y={yScale(10000) + 3} fontSize="9"
                            fill={COLORS.textMute} textAnchor="end" fontFamily="ui-monospace">$10K</text>
                      <text x={padL - 4} y={yScale(maxV) + 3} fontSize="9"
                            fill={COLORS.textMute} textAnchor="end" fontFamily="ui-monospace">${(maxV / 1000).toFixed(0)}K</text>
                      <text x={padL - 4} y={yScale(minV) + 3} fontSize="9"
                            fill={COLORS.textMute} textAnchor="end" fontFamily="ui-monospace">${(minV / 1000).toFixed(0)}K</text>
                      <path d={bhPath} fill="none" stroke={COLORS.chartGold} strokeWidth="1.5" opacity="0.85" />
                      <path d={stratPath} fill="none" stroke={COLORS.mint} strokeWidth="2" />
                      {/* Date labels */}
                      {[0, Math.floor(result.equity.length / 2), result.equity.length - 1].map(i => (
                        <text key={i} x={xScale(i)} y={200 - 6}
                              fontSize="9" fill={COLORS.textDim}
                              textAnchor="middle" fontFamily="ui-monospace">
                          {result.equity[i].date}
                        </text>
                      ))}
                    </>
                  );
                })()}
              </svg>
            </div>
          )}
          <div className="text-[10px] mt-2" style={{ color: COLORS.textDim }}>
            <strong>Strategy</strong>: every {rebalanceInterval} month{rebalanceInterval === 1 ? '' : 's'},
            rank 11 SPDR sector ETFs by 3-month momentum, equal-weight allocate to top {topK}
            {useRegimeFilter ? ' (only when SPY > 200-SMA; otherwise rotate to IEF bonds)' : ''}.
            Cross-sectional momentum is well-documented but has degraded post-2008. Regime filter cushions
            drawdowns at the cost of some upside. <strong>Trading costs not modeled</strong> — assume
            10-15bps round-trip per rebalance for realistic net returns. Results are point-estimates,
            not robust to parameter changes — Walk-Forward Backtester (Strategies tab) handles overfit
            risk more rigorously.
          </div>
        </>
      )}
    </div>
  );
};

// SmartMoneyTab — curated 13F holdings

// ════════════════════════════════════════════════════════════════════
// EARNINGS & EVENTS CALENDAR
// ════════════════════════════════════════════════════════════════════
//
// Aggregates upcoming corporate events (earnings, ex-dividends, splits,
// etc.) + macro events (FOMC meetings, CPI/NFP/jobs releases) into a
// unified calendar. Per-position tagged so users see "you have AAPL
// earnings in 3 days, position is $24,300 long".
//
// Data sources:
//   - Earnings dates: Polygon /reference/financials and a curated
//     hardcoded set for major tickers (mock data for those without
//     Polygon coverage)
//   - Dividends: Polygon /reference/dividends
//   - Macro events: hardcoded calendar of typical schedule (FOMC = ~8x/yr,
//     CPI = monthly mid-month, NFP = first Friday, etc.)
//
// What we DON'T have (yet):
//   - Real-time event feed from a paid provider (Bloomberg, Refinitiv)
//   - Earnings whisper numbers / consensus estimates
//   - Push alerts when an event approaches (deferred — could plug into
//     the same SSE pipeline as the scanner)

// MACRO_EVENTS — recurring scheduled events. Generated programmatically
// for the next 60 days. Each event has a "weight" indicating market-
// moving importance (1-3, where 3 = FOMC / NFP).
const generateMacroEvents = (lookAheadDays = 60) => {
  const out = [];
  const now = new Date();
  for (let d = 0; d < lookAheadDays; d++) {
    const date = new Date(now.getTime() + d * 86400000);
    const dow = date.getDay(); // 0=Sun, 1=Mon...
    const dom = date.getDate();
    const month = date.getMonth();

    // First Friday of month → NFP (Non-Farm Payrolls), 8:30 AM ET
    if (dow === 5 && dom <= 7) {
      out.push({
        ts: date.setHours(8, 30, 0, 0),
        type: 'macro',
        weight: 3,
        title: 'Non-Farm Payrolls',
        ticker: '__macro__',
        details: 'BLS releases monthly employment data; major market mover.',
      });
    }
    // Mid-month CPI release (typically around the 10th-15th, business day)
    if (dom >= 10 && dom <= 15 && dow >= 1 && dow <= 5) {
      // Only put one CPI per month — heuristic: if the previous business
      // day was already in the 10-15 window, skip
      const lastDay = new Date(date.getTime() - 86400000).getDate();
      if (lastDay < 10 || (lastDay >= 10 && date.getDay() === 1)) {
        out.push({
          ts: new Date(date.setHours(8, 30, 0, 0)).getTime(),
          type: 'macro',
          weight: 3,
          title: 'CPI release',
          ticker: '__macro__',
          details: 'Consumer Price Index. Headline + core; bond/dollar moves on miss.',
        });
      }
    }
    // FOMC meetings — typically 8 per year, third Wed of certain months.
    // Approximate: Jan/Mar/May/Jun/Jul/Sep/Nov/Dec, third Wed.
    const fomcMonths = [0, 2, 4, 5, 6, 8, 10, 11];
    if (dow === 3 && dom >= 15 && dom <= 21 && fomcMonths.includes(month)) {
      out.push({
        ts: date.setHours(14, 0, 0, 0),
        type: 'macro',
        weight: 3,
        title: 'FOMC Decision',
        ticker: '__macro__',
        details: 'Fed funds rate decision + Powell press conference at 2:30 PM ET.',
      });
    }
    // Initial Jobless Claims — every Thursday 8:30 AM
    if (dow === 4) {
      out.push({
        ts: new Date(date.setHours(8, 30, 0, 0)).getTime(),
        type: 'macro',
        weight: 1,
        title: 'Initial Jobless Claims',
        ticker: '__macro__',
        details: 'Weekly unemployment claims. Modest market mover.',
      });
    }
    // ISM Manufacturing — first business day of each month, 10:00 AM
    if (dom <= 3 && dow >= 1 && dow <= 5) {
      const lastDay = new Date(date.getTime() - 86400000).getDate();
      if (lastDay > 25 || lastDay === 0) {
        out.push({
          ts: new Date(date.setHours(10, 0, 0, 0)).getTime(),
          type: 'macro',
          weight: 2,
          title: 'ISM Manufacturing PMI',
          ticker: '__macro__',
          details: 'Manufacturing activity barometer. Below 50 = contraction.',
        });
      }
    }
  }
  return out.sort((a, b) => a.ts - b.ts);
};

// Curated earnings calendar for major tickers — fallback when Polygon
// doesn't have the date. Approximated based on each company's typical
// reporting cadence (quarterly, with the date drifting roughly within
// a 7-day window of the previous year's date).
