// ════════════════════════════════════════════════════════════════════
// WORKFLOW NODE EDITOR
// ════════════════════════════════════════════════════════════════════
//
// Visual node-graph strategy builder. Users drag nodes onto a canvas
// and connect them. Each bar, the graph is evaluated in topological
// order — values flow through edges from input nodes (price, RSI,
// SMA…) through transform nodes (compare, AND/OR, threshold) to a
// terminal signal node that returns 'enter'|'exit'|'hold'.
//
// Why build our own rather than depend on react-flow?
//   - react-flow is ~200KB minified — meaningful bundle hit
//   - Our graph is small (typically < 20 nodes) and our use case
//     doesn't need react-flow's mini-map, multi-canvas, etc.
//   - Native SVG gives us full control over rendering and avoids
//     a dep that's overkill for this scope.
//
// Tradeoff: features react-flow ships for free (snap-to-grid, rubber-
// band selection, undo/redo, copy/paste) we'd have to build. This
// drop ships the core (drag, connect, evaluate, persist); future
// drops can add polish if there's user demand.
//
// Data shape:
//   workflow = {
//     id: string, name: string, savedAt: number,
//     nodes: [{ id, type, position: {x, y}, params: {...} }],
//     edges: [{ from: { node, port }, to: { node, port } }]
//   }
//
// Node registry — each entry defines:
//   id        — node type id
//   label     — human-readable name
//   category  — 'input' | 'transform' | 'output' (for palette grouping)
//   inputs    — [{ id, label, type: 'number'|'boolean' }] (read from edges)
//   outputs   — [{ id, label, type }] (provided to downstream)
//   params    — [{ id, label, kind: 'number'|'select'|'string', ... }]
//               configurable per-instance values
//   evaluate  — (params, inputs, ctx) => { [outputId]: value }
//               called once per bar with resolved input values
//
// Inputs/outputs are addressed by port id within each node.

// Compile a workflow into a function-mode strategy. Performs:
//   1. Topological sort (with cycle detection — returns error if cyclic)
//   2. Per-bar evaluation: walk the topo order, resolve inputs from
//      upstream output cache, run evaluate(), cache outputs.
//   3. Pull final signal from the output-signal node.
//
// Returns: { fn, error } where fn = (bars, i, ctx) => 'enter'|'exit'|'hold'

// localStorage persistence

// Default starter workflow — a working 3-node example so users land
// in a non-empty graph and can see how connections work.

// ════════════════════════════════════════════════════════════════════
// AI MARKET SCANNER
// ════════════════════════════════════════════════════════════════════
//
// The scanner walks a watchlist of tickers, fetches OHLCV, and runs a
// battery of pattern-detection rules entirely client-side. Each rule
// emits a SetupCandidate { ticker, setup, score, levels, ... } when
// its conditions trigger; the scanner ranks and surfaces the top N.
//
// Why client-side detection instead of an LLM call per ticker?
//   - LLM-per-ticker would burn budget fast (50 tickers × 20s each)
//   - Pattern detection is purely deterministic
//   - The LLM still earns its keep on the FINALISTS — see
//     summarizeSetupWithAI below — where it can synthesize the
//     scanner's structured signals into a 2-3 sentence trader
//     narrative the user can read at a glance
//
// Setup types modeled (loosely after the Vibe-Trading "five schools"
// + classic Western TA + a few SMC patterns):
//
//   bull-breakout     20-day high break with volume spike
//   bear-breakdown    20-day low break with volume spike
//   bull-flag         pullback after impulse, holding above 20EMA
//   bear-flag         bounce after impulse down, capped under 20EMA
//   oversold-bounce   RSI cross from <30 with bullish candle
//   overbought-fade   RSI cross from >70 with bearish candle
//   bb-squeeze        BB width compressed → primed for expansion
//   bb-expansion      BB width expanding from squeeze, direction set
//   golden-cross      50-day SMA crossing above 200-day SMA
//   death-cross       50-day SMA crossing below 200-day SMA
//   macd-bull-cross   MACD line crosses above signal in oversold
//   macd-bear-cross   MACD line crosses below signal in overbought
//   higher-low-stack  Series of higher lows (uptrend confirmation)
//   lower-high-stack  Series of lower highs (downtrend confirmation)
//   gap-and-go        Open gap up + held above gap line
//   gap-fill-fade     Open gap up + closed in gap (failed)
//   volume-thrust     5x average volume + close in upper third
//   smc-bull-bos      Break of structure up after liquidity sweep
//   smc-bear-bos      Break of structure down after liquidity sweep

// SETUP_RULES — array of detector functions. Each takes (bars, i) and
// returns null OR { setup, side, score, ... details }. The framework
// runs every rule against the most recent bar and aggregates results.
//
// `score` is 0-100; higher = stronger setup. Detectors can use
// QUANT_PRIMITIVES or read bars directly. They should ONLY look
// at bars[0..i] (no lookahead) since the scanner runs in "current
// bar" mode, not historical replay.
// DETECTOR_DEFAULTS — central table of every detector's tunable
// parameters with their defaults. Surfaced in scanner settings so
// users can tighten/loosen each detector to their style.


// detectSetups — run every SETUP_RULES detector against the latest
// bar (i = bars.length - 1) and return all matching candidates,
// sorted by score descending.
const detectSetups = (bars, ticker, detectorParams = {}) => {
  if (!bars || bars.length < 30) return [];
  const i = bars.length - 1;
  const out = [];
  for (const rule of SETUP_RULES) {
    try {
      const r = rule.detect(bars, i, detectorParams[rule.id] || {});
      if (r && r.score >= 30) {
        out.push({
          ticker,
          ruleId: rule.id,
          label:  rule.label,
          side:   r.side ?? rule.side,
          score:  r.score,
          levels: r.levels || {},
          notes:  r.notes || '',
          barIdx: i,
          asOfT:  bars[i].t,
          // Carry the bars so the chart-renderer + AI summarizer can
          // use them. They're a few KB so no real cost.
          bars,
        });
      }
    } catch (e) {
      // Detector failure — skip silently
    }
  }
  out.sort((a, b) => b.score - a.score);
  return out;
};





// Default scanner watchlist — large-cap US equities. Users can edit.


// ════════════════════════════════════════════════════════════════════
// BEHAVIORAL TRADE-JOURNAL DIAGNOSTICS
// ════════════════════════════════════════════════════════════════════
//
// Adapted from the Vibe-Trading "trade-journal" skill — analyzes a
// user's trade history for cognitive biases that quietly hurt
// performance. All four diagnostics are deterministic with explicit
// numeric thresholds (no LLM call, no ambiguity).
//
// The analyzer takes the account's `trades` array and matches buy/sell
// pairs by ticker (FIFO), constructing a list of completed round-trips
// with entry price, exit price, hold duration, and realized PnL.
// Then runs four diagnostics:
//
//   1. Disposition effect — do you cut winners short and ride losers?
//      Compare avg holding period of winners vs losers.
//   2. Overtrading — too many small trades. Look at trades-per-week
//      and median PnL relative to typical fees+spread.
//   3. Chasing momentum — entering positions late in moves. Look at
//      entry-day return % to estimate "how heated was the move?"
//   4. Anchoring — bias toward round numbers and recent peaks. Check
//      what fraction of entries are within 2% of recent 20-day high.
//
// Each diagnostic returns:
//   { severity: 'low'|'medium'|'high', evidence: [{ label, value }] }

// Phase 3o.95 (file split, batch 7): buildRoundTrips extracted to
// src/lib/quant/quant-misc.js.

// Disposition effect — losers held longer than winners?
const diagDispositionEffect = (trips) => {
  if (trips.length < 5) return { severity: 'low', evidence: [{ label: 'Trades', value: 'Not enough trades to detect (need >= 5 round-trips)' }] };
  const winners = trips.filter(t => t.pnl > 0);
  const losers  = trips.filter(t => t.pnl < 0);
  if (winners.length === 0 || losers.length === 0) {
    return {
      severity: 'low',
      evidence: [
        { label: 'Winners', value: `${winners.length}` },
        { label: 'Losers',  value: `${losers.length}` },
        { label: 'Note',    value: 'Need both winning and losing trades to detect this bias' },
      ],
    };
  }
  // We don't have rich timestamps from the synthetic trade log so we
  // approximate hold duration by trade-list-order (rank) rather than
  // calendar time. With real broker exports, replace this with actual
  // datetime parsing. Hold "rank" = exit position - entry position.
  const orderedTrips = [...trips];
  orderedTrips.forEach((t, i) => { t._idx = i; });
  // For each round-trip, hold "duration" approximation = exit time
  // string compared to entry time string. We just count round-trips
  // for now and use win/loss size ratio as the disposition proxy:
  // "letting losers grow vs cutting winners" → avg loser size / avg
  // winner size. Bigger losers than winners by abs(ret) = disposition
  // bias.
  const avgWinRet  = winners.reduce((a, b) => a + b.ret, 0) / winners.length;
  const avgLossRet = losers.reduce((a, b) => a + b.ret, 0)  / losers.length;
  const ratio = Math.abs(avgLossRet) / (Math.abs(avgWinRet) || 0.0001);
  let severity = 'low';
  if (ratio > 2.0) severity = 'high';
  else if (ratio > 1.3) severity = 'medium';
  return {
    severity,
    evidence: [
      { label: 'Avg winning return',  value: `${(avgWinRet * 100).toFixed(2)}%` },
      { label: 'Avg losing return',   value: `${(avgLossRet * 100).toFixed(2)}%` },
      { label: 'Loss/win magnitude',  value: ratio.toFixed(2) + 'x' },
      { label: 'Reading',             value: severity === 'high'
                                        ? 'Losses are much larger than wins — classic disposition effect (cutting winners, riding losers)'
                                        : severity === 'medium'
                                        ? 'Some asymmetry between winning and losing trades; consider tighter stops on losers'
                                        : 'Win/loss magnitudes look balanced' },
    ],
  };
};

// Overtrading — too many small trades?
const diagOvertrading = (trips) => {
  if (trips.length < 3) return { severity: 'low', evidence: [{ label: 'Trades', value: 'Not enough activity to detect' }] };
  const totalPnL = trips.reduce((a, b) => a + b.pnl, 0);
  const medianPnL = (() => {
    const sorted = [...trips].map(t => t.pnl).sort((a, b) => a - b);
    return sorted[Math.floor(sorted.length / 2)];
  })();
  const winRate = trips.filter(t => t.pnl > 0).length / trips.length;
  // Overtrading proxy — many trades with median PnL near zero
  // suggests churning. Real implementation would weigh fees/spread.
  let severity = 'low';
  if (trips.length > 30 && Math.abs(medianPnL) < 5) severity = 'high';
  else if (trips.length > 15 && Math.abs(medianPnL) < 10) severity = 'medium';
  return {
    severity,
    evidence: [
      { label: 'Total round-trips', value: `${trips.length}` },
      { label: 'Total PnL',         value: `$${totalPnL.toFixed(2)}` },
      { label: 'Median PnL',        value: `$${medianPnL.toFixed(2)}` },
      { label: 'Win rate',          value: `${(winRate * 100).toFixed(1)}%` },
      { label: 'Reading',           value: severity === 'high'
                                       ? 'Many trades with low median PnL — likely churning. Fees and spread eat the edge.'
                                       : severity === 'medium'
                                       ? 'Frequent activity with thin per-trade PnL; review whether fees are eating returns'
                                       : 'Trade frequency is reasonable for the per-trade PnL distribution' },
    ],
  };
};

// Chasing momentum — entering after big moves up
const diagChasingMomentum = (trips) => {
  if (trips.length < 5) return { severity: 'low', evidence: [{ label: 'Trades', value: 'Not enough trades to detect' }] };
  // Use realized return as a proxy for "did the trade work" — if
  // many entries had negative returns it suggests entering hot moves
  // that then reverted. Lacking entry-day historical context here.
  const losers = trips.filter(t => t.pnl < 0);
  const lossRate = losers.length / trips.length;
  const avgLoser = losers.length > 0 ? losers.reduce((a, b) => a + b.ret, 0) / losers.length : 0;
  let severity = 'low';
  if (lossRate > 0.65 && avgLoser < -0.05) severity = 'high';
  else if (lossRate > 0.55) severity = 'medium';
  return {
    severity,
    evidence: [
      { label: 'Loss rate',          value: `${(lossRate * 100).toFixed(1)}%` },
      { label: 'Avg losing return',  value: `${(avgLoser * 100).toFixed(2)}%` },
      { label: 'Reading',            value: severity === 'high'
                                        ? 'High loss rate with notable losing returns — entries may be late in moves. Consider waiting for pullbacks rather than chasing'
                                        : severity === 'medium'
                                        ? 'More than half of trades closed at a loss; review entry timing'
                                        : 'Entry timing looks reasonable' },
    ],
  };
};

// Anchoring — entries clustered around round numbers
const diagAnchoring = (trips) => {
  if (trips.length < 5) return { severity: 'low', evidence: [{ label: 'Trades', value: 'Not enough trades' }] };
  // Check fraction of entry prices that are within 1% of a round
  // number (ending in .00 or .50)
  let anchored = 0;
  for (const t of trips) {
    const p = t.entryPrice;
    if (!Number.isFinite(p) || p <= 0) continue;
    // Round to nearest .00, .50, or 5.00 / 10.00 depending on price
    const tier = p > 100 ? 5 : p > 10 ? 1 : 0.5;
    const nearest = Math.round(p / tier) * tier;
    const distPct = Math.abs(p - nearest) / p;
    if (distPct < 0.01) anchored++;
  }
  const ratio = anchored / trips.length;
  let severity = 'low';
  if (ratio > 0.5) severity = 'high';
  else if (ratio > 0.3) severity = 'medium';
  return {
    severity,
    evidence: [
      { label: 'Trades near round numbers', value: `${anchored} / ${trips.length}` },
      { label: 'Fraction',                  value: `${(ratio * 100).toFixed(1)}%` },
      { label: 'Reading',                   value: severity === 'high'
                                              ? 'Many entries cluster around round numbers — anchor bias. Try entering on technical levels instead.'
                                              : severity === 'medium'
                                              ? 'Some clustering near round numbers; review whether entries are price-driven or level-driven'
                                              : 'Entry prices show no clear round-number anchoring' },
    ],
  };
};

const analyzeTradeJournal = (trades) => {
  const trips = buildRoundTrips(trades);
  return {
    summary: {
      tradesTotal:    trades?.length || 0,
      roundTripsTotal: trips.length,
      totalPnL:       trips.reduce((a, b) => a + b.pnl, 0),
      winRate:        trips.length > 0 ? trips.filter(t => t.pnl > 0).length / trips.length : 0,
      avgWin:         (() => {
        const w = trips.filter(t => t.pnl > 0);
        return w.length > 0 ? w.reduce((a, b) => a + b.pnl, 0) / w.length : 0;
      })(),
      avgLoss:        (() => {
        const l = trips.filter(t => t.pnl < 0);
        return l.length > 0 ? l.reduce((a, b) => a + b.pnl, 0) / l.length : 0;
      })(),
    },
    diagnostics: {
      disposition:  diagDispositionEffect(trips),
      overtrading:  diagOvertrading(trips),
      chasing:      diagChasingMomentum(trips),
      anchoring:    diagAnchoring(trips),
    },
    roundTrips: trips,
  };
};

// parseBrokerCSV — parses a broker trade export CSV into our internal
// trade format. Supports common shapes from IBKR (Flex Query),
// Fidelity, Schwab, Robinhood, generic (date/symbol/side/qty/price).
//
// Strategy:
//   1. Try to detect format from headers
//   2. Apply the matching column mapping
//   3. Normalize each row to { sym, side, size, price, time, source }
//
// Returns { trades: [...], format: 'ibkr'|'fidelity'|'schwab'|'rh'|'generic'|'unknown',
//          errors: [...], rowCount }
const parseBrokerCSV = (text, manualMapping = null) => {
  if (!text || typeof text !== 'string') {
    return { trades: [], format: 'unknown', errors: ['Empty file'], rowCount: 0, header: [], rawSample: [] };
  }
  // Naive CSV split — handles quoted fields with commas
  const splitCSVLine = (line) => {
    const out = [];
    let cur = '', inQuotes = false;
    for (let i = 0; i < line.length; i++) {
      const ch = line[i];
      if (ch === '"') { inQuotes = !inQuotes; continue; }
      if (ch === ',' && !inQuotes) { out.push(cur); cur = ''; continue; }
      cur += ch;
    }
    out.push(cur);
    return out.map(c => c.trim());
  };
  const lines = text.split(/\r?\n/).filter(l => l.trim().length > 0);
  if (lines.length < 2) {
    return { trades: [], format: 'unknown', errors: ['No data rows found'], rowCount: 0, header: [], rawSample: [] };
  }
  const headerRaw = splitCSVLine(lines[0]);
  const header = headerRaw.map(h => h.toLowerCase().replace(/[\s_-]/g, ''));
  // Sample first 3 rows for manual-mapping UI
  const rawSample = lines.slice(0, Math.min(4, lines.length)).map(splitCSVLine);
  // Format detection
  let format = 'generic';
  if (header.includes('clientaccountid') || header.includes('symbol') && header.includes('tradedate') && header.includes('proceeds')) {
    format = 'ibkr';
  } else if (header.includes('action') && header.includes('symbol') && header.includes('quantity') && header.includes('price')) {
    format = 'fidelity';
  } else if (header.includes('action') && header.includes('symbol') && (header.includes('shares') || header.includes('qty'))) {
    format = 'schwab';
  } else if (header.includes('side') && header.includes('symbol') && header.includes('quantity')) {
    format = 'rh';
  }
  // Column lookup helpers
  const findCol = (...names) => {
    for (const n of names) {
      const idx = header.indexOf(n.toLowerCase().replace(/[\s_-]/g, ''));
      if (idx >= 0) return idx;
    }
    return -1;
  };
  // Format-specific column mapping
  const mapping = {
    ibkr: {
      symbol: findCol('symbol'),
      side:   findCol('buysell'),
      qty:    findCol('quantity'),
      price:  findCol('tradeprice'),
      date:   findCol('tradedate', 'datetime'),
    },
    fidelity: {
      symbol: findCol('symbol'),
      side:   findCol('action'),
      qty:    findCol('quantity'),
      price:  findCol('price'),
      date:   findCol('rundate', 'date', 'tradedate'),
    },
    schwab: {
      symbol: findCol('symbol'),
      side:   findCol('action'),
      qty:    findCol('quantity', 'qty', 'shares'),
      price:  findCol('price'),
      date:   findCol('date'),
    },
    rh: {
      symbol: findCol('symbol'),
      side:   findCol('side'),
      qty:    findCol('quantity'),
      price:  findCol('averageprice', 'price'),
      date:   findCol('date'),
    },
    generic: {
      symbol: findCol('symbol', 'ticker'),
      side:   findCol('side', 'action', 'type'),
      qty:    findCol('quantity', 'qty', 'shares', 'size'),
      price:  findCol('price', 'fillprice'),
      date:   findCol('date', 'datetime', 'time', 'tradedate'),
    },
  };
  // If a manual column mapping is provided, override auto-detected
  // column indices. manualMapping = { symbol: 2, side: 3, qty: 4, price: 5, date: 1 }
  let cols = mapping[format] || mapping.generic;
  if (manualMapping && typeof manualMapping === 'object') {
    cols = {
      symbol: typeof manualMapping.symbol === 'number' ? manualMapping.symbol : cols.symbol,
      side:   typeof manualMapping.side   === 'number' ? manualMapping.side   : cols.side,
      qty:    typeof manualMapping.qty    === 'number' ? manualMapping.qty    : cols.qty,
      price:  typeof manualMapping.price  === 'number' ? manualMapping.price  : cols.price,
      date:   typeof manualMapping.date   === 'number' ? manualMapping.date   : cols.date,
    };
    format = 'manual';
  }
  if (cols.symbol < 0 || cols.qty < 0 || cols.price < 0) {
    return {
      trades: [],
      format: 'unknown',
      errors: [`Couldn't find required columns. Need at least symbol, quantity, price. Detected format: ${format}. Use the manual column mapping below.`],
      rowCount: 0,
      header: headerRaw,
      rawSample,
    };
  }
  const trades = [];
  const errors = [];
  for (let i = 1; i < lines.length; i++) {
    const row = splitCSVLine(lines[i]);
    if (row.length < 3) continue;
    const sym = (row[cols.symbol] || '').toUpperCase().trim();
    if (!sym || sym.length > 10) continue;
    let side = (row[cols.side] || 'buy').toLowerCase().trim();
    // Normalize side spellings: "BUY", "BOT", "Buy to Open", "Sell to Close" etc.
    if (side.includes('buy') || side === 'b' || side === 'bot') side = 'buy';
    else if (side.includes('sell') || side === 's' || side === 'sld') side = 'sell';
    else continue;
    const qty = Math.abs(parseFloat(row[cols.qty]) || 0);
    const price = parseFloat(row[cols.price]) || 0;
    if (qty <= 0 || price <= 0) {
      errors.push(`Row ${i + 1}: invalid qty/price`);
      continue;
    }
    let time = '';
    if (cols.date >= 0 && row[cols.date]) {
      time = row[cols.date];
    }
    trades.push({
      sym, side,
      size: qty.toString(),
      price: price.toFixed(2),
      time,
      source: format,
    });
  }
  return {
    trades,
    format,
    errors: errors.slice(0, 10),
    rowCount: lines.length - 1,
    header: headerRaw,
    rawSample,
  };
};

