// ════════════════════════════════════════════════════════════════════
// SECTOR ROTATION TRACKER
// ════════════════════════════════════════════════════════════════════
//
// Tracks momentum across the 11 SPDR sector ETFs, ranks them, and
// suggests a rotation strategy (top-3 long / bottom-3 short, or
// momentum-overlay weighting).
const SECTOR_ETFS = [
  { symbol: 'XLK', label: 'Technology' },
  { symbol: 'XLV', label: 'Health Care' },
  { symbol: 'XLF', label: 'Financials' },
  { symbol: 'XLY', label: 'Consumer Discretionary' },
  { symbol: 'XLP', label: 'Consumer Staples' },
  { symbol: 'XLE', label: 'Energy' },
  { symbol: 'XLI', label: 'Industrials' },
  { symbol: 'XLB', label: 'Materials' },
  { symbol: 'XLU', label: 'Utilities' },
  { symbol: 'XLRE', label: 'Real Estate' },
  { symbol: 'XLC', label: 'Communications' },
];

// computeSectorMomentum — for each sector ETF, compute 1m / 3m / 6m
// momentum from price series. Returns ranked list. Standard momentum
// formula: (P_t - P_{t-N}) / P_{t-N}.
const computeSectorMomentum = (priceSeriesBySymbol) => {
  const out = [];
  for (const sec of SECTOR_ETFS) {
    const prices = priceSeriesBySymbol[sec.symbol];
    if (!Array.isArray(prices) || prices.length < 130) continue;
    const cur = prices[prices.length - 1];
    const m1  = prices[prices.length - 21]  || cur;
    const m3  = prices[prices.length - 63]  || cur;
    const m6  = prices[prices.length - 126] || cur;
    if (!cur || cur <= 0) continue;
    out.push({
      symbol: sec.symbol,
      label: sec.label,
      cur,
      mom1m: ((cur - m1) / m1) * 100,
      mom3m: ((cur - m3) / m3) * 100,
      mom6m: ((cur - m6) / m6) * 100,
      // Composite score = average of three momenta with longer window
      // weighted slightly more (favors persistence over recency)
      composite: (((cur - m1) / m1) * 0.20 +
                  ((cur - m3) / m3) * 0.35 +
                  ((cur - m6) / m6) * 0.45) * 100,
    });
  }
  out.sort((a, b) => b.composite - a.composite);
  // Tag rank-based recommendations
  const n = out.length;
  for (let i = 0; i < n; i++) {
    if (i < 3) out[i].recommendation = 'overweight';
    else if (i >= n - 3) out[i].recommendation = 'underweight';
    else out[i].recommendation = 'neutral';
  }
  return out;
};

// ════════════════════════════════════════════════════════════════════
// RISK-PARITY PORTFOLIO CONSTRUCTOR
// ════════════════════════════════════════════════════════════════════
//
// Risk parity allocates capital so that each position contributes
// EQUALLY to portfolio variance — not equally weighted in dollars.
// This means low-vol assets get more dollars, high-vol assets get
// fewer. The classical Markowitz alternative when you have no view
// on returns, just on the risk profile.
//
// Algorithm: iterative Newton-style update
//   Risk contribution of asset i = w_i · (Σw)_i / σ_p
//   We want all RC_i = 1/n (equal contribution)
//   Update: w_i ← w_i · (1/n) / RC_i, then renormalize
//   Repeat until convergence (RC_i within tolerance)
//
// Inputs:
//   holdings: [{symbol, qty, mark, returns}]
// Output:
//   {
//     optimalWeights: { symbol → weight },
//     currentWeights: { symbol → weight },
//     riskContributions: { symbol → fraction of total var },
//     suggestions: [{symbol, currentWeight, optimalWeight, deltaPct}],
//     iterations: number,
//     converged: bool,
//     error?: string
//   }
const runRiskParity = ({ holdings, maxIterations = 200, tolerance = 1e-5 }) => {
  const empty = {
    optimalWeights: {}, currentWeights: {}, riskContributions: {},
    suggestions: [], iterations: 0, converged: false, error: null,
  };
  if (!Array.isArray(holdings) || holdings.length < 2) {
    return { ...empty, error: 'Need at least 2 positions' };
  }
  const valid = holdings.filter(h =>
    Array.isArray(h.returns) && h.returns.length >= 30 &&
    Number.isFinite(h.qty) && Number.isFinite(h.mark)
  );
  if (valid.length < 2) {
    return { ...empty, error: 'Need at least 2 positions with 30+ bars of return history' };
  }
  const n = valid.length;
  const symbols = valid.map(h => h.symbol);
  const minLen = Math.min(...valid.map(h => h.returns.length));
  if (minLen < 30) return { ...empty, error: 'Insufficient return history' };
  const series = valid.map(h => h.returns.slice(-minLen));
  // Build covariance matrix (annualized)
  const ANN = 252;
  const means = series.map(s => s.reduce((a, b) => a + b, 0) / minLen);
  const Sigma = Array.from({ length: n }, () => new Array(n).fill(0));
  for (let i = 0; i < n; i++) {
    for (let j = i; j < n; j++) {
      let cov = 0;
      for (let k = 0; k < minLen; k++) {
        cov += (series[i][k] - means[i]) * (series[j][k] - means[j]);
      }
      cov = (cov / minLen) * ANN;
      Sigma[i][j] = Sigma[j][i] = cov;
    }
  }
  // Initial weights: 1/n equal-dollar (a reasonable starting point)
  let w = new Array(n).fill(1 / n);
  // Iterate
  let iter = 0;
  let converged = false;
  for (iter = 0; iter < maxIterations; iter++) {
    // Σw
    const Sw = new Array(n).fill(0);
    for (let i = 0; i < n; i++) {
      for (let j = 0; j < n; j++) Sw[i] += Sigma[i][j] * w[j];
    }
    // σ_p² = w' Σ w
    let sigma2 = 0;
    for (let i = 0; i < n; i++) sigma2 += w[i] * Sw[i];
    if (sigma2 <= 0) break;
    // Risk contribution RC_i = w_i · (Σw)_i / σ_p²
    const rc = w.map((wi, i) => (wi * Sw[i]) / sigma2);
    const target = 1 / n;
    // Check convergence
    const maxDev = Math.max(...rc.map(r => Math.abs(r - target)));
    if (maxDev < tolerance) {
      converged = true;
      break;
    }
    // Update: w_i ← w_i · target / RC_i (with safety floor)
    const wNew = w.map((wi, i) => wi * target / Math.max(1e-9, rc[i]));
    const sum = wNew.reduce((a, b) => a + b, 0);
    if (sum <= 0) break;
    w = wNew.map(wi => wi / sum);
  }
  // Final risk contributions
  const SwFinal = new Array(n).fill(0);
  for (let i = 0; i < n; i++) {
    for (let j = 0; j < n; j++) SwFinal[i] += Sigma[i][j] * w[j];
  }
  let sigma2Final = 0;
  for (let i = 0; i < n; i++) sigma2Final += w[i] * SwFinal[i];
  const rcFinal = w.map((wi, i) => sigma2Final > 0 ? (wi * SwFinal[i]) / sigma2Final : 0);
  // Current weights from holdings
  const totalMV = valid.reduce((s, h) => s + Math.abs(h.qty * h.mark), 0);
  const wCur = valid.map(h => Math.abs(h.qty * h.mark) / Math.max(1, totalMV));
  const optMap = {}, curMap = {}, rcMap = {};
  for (let i = 0; i < n; i++) {
    optMap[symbols[i]] = w[i];
    curMap[symbols[i]] = wCur[i];
    rcMap[symbols[i]] = rcFinal[i];
  }
  const suggestions = symbols.map((s, i) => ({
    symbol: s,
    currentWeight: wCur[i],
    optimalWeight: w[i],
    riskContribution: rcFinal[i],
    deltaPct: (w[i] - wCur[i]) * 100,
  })).sort((a, b) => Math.abs(b.deltaPct) - Math.abs(a.deltaPct));
  return {
    optimalWeights: optMap,
    currentWeights: curMap,
    riskContributions: rcMap,
    suggestions,
    iterations: iter + 1,
    converged,
    error: null,
    portfolioVol: Math.sqrt(sigma2Final),
  };
};

