// computeInsiderClusterScore — for a given ticker, compute a score
// 0-100 reflecting recent insider activity (heavier weight on buys
// than sells since buys are more informative). Used to rank tickers
// by "insider conviction" signal.
const computeInsiderClusterScore = (trades) => {
  if (!Array.isArray(trades) || trades.length === 0) return 0;
  let score = 0;
  for (const t of trades) {
    const dollars = (Number(t.shares) || 0) * (Number(t.pricePerShare) || 0);
    const ageDays = (Date.now() - new Date(t.date).getTime()) / 86400000;
    if (ageDays > 90) continue; // ignore stale
    const recencyWeight = Math.exp(-ageDays / 60); // decays over 60 days
    if (t.type === 'buy') {
      score += 1.5 * Math.log10(Math.max(10, dollars)) * recencyWeight; // buys weighted 1.5x
    } else {
      score -= 1.0 * Math.log10(Math.max(10, dollars)) * recencyWeight;
    }
  }
  return Math.max(0, Math.min(100, 50 + score * 10));
};

// ════════════════════════════════════════════════════════════════════
// MACROECONOMIC REGIME CLASSIFIER
// ════════════════════════════════════════════════════════════════════
//
// Aggregates several "regime indicators" into a classification of
// the current macro environment:
//
//   Regime axis 1: Risk-On vs Risk-Off
//     Indicators: SPX vs 200SMA, VIX level, HYG/IEF credit spread
//
//   Regime axis 2: Growth vs Contraction
//     Indicators: SPX 6m return, IWM (small caps), copper/gold ratio,
//                 yield curve slope (steepening = growth expectation)
//
//   Regime axis 3: Inflation Up vs Down
//     Indicators: TIPS breakeven (we proxy via TIP/IEF), 5Y5Y forward,
//                 commodity index (DBC), DXY (USD strength)
//
// Output: a single composite regime label + axis scores in [-1, 1].
const classifyMacroRegime = (signals) => {
  // signals is a dict of { symbol → priceSeries }
  const safe = (sym) => Array.isArray(signals[sym]) && signals[sym].length >= 200 ? signals[sym] : null;
  const spx = safe('SPY');
  const vix = safe('VIX') || safe('^VIX');
  const hyg = safe('HYG');
  const ief = safe('IEF');
  const iwm = safe('IWM');
  const tip = safe('TIP');
  const dbc = safe('DBC');
  const uup = safe('UUP');
  // Risk-on axis
  let riskOn = 0, riskOnTerms = 0;
  if (spx) {
    const cur = spx[spx.length - 1];
    const sma200 = spx.slice(-200).reduce((a, b) => a + b, 0) / 200;
    riskOn += cur > sma200 ? 1 : -1;
    riskOnTerms++;
  }
  if (hyg && ief) {
    // Use return ratio over last 60 days as a proxy for credit-spread direction
    const hygRet = (hyg[hyg.length - 1] - hyg[hyg.length - 61]) / hyg[hyg.length - 61];
    const iefRet = (ief[ief.length - 1] - ief[ief.length - 61]) / ief[ief.length - 61];
    riskOn += (hygRet - iefRet) > 0 ? 1 : -1;
    riskOnTerms++;
  }
  if (vix && vix.length > 1) {
    const cur = vix[vix.length - 1];
    riskOn += cur < 18 ? 1 : cur > 25 ? -1 : 0;
    riskOnTerms++;
  }
  riskOn = riskOnTerms > 0 ? riskOn / riskOnTerms : 0;
  // Growth axis
  let growth = 0, growthTerms = 0;
  if (spx) {
    const ret6m = (spx[spx.length - 1] - spx[spx.length - 126]) / spx[spx.length - 126];
    growth += ret6m > 0.05 ? 1 : ret6m < -0.05 ? -1 : ret6m * 10;
    growthTerms++;
  }
  if (iwm && spx) {
    // Small-caps outperformance signals growth optimism
    const iwmRet = (iwm[iwm.length - 1] - iwm[iwm.length - 63]) / iwm[iwm.length - 63];
    const spxRet = (spx[spx.length - 1] - spx[spx.length - 63]) / spx[spx.length - 63];
    growth += (iwmRet - spxRet) > 0 ? 1 : -1;
    growthTerms++;
  }
  growth = growthTerms > 0 ? growth / growthTerms : 0;
  // Inflation axis (TIPS/IEF ratio = breakeven proxy)
  let inflation = 0, inflTerms = 0;
  if (tip && ief) {
    const tipRet = (tip[tip.length - 1] - tip[tip.length - 63]) / tip[tip.length - 63];
    const iefRet = (ief[ief.length - 1] - ief[ief.length - 63]) / ief[ief.length - 63];
    // If TIP outperforms IEF, breakevens widening → inflation rising
    inflation += (tipRet - iefRet) > 0 ? 1 : -1;
    inflTerms++;
  }
  if (dbc) {
    const ret3m = (dbc[dbc.length - 1] - dbc[dbc.length - 63]) / dbc[dbc.length - 63];
    inflation += ret3m > 0.05 ? 1 : ret3m < -0.05 ? -1 : ret3m * 10;
    inflTerms++;
  }
  if (uup) {
    // Strong USD typically deflationary
    const ret3m = (uup[uup.length - 1] - uup[uup.length - 63]) / uup[uup.length - 63];
    inflation -= ret3m > 0.03 ? 1 : ret3m < -0.03 ? -1 : 0;
    inflTerms++;
  }
  inflation = inflTerms > 0 ? inflation / inflTerms : 0;
  // Regime label — pick the dominant pair
  const labels = [];
  if (Math.abs(riskOn) > 0.3) labels.push(riskOn > 0 ? 'Risk-On' : 'Risk-Off');
  if (Math.abs(growth) > 0.3) labels.push(growth > 0 ? 'Growth' : 'Contraction');
  if (Math.abs(inflation) > 0.3) labels.push(inflation > 0 ? 'Inflation' : 'Disinflation');
  const label = labels.length === 0 ? 'Mixed / Transitional' : labels.join(' · ');
  return {
    label,
    riskOn: Math.max(-1, Math.min(1, riskOn)),
    growth: Math.max(-1, Math.min(1, growth)),
    inflation: Math.max(-1, Math.min(1, inflation)),
    confidence: ((riskOnTerms + growthTerms + inflTerms) / 8), // max 8 indicators
  };
};

// REGIME_PLAYBOOK — historical patterns for what tends to work in each regime.
// Hand-curated from finance-textbook playbooks. Not investment advice; meant
// to give users context for "what does the past say about this kind of
// environment?".
const REGIME_PLAYBOOK = {
  'Risk-On · Growth': {
    favored: ['Tech (XLK)', 'Small caps (IWM)', 'Cyclicals (XLY)', 'Emerging markets (EEM)'],
    avoided: ['Long duration bonds (TLT)', 'Defensive staples (XLP)', 'Utilities (XLU)'],
    rationale: 'Equity beta wins; risk premia tighten; growth multiples expand. Historical: 2017, 2020 H2-2021.',
  },
  'Risk-Off · Contraction': {
    favored: ['Long bonds (TLT)', 'Gold (GLD)', 'Defensive staples (XLP)', 'Healthcare (XLV)'],
    avoided: ['Small caps (IWM)', 'High yield (HYG)', 'Cyclicals (XLY)', 'Energy (XLE)'],
    rationale: 'Flight to quality; duration rallies; risk assets sell off. Historical: 2008, 2020 Q1, 2022 H1.',
  },
  'Risk-On · Inflation': {
    favored: ['Energy (XLE)', 'Materials (XLB)', 'Financials (XLF)', 'TIPS (TIP)', 'Commodities (DBC)'],
    avoided: ['Long bonds (TLT)', 'Tech with no earnings', 'Real estate (XLRE)'],
    rationale: 'Reflation trade; nominal growth re-accelerates; cyclicals + commodities outperform. Historical: 2021-22 reflation.',
  },
  'Risk-Off · Inflation': {
    favored: ['Cash / short duration (BIL)', 'Energy (XLE)', 'Defensive staples (XLP)', 'Gold (GLD)'],
    avoided: ['Long bonds (TLT)', 'Growth tech', 'Small caps (IWM)'],
    rationale: 'Stagflation regime — rare and painful. 1973-74 the canonical example. Both equities and bonds suffer.',
  },
  'Risk-On · Disinflation': {
    favored: ['Long bonds (TLT)', 'Tech (XLK)', 'Communications (XLC)', 'Real estate (XLRE)'],
    avoided: ['Energy (XLE)', 'Materials (XLB)', 'Commodities (DBC)'],
    rationale: 'Goldilocks: growth without inflation pressure; multiples expand; duration rallies. Historical: 2014-15, late 2019.',
  },
};

// pickPlaybook — given regime axis scores, return the matching playbook
const pickPlaybook = (regime) => {
  const ro = regime.riskOn > 0 ? 'Risk-On' : 'Risk-Off';
  if (regime.inflation > 0.2) return REGIME_PLAYBOOK[`${ro} · Inflation`];
  if (regime.inflation < -0.2) return REGIME_PLAYBOOK[`${ro} · Disinflation`];
  if (regime.growth > 0) return REGIME_PLAYBOOK[`${ro} · Growth`];
  return REGIME_PLAYBOOK[`${ro} · Contraction`];
};

// ════════════════════════════════════════════════════════════════════
// DRAWDOWN ANALYZER
// ════════════════════════════════════════════════════════════════════
//
// Tracks a portfolio's drawdown over time — the percentage decline
// from its running peak. The "underwater curve" is one of the most
// important visualizations in performance analysis because the
// average return tells you nothing about how painful the journey
// was.
//
// computeDrawdownSeries — given a portfolio MV time series, returns:
//   - drawdownPct[]  per-bar drawdown (0 to -1, where -0.20 = -20%)
//   - peakIdx[]      index of the running peak at each bar
//   - currentDD      drawdown at the latest bar
//   - maxDD          worst drawdown over the period
//   - maxDDStart     bar index where the worst DD began
//   - maxDDEnd       bar index where the worst DD bottomed
//   - maxDDRecover   bar index where MV recovered (or -1 if still underwater)
//   - daysUnderwater bars since the last all-time high
//   - timeToRecover  avg recovery time across closed drawdowns

const computeDrawdownSeries = (mvSeries) => {
  const empty = {
    drawdownPct: [], peakIdx: [], currentDD: 0, maxDD: 0,
    maxDDStart: 0, maxDDEnd: 0, maxDDRecover: -1,
    daysUnderwater: 0, timeToRecover: 0, drawdowns: [],
  };
  if (!Array.isArray(mvSeries) || mvSeries.length < 2) return empty;
  const n = mvSeries.length;
  const drawdownPct = new Array(n).fill(0);
  const peakIdx = new Array(n).fill(0);
  let runningPeak = mvSeries[0];
  let runningPeakIdx = 0;
  for (let i = 0; i < n; i++) {
    if (mvSeries[i] > runningPeak) {
      runningPeak = mvSeries[i];
      runningPeakIdx = i;
    }
    drawdownPct[i] = runningPeak > 0 ? (mvSeries[i] - runningPeak) / runningPeak : 0;
    peakIdx[i] = runningPeakIdx;
  }
  // Identify all distinct drawdown episodes (peak → trough → recovery)
  const drawdowns = [];
  let inDD = false;
  let ddStart = 0, ddTrough = 0, ddTroughVal = 0;
  for (let i = 0; i < n; i++) {
    if (!inDD && drawdownPct[i] < 0) {
      inDD = true;
      ddStart = peakIdx[i];
      ddTrough = i;
      ddTroughVal = drawdownPct[i];
    } else if (inDD) {
      if (drawdownPct[i] < ddTroughVal) {
        ddTrough = i;
        ddTroughVal = drawdownPct[i];
      }
      if (drawdownPct[i] >= 0) {
        drawdowns.push({
          start: ddStart, trough: ddTrough, recover: i,
          depthPct: ddTroughVal, durationBars: i - ddStart,
        });
        inDD = false;
      }
    }
  }
  // If still in DD at the end, record an open episode
  if (inDD) {
    drawdowns.push({
      start: ddStart, trough: ddTrough, recover: -1,
      depthPct: ddTroughVal, durationBars: (n - 1) - ddStart,
    });
  }
  // Aggregates
  const currentDD = drawdownPct[n - 1];
  let maxDD = 0, maxDDStart = 0, maxDDEnd = 0, maxDDRecover = -1;
  for (const dd of drawdowns) {
    if (dd.depthPct < maxDD) {
      maxDD = dd.depthPct;
      maxDDStart = dd.start;
      maxDDEnd = dd.trough;
      maxDDRecover = dd.recover;
    }
  }
  // Days underwater = bars since last all-time high
  const lastPeakIdx = peakIdx[n - 1];
  const daysUnderwater = (n - 1) - lastPeakIdx;
  // Avg recovery time across closed drawdowns
  const closed = drawdowns.filter(d => d.recover !== -1);
  const timeToRecover = closed.length > 0
    ? closed.reduce((sum, d) => sum + (d.recover - d.trough), 0) / closed.length
    : 0;
  return {
    drawdownPct, peakIdx, currentDD, maxDD,
    maxDDStart, maxDDEnd, maxDDRecover,
    daysUnderwater, timeToRecover, drawdowns,
  };
};

// ════════════════════════════════════════════════════════════════════
// YIELD CURVE / RECESSION MONITOR
// ════════════════════════════════════════════════════════════════════
//
// The 3M-10Y treasury yield spread is the single best leading
// recession indicator (Estrella & Mishkin, 1998 — NY Fed working
// paper). When the curve inverts (3M > 10Y), recession probability
// 12 months out rises sharply.
//
// computeRecessionProbability — Estrella-Mishkin probit-style
// estimate. Given the 3M-10Y spread (in percentage points), returns
// 12-month-ahead recession probability in [0, 1].
//
// Original Estrella coefficients (US, 1959-1995 data):
//   logit(P) = -0.5333 - 0.6330 × spread
// We use this calibration as-is; updates from later data are similar.
const computeRecessionProbability = (spread3m10y) => {
  if (!Number.isFinite(spread3m10y)) return null;
  const logit = -0.5333 - 0.6330 * spread3m10y;
  const prob = 1 / (1 + Math.exp(-logit));
  return Math.max(0, Math.min(1, prob));
};

// ETF proxies for treasury yields. We use TLT-style funds because
// Polygon doesn't expose the actual constant-maturity rates as
// aggregateable tickers; we approximate yields from price-implied
// duration. For real production this would use the Treasury direct
// rates feed via DBnomics (which we already have).
//
// SHY = 1-3 yr, IEI = 3-7 yr, IEF = 7-10 yr, TLT = 20+ yr,
// BIL = 1-3 mo (close to 3M rate)
const TREASURY_PROXIES = [
  { symbol: 'BIL', label: '1-3M T-bills', tenor: '3M' },
  { symbol: 'SHY', label: '1-3Y notes',   tenor: '2Y' },
  { symbol: 'IEI', label: '3-7Y notes',   tenor: '5Y' },
  { symbol: 'IEF', label: '7-10Y notes',  tenor: '10Y' },
  { symbol: 'TLT', label: '20+Y bonds',   tenor: '30Y' },
];

// ════════════════════════════════════════════════════════════════════
// VOLATILITY REGIME TRACKER
// ════════════════════════════════════════════════════════════════════
//
// Tracks vol regime via three lenses:
//   1. Spot vol level (VIX-equivalent — we compute realized 30d on SPY)
//   2. Term structure (short-vol / long-vol ratio; > 1 = backwardation
//      = stress regime; < 1 = contango = calm regime)
//   3. IV vs RV — implied vs realized vol gap. High gap = vol risk
//      premium is rich (good time to be short vol via covered calls).
//      Low gap = compressed = vol about to expand.

const computeRealizedVol = (returns, period = 30) => {
  if (!Array.isArray(returns) || returns.length < period + 1) return null;
  const slice = returns.slice(-period);
  const mean = slice.reduce((a, b) => a + b, 0) / period;
  const variance = slice.reduce((a, b) => a + (b - mean) ** 2, 0) / period;
  return Math.sqrt(variance) * Math.sqrt(252) * 100; // annualized %
};

// ════════════════════════════════════════════════════════════════════
// VOLUME PROFILE / PRICE HISTOGRAM
// ════════════════════════════════════════════════════════════════════
//
// Aggregates volume-traded by price level over a lookback window.
// Outputs:
//   - bins: [{ priceLow, priceHigh, priceMid, volume }, …]
//   - poc:        Point of Control — price with highest volume
//   - valueArea:  high-volume range covering 70% of total volume (VAH/VAL)
//   - hvn:        High Volume Nodes (local maxima — strong support/resistance)
//   - lvn:        Low Volume Nodes (local minima — weak liquidity zones)
//
// Each OHLCV bar contributes its volume distributed across the
// [low, high] range it touched, weighted by typical-price proximity.
// We use a simple uniform-distribution model: each bar's volume
// gets divided evenly across the bins that fall in its [low, high].
const computeVolumeProfile = (bars, binCount = 24) => {
  if (!Array.isArray(bars) || bars.length === 0) {
    return { bins: [], poc: null, vah: null, val: null, hvn: [], lvn: [], totalVolume: 0 };
  }
  // Determine overall price range
  let minP = Infinity, maxP = -Infinity, totalVol = 0;
  for (const b of bars) {
    if (Number.isFinite(b.low)  && b.low  < minP) minP = b.low;
    if (Number.isFinite(b.high) && b.high > maxP) maxP = b.high;
    totalVol += Number(b.volume) || 0;
  }
  if (!Number.isFinite(minP) || !Number.isFinite(maxP) || maxP <= minP || totalVol <= 0) {
    return { bins: [], poc: null, vah: null, val: null, hvn: [], lvn: [], totalVolume: 0 };
  }
  // Build bins
  const binW = (maxP - minP) / binCount;
  const bins = Array.from({ length: binCount }, (_, i) => ({
    priceLow:  minP + i * binW,
    priceHigh: minP + (i + 1) * binW,
    priceMid:  minP + (i + 0.5) * binW,
    volume:    0,
  }));
  // Distribute each bar's volume across the bins it touched
  for (const b of bars) {
    const bLow  = Number(b.low)  || 0;
    const bHigh = Number(b.high) || 0;
    const bVol  = Number(b.volume) || 0;
    if (bHigh <= bLow || bVol <= 0) continue;
    // Find first bin whose priceLow <= bLow (upper-bounded)
    const startBin = Math.max(0, Math.floor((bLow - minP) / binW));
    const endBin   = Math.min(binCount - 1, Math.floor((bHigh - minP) / binW));
    if (endBin < startBin) continue;
    const span = (endBin - startBin) + 1;
    const volPerBin = bVol / span;
    for (let i = startBin; i <= endBin; i++) bins[i].volume += volPerBin;
  }
  // Point of Control — bin with highest volume
  let pocIdx = 0;
  for (let i = 1; i < bins.length; i++) {
    if (bins[i].volume > bins[pocIdx].volume) pocIdx = i;
  }
  // Value Area — expand around POC until 70% of volume captured
  const targetVol = totalVol * 0.70;
  let vaLow = pocIdx, vaHigh = pocIdx;
  let cumVol = bins[pocIdx].volume;
  while (cumVol < targetVol && (vaLow > 0 || vaHigh < binCount - 1)) {
    const nextLow  = vaLow > 0            ? bins[vaLow - 1].volume : -1;
    const nextHigh = vaHigh < binCount - 1 ? bins[vaHigh + 1].volume : -1;
    if (nextLow >= nextHigh && nextLow > 0) {
      vaLow--;
      cumVol += bins[vaLow].volume;
    } else if (nextHigh > 0) {
      vaHigh++;
      cumVol += bins[vaHigh].volume;
    } else {
      break;
    }
  }
  // High-Volume Nodes (HVN) and Low-Volume Nodes (LVN) — local extrema
  const hvn = [];
  const lvn = [];
  for (let i = 1; i < bins.length - 1; i++) {
    if (bins[i].volume > bins[i - 1].volume && bins[i].volume > bins[i + 1].volume) {
      // Local max — significant if ≥50% of POC volume
      if (bins[i].volume >= bins[pocIdx].volume * 0.5) {
        hvn.push({ priceMid: bins[i].priceMid, volume: bins[i].volume });
      }
    }
    if (bins[i].volume < bins[i - 1].volume && bins[i].volume < bins[i + 1].volume) {
      // Local min — significant if ≤25% of POC volume
      if (bins[i].volume <= bins[pocIdx].volume * 0.25) {
        lvn.push({ priceMid: bins[i].priceMid, volume: bins[i].volume });
      }
    }
  }
  return {
    bins,
    poc: bins[pocIdx].priceMid,
    pocVolume: bins[pocIdx].volume,
    vah: bins[vaHigh].priceHigh,
    val: bins[vaLow].priceLow,
    valueAreaVolPct: (cumVol / totalVol) * 100,
    hvn, lvn,
    totalVolume: totalVol,
    binWidth: binW,
  };
};

