// computeSqueezeRisk — score 0-100 reflecting short-squeeze potential.
// Higher = more squeeze potential. Combines:
//   - % of float short (high = more shorts to cover)
//   - Days to cover (high = harder to cover quickly)
//   - Recent change (rising short interest before a catalyst = setup)
const computeSqueezeRisk = (entry) => {
  if (!entry) return 0;
  const floatComponent = Math.min(50, entry.pctOfFloat * 1.0); // up to 50 pts from float
  const dtcComponent = Math.min(30, entry.daysToCover * 4);     // up to 30 pts from DTC
  const trendComponent = Math.max(0, Math.min(20, entry.recentChange * 8)); // up to 20 pts from rising shorts
  return Math.min(100, Math.round(floatComponent + dtcComponent + trendComponent));
};

