// computeAnalystSentiment — convert buy/hold/sell counts into a
// score 0-100. Each buy = +1, hold = 0, sell = -1. Normalize by
// total analysts and rescale to 0-100.
const computeAnalystSentiment = (rating) => {
  if (!rating) return null;
  const total = rating.buy + rating.hold + rating.sell;
  if (total === 0) return null;
  const rawScore = (rating.buy - rating.sell) / total; // -1 to +1
  return {
    score: Math.round(((rawScore + 1) / 2) * 100), // 0-100
    consensus: rawScore >= 0.5 ? 'Strong Buy'
             : rawScore >= 0.2 ? 'Buy'
             : rawScore >= -0.2 ? 'Hold'
             : rawScore >= -0.5 ? 'Sell'
             :                    'Strong Sell',
    upside: rating.priceTarget && rating.currentPrice
      ? ((rating.priceTarget - rating.currentPrice) / rating.currentPrice) * 100
      : null,
    bullCase: rating.high && rating.currentPrice
      ? ((rating.high - rating.currentPrice) / rating.currentPrice) * 100
      : null,
    bearCase: rating.low && rating.currentPrice
      ? ((rating.low - rating.currentPrice) / rating.currentPrice) * 100
      : null,
    total,
  };
};

// ════════════════════════════════════════════════════════════════════
// MARKET BREADTH INDICATORS
// ════════════════════════════════════════════════════════════════════
//
// Market breadth measures how many stocks are participating in a
// move, vs just the index. Strong breadth (most stocks rising) =
// healthy bull market. Weak breadth (only a few names lifting the
// index) = "narrow leadership" = late-cycle warning.
//
// Universe used: S&P 100 (or the largest cap subset we can fetch).
// Real production would track all SPX or Russell 3000 components.

// computeBreadthMetrics — given a map of priceSeriesBySymbol, computes:
//   - pctAbove200SMA  % of universe trading above 200-day SMA
//   - pctAbove50SMA   % above 50-day SMA
//   - advances        # of names up over last 21 bars
//   - declines        # of names down over last 21 bars
//   - newHighs        # of names at 52-week (252-bar) high
//   - newLows         # of names at 52-week low
//   - mcclellanRaw    19/39 EMA difference of advances minus declines
//   - thrustSignal    bool — Zweig breadth thrust (advances/(advances+declines)
//                     moves from < 0.40 to > 0.615 in 10 bars)
const computeBreadthMetrics = (priceSeriesBySymbol, breadthHistory = null) => {
  const symbols = Object.keys(priceSeriesBySymbol).filter(s =>
    Array.isArray(priceSeriesBySymbol[s]) && priceSeriesBySymbol[s].length >= 252);
  if (symbols.length === 0) {
    return {
      pctAbove200SMA: null, pctAbove50SMA: null,
      advances: 0, declines: 0, unchanged: 0,
      newHighs: 0, newLows: 0, mcclellanRaw: null,
      thrustSignal: false, totalSymbols: 0,
    };
  }
  let above200 = 0, above50 = 0;
  let adv = 0, dec = 0, unc = 0;
  let nh = 0, nl = 0;
  for (const s of symbols) {
    const prices = priceSeriesBySymbol[s];
    const cur = prices[prices.length - 1];
    if (!cur || cur <= 0) continue;
    // 200-day SMA
    const sma200 = prices.slice(-200).reduce((a, b) => a + b, 0) / 200;
    if (cur > sma200) above200++;
    // 50-day SMA
    if (prices.length >= 50) {
      const sma50 = prices.slice(-50).reduce((a, b) => a + b, 0) / 50;
      if (cur > sma50) above50++;
    }
    // 21-day return for adv/dec
    if (prices.length >= 22) {
      const ret = (cur - prices[prices.length - 22]) / prices[prices.length - 22];
      if (ret > 0.005) adv++;
      else if (ret < -0.005) dec++;
      else unc++;
    }
    // 52-week high / low
    const slice = prices.slice(-252);
    const max = Math.max(...slice);
    const min = Math.min(...slice);
    if (cur >= max * 0.99) nh++;
    if (cur <= min * 1.01) nl++;
  }
  const total = symbols.length;
  // McClellan Oscillator approximation: 19-EMA minus 39-EMA of (adv - dec)
  // The single-bar fallback is just the raw difference. When breadthHistory
  // is provided (an array of past {advances, declines}), we compute the
  // true 19/39 EMA difference. EMA smoothing constants:
  //   α₁₉ = 2/(19+1) = 0.10
  //   α₃₉ = 2/(39+1) = 0.05
  const mcclellanRaw = adv - dec;
  let mcclellanEMA = null;
  let mcclellanCoverage = 0; // # of history points used
  if (Array.isArray(breadthHistory) && breadthHistory.length >= 5) {
    // Sort chronologically, append today's reading
    const sorted = [...breadthHistory].sort((a, b) => (a.date || '').localeCompare(b.date || ''));
    const series = sorted.map(h => (h.advances || 0) - (h.declines || 0));
    series.push(mcclellanRaw); // today
    mcclellanCoverage = series.length;
    const alpha19 = 2 / (19 + 1);
    const alpha39 = 2 / (39 + 1);
    // Seed both EMAs with the first observation
    let ema19 = series[0];
    let ema39 = series[0];
    for (let i = 1; i < series.length; i++) {
      ema19 = alpha19 * series[i] + (1 - alpha19) * ema19;
      ema39 = alpha39 * series[i] + (1 - alpha39) * ema39;
    }
    mcclellanEMA = ema19 - ema39;
  }
  // Zweig thrust: ratio (adv / (adv + dec)) crossing > 0.615 from < 0.40
  // in last 10 bars. With history we check the canonical 10-bar transition;
  // without, fall back to single-bar check.
  const advRatio = (adv + dec) > 0 ? adv / (adv + dec) : 0.5;
  let thrustSignal = advRatio >= 0.615;
  if (Array.isArray(breadthHistory) && breadthHistory.length >= 10) {
    // True Zweig: check if any of last 10 days had ratio < 0.40 AND today's ratio > 0.615
    const last10 = [...breadthHistory].sort((a, b) => (a.date || '').localeCompare(b.date || '')).slice(-10);
    const anyLow = last10.some(h => {
      const t = (h.advances || 0) + (h.declines || 0);
      return t > 0 && (h.advances / t) < 0.40;
    });
    thrustSignal = anyLow && advRatio >= 0.615;
  }
  return {
    pctAbove200SMA: total > 0 ? (above200 / total) * 100 : null,
    pctAbove50SMA:  total > 0 ? (above50  / total) * 100 : null,
    advances: adv, declines: dec, unchanged: unc,
    newHighs: nh, newLows: nl,
    mcclellanRaw, mcclellanEMA, mcclellanCoverage,
    thrustSignal,
    totalSymbols: total,
    advRatio,
  };
};

// SP100_TICKERS — universe used for breadth analysis. Subset chosen
